INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 15, 'Y dijo más Dios á Moisés: Así dirás á los hijos de Israel: Jehová, el Dios de vuestros padres, el Dios de Abraham, Dios de Isaac y Dios de Jacob, me ha enviado á vosotros. Este es mi nombre para siempre, este es mi memorial por todos los siglos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 16, 'Ve, y junta los ancianos de Israel, y diles: Jehová, el Dios de vuestros padres, el Dios de Abraham, de Isaac, y de Jacob, me apareció, diciendo: De cierto os he visitado, y visto lo que se os hace en Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 17, 'Y he dicho: Yo os sacaré de la aflicción de Egipto á la tierra del Cananeo, y del Hetheo, y del Amorrheo, y del Pherezeo, y del Heveo, y del Jebuseo, á una tierra que fluye leche y miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 18, 'Y oirán tu voz; é irás tú, y los ancianos de Israel, al rey de Egipto, y le diréis: Jehová, el Dios de los Hebreos, nos ha encontrado; por tanto nosotros iremos ahora camino de tres días por el desierto, para que sacrifiquemos á Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 19, 'Mas yo sé que el rey de Egipto no os dejará ir sino por mano fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 20, 'Empero yo extenderé mi mano, y heriré á Egipto con todas mis maravillas que haré en él, y entonces os dejará ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 21, 'Y yo daré á este pueblo gracia en los ojos de los Egipcios, para que cuando os partiereis, no salgáis vacíos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 3, 22, 'Sino que demandará cada mujer á su vecina y á su huéspeda vasos de plata, vasos de oro, y vestidos: los cuales pondréis sobre vuestros hijos y vuestras hijas, y despojaréis á Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 1, 'ENTONCES Moisés respondió, y dijo: He aquí que ellos no me creerán, ni oirán mi voz; porque dirán: No te ha aparecido Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 2, 'Y Jehová dijo: ¿Qué es eso que tienes en tu mano? Y él respondió: Una vara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 3, 'Y él le dijo: Échala en tierra. Y él la echó en tierra, y tornóse una culebra: y Moisés huía de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 4, 'Entonces dijo Jehová á Moisés: Extiende tu mano, y tómala por la cola. Y él extendió su mano, y tomóla, y tornóse vara en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 5, 'Por esto creerán que se te ha aparecido Jehová, el Dios de tus padres, el Dios de Abraham, Dios de Isaac, y Dios de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 6, 'Y díjole más Jehová: Mete ahora tu mano en tu seno. Y él metió la mano en su seno; y como la sacó, he aquí que su mano estaba leprosa como la nieve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 7, 'Y dijo: Vuelve á meter tu mano en tu seno: y él volvió á meter su mano en su seno; y volviéndola á sacar del seno, he aquí que se había vuelto como la otra carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 8, 'Si aconteciere, que no te creyeren, ni obedecieren á la voz de la primera señal, creerán á la voz de la postrera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 9, 'Y si aún no creyeren á estas dos señales, ni oyeren tu voz, tomarás de las aguas del río, y derrámalas en tierra; y volverse han aquellas aguas que tomarás del río, se volverán sangre en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 10, 'Entonces dijo Moisés á Jehová: ¡Ay Señor! yo no soy hombre de palabras de ayer ni de anteayer, ni aun desde que tú hablas á tu siervo; porque soy tardo en el habla y torpe de lengua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 11, 'Y Jehová le respondió: ¿Quién dió la boca al hombre? ¿ó quién hizo al mudo y al sordo, al que ve y al ciego? ¿no soy yo Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 12, 'Ahora pues, ve, que yo seré en tu boca, y te enseñaré lo que hayas de hablar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 13, 'Y él dijo: ¡Ay Señor! envía por mano del que has de enviar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 14, 'Entonces Jehová se enojó contra Moisés, y dijo: ¿No conozco yo á tu hermano Aarón, Levita, y que él hablará? Y aun he aquí que él te saldrá á recibir, y en viéndote, se alegrará en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 15, 'Tú hablarás á él, y pondrás en su boca las palabras, y yo seré en tu boca y en la suya, y os enseñaré lo que hayáis de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 16, 'Y él hablará por ti al pueblo; y él te será á ti en lugar de boca, y tú serás para él en lugar de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 17, 'Y tomarás esta vara en tu mano, con la cual harás las señales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 18, 'Así se fué Moisés, y volviendo á su suegro Jethro, díjole: Iré ahora, y volveré á mis hermanos que están en Egipto, para ver si aún viven. Y Jethro dijo á Moisés: Ve en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 19, 'Dijo también Jehová á Moisés en Madián: Ve, y vuélvete á Egipto, porque han muerto todos los que procuraban tu muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 20, 'Entonces Moisés tomó su mujer y sus hijos, y púsolos sobre un asno, y volvióse á tierra de Egipto: tomó también Moisés la vara de Dios en su mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 21, 'Y dijo Jehová á Moisés: Cuando hubiereis vuelto á Egipto, mira que hagas delante de Faraón todas las maravillas que he puesto en tu mano: yo empero endureceré su corazón, de modo que no dejará ir al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 22, 'Y dirás á Faraón: Jehová ha dicho así: Israel es mi hijo, mi primogénito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 23, 'Ya te he dicho que dejes ir á mi hijo, para que me sirva, mas no has querido dejarlo ir: he aquí yo voy á matar á tu hijo, tu primogénito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 24, 'Y aconteció en el camino, que en una posada le salió al encuentro Jehová, y quiso matarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 25, 'Entonces Séphora cogió un afilado pedernal, y cortó el prepucio de su hijo, y echólo á sus pies, diciendo: A la verdad tú me eres un esposo de sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 26, 'Así le dejó luego ir. Y ella dijo: Esposo de sangre, á causa de la circuncisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 27, 'Y Jehová dijo á Aarón: Ve á recibir á Moisés al desierto. Y él fue, y encontrólo en el monte de Dios, y besóle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 28, 'Entonces contó Moisés á Aarón todas las palabras de Jehová que le enviaba, y todas las señales que le había dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 29, 'Y fueron Moisés y Aarón, y juntaron todos los ancianos de los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 30, 'Y habló Aarón todas las palabras que Jehová había dicho á Moisés, é hizo las señales delante de los ojos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 4, 31, 'Y el pueblo creyó: y oyendo que Jehová había visitado los hijos de Israel, y que había visto su aflicción, inclináronse y adoraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 1, 'DESPUÉS entraron Moisés y Aarón á Faraón, y le dijeron: Jehová, el Dios de Israel, dice así: Deja ir á mi pueblo á celebrarme fiesta en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 2, 'Y Faraón respondió: ¿Quién es Jehová, para que yo oiga su voz y deje ir á Israel? Yo no conozco á Jehová, ni tampoco dejaré ir á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 3, 'Y ellos dijeron: El Dios de los Hebreos nos ha encontrado: iremos, pues, ahora camino de tres días por el desierto, y sacrificaremos á Jehová nuestro Dios; porque no venga sobre nosotros con pestilencia ó con espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 4, 'Entonces el rey de Egipto les dijo: Moisés y Aarón, ¿por qué hacéis cesar al pueblo de su obra? idos á vuestros cargos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 5, 'Dijo también Faraón: He aquí el pueblo de la tierra es ahora mucho, y vosotros les hacéis cesar de sus cargos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 6, 'Y mandó Faraón aquel mismo día á los cuadrilleros del pueblo que le tenían á su cargo, y á sus gobernadores, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 7, 'De aquí adelante no daréis paja al pueblo para hacer ladrillo, como ayer y antes de ayer; vayan ellos y recojan por sí mismos la paja:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 8, 'Y habéis de ponerles la tarea del ladrillo que hacían antes, y no les disminuiréis nada; porque están ociosos, y por eso levantan la voz diciendo: Vamos y sacrificaremos á nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 9, 'Agrávese la servidumbre sobre ellos, para que se ocupen en ella, y no atiendan á palabras de mentira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 10, 'Y saliendo los cuadrilleros del pueblo y sus gobernadores, hablaron al pueblo, diciendo: Así ha dicho Faraón: Yo no os doy paja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 11, 'Id vosotros, y recoged paja donde la hallareis; que nada se disminuirá de vuestra tarea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 12, 'Entonces el pueblo se derramó por toda la tierra de Egipto á coger rastrojo en lugar de paja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 13, 'Y los cuadrilleros los apremiaban, diciendo: Acabad vuestra obra, la tarea del día en su día, como cuando se os daba paja.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 14, 'Y azotaban á los capataces de los hijos de Israel, que los cuadrilleros de Faraón habían puesto sobre ellos, diciendo: ¿Por qué no habéis cumplido vuestra tarea de ladrillo ni ayer ni hoy, como antes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 15, 'Y los capataces de los hijos de Israel vinieron á Faraón, y se quejaron á él, diciendo: ¿Por qué lo haces así con tus siervos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 16, 'No se da paja á tus siervos, y con todo nos dicen: Haced el ladrillo. Y he aquí tus siervos son azotados, y tu pueblo cae en falta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 17, 'Y él respondió: Estáis ociosos, sí, ociosos, y por eso decís: Vamos y sacrifiquemos á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 18, 'Id pues ahora, y trabajad. No se os dará paja, y habéis de dar la tarea del ladrillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 19, 'Entonces los capataces de los hijos de Israel se vieron en aflicción, habiéndoseles dicho: No se disminuirá nada de vuestro ladrillo, de la tarea de cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 20, 'Y encontrando á Moisés y á Aarón, que estaban á la vista de ellos cuando salían de Faraón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 21, 'Dijéronles: Mire Jehová sobre vosotros, y juzgue; pues habéis hecho heder nuestro olor delante de Faraón y de sus siervos, dándoles el cuchillo en las manos para que nos maten.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 22, 'Entonces Moisés se volvió á Jehová, y dijo: Señor, ¿por qué afliges á este pueblo? ¿para qué me enviaste?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 5, 23, 'Porque desde que yo vine á Faraón para hablarle en tu nombre, ha afligido á este pueblo; y tú tampoco has librado á tu pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 1, 'JEHOVA respondió á Moisés: Ahora verás lo que yo haré á Faraón; porque con mano fuerte los ha de dejar ir; y con mano fuerte los ha de echar de su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 2, 'Habló todavía Dios á Moisés, y díjole: Yo soy JEHOVA;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 3, 'Y aparecí á Abraham, á Isaac y á Jacob bajo el nombre de Dios Omnipotente, mas en mi nombre JEHOVA no me notifiqué á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 4, 'Y también establecí mi pacto con ellos, de darles la tierra de Canaán, la tierra en que fueron extranjeros, y en la cual peregrinaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 5, 'Y asimismo yo he oído el gemido de los hijos de Israel, á quienes hacen servir los Egipcios, y heme acordado de mi pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 6, 'Por tanto dirás á los hijos de Israel: YO JEHOVA; y yo os sacaré de debajo de las cargas de Egipto, y os libraré de su servidumbre, y os redimiré con brazo extendido, y con juicios grandes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 7, 'Y os tomaré por mi pueblo y seré vuestro Dios: y vosotros sabréis que yo soy Jehová vuestro Dios, que os saco de debajo de las cargas de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 8, 'Y os meteré en la tierra, por la cual alcé mi mano que la daría á Abraham, á Isaac y á Jacob: y yo os la daré por heredad. YO JEHOVA.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 9, 'De esta manera habló Moisés á los hijos de Israel: mas ellos no escuchaban á Moisés á causa de la congoja de espíritu, y de la dura servidumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 10, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 11, 'Entra, y habla á Faraón rey de Egipto, que deje ir de su tierra á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 12, 'Y respondió Moisés delante de Jehová, diciendo: He aquí, los hijos de Israel no me escuchan: ¿cómo pues me escuchará Faraón, mayormente siendo yo incircunciso de labios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 13, 'Entonces Jehová habló á Moisés y á Aarón, y dióles mandamiento para los hijos de Israel, y para Faraón rey de Egipto, para que sacasen á los hijos de Israel de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 14, 'Estas son las cabezas de las familias de sus padres. Los hijos de Rubén, el primogénito de Israel: Hanoch y Phallú, Hezrón y Carmi: estas son las familias de Rubén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 15, 'Los hijos de Simeón: Jemuel, y Jamín, y Ohad, y Jachîn, y Zoar, y Saúl, hijo de una Cananea: estas son las familias de Simeón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 16, 'Y estos son los nombres de los hijos de Leví por sus linajes: Gersón, y Coath, y Merari: Y los años de la vida de Leví fueron ciento treinta y siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 17, 'Y los hijos de Gersón: Libni, y Shimi, por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 18, 'Y los hijos de Coath: Amram, é Izhar, y Hebrón, y Uzziel. Y los años de la vida de Coath fueron ciento treinta y tres años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 19, 'Y los hijos de Merari: Mahali, y Musi: estas son las familias de Leví por sus linajes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 20, 'Y Amram tomó por mujer á Jochêbed su tía, la cual le parió á Aarón y á Moisés. Y los años de la vida de Amram fueron ciento treinta y siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 21, 'Y los hijos de Izhar: Cora, y Nepheg y Zithri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 22, 'Y los hijos de Uzziel: Misael, y Elzaphán y Zithri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 23, 'Y tomóse Aarón por mujer á Elisabeth, hija de Aminadab, hermana de Naasón; la cual le parió á Nadab, y á Abiú, y á Eleazar, y á Ithamar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 24, 'Y los hijos de Cora: Assir, y Elcana, y Abiasaph: estas son las familias de los Coritas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 25, 'Y Eleazar, hijo de Aarón, tomó para sí mujer de las hijas de Phutiel, la cual le parió á Phinees: Y estas son las cabezas de los padres de los Levitas por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 26, 'Este es aquel Aarón y aquel Moisés, á los cuales Jehová dijo: Sacad á los hijos de Israel de la tierra de Egipto por sus escuadrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 27, 'Estos son los que hablaron á Faraón rey de Egipto, para sacar de Egipto á los hijos de Israel. Moisés y Aarón fueron éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 28, 'Cuando Jehová habló á Moisés en la tierra de Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 29, 'Entonces Jehová habló á Moisés, diciendo: Yo soy JEHOVA; di á Faraón rey de Egipto todas las cosas que yo te digo á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 6, 30, 'Y Moisés respondió delante de Jehová: He aquí, yo soy incircunciso de labios, ¿cómo pues me ha de oír Faraón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 1, 'JEHOVA dijo á Moisés: Mira, yo te he constituído dios para Faraón, y tu hermano Aarón será tu profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 2, 'Tú dirás todas las cosas que yo te mandaré, y Aarón tu hermano hablará á Faraón, para que deje ir de su tierra á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 3, 'Y yo endureceré el corazón de Faraón, y multiplicaré en la tierra de Egipto mis señales y mis maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 4, 'Y Faraón no os oirá; mas yo pondré mi mano sobre Egipto, y sacaré á mis ejércitos, mi pueblo, los hijos de Israel, de la tierra de Egipto, con grandes juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 5, 'Y sabrán los Egipcios que yo soy Jehová, cuando extenderé mi mano sobre Egipto, y sacaré los hijos de Israel de en medio de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 6, 'E hizo Moisés y Aarón como Jehová les mandó: hiciéronlo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 7, 'Y era Moisés de edad de ochenta años, y Aarón de edad de ochenta y tres, cuando hablaron á Faraón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 8, 'Y habló Jehová á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 9, 'Si Faraón os respondiere diciendo, Mostrad milagro; dirás á Aarón: Toma tu vara, y échala delante de Faraón, para que se torne culebra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 10, 'Vinieron, pues, Moisés y Aarón á Faraón, é hicieron como Jehová lo había mandado: y echó Aarón su vara delante de Faraón y de sus siervos, y tornóse culebra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 11, 'Entonces llamó también Faraón sabios y encantadores; é hicieron también lo mismo los encantadores de Egipto con sus encantamientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 12, 'Pues echó cada uno su vara, las cuales se volvieron culebras: mas la vara de Aarón devoró las varas de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 13, 'Y el corazón de Faraón se endureció, y no los escuchó; como Jehová lo había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 14, 'Entonces Jehová dijo á Moisés: El corazón de Faraón está agravado, que no quiere dejar ir al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 15, 'Ve por la mañana á Faraón, he aquí que él sale á las aguas; y tú ponte á la orilla del río delante de él, y toma en tu mano la vara que se volvió culebra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 16, 'Y dile: Jehová el Dios de los Hebreos me ha enviado á ti, diciendo: Deja ir á mi pueblo, para que me sirvan en el desierto; y he aquí que hasta ahora no has querido oir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 17, 'Así ha dicho Jehová: En esto conocerás que yo soy Jehová: he aquí, yo heriré con la vara que tengo en mi mano el agua que está en el río, y se convertirá en sangre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 18, 'Y los peces que hay en el río morirán, y hederá el río, y tendrán asco los Egipcios de beber el agua del río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 19, 'Y Jehová dijo á Moisés: Di á Aarón: Toma tu vara, y extiende tu mano sobre las aguas de Egipto, sobre sus ríos, sobre sus arroyos y sobre sus estanques, y sobre todos sus depósitos de aguas, para que se conviertan en sangre, y haya sangre por toda la región de Egipto, así en los vasos de madera como en los de piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 20, 'Y Moisés y Aarón hicieron como Jehová lo mandó; y alzando la vara hirió las aguas que había en el río, en presencia de Faraón y de sus siervos; y todas las aguas que había en el río se convirtieron en sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 21, 'Asimismo los peces que había en el río murieron; y el río se corrompió, que los Egipcios no podían beber de él: y hubo sangre por toda la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 22, 'Y los encantadores de Egipto hicieron lo mismo con sus encantamientos: y el corazón de Faraón se endureció, y no los escuchó; como Jehová lo había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 23, 'Y tornando Faraón volvióse á su casa, y no puso su corazón aun en esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 24, 'Y en todo Egipto hicieron pozos alrededor del río para beber, porque no podían beber de las aguas del río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 7, 25, 'Y cumpliéronse siete días después que Jehová hirió el río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 1, 'ENTONCES Jehová dijo á Moisés: Entra á Faraón, y dile: Jehová ha dicho así: Deja ir á mi pueblo, para que me sirvan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 2, 'Y si no lo quisieres dejar ir, he aquí yo heriré con ranas todos tus términos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 3, 'Y el río criará ranas, las cuales subirán, y entrarán en tu casa, y en la cámara de tu cama, y sobre tu cama, y en las casas de tus siervos, y en tu pueblo, y en tus hornos, y en tus artesas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 4, 'Y las ranas subirán sobre ti, y sobre tu pueblo, y sobre todos tus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 5, 'Y Jehová dijo á Moisés: Di á Aarón: Extiende tu mano con tu vara sobre los ríos, arroyos, y estanques, para que haga venir ranas sobre la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 6, 'Entonces Aarón extendió su mano sobre las aguas de Egipto, y subieron ranas que cubrieron la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 7, 'Y los encantadores hicieron lo mismo con sus encantamientos, é hicieron venir ranas sobre la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 8, 'Entonces Faraón llamó á Moisés y á Aarón, y díjoles: Orad á Jehová que quite las ranas de mí y de mi pueblo; y dejaré ir al pueblo, para que sacrifique á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 9, 'Y dijo Moisés á Faraón: Gloríate sobre mí: ¿cuándo oraré por ti, y por tus siervos, y por tu pueblo, para que las ranas sean quitadas de ti, y de tus casas, y que solamente se queden en el río?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 10, 'Y él dijo: Mañana. Y Moisés respondió: Se hará conforme á tu palabra, para que conozcas que no hay como Jehová nuestro Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 11, 'Y las ranas se irán de ti, y de tus casas, y de tus siervos, y de tu pueblo, y solamente se quedarán en el río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 12, 'Entonces salieron Moisés y Aarón de con Faraón, y clamó Moisés á Jehová sobre el negocio de las ranas que había puesto á Faraón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 13, 'E hizo Jehová conforme á la palabra de Moisés, y murieron las ranas de las casas, de los cortijos, y de los campos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 14, 'Y las juntaron en montones, y apestaban la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 15, 'Y viendo Faraón que le habían dado reposo, agravó su corazón, y no los escuchó; como Jehová lo había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 16, 'Entonces Jehová dijo á Moisés: Di á Aarón: Extiende tu vara, y hiere el polvo de la tierra, para que se vuelva piojos por todo el país de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 17, 'Y ellos lo hicieron así; y Aarón extendió su mano con su vara, é hirió el polvo de la tierra, el cual se volvió piojos, así en los hombres como en las bestias: todo el polvo de la tierra se volvió piojos en todo el país de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 18, 'Y los encantadores hicieron así también, para sacar piojos con sus encantamientos; mas no pudieron. Y había piojos así en los hombres como en las bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 19, 'Entonces los magos dijeron á Faraón: Dedo de Dios es este. Mas el corazón de Faraón se endureció, y no los escuchó; como Jehová lo había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 20, 'Y Jehová dijo á Moisés: Levántate de mañana y ponte delante de Faraón, he aquí él sale á las aguas; y dile: Jehová ha dicho así: Deja ir á mi pueblo, para que me sirva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 21, 'Porque si no dejares ir á mi pueblo, he aquí yo enviaré sobre ti, y sobre tus siervos, y sobre tu pueblo, y sobre tus casas toda suerte de moscas; y las casas de los Egipcios se henchirán de toda suerte de moscas, y asimismo la tierra donde ellos estuvieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 22, 'Y aquel día yo apartaré la tierra de Gosén, en la cual mi pueblo habita, para que ninguna suerte de moscas haya en ella; á fin de que sepas que yo soy Jehová en medio de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 23, 'Y yo pondré redención entre mi pueblo y el tuyo. Mañana será esta señal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 24, 'Y Jehová lo hizo así: que vino toda suerte de moscas molestísimas sobre la casa de Faraón, y sobre las casas de sus siervos, y sobre todo el país de Egipto; y la tierra fué corrompida á causa de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 25, 'Entonces Faraón llamó á Moisés y á Aarón, y díjoles: Andad, sacrificad á vuestro Dios en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 26, 'Y Moisés respondió: No conviene que hagamos así, porque sacrificaríamos á Jehová nuestro Dios la abominación de los Egipcios. He aquí, si sacrificáramos la abominación de los Egipcios delante de ellos, ¿no nos apedrearían?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 27, 'Camino de tres días iremos por el desierto, y sacrificaremos á Jehová nuestro Dios, como él nos dirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 28, 'Y dijo Faraón: Yo os dejaré ir para que sacrifiquéis á Jehová vuestro Dios en el desierto, con tal que no vayáis más lejos: orad por mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 29, 'Y respondió Moisés: He aquí, en saliendo yo de contigo, rogaré á Jehová que las diversas suertes de moscas se vayan de Faraón, y de sus siervos, y de su pueblo mañana; con tal que Faraón no falte más, no dejando ir al pueblo á sacrificar á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 30, 'Entonces Moisés salió de con Faraón, y oró á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 31, 'Y Jehová hizo conforme á la palabra de Moisés; y quitó todas aquellas moscas de Faraón, y de sus siervos, y de su pueblo, sin que quedara una.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 8, 32, 'Mas Faraón agravó aún esta vez su corazón, y no dejó ir al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 1, 'ENTONCES Jehová dijo á Moisés: Entra á Faraón, y dile: Jehová, el Dios de los Hebreos, dice así: Deja ir á mi pueblo, para que me sirvan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 2, 'Porque si no lo quieres dejar ir, y los detuvieres aún,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 3, 'He aquí la mano de Jehová será sobre tus ganados que están en el campo, caballos, asnos, camellos, vacas y ovejas, con pestilencia gravísima:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 4, 'Y Jehová hará separación entre los ganados de Israel y los de Egipto, de modo que nada muera de todo lo de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 5, 'Y Jehová señaló tiempo, diciendo: Mañana hará Jehová esta cosa en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 6, 'Y el día siguiente Jehová hizo aquello, y murió todo el ganado de Egipto; mas del ganado de los hijos de Israel no murió uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 7, 'Entonces Faraón envió, y he aquí que del ganado de los hijos de Israel no había muerto uno. Mas el corazón de Faraón se agravó, y no dejó ir al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 8, 'Y Jehová dijo á Moisés y á Aarón: Tomad puñados de ceniza de un horno, y espárzala Moisés hacia el cielo delante de Faraón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 9, 'Y vendrá á ser polvo sobre toda la tierra de Egipto, el cual originará sarpullido que cause tumores apostemados en los hombres y en las bestias, por todo el país de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 10, 'Y tomaron la ceniza del horno, y pusiéronse delante de Faraón, y esparcióla Moisés hacia el cielo; y vino un sarpullido que causaba tumores apostemados así en los hombres como en las bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 11, 'Y los magos no podían estar delante de Moisés á causa de los tumores, porque hubo sarpullido en los magos y en todos los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 12, 'Y Jehová endureció el corazón de Faraón, y no los oyó; como Jehová lo había dicho á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 13, 'Entonces Jehová dijo á Moisés: Levántate de mañana, y ponte delante de Faraón, y dile: Jehová, el Dios de los Hebreos, dice así: Deja ir á mi pueblo, para que me sirva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 14, 'Porque yo enviaré esta vez todas mis plagas á tu corazón, sobre tus siervos, y sobre tu pueblo, para que entiendas que no hay otro como yo en toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 15, 'Porque ahora yo extenderé mi mano para herirte á ti y á tu pueblo de pestilencia, y serás quitado de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 16, 'Y á la verdad yo te he puesto para declarar en ti mi potencia, y que mi Nombre sea contado en toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 17, '¿Todavía te ensalzas tú contra mi pueblo, para no dejarlos ir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 18, 'He aquí que mañana á estas horas yo haré llover granizo muy grave, cual nunca fué en Egipto, desde el día que se fundó hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 19, 'Envía, pues, á recoger tu ganado, y todo lo que tienes en el campo; porque todo hombre ó animal que se hallare en el campo, y no fuere recogido á casa, el granizo descenderá sobre él, y morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 20, 'De los siervos de Faraón el que temió la palabra de Jehová, hizo huir sus criados y su ganado á casa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 21, 'Mas el que no puso en su corazón la palabra de Jehová, dejó sus criados y sus ganados en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 22, 'Y Jehová dijo á Moisés: Extiende tu mano hacia el cielo, para que venga granizo en toda la tierra de Egipto sobre los hombres, y sobre las bestias, y sobre toda la hierba del campo en el país de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 23, 'Y Moisés extendió su vara hacia el cielo, y Jehová hizo tronar y granizar, y el fuego discurría por la tierra; y llovió Jehová granizo sobre la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 24, 'Hubo pues granizo, y fuego mezclado con el granizo, tan grande, cual nunca hubo en toda la tierra de Egipto desde que fué habitada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 25, 'Y aquel granizo hirió en toda la tierra de Egipto todo lo que estaba en el campo, así hombres como bestias; asimismo hirió el granizo toda la hierba del campo, y desgajó todos los árboles del país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 26, 'Solamente en la tierra de Gosén, donde los hijos de Israel estaban, no hubo granizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 27, 'Entonces Faraón envió á llamar á Moisés y á Aarón, y les dijo: He pecado esta vez: Jehová es justo, y yo y mi pueblo impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 28, 'Orad á Jehová: y cesen los truenos de Dios y el granizo; y yo os dejaré ir, y no os detendréis más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 29, 'Y respondióle Moisés: En saliendo yo de la ciudad extenderé mis manos á Jehová, y los truenos cesarán, y no habrá más granizo; para que sepas que de Jehová es la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 30, 'Mas yo sé que ni tú ni tus siervos temeréis todavía la presencia del Dios Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 31, 'El lino, pues, y la cebada fueron heridos; porque la cebada estaba ya espigada, y el lino en caña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 32, 'Mas el trigo y el centeno no fueron heridos; porque eran tardíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 33, 'Y salido Moisés de con Faraón de la ciudad, extendió sus manos á Jehová, y cesaron los truenos y el granizo; y la lluvia no cayó más sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 34, 'Y viendo Faraón que la lluvia había cesado y el granizo y los truenos, perseveró en pecar, y agravó su corazón, él y sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 9, 35, 'Y el corazón de Faraón se endureció, y no dejó ir á los hijos de Israel; como Jehová lo había dicho por medio de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 1, 'Y JEHOVA dijo á Moisés: Entra á Faraón; porque yo he agravado su corazón, y el corazón de sus siervos, para dar entre ellos estas mis señales;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 2, 'Y para que cuentes á tus hijos y á tus nietos las cosas que yo hice en Egipto, y mis señales que dí entre ellos; y para que sepáis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 3, 'Entonces vinieron Moisés y Aarón á Faraón, y le dijeron: Jehová, el Dios de los Hebreos ha dicho así: ¿Hasta cuándo no querrás humillarte delante de mí? Deja ir á mi pueblo para que me sirvan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 4, 'Y si aún rehusas dejarlo ir, he aquí que yo traeré mañana langosta en tus términos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 5, 'La cual cubrirá la faz de la tierra, de modo que no pueda verse la tierra; y ella comerá lo que quedó salvo, lo que os ha quedado del granizo; comerá asimismo todo árbol que os produce fruto en el campo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 6, 'Y llenarse han tus casas, y las casas de todos tus siervos, y las casas de todos los Egipcios, cual nunca vieron tus padres ni tus abuelos, desde que ellos fueron sobre la tierra hasta hoy. Y volvióse, y salió de con Faraón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 7, 'Entonces los siervos de Faraón le dijeron: ¿Hasta cuándo nos ha de ser éste por lazo? Deja ir á estos hombres, para que sirvan á Jehová su Dios; ¿aun no sabes que Egipto está destruido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 8, 'Y Moisés y Aarón volvieron á ser llamados á Faraón, el cual les dijo: Andad, servid á Jehová vuestro Dios. ¿Quién y quién son los que han de ir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 9, 'Y Moisés respondió: Hemos de ir con nuestros niños y con nuestros viejos, con nuestros hijos y con nuestras hijas: con nuestras ovejas y con nuestras vacas hemos de ir; porque tenemos solemnidad de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 10, 'Y él les dijo: Así sea Jehová con vosotros como yo os dejaré ir á vosotros y á vuestros niños: mirad como el mal está delante de vuestro rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 11, 'No será así: id ahora vosotros los varones, y servid á Jehová: pues esto es lo que vosotros demandasteis. Y echáronlos de delante de Faraón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 12, 'Entonces Jehová dijo á Moisés: Extiende tu mano sobre la tierra de Egipto para langosta, á fin de que suba sobre el país de Egipto, y consuma todo lo que el granizo dejó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 13, 'Y extendió Moisés su vara sobre la tierra de Egipto, y Jehová trajo un viento oriental sobre el país todo aquel día y toda aquella noche; y á la mañana el viento oriental trajo la langosta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 14, 'Y subió la langosta sobre toda la tierra de Egipto, y asentóse en todos los términos de Egipto, en gran manera grave: antes de ella no hubo langosta semejante, ni después de ella vendrá otra tal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 15, 'Y cubrió la faz de todo el país, y oscurecióse la tierra; y consumió toda la hierba de la tierra, y todo el fruto de los árboles que había dejado el granizo; que no quedó cosa verde en árboles ni en hierba del campo, por toda la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 16, 'Entonces Faraón hizo llamar apriesa á Moisés y á Aarón, y dijo: He pecado contra Jehová vuestro Dios, y contra vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 17, 'Mas ruego ahora que perdones mi pecado solamente esta vez, y que oréis á Jehová vuestro Dios que quite de mí solamente esta muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 18, 'Y salió de con Faraón, y oró á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 19, 'Y Jehová volvió un viento occidental fortísimo, y quitó la langosta, y arrojóla en el mar Bermejo: ni una langosta quedó en todo el término de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 20, 'Mas Jehová endureció el corazón de Faraón; y no envió los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 21, 'Y Jehová dijo á Moisés: Extiende tu mano hacia el cielo, para que haya tinieblas sobre la tierra de Egipto, tales que cualquiera las palpe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 22, 'Y extendió Moisés su mano hacia el cielo, y hubo densas tinieblas tres días por toda la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 23, 'Ninguno vió á su prójimo, ni nadie se levantó de su lugar en tres días; mas todos los hijos de Israel tenían luz en sus habitaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 24, 'Entonces Faraón hizo llamar á Moisés, y dijo: Id, servid á Jehová; solamente queden vuestras ovejas y vuestras vacas: vayan también vuestros niños con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 25, 'Y Moisés respondió: Tú también nos entregarás sacrificios y holocaustos que sacrifiquemos á Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 26, 'Nuestros ganados irán también con nosotros; no quedará ni una uña; porque de ellos hemos de tomar para servir á Jehová nuestro Dios; y no sabemos con qué hemos de servir á Jehová, hasta que lleguemos allá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 27, 'Mas Jehová endureció el corazón de Faraón, y no quiso dejarlos ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 28, 'Y díjole Faraón: Retírate de mí: guárdate que no veas más mi rostro, porque en cualquier día que vieres mi rostro, morirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 10, 29, 'Y Moisés respondió: Bien has dicho; no veré más tu rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 1, 'Y JEHOVA dijo á Moisés: Una plaga traeré aún sobre Faraón, y sobre Egipto; después de la cual él os dejará ir de aquí; y seguramente os echará de aquí del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 2, 'Habla ahora al pueblo, y que cada uno demande á su vecino, y cada una á su vecina, vasos de plata y de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 3, 'Y Jehová dió gracia al pueblo en los ojos de los Egipcios. También Moisés era muy gran varón en la tierra de Egipto, á los ojos de los siervos de Faraón, y á los ojos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 4, 'Y dijo Moisés: Jehová ha dicho así: A la media noche yo saldré por medio de Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 5, 'Y morirá todo primogénito en tierra de Egipto, desde el primogénito de Faraón que se sienta en su trono, hasta el primogénito de la sierva que está tras la muela; y todo primogénito de las bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 6, 'Y habrá gran clamor por toda la tierra de Egipto, cual nunca fué, ni jamás será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 7, 'Mas entre todos los hijos de Israel, desde el hombre hasta la bestia, ni un perro moverá su lengua: para que sepáis que hará diferencia Jehová entre los Egipcios y los Israelitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 8, 'Y descenderán á mí todos estos tus siervos, é inclinados delante de mí dirán: Sal tú, y todo el pueblo que está bajo de ti; y después de esto yo saldré. Y salióse muy enojado de con Faraón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 9, 'Y Jehová dijo á Moisés: Faraón no os oirá, para que mis maravillas se multipliquen en la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 11, 10, 'Y Moisés y Aarón hicieron todos estos prodigios delante de Faraón: mas Jehová había endurecido el corazón de Faraón, y no envió á los hijos de Israel fuera de su país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 1, 'Y HABLO Jehová á Moisés y á Aarón en la tierra de Egipto, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 2, 'Este mes os será principio de los meses; será este para vosotros el primero en los meses del año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 3, 'Hablad á toda la congregación de Israel, diciendo: En el diez de aqueste mes tómese cada uno un cordero por las familias de los padres, un cordero por familia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 4, 'Mas si la familia fuere pequeña que no baste á comer el cordero, entonces tomará á su vecino inmediato á su casa, y según el número de las personas, cada uno conforme á su comer, echaréis la cuenta sobre el cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 5, 'El cordero será sin defecto, macho de un año: tomaréislo de las ovejas ó de las cabras:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 6, 'Y habéis de guardarlo hasta el día catorce de este mes; y lo inmolará toda la congregación del pueblo de Israel entre las dos tardes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 7, 'Y tomarán de la sangre, y pondrán en los dos postes y en el dintel de las casas en que lo han de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 8, 'Y aquella noche comerán la carne asada al fuego, y panes sin levadura: con hierbas amargas lo comerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 9, 'Ninguna cosa comeréis de él cruda, ni cocida en agua, sino asada al fuego; su cabeza con sus pies y sus intestinos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 10, 'Ninguna cosa dejaréis de él hasta la mañana; y lo que habrá quedado hasta la mañana, habéis de quemarlo en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 11, 'Y así habéis de comerlo: ceñidos vuestros lomos, vuestros zapatos en vuestros pies, y vuestro bordón en vuestra mano; y lo comeréis apresuradamente: es la Pascua de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 12, 'Pues yo pasaré aquella noche por la tierra de Egipto, y heriré á todo primogénito en la tierra de Egipto, así en los hombres como en las bestias: y haré juicios en todos los dioses de Egipto. YO JEHOVA.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 13, 'Y la sangre os será por señal en las casas donde vosotros estéis; y veré la sangre, y pasaré de vosotros, y no habrá en vosotros plaga de mortandad, cuando heriré la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 14, 'Y este día os ha de ser en memoria, y habéis de celebrarlo como solemne á Jehová durante vuestras generaciones: por estatuto perpetuo lo celebraréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 15, 'Siete días comeréis panes sin levadura; y así el primer día haréis que no haya levadura en vuestras casas: porque cualquiera que comiere leudado desde el primer día hasta el séptimo, aquella alma será cortada de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 16, 'El primer día habrá santa convocación, y asimismo en el séptimo día tendréis una santa convocación: ninguna obra se hará en ellos, excepto solamente que aderecéis lo que cada cual hubiere de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 17, 'Y guardaréis la fiesta de los ázimos, porque en aqueste mismo día saqué vuestros ejércitos de la tierra de Egipto: por tanto guardaréis este día en vuestras generaciones por costumbre perpetua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 18, 'En el mes primero, el día catorce del mes por la tarde, comeréis los panes sin levadura, hasta el veintiuno del mes por la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 19, 'Por siete días no se hallará levadura en vuestras casas, porque cualquiera que comiere leudado, así extranjero como natural del país, aquella alma será cortada de la congregación de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 20, 'Ninguna cosa leudada comeréis; en todas vuestras habitaciones comeréis panes sin levadura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 21, 'Y Moisés convocó á todos los ancianos de Israel, y díjoles: Sacad, y tomaos corderos por vuestras familias, y sacrificad la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 22, 'Y tomad un manojo de hisopo, y mojadle en la sangre que estará en una jofaina, y untad el dintel y los dos postes con la sangre que estará en la jofaina; y ninguno de vosotros salga de las puertas de su casa hasta la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 23, 'Porque Jehová pasará hiriendo á los Egipcios; y como verá la sangre en el dintel y en los dos postes, pasará Jehová aquella puerta, y no dejará entrar al heridor en vuestras casas para herir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 24, 'Y guardaréis esto por estatuto para vosotros y para vuestros hijos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 25, 'Y será, cuando habréis entrado en la tierra que Jehová os dará, como tiene hablado, que guardaréis este rito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 26, 'Y cuando os dijeren vuestros hijos: ¿Qué rito es este vuestro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 27, 'Vosotros responderéis: Es la víctima de la Pascua de Jehová, el cual pasó las casas de los hijos de Israel en Egipto, cuando hirió á los Egipcios, y libró nuestras casas. Entonces el pueblo se inclinó y adoró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 28, 'Y los hijos de Israel se fueron, é hicieron puntualmente así; como Jehová había mandado á Moisés y á Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 29, 'Y aconteció que á la medianoche Jehová hirió á todo primogénito en la tierra de Egipto, desde el primogénito de Faraón que se sentaba sobre su trono, hasta el primogénito del cautivo que estaba en la cárcel, y todo primogénito de los animales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 30, 'Y levantóse aquella noche Faraón, él y todos sus siervos, y todos los Egipcios; y había un gran clamor en Egipto, porque no había casa donde no hubiese muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 31, 'E hizo llamar á Moisés y á Aarón de noche, y díjoles: Salid de en medio de mi pueblo vosotros, y los hijos de Israel; é id, servid á Jehová, como habéis dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 32, 'Tomad también vuestras ovejas y vuestras vacas, como habéis dicho, é idos; y bendecidme también á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 33, 'Y los Egipcios apremiaban al pueblo, dándose priesa á echarlos de la tierra; porque decían: Todos somos muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 34, 'Y llevó el pueblo su masa antes que se leudase, sus masas envueltas en sus sábanas sobre sus hombros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 35, 'E hicieron los hijos de Israel conforme al mandamiento de Moisés, demandando á los Egipcios vasos de plata, y vasos de oro, y vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 36, 'Y Jehová dió gracia al pueblo delante de los Egipcios, y prestáronles; y ellos despojaron á los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 37, 'Y partieron los hijos de Israel de Rameses á Succoth, como seiscientos mil hombres de á pie, sin contar los niños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 38, 'Y también subió con ellos grande multitud de diversa suerte de gentes; y ovejas, y ganados muy muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 39, 'Y cocieron tortas sin levadura de la masa que habían sacado de Egipto; porque no había leudado, por cuanto echándolos los Egipcios, no habían podido detenerse, ni aun prepararse comida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 40, 'El tiempo que los hijos de Israel habitaron en Egipto, fué cuatrocientos treinta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 41, 'Y pasados cuatrocientos treinta años, en el mismo día salieron todos los ejércitos de Jehová de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 42, 'Es noche de guardar á Jehová, por haberlos sacado en ella de la tierra de Egipto. Esta noche deben guardar á Jehová todos los hijos de Israel en sus generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 43, 'Y Jehová dijo á Moisés y á Aarón: Esta es la ordenanza de la Pascua: Ningún extraño comerá de ella:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 44, 'Mas todo siervo humano comprado por dinero, comerá de ella después que lo hubieres circuncidado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 45, 'El extranjero y el asalariado no comerán de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 46, 'En una casa se comerá, y no llevarás de aquella carne fuera de casa, ni quebraréis hueso suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 47, 'Toda la congregación de Israel le sacrificará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 48, 'Mas si algún extranjero peregrinare contigo, y quisiere hacer la pascua á Jehová, séale circuncidado todo varón, y entonces se llegará á hacerla, y será como el natural de la tierra; pero ningún incircunciso comerá de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 49, 'La misma ley será para el natural y para el extranjero que peregrinare entre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 50, 'Así lo hicieron todos los hijos de Israel; como mandó Jehová á Moisés y á Aarón, así lo hicieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 12, 51, 'Y en aquel mismo día sacó Jehová á los hijos de Israel de la tierra de Egipto por sus escuadrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 2, 'Santifícame todo primogénito, cualquiera que abre matriz entre los hijos de Israel, así de los hombres como de los animales: mío es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 3, 'Y Moisés dijo al pueblo: Tened memoria de aqueste día, en el cual habéis salido de Egipto, de la casa de servidumbre; pues Jehová os ha sacado de aquí con mano fuerte; por tanto, no comeréis leudado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 4, 'Vosotros salís hoy en el mes de Abib.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 5, 'Y cuando Jehová te hubiere metido en la tierra del Cananeo, y del Hetheo, y del Amorrheo, y del Hebeo, y del Jebuseo, la cual juró á tus padres que te daría, tierra que destila leche y miel, harás esta servicio en aqueste mes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 6, 'Siete días comerás por leudar, y el séptimo día será fiesta á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 7, 'Por los siete días se comerán los panes sin levadura; y no se verá contigo leudado, ni levadura en todo tu término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 8, 'Y contarás en aquel día á tu hijo, diciendo: Hácese esto con motivo de lo que Jehová hizo conmigo cuando me sacó de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 9, 'Y serte ha como una señal sobre tu mano, y como una memoria delante de tus ojos, para que la ley de Jehová esté en tu boca; por cuanto con mano fuerte te sacó Jehová de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 10, 'Por tanto, tú guardarás este rito en su tiempo de año en año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 11, 'Y cuando Jehová te hubiere metido en la tierra del Cananeo, como te ha jurado á ti y á tus padres, y cuando te la hubiere dado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 12, 'Harás pasar á Jehová todo lo que abriere la matriz, asimismo todo primerizo que abriere la matriz de tus animales: los machos serán de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 13, 'Mas todo primogénito de asno redimirás con un cordero; y si no lo redimieres, le degollarás: asimismo redimirás todo humano primogénito de tus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 14, 'Y cuando mañana te preguntare tu hijo, diciendo: ¿Qué es esto? decirle has: Jehová nos sacó con mano fuerte de Egipto, de casa de servidumbre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 15, 'Y endureciéndose Faraón en no dejarnos ir, Jehová mató en la tierra de Egipto á todo primogénito, desde el primogénito humano hasta el primogénito de la bestia: y por esta causa yo sacrifico á Jehová todo primogénito macho, y redimo todo primogénito de mis hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 16, 'Serte ha, pues, como una señal sobre tu mano, y por una memoria delante de tus ojos; ya que Jehová nos sacó de Egipto con mano fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 17, 'Y luego que Faraón dejó ir al pueblo, Dios no los llevó por el camino de la tierra de los Filisteos, que estaba cerca; porque dijo Dios: Que quizá no se arrepienta el pueblo cuando vieren la guerra, y se vuelvan á Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 18, 'Mas hizo Dios al pueblo que rodease por el camino del desierto del mar Bermejo. Y subieron los hijos de Israel de Egipto armados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 19, 'Tomó también consigo Moisés los huesos de José, el cual había juramentado á los hijos de Israel, diciendo: Dios ciertamente os visitará, y haréis subir mis huesos de aquí con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 20, 'Y partidos de Succoth, asentaron campo en Etham, á la entrada del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 21, 'Y Jehová iba delante de ellos de día en una columna de nube, para guiarlos por el camino; y de noche en una columna de fuego para alumbrarles; á fin de que anduviesen de día y de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 13, 22, 'Nunca se partió de delante del pueblo la columna de nube de día, ni de noche la columna de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 2, 'Habla á los hijos de Israel que den la vuelta, y asienten su campo delante de Pihahiroth, entre Migdol y la mar hacia Baalzephón: delante de él asentaréis el campo, junto á la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 3, 'Porque Faraón dirá de los hijos de Israel: Encerrados están en la tierra, el desierto los ha encerrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 4, 'Y yo endureceré el corazón de Faraón para que los siga; y seré glorificado en Faraón y en todo su ejército; y sabrán los Egipcios que yo soy Jehová. Y ellos lo hicieron así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 5, 'Y fué dado aviso al rey de Egipto cómo el pueblo se huía: y el corazón de Faraón y de sus siervos se volvió contra el pueblo, y dijeron: ¿Cómo hemos hecho esto de haber dejado ir á Israel, para que no nos sirva?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 6, 'Y unció su carro, y tomó consigo su pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 7, 'y tomó seiscientos carros escogidos, y todos los carros de Egipto, y los capitanes sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 8, 'Y endureció Jehová el corazón de Faraón rey de Egipto, y siguió á los hijos de Israel; pero los hijos de Israel habían salido con mano poderosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 9, 'Siguiéndolos, pues, los Egipcios, con toda la caballería y carros de Faraón, su gente de á caballo, y todo su ejército, alcanzáronlos asentando el campo junto á la mar, al lado de Pihahiroth, delante de Baalzephón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 10, 'Y cuando Faraón se hubo acercado, los hijos de Israel alzaron sus ojos, y he aquí los Egipcios que venían tras ellos; por lo que temieron en gran manera, y clamaron los hijos de Israel á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 11, 'Y dijeron á Moisés: ¿No había sepulcros en Egipto, que nos has sacado para que muramos en el desierto? ¿Por qué lo has hecho así con nosotros, que nos has sacado de Egipto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 12, '¿No es esto lo que te hablamos en Egipto, diciendo: Déjanos servir á los Egipcios? Que mejor nos fuera servir á los Egipcios, que morir nosotros en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 13, 'Y Moisés dijo al pueblo: No temáis; estaos quedos, y ved la salud de Jehová, que él hará hoy con vosotros; porque los Egipcios que hoy habéis visto, nunca más para siempre los veréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 14, 'Jehová peleará por vosotros, y vosotros estaréis quedos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 15, 'Entonces Jehová dijo á Moisés: ¿Por qué clamas á mí? Di á los hijos de Israel que marchen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 16, 'Y tú alza tu vara, y extiende tu mano sobre la mar, y divídela; y entren los hijos de Israel por medio de la mar en seco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 17, 'Y yo, he aquí yo endureceré el corazón de los Egipcios, para que los sigan: y yo me glorificaré en Faraón, y en todo su ejército, y en sus carros, y en su caballería;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 18, 'Y sabrán los Egipcios que yo soy Jehová, cuando me glorificaré en Faraón, en sus carros, y en su gente de á caballo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 19, 'Y el ángel de Dios que iba delante del campo de Israel, se apartó, é iba en pos de ellos; y asimismo la columna de nube que iba delante de ellos, se apartó, y púsose á sus espaldas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 20, 'E iba entre el campo de los Egipcios y el campo de Israel; y era nube y tinieblas para aquéllos, y alumbraba á Israel de noche: y en toda aquella noche nunca llegaron los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 21, 'Y extendió Moisés su mano sobre la mar, é hizo Jehová que la mar se retirase por recio viento oriental toda aquella noche; y tornó la mar en seco, y las aguas quedaron divididas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 22, 'Entonces los hijos de Israel entraron por medio de la mar en seco, teniendo las aguas como muro á su diestra y á su siniestra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 23, 'Y siguiéndolos los Egipcios, entraron tras ellos hasta el medio de la mar, toda la caballería de Faraón, sus carros, y su gente de á caballo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 24, 'Y aconteció á la vela de la mañana, que Jehová miró al campo de los Egipcios desde la columna de fuego y nube, y perturbó el campo de los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 25, 'Y quitóles las ruedas de sus carros, y trastornólos gravemente. Entonces los Egipcios dijeron: Huyamos de delante de Israel, porque Jehová pelea por ellos contra los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 26, 'Y Jehová dijo á Moisés: Extiende tu mano sobre la mar, para que las aguas vuelvan sobre los Egipcios, sobre sus carros, y sobre su caballería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 27, 'Y Moisés extendió su mano sobre la mar, y la mar se volvió en su fuerza cuando amanecía; y los Egipcios iban hacia ella: y Jehová derribó á los Egipcios en medio de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 28, 'Y volvieron las aguas, y cubrieron los carros y la caballería, y todo el ejército de Faraón que había entrado tras ellos en la mar; no quedó de ellos ni uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 29, 'Y los hijos de Israel fueron por medio de la mar en seco, teniendo las aguas por muro á su diestra y á su siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 30, 'Así salvó Jehová aquel día á Israel de mano de los Egipcios; é Israel vió á los Egipcios muertos á la orilla de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 14, 31, 'Y vió Israel aquel grande hecho que Jehová ejecutó contra los Egipcios: y el pueblo temió á Jehová, y creyeron á Jehová y á Moisés su siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 1, 'ENTONCES cantó Moisés y los hijos de Israel este cántico á Jehová, y dijeron: Cantaré yo á Jehová, porque se ha magnificado grandemente, Echando en la mar al caballo y al que en él subía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 2, 'Jehová es mi fortaleza, y mi canción, Y hame sido por salud: Este es mi Dios, y á éste engrandeceré; Dios de mi padre, y á éste ensalzaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 3, 'Jehová, varón de guerra; Jehová es su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 4, 'Los carros de Faraón y á su ejército echó en la mar; Y sus escogidos príncipes fueron hundidos en el mar Bermejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 5, 'Los abismos los cubrieron; Como piedra descendieron á los profundos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 6, 'Tu diestra, oh Jehová, ha sido magnificada en fortaleza; Tu diestra, oh Jehová, ha quebrantado al enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 7, 'Y con la grandeza de tu poder has trastornado á los que se levantaron contra ti: Enviaste tu furor; los tragó como á hojarasca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 8, 'Con el soplo de tus narices se amontonaron las aguas; Paráronse las corrientes como en un montón; Los abismos se cuajaron en medio de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 9, 'El enemigo dijo: Perseguiré, prenderé, repartiré despojos; Mi alma se henchirá de ellos; Sacaré mi espada, destruirlos ha mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 10, 'Soplaste con tu viento, cubriólos la mar: Hundiéronse como plomo en las impetuosas aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 11, '¿Quién como tú, Jehová, entre los dioses? ¿Quién como tú, magnífico en santidad, Terrible en loores, hacedor de maravillas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 12, 'Extendiste tu diestra; La tierra los tragó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 13, 'Condujiste en tu misericordia á este pueblo, al cual salvaste; Llevástelo con tu fortaleza á la habitación de tu santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 14, 'Oiránlo los pueblos, y temblarán; Apoderarse ha dolor de los moradores de Palestina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 15, 'Entonces los príncipes de Edom se turbarán; A los robustos de Moab los ocupará temblor; Abatirse han todos los moradores de Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 16, 'Caiga sobre ellos temblor y espanto; A la grandeza de tu brazo enmudezcan como una piedra; Hasta que haya pasado tu pueblo, oh Jehová, Hasta que haya pasado este pueblo que tú rescataste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 17, 'Tú los introducirás y los plantarás en el monte de tu heredad, En el lugar de tu morada, que tú has aparejado, oh Jehová; En el santuario del Señor, que han afirmado tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 18, 'Jehová reinará por los siglos de los siglos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 19, 'Porque Faraón entró cabalgando con sus carros y su gente de á caballo en la mar, y Jehová volvió á traer las aguas de la mar sobre ellos; mas los hijos de Israel fueron en seco por medio de la mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 20, 'Y María la profetisa, hermana de Aarón, tomó un pandero en su mano, y todas las mujeres salieron en pos de ella con panderos y danzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 21, 'Y María les respondía: Cantad á Jehová; porque en extremo se ha engrandecido, Echando en la mar al caballo, y al que en él subía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 22, 'E hizo Moisés que partiese Israel del mar Bermejo, y salieron al desierto de Shur; y anduvieron tres días por el desierto sin hallar agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 23, 'Y llegaron á Mara, y no pudieron beber las aguas de Mara, porque eran amargas; por eso le pusieron el nombre de Mara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 24, 'Entonces el pueblo murmuró contra Moisés, y dijo: ¿Qué hemos de beber?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 25, 'Y Moisés clamó á Jehová; y Jehová le mostró un árbol, el cual metídolo que hubo dentro de las aguas, las aguas se endulzaron. Allí les dió estatutos y ordenanzas, y allí los probó;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 26, 'Y dijo: Si oyeres atentamente la voz de Jehová tu Dios, é hicieres lo recto delante de sus ojos, y dieres oído á sus mandamientos, y guardares todos sus estatutos, ninguna enfermedad de las que envié á los Egipcios te enviaré á ti; porque yo soy Jehová tu Sanador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 15, 27, 'Y llegaron á Elim, donde había doce fuentes de aguas, y setenta palmas; y asentaron allí junto á las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 1, 'Y PARTIENDO de Elim toda la congregación de los hijos de Israel, vino al desierto de Sin, que está entre Elim y Sinaí, á los quince días del segundo mes después que salieron de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 2, 'Y toda la congregación de los hijos de Israel murmuró contra Moisés y Aarón en el desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 3, 'Y decíanles los hijos de Israel: Ojalá hubiéramos muerto por mano de Jehová en la tierra de Egipto, cuando nos sentábamos á las ollas de las carnes, cuando comíamos pan en hartura; pues nos habéis sacado á este desierto, para matar de hambre á toda esta multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 4, 'Y Jehová dijo á Moisés: He aquí yo os haré llover pan del cielo; y el pueblo saldrá, y cogerá para cada un día, para que yo le pruebe si anda en mi ley, ó no.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 5, 'Mas al sexto día aparejarán lo que han de encerrar, que será el doble de lo que solían coger cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 6, 'Entonces dijo Moisés y Aarón á todos los hijos de Israel: A la tarde sabréis que Jehová os ha sacado de la tierra de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 7, 'Y á la mañana veréis la gloria de Jehová; porque él ha oído vuestras murmuraciones contra Jehová; que nosotros, ¿qué somos, para que vosotros murmuréis contra nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 8, 'Y dijo Moisés: Jehová os dará á la tarde carne para comer, y á la mañana pan en hartura; por cuanto Jehová ha oído vuestras murmuraciones con que habéis murmurado contra él: que nosotros, ¿qué somos? vuestras murmuraciones no son contra nosotros, sino contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 9, 'Y dijo Moisés á Aarón: Di á toda la congregación de los hijos de Israel: Acercaos á la presencia de Jehová; que él ha oído vuestras murmuraciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 10, 'Y hablando Aarón á toda la congregación de los hijos de Israel, miraron hacia el desierto, y he aquí la gloria de Jehová, que apareció en la nube.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 11, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 12, 'Yo he oído las murmuraciones de los hijos de Israel; háblales, diciendo: Entre las dos tardes comeréis carne, y por la mañana os hartaréis de pan, y sabréis que yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 13, 'Y venida la tarde subieron codornices que cubrieron el real; y á la mañana descendió rocío en derredor del real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 14, 'Y como el rocío cesó de descender, he aquí sobre la haz del desierto una cosa menuda, redonda, menuda como una helada sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 15, 'Y viéndolo los hijos de Israel, se dijeron unos á otros: ¿Qué es esto? porque no sabían qué era. Entonces Moisés les dijo: Es el pan que Jehová os da para comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 16, 'Esto es lo que Jehová ha mandado: Cogereis de él cada uno según pudiere comer; un gomer por cabeza, conforme al número de vuestras personas, tomaréis cada uno para los que están en su tienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 17, 'Y los hijos de Israel lo hicieron así: y recogieron unos más, otros menos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 18, 'Y medíanlo por gomer, y no sobraba al que había recogido mucho, ni faltaba al que había recogido poco: cada uno recogió conforme á lo que había de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 19, 'Y díjoles Moisés: Ninguno deje nada de ello para mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 20, 'Mas ellos no obedecieron á Moisés, sino que algunos dejaron de ello para otro día, y crió gusanos, y pudrióse; y enojóse contra ellos Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 21, 'Y recogíanlo cada mañana, cada uno según lo que había de comer: y luego que el sol calentaba, derretíase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 22, 'En el sexto día recogieron doblada comida, dos gomeres para cada uno: y todos los príncipes de la congregación vinieron á Moisés, y se lo hicieron saber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 23, 'Y él les dijo: Esto es lo que ha dicho Jehová: Mañana es el santo sábado, el reposo de Jehová: lo que hubiereis de cocer, cocedlo hoy, y lo que hubiereis de cocinar, cocinadlo; y todo lo que os sobrare, guardadlo para mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 24, 'Y ellos lo guardaron hasta la mañana, según que Moisés había mandado, y no se pudrió, ni hubo en él gusano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 25, 'Y dijo Moisés: Comedlo hoy, porque hoy es sábado de Jehová: hoy no hallaréis en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 26, 'En los seis días lo recogeréis; mas el séptimo día es sábado, en el cual no se hallará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 27, 'Y aconteció que algunos del pueblo salieron en el séptimo día á recoger, y no hallaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 28, 'Y Jehová dijo á Moisés: ¿Hasta cuándo no querréis guardar mis mandamientos y mis leyes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 29, 'Mirad que Jehová os dió el sábado, y por eso os da en el sexto día pan para dos días. Estése, pues, cada uno en su estancia, y nadie salga de su lugar en el séptimo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 30, 'Así el pueblo reposó el séptimo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 31, 'Y la casa de Israel lo llamó Maná; y era como simiente de culantro, blanco, y su sabor como de hojuelas con miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 32, 'Y dijo Moisés: Esto es lo que Jehová ha mandado: Henchirás un gomer de él para que se guarde para vuestros descendientes, á fin de que vean el pan que yo os dí á comer en el desierto, cuando yo os saqué de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 33, 'Y dijo Moisés á Aarón: Toma un vaso y pon en él un gomer lleno de maná, y ponlo delante de Jehová, para que sea guardado para vuestros descendientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 34, 'Y Aarón lo puso delante del Testimonio para guardarlo, como Jehová lo mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 35, 'Así comieron los hijos de Israel maná cuarenta años, hasta que entraron en la tierra habitada: maná comieron hasta que llegaron al término de la tierra de Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 16, 36, 'Y un gomer es la décima parte del epha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 1, 'Y TODA la congregación de los hijos de Israel partió del desierto de Sin, por sus jornadas, al mandamiento de Jehová, y asentaron el campo en Rephidim: y no había agua para que el pueblo bebiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 2, 'Y altercó el pueblo con Moisés, y dijeron: Danos agua que bebamos. Y Moisés les dijo: ¿Por qué altercáis conmigo? ¿por qué tentáis á Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 3, 'Así que el pueblo tuvo allí sed de agua, y murmuró contra Moisés, y dijo: ¿Por qué nos hiciste subir de Egipto para matarnos de sed á nosotros, y á nuestros hijos y á nuestros ganados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 4, 'Entonces clamó Moisés á Jehová, diciendo: ¿Qué haré con este pueblo? de aquí á un poco me apedrearán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 5, 'Y Jehová dijo á Moisés: Pasa delante del pueblo, y toma contigo de los ancianos de Israel; y toma también en tu mano tu vara, con que heriste el río, y ve:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 6, 'He aquí que yo estoy delante de ti allí sobre la peña en Horeb; y herirás la peña, y saldrán de ella aguas, y beberá el pueblo. Y Moisés lo hizo así en presencia de los ancianos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 7, 'Y llamó el nombre de aquel lugar Massah y Meribah, por la rencilla de los hijos de Israel, y porque tentaron á Jehová, diciendo: ¿Está, pues, Jehová entre nosotros, ó no?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 8, 'Y vino Amalec y peleó con Israel en Rephidim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 9, 'Y dijo Moisés á Josué: Escógenos varones, y sal, pelea con Amalec: mañana yo estaré sobre la cumbre del collado, y la vara de Dios en mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 10, 'E hizo Josué como le dijo Moisés, peleando con Amalec; y Moisés y Aarón y Hur subieron á la cumbre del collado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 11, 'Y sucedía que cuando alzaba Moisés su mano, Israel prevalecía; mas cuando él bajaba su mano, prevalecía Amalec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 12, 'Y las manos de Moisés estaban pesadas; por lo que tomaron una piedra, y pusiéronla debajo de él, y se sentó sobre ella; y Aarón y Hur sustentaban sus manos, el uno de una parte y el otro de otra; así hubo en sus manos firmeza hasta que se puso el sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 13, 'Y Josué deshizo á Amalec y á su pueblo á filo de espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 14, 'Y Jehová dijo á Moisés: Escribe esto para memoria en un libro, y di á Josué que del todo tengo de raer la memoria de Amalec de debajo del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 15, 'Y Moisés edificó un altar, y llamó su nombre Jehová-nissi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 17, 16, 'Y dijo: Por cuanto la mano sobre el trono de Jehová, Jehová tendrá guerra con Amalec de generación en generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 1, 'Y OYO Jethro, sacerdote de Madián, suegro de Moisés, todas las cosas que Dios había hecho con Moisés, y con Israel su pueblo, y cómo Jehová había sacado á Israel de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 2, 'Y tomó Jethro, suegro de Moisés á Séphora la mujer de Moisés, después que él la envió,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 3, 'Y á sus dos hijos; el uno se llamaba Gersóm, porque dijo: Peregrino he sido en tierra ajena;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 4, 'Y el otro se llamaba Eliezer, porque dijo, El Dios de mi padre me ayudó, y me libró del cuchillo de Faraón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 5, 'Y Jethro el suegro de Moisés, con sus hijos y su mujer, llegó á Moisés en el desierto, donde tenía el campo junto al monte de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 6, 'Y dijo á Moisés: Yo tu suegro Jethro vengo á ti, con tu mujer, y sus dos hijos con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 7, 'Y Moisés salió á recibir á su suegro, é inclinóse, y besólo: y preguntáronse el uno al otro cómo estaban, y vinieron á la tienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 8, 'Y Moisés contó á su suegro todas las cosas que Jehová había hecho á Faraón y á los Egipcios por amor de Israel, y todo el trabajo que habían pasado en el camino, y cómo los había librado Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 9, 'Y alegróse Jethro de todo el bien que Jehová había hecho á Israel, que lo había librado de mano de los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 10, 'Y Jethro dijo: Bendito sea Jehová, que os libró de mano de los Egipcios, y de la mano de Faraón, y que libró al pueblo de la mano de los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 11, 'Ahora conozco que Jehová es grande más que todos los dioses; hasta en lo que se ensoberbecieron contra ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 12, 'Y tomó Jethro, suegro de Moisés, holocaustos y sacrificios para Dios: y vino Aarón y todos los ancianos de Israel á comer pan con el suegro de Moisés delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 13, 'Y aconteció que otro día se sentó Moisés á juzgar al pueblo; y el pueblo estuvo delante de Moisés desde la mañana hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 14, 'Y viendo el suegro de Moisés todo lo que él hacía con el pueblo, dijo: ¿Qué es esto que haces tú con el pueblo? ¿por qué te sientas tú solo, y todo el pueblo está delante de ti desde la mañana hasta la tarde?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 15, 'Y Moisés respondió á su suegro: Porque el pueblo viene á mí para consultar á Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 16, 'Cuando tienen negocios, vienen á mí; y yo juzgo entre el uno y el otro, y declaro las ordenanzas de Dios y sus leyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 17, 'Entonces el suegro de Moisés le dijo: No haces bien:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 18, 'Desfallecerás del todo, tú, y también este pueblo que está contigo; porque el negocio es demasiado pesado para ti; no podrás hacerlo tú solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 19, 'Oye ahora mi voz; yo te aconsejaré, y Dios será contigo. Está tú por el pueblo delante de Dios, y somete tú los negocios á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 20, 'Y enseña á ellos las ordenanzas y las leyes, y muéstrales el camino por donde anden, y lo que han de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 21, 'Además inquiere tú de entre todo el pueblo varones de virtud, temerosos de Dios, varones de verdad, que aborrezcan la avaricia; y constituirás á éstos sobre ellos caporales sobre mil, sobre ciento, sobre cincuenta y sobre diez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 22, 'Los cuales juzgarán al pueblo en todo tiempo; y será que todo negocio grave lo traerán á ti, y ellos juzgarán todo negocio pequeño: alivia así la carga de sobre ti, y llevarla han ellos contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 23, 'Si esto hicieres, y Dios te lo mandare, tú podrás persistir, y todo este pueblo se irá también en paz á su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 24, 'Y oyó Moisés la voz de su suegro, é hizo todo lo que dijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 25, 'Y escogió Moisés varones de virtud de todo Israel, y púsolos por cabezas sobre el pueblo, caporales sobre mil, sobre ciento, sobre cincuenta, y sobre diez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 26, 'Y juzgaban al pueblo en todo tiempo: el negocio árduo traíanlo á Moisés, y ellos juzgaban todo negocio pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 18, 27, 'Y despidió Moisés á su suegro, y fuése á su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 1, 'AL mes tercero de la salida de los hijos de Israel de la tierra de Egipto, en aquel día vinieron al desierto de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 2, 'Porque partieron de Rephidim, y llegaron al desierto de Sinaí, y asentaron en el desierto; y acampó allí Israel delante del monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 3, 'Y Moisés subió á Dios; y Jehová lo llamó desde el monte, diciendo: Así dirás á la casa de Jacob, y denunciarás á los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 4, 'Vosotros visteis lo que hice á los Egipcios, y cómo os tomé sobre alas de águilas, y os he traído á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 5, 'Ahora pues, si diereis oído á mi voz, y guardareis mi pacto, vosotros seréis mi especial tesoro sobre todos los pueblos; porque mía es toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 6, 'Y vosotros seréis mi reino de sacerdotes, y gente santa. Estas son las palabras que dirás á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 7, 'Entonces vino Moisés, y llamó á los ancianos del pueblo, y propuso en presencia de ellos todas estas palabras que Jehová le había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 8, 'Y todo el pueblo respondió á una, y dijeron: Todo lo que Jehová ha dicho haremos. Y Moisés refirió las palabras del pueblo á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 9, 'Y Jehová dijo á Moisés: He aquí, yo vengo á ti en una nube espesa, para que el pueblo oiga mientras yo hablo contigo, y también para que te crean para siempre. Y Moisés denunció las palabras del pueblo á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 10, 'Y Jehová dijo á Moisés: Ve al pueblo, y santifícalos hoy y mañana, y laven sus vestidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 11, 'Y estén apercibidos para el día tercero, porque al tercer día Jehová descenderá, á ojos de todo el pueblo, sobre el monte de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 12, 'Y señalarás término al pueblo en derredor, diciendo: Guardaos, no subáis al monte, ni toquéis á su término: cualquiera que tocare el monte, de seguro morirá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 13, 'No le tocará mano, mas será apedreado ó asaeteado; sea animal ó sea hombre, no vivirá. En habiendo sonado largamente la bocina, subirán al monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 14, 'Y descendió Moisés del monte al pueblo, y santificó al pueblo; y lavaron sus vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 15, 'Y dijo al pueblo: Estad apercibidos para el tercer día; no lleguéis á mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 16, 'Y aconteció al tercer día cuando vino la mañana, que vinieron truenos y relámpagos, y espesa nube sobre el monte, y sonido de bocina muy fuerte; y estremecióse todo el pueblo que estaba en el real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 17, 'Y Moisés sacó del real al pueblo á recibir á Dios; y pusiéronse á lo bajo del monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 18, 'Y todo el monte de Sinaí humeaba, porque Jehová había descendido sobre él en fuego: y el humo de él subía como el humo de un horno, y todo el monte se estremeció en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 19, 'Y el sonido de la bocina iba esforzándose en extremo: Moisés hablaba, y Dios le respondía en voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 20, 'Y descendió Jehová sobre el monte de Sinaí, sobre la cumbre del monte: y llamó Jehová á Moisés á la cumbre del monte, y Moisés subió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 21, 'Y Jehová dijo á Moisés: Desciende, requiere al pueblo que no traspasen el término por ver á Jehová, porque caerá multitud de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 22, 'Y también los sacerdotes que se llegan á Jehová, se santifiquen, porque Jehová no haga en ellos estrago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 23, 'Y Moisés dijo á Jehová: El pueblo no podrá subir al monte de Sinaí, porque tú nos has requerido diciendo: Señala términos al monte, y santifícalo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 24, 'Y Jehová le dijo: Ve, desciende, y subirás tú, y Aarón contigo: mas los sacerdotes y el pueblo no traspasen el término por subir á Jehová, porque no haga en ellos estrago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 19, 25, 'Entonces Moisés descendió al pueblo y habló con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 1, 'Y HABLO Dios todas estas palabras, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 2, 'Yo soy JEHOVA tu Dios, que te saqué de la tierra de Egipto, de casa de siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 3, 'No tendrás dioses ajenos delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 4, 'No te harás imagen, ni ninguna semejanza de cosa que esté arriba en el cielo, ni abajo en la tierra, ni en las aguas debajo de la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 5, 'No te inclinarás á ellas, ni las honrarás; porque yo soy Jehová tu Dios, fuerte, celoso, que visito la maldad de los padres sobre los hijos, sobre los terceros y sobre los cuartos, á los que me aborrecen,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 6, 'Y que hago misericordia en millares á los que me aman, y guardan mis mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 7, 'No tomarás el nombre de Jehová tu Dios en vano; porque no dará por inocente Jehová al que tomare su nombre en vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 8, 'Acordarte has del día del reposo, para santificarlo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 9, 'Seis días trabajarás, y harás toda tu obra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 10, 'Mas el séptimo día será reposo para Jehová tu Dios: no hagas en él obra alguna, tú, ni tu hijo, ni tu hija, ni tu siervo, ni tu criada, ni tu bestia, ni tu extranjero que está dentro de tus puertas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 11, 'Porque en seis días hizo Jehová los cielos y la tierra, la mar y todas las cosas que en ellos hay, y reposó en el séptimo día: por tanto Jehová bendijo el día del reposo y lo santificó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 12, 'Honra á tu padre y á tu madre, porque tus días se alarguen en la tierra que Jehová tu Dios te da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 13, 'No matarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 14, 'No cometerás adulterio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 15, 'No hurtarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 16, 'No hablarás contra tu prójimo falso testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 17, 'No codiciarás la casa de tu prójimo, no codiciarás la mujer de tu prójimo, ni su siervo, ni su criada, ni su buey, ni su asno, ni cosa alguna de tu prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 18, 'Todo el pueblo consideraba las voces, y las llamas, y el sonido de la bocina, y el monte que humeaba: y viéndolo el pueblo, temblaron, y pusiéronse de lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 19, 'Y dijeron á Moisés: Habla tú con nosotros, que nosotros oiremos; mas no hable Dios con nosotros, porque no muramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 20, 'Y Moisés respondió al pueblo: No temáis; que por probaros vino Dios, y porque su temor esté en vuestra presencia para que no pequéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 21, 'Entonces el pueblo se puso de lejos, y Moisés se llegó á la osbcuridad en la cual estaba Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 22, 'Y Jehová dijo á Moisés: Así dirás á los hijos de Israel: Vosotros habéis visto que he hablado desde el cielo con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 23, 'No hagáis conmigo dioses de plata, ni dioses de oro os haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 24, 'Altar de tierra harás para mí, y sacrificarás sobre él tus holocaustos y tus pacíficos, tus ovejas y tus vacas: en cualquier lugar donde yo hiciere que esté la memoria de mi nombre, vendré á ti, y te bendeciré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 25, 'Y si me hicieres altar de piedras, no las labres de cantería; porque si alzares tu pico sobre él, tú lo profanarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 20, 26, 'Y no subirás por gradas á mi altar, porque tu desnudez no sea junto á él descubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 1, 'Y ESTOS son los derechos que les propondrás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 2, 'Si comprares siervo hebreo, seis años servirá; mas al séptimo saldrá horro de balde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 3, 'Si entró solo, solo saldrá: si tenía mujer, saldrá él y su mujer con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 4, 'Si su amo le hubiere dado mujer, y ella le hubiere parido hijos ó hijas, la mujer y sus hijos serán de su amo, y él saldrá solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 5, 'Y si el siervo dijere: Yo amo á mi señor, á mi mujer y á mis hijos, no saldré libre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 6, 'Entonces su amo lo hará llegar á los jueces, y harále llegar á la puerta ó al poste; y su amo le horadará la oreja con lesna, y será su siervo para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 7, 'Y cuando alguno vendiere su hija por sierva, no saldrá como suelen salir los siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 8, 'Si no agradare á su señor, por lo cual no la tomó por esposa, permitirle ha que se rescate, y no la podrá vender á pueblo extraño cuando la desechare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 9, 'Mas si la hubiere desposado con su hijo, hará con ella según la costumbre de las hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 10, 'Si le tomare otra, no disminuirá su alimento, ni su vestido, ni el débito conyugal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 11, 'Y si ninguna de estas tres cosas hiciere, ella saldrá de gracia sin dinero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 12, 'El que hiriere á alguno, haciéndole así morir, él morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 13, 'Mas el que no armó asechanzas, sino que Dios lo puso en sus manos, entonces yo te señalaré lugar al cual ha de huir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 14, 'Además, si alguno se ensoberbeciere contra su prójimo, y lo matare con alevosía, de mi altar lo quitarás para que muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 15, 'Y el que hiriere á su padre ó á su madre, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 16, 'Asimismo el que robare una persona, y la vendiere, ó se hallare en sus manos, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 17, 'Igualmente el que maldijere á su padre ó á su madre, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 18, 'Además, si algunos riñeren, y alguno hiriere á su prójimo con piedra ó con el puño, y no muriere, pero cayere en cama;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 19, 'Si se levantare y anduviere fuera sobre su báculo, entonces será el que le hirió absuelto: solamente le satisfará lo que estuvo parado, y hará que le curen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 20, 'Y si alguno hiriere á su siervo ó á su sierva con palo, y muriere bajo de su mano, será castigado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 21, 'Mas si durare por un día ó dos, no será castigado, porque su dinero es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 22, 'Si algunos riñeren, é hiriesen á mujer preñada, y ésta abortare, pero sin haber muerte, será penado conforme á lo que le impusiere el marido de la mujer y juzgaren los árbitros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 23, 'Mas si hubiere muerte, entonces pagarás vida por vida,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 24, 'Ojo por ojo, diente por diente, mano por mano, pie por pie,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 25, 'Quemadura por quemadura, herida por herida, golpe por golpe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 26, 'Y cuando alguno hiriere el ojo de su siervo, ó el ojo de su sierva, y lo entortare, darále libertad por razón de su ojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 27, 'Y si sacare el diente de su siervo, ó el diente de su sierva, por su diente le dejará ir libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 28, 'Si un buey acorneare hombre ó mujer, y de resultas muriere, el buey será apedreado, y no se comerá su carne; mas el dueño del buey será absuelto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 29, 'Pero si el buey era acorneador desde ayer y antes de ayer, y á su dueño le fué hecho requerimiento, y no lo hubiere guardado, y matare hombre ó mujer, el buey será apedreado, y también morirá su dueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 30, 'Si le fuere impuesto rescate, entonces dará por el rescate de su persona cuanto le fuere impuesto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 31, 'Haya acorneado hijo, ó haya acorneado hija, conforme á este juicio se hará con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 32, 'Si el buey acorneare siervo ó sierva, pagará treinta siclos de plata su señor, y el buey será apedreado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 33, 'Y si alguno abriere hoyo, ó cavare cisterna, y no la cubriere, y cayere allí buey ó asno,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 34, 'El dueño de la cisterna pagará el dinero, resarciendo á su dueño, y lo que fue muerto será suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 35, 'Y si el buey de alguno hiriere al buey de su prójimo, y éste muriere, entonces venderán el buey vivo, y partirán el dinero de él, y también partirán el muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 21, 36, 'Mas si era notorio que el buey era acorneador de ayer y antes de ayer, y su dueño no lo hubiere guardado, pagará buey por buey, y el muerto será suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 1, 'CUANDO alguno hurtare buey ú oveja, y le degollare ó vendiere, por aquel buey pagará cinco bueyes, y por aquella oveja cuatro ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 2, 'Si el ladrón fuere hallado forzando una casa, y fuere herido y muriere, el que le hirió no será culpado de su muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 3, 'Si el sol hubiere sobre él salido, el matador será reo de homicidio: el ladrón habrá de restituir cumplidamente; si no tuviere, será vendido por su hurto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 4, 'Si fuere hallado con el hurto en la mano, sea buey ó asno ú oveja vivos, pagará el duplo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 5, 'Si alguno hiciere pacer campo ó viña, y metiere su bestia, y comiere la tierra de otro, de lo mejor de su tierra y de lo mejor de su viña pagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 6, 'Cuando rompiere un fuego, y hallare espinas, y fuere quemado montón, ó haza, ó campo, el que encendió el fuego pagará lo quemado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 7, 'Cuando alguno diere á su prójimo plata ó alhajas á guardar, y fuere hurtado de la casa de aquel hombre, si el ladrón se hallare, pagará el doble.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 8, 'Si el ladrón no se hallare, entonces el dueño de la casa será presentado á los jueces, para ver si ha metido su mano en la hacienda de su prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 9, 'Sobre todo negocio de fraude, sobre buey, sobre asno, sobre oveja, sobre vestido, sobre toda cosa perdida, cuando uno dijere: Esto es mío, la causa de ambos vendrá delante de los jueces; y el que los jueces condenaren, pagará el doble á su prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 10, 'Si alguno hubiere dado á su prójimo asno, ó buey, ú oveja, ó cualquier otro animal á guardar, y se muriere ó se perniquebrare, ó fuere llevado sin verlo nadie;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 11, 'Juramento de Jehová tendrá lugar entre ambos de que no echó su mano á la hacienda de su prójimo: y su dueño lo aceptará, y el otro no pagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 12, 'Mas si le hubiere sido hurtado, resarcirá á su dueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 13, 'Y si le hubiere sido arrebatado por fiera, traerle ha testimonio, y no pagará lo arrebatado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 14, 'Pero si alguno hubiere tomado prestada bestia de su prójimo, y fuere estropeada ó muerta, ausente su dueño, deberá pagar la.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 15, 'Si el dueño estaba presente, no la pagará. Si era alquilada, él vendrá por su alquiler.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 16, 'Y si alguno engañare á alguna doncella que no fuere desposada, y durmiere con ella, deberá dotarla y tomarla por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 17, 'Si su padre no quisiere dársela, él le pesará plata conforme al dote de las vírgenes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 18, 'A la hechicera no dejarás que viva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 19, 'Cualquiera que tuviere ayuntamiento con bestia, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 20, 'El que sacrificare á dioses, excepto á sólo Jehová, será muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 21, 'Y al extranjero no engañarás, ni angustiarás, porque extranjeros fuisteis vosotros en la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 22, 'A ninguna viuda ni huérfano afligiréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 23, 'Que si tú llegas á afligirle, y él á mí clamare, ciertamente oiré yo su clamor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 24, 'Y mi furor se encenderá, y os mataré á cuchillo, y vuestras mujeres serán viudas, y huérfanos vuestros hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 25, 'Si dieres á mi pueblo dinero emprestado, al pobre que está contigo, no te portarás con él como logrero, ni le impondrás usura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 26, 'Si tomares en prenda el vestido de tu prójimo, á puestas del sol se lo volverás:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 27, 'Porque sólo aquello es su cubierta, es aquel el vestido para cubrir sus carnes, en el que ha de dormir: y será que cuando él á mí clamare, yo entonces le oiré, porque soy misericordioso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 28, 'No denostarás á los jueces, ni maldecirás al príncipe de tu pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 29, 'No dilatarás la primicia de tu cosecha, ni de tu licor, me darás el primogénito de tus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 30, 'Así harás con el de tu buey y de tu oveja: siete días estará con su madre, y al octavo día me lo darás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 22, 31, 'Y habéis de serme varones santos: y no comeréis carne arrebatada de las fieras en el campo; á los perros la echaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 1, 'NO admitirás falso rumor. No te concertarás con el impío para ser testigo falso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 2, 'No seguirás á los muchos para mal hacer; ni responderás en litigio inclinándote á los más para hacer agravios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 3, 'Ni al pobre distinguirás en su causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 4, 'Si encontrares el buey de tu enemigo ó su asno extraviado, vuelve á llevárselo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 5, 'Si vieres el asno del que te aborrece caído debajo de su carga, ¿le dejarás entonces desamparado? Sin falta ayudarás con él á levantarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 6, 'No pervertirás el derecho de tu mendigo en su pleito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 7, 'De palabra de mentira te alejarás, y no matarás al inocente y justo; porque yo no justificaré al impío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 8, 'No recibirás presente; porque el presente ciega á los que ven, y pervierte las palabras justas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 9, 'Y no angustiarás al extranjero: pues vosotros sabéis cómo se halla el alma del extranjero, ya que extranjeros fuisteis en la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 10, 'Seis años sembrarás tu tierra, y allegarás su cosecha:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 11, 'Mas el séptimo la dejarás vacante y soltarás, para que coman los pobres de tu pueblo; y de lo que quedare comerán las bestias del campo; así harás de tu viña y de tu olivar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 12, 'Seis días harás tus negocios, y al séptimo día holgarás, á fin que descanse tu buey y tu asno, y tome refrigerio el hijo de tu sierva, y el extranjero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 13, 'Y en todo lo que os he dicho seréis avisados. Y nombre de otros dioses no mentaréis, ni se oirá de vuestra boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 14, 'Tres veces en el año me celebraréis fiesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 15, 'La fiesta de los ázimos guardarás: Siete días comerás los panes sin levadura, como yo te mandé, en el tiempo del mes de Abib; porque en él saliste de Egipto: y ninguno comparecerá vacío delante de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 16, 'También la fiesta de la siega, los primeros frutos de tus labores que hubieres sembrado en el campo; y la fiesta de la cosecha á la salida del año, cuando habrás recogido tus labores del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 17, 'Tres veces en el año parecerá todo varón tuyo delante del Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 18, 'No ofrecerás con pan leudo la sangre de mi sacrificio, ni el sebo de mi víctima quedará de la noche hasta la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 19, 'Las primicias de los primeros frutos de tu tierra traerás á la casa de Jehová tu Dios. No guisarás el cabrito con la leche de su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 20, 'He aquí yo envío el Angel delante de ti para que te guarde en el camino, y te introduzca en el lugar que yo he preparado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 21, 'Guárdate delante de él, y oye su voz; no le seas rebelde; porque él no perdonará vuestra rebelión: porque mi nombre está en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 22, 'Pero si en verdad oyeres su voz, é hicieres todo lo que yo te dijere, seré enemigo á tus enemigos, y afligiré á los que te afligieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 23, 'Porque mi Angel irá delante de ti, y te introducirá al Amorrheo, y al Hetheo, y al Pherezeo, y al Cananeo, y al Heveo, y al Jebuseo, á los cuales yo haré destruir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 24, 'No te inclinarás á sus dioses, ni los servirás, ni harás como ellos hacen; antes los destruirás del todo, y quebrantarás enteramente sus estatuas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 25, 'Mas á Jehová vuestro Dios serviréis, y él bendecirá tu pan y tus aguas; y yo quitaré toda enfermedad de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 26, 'No habrá mujer que aborte, ni estéril en tu tierra; y yo cumpliré el número de tus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 27, 'Yo enviaré mi terror delante de ti, y consternaré á todo pueblo donde tú entrares, y te daré la cerviz de todos tus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 28, 'Yo enviaré la avispa delante de ti, que eche fuera al Heveo, y al Cananeo, y al Hetheo, de delante de ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 29, 'No los echaré de delante de ti en un año, porque no quede la tierra desierta, y se aumenten contra ti las bestias del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 30, 'Poco á poco los echaré de delante de ti, hasta que te multipliques y tomes la tierra por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 31, 'Y yo pondré tu término desde el mar Bermejo hasta la mar de Palestina, y desde el desierto hasta el río: porque pondré en vuestras manos los moradores de la tierra, y tú los echarás de delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 32, 'No harás alianza con ellos, ni con sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 23, 33, 'En tu tierra no habitarán, no sea que te hagan pecar contra mí sirviendo á sus dioses: porque te será de tropiezo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 1, 'Y DIJO á Moisés: Sube á Jehová, tú, y Aarón, Nadab, y Abiú, y setenta de los ancianos de Israel; y os inclinaréis desde lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 2, 'Mas Moisés sólo se llegará á Jehová; y ellos no se lleguen cerca, ni suba con él el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 3, 'Y Moisés vino y contó al pueblo todas las palabras de Jehová, y todos los derechos: y todo el pueblo respondió á una voz, y dijeron: Ejecutaremos todas las palabras que Jehová ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 4, 'Y Moisés escribió todas las palabras de Jehová, y levantándose de mañana edificó un altar al pie del monte, y doce columnas, según las doce tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 5, 'Y envió á los mancebos de los hijos de Israel, los cuales ofrecieron holocaustos y sacrificaron pacíficos á Jehová, becerros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 6, 'Y Moisés tomó la mitad de la sangre, y púsola en tazones, y esparció la otra mitad de la sangre sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 7, 'Y tomó el libro de la alianza, y leyó á oídos del pueblo, el cual dijo: Haremos todas las cosas que Jehová ha dicho, y obedeceremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 8, 'Entonces Moisés tomó la sangre, y roció sobre el pueblo, y dijo: He aquí la sangre de la alianza que Jehová ha hecho con vosotros sobre todas estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 9, 'Y subieron Moisés y Aarón, Nadab y Abiú, y setenta de los ancianos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 10, 'Y vieron al Dios de Israel; y había debajo de sus pies como un embaldosado de zafiro, semejante al cielo cuando está sereno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 11, 'Mas no extendió su mano sobre los príncipes de los hijos de Israel: y vieron á Dios, y comieron y bebieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 12, 'Entonces Jehová dijo á Moisés: Sube á mí al monte, y espera allá, y te daré tablas de piedra, y la ley, y mandamientos que he escrito para enseñarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 13, 'Y levantóse Moisés, y Josué su ministro; y Moisés subió al monte de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 14, 'Y dijo á los ancianos: Esperadnos aquí hasta que volvamos á vosotros: y he aquí Aarón y Hur están con vosotros: el que tuviere negocios, lléguese á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 15, 'Entonces Moisés subió al monte, y una nube cubrió el monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 16, 'Y la gloria de Jehová reposó sobre el monte Sinaí, y la nube lo cubrió por seis días: y al séptimo día llamó á Moisés de en medio de la nube.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 17, 'Y el parecer de la gloria de Jehová era como un fuego abrasador en la cumbre del monte, á los ojos de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 24, 18, 'Y entró Moisés en medio de la nube, y subió al monte: y estuvo Moisés en el monte cuarenta días y cuarenta noches.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 2, 'Di á los hijos de Israel que tomen para mí ofrenda: de todo varón que la diere de su voluntad, de corazón, tomaréis mi ofrenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 3, 'Y esta es la ofrenda que tomaréis de ellos: Oro, y plata, y cobre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 4, 'Y jacinto, y púrpura, y carmesí, y lino fino, y pelo de cabras,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 5, 'Y cueros de carneros teñidos de rojo, y cueros de tejones, y madera de Sittim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 6, 'Aceite para la luminaria, especias para el aceite de la unción, y para el sahumerio aromático;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 7, 'Piedras de onix, y piedras de engastes, para el ephod, y para el racional.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 8, 'Y hacerme han un santuario, y yo habitaré entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 9, 'Conforme á todo lo que yo te mostrare, el diseño del tabernáculo, y el diseño de todos sus vasos, así lo haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 10, 'Harán también un arca de madera de Sittim, cuya longitud será de dos codos y medio, y su anchura de codo y medio, y su altura de codo y medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 11, 'Y la cubrirás de oro puro; por dentro y por fuera la cubrirás; y harás sobre ella una cornisa de oro alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 12, 'Y para ella harás de fundición cuatro anillos de oro, que pondrás á sus cuatro esquinas; dos anillos al un lado de ella, y dos anillos al otro lado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 13, 'Y harás unas varas de madera de Sittim, las cuales cubrirás de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 14, 'Y meterás las varas por los anillos á los lados del arca, para llevar el arca con ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 15, 'Las varas se estarán en los anillos del arca: no se quitarán de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 16, 'Y pondrás en el arca el testimonio que yo te daré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 17, 'Y harás una cubierta de oro fino, cuya longitud será de dos codos y medio, y su anchura de codo y medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 18, 'Harás también dos querubines de oro, labrados á martillo los harás, en los dos cabos de la cubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 19, 'Harás, pues, un querubín al extremo de un lado, y un querubín al otro extremo del lado opuesto: de la calidad de la cubierta harás los querubines en sus dos extremidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 20, 'Y los querubines extenderán por encima las alas, cubriendo con sus alas la cubierta: sus caras la una enfrente de la otra, mirando á la cubierta las caras de los querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 21, 'Y pondrás la cubierta encima del arca, y en el arca pondrás el testimonio que yo te daré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 22, 'Y de allí me declararé á ti, y hablaré contigo de sobre la cubierta, de entre los dos querubines que están sobre el arca del testimonio, todo lo que yo te mandaré para los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 23, 'Harás asimismo una mesa de madera de Sittim: su longitud será de dos codos, y de uu codo su anchura, y su altura de codo y medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 24, 'Y la cubrirás de oro puro, y le has de hacer una cornisa de oro alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 25, 'Hacerle has también una moldura alrededor, del ancho de una mano, á la cual moldura harás una cornisa de oro en circunferencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 26, 'Y le harás cuatro anillos de oro, los cuales pondrás á las cuatro esquinas que corresponden á sus cuatro pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 27, 'Los anillos estarán antes de la moldura, por lugares de las varas, para llevar la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 28, 'Y harás las varas de madera de Sittim, y las cubrirás de oro, y con ellas será llevada la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 29, 'Harás también sus platos, y sus cucharas, y sus cubiertas, y sus tazones, con que se libará: de oro fino los harás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 30, 'Y pondrás sobre la mesa el pan de la proposición delante de mí continuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 31, 'Harás además un candelero de oro puro; labrado á martillo se hará el candelero: su pie, y su caña, sus copas, sus manzanas, y sus flores, serán de lo mismo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 32, 'Y saldrán seis brazos de sus lados: tres brazos del candelero del un lado suyo, y tres brazos del candelero del otro su lado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 33, 'Tres copas en forma de almendras en el un brazo, una manzana y una flor; y tres copas, figura de almendras en el otro brazo, una manzana y una flor: así pues, en los seis brazos que salen del candelero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 34, 'Y en el candelero cuatro copas en forma de almendras, sus manzanas y sus flores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 35, 'Habrá una manzana debajo de los dos brazos de lo mismo, otra manzana debajo de los otros dos brazos de lo mismo, y otra manzana debajo de los otros dos brazos de lo mismo, en conformidad á los seis brazos que salen del candelero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 36, 'Sus manzanas y sus brazos serán de lo mismo, todo ello una pieza labrada á martillo, de oro puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 37, 'Y hacerle has siete candilejas, las cuales encenderás para que alumbren á la parte de su delantera:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 38, 'También sus despabiladeras y sus platillos, de oro puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 39, 'De un talento de oro fino lo harás, con todos estos vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 25, 40, 'Y mira, y hazlos conforme á su modelo, que te ha sido mostrado en el monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 1, 'Y HARAS el tabernáculo de diez cortinas de lino torcido, cárdeno, y púrpura, y carmesí: y harás querubines de obra delicada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 2, 'La longitud de la una cortina de veintiocho codos, y la anchura de la misma cortina de cuatro codos: todas las cortinas tendrán una medida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 3, 'Cinco cortinas estarán juntas la una con la otra, y cinco cortinas unidas la una con la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 4, 'Y harás lazadas de cárdeno en la orilla de la una cortina, en el borde, en la juntura: y así harás en la orilla de la postrera cortina en la juntura segunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 5, 'Cincuenta lazadas harás en la una cortina, y cincuenta lazadas harás en el borde de la cortina que está en la segunda juntura: las lazadas estarán contrapuestas la una á la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 6, 'Harás también cincuenta corchetes de oro, con los cuales juntarás las cortinas la una con la otra, y se formará un tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 7, 'Harás asimismo cortinas de pelo de cabras para una cubierta sobre el tabernáculo; once cortinas harás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 8, 'La longitud de la una cortina será de treinta codos, y la anchura de la misma cortina de cuatro codos: una medida tendrán las once cortinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 9, 'Y juntarás las cinco cortinas aparte y las otras seis cortinas separadamente; y doblarás la sexta cortina delante de la faz del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 10, 'Y harás cincuenta lazadas en la orilla de la una cortina, al borde en la juntura, y cincuenta lazadas en la orilla de la segunda cortina en la otra juntura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 11, 'Harás asimismo cincuenta corchetes de alambre, los cuales meterás por las lazadas: y juntarás la tienda, para que se haga una sola cubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 12, 'Y el sobrante que resulta en las cortinas de la tienda, la mitad de la una cortina que sobra, quedará á las espaldas del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 13, 'Y un codo de la una parte, y otro codo de la otra que sobra en la longitud de las cortinas de la tienda, cargará sobre los lados del tabernáculo de la una parte y de la otra, para cubrirlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 14, 'Harás también á la tienda una cubierta de cueros de carneros, teñidos de rojo, y una cubierta de cueros de tejones encima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 15, 'Y harás para el tabernáculo tablas de madera de Sittim, que estén derechas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 16, 'La longitud de cada tabla será de diez codos, y de codo y medio la anchura de cada tabla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 17, 'Dos quicios tendrá cada tabla, trabadas la una con la otra; así harás todas las tablas del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 18, 'Harás, pues, las tablas del tabernáculo: veinte tablas al lado del mediodía, al austro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 19, 'Y harás cuarenta basas de plata debajo de las veinte tablas; dos basas debajo de la una tabla para sus dos quicios, y dos basas debajo de la otra tabla para sus dos quicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 20, 'Y al otro lado del tabernáculo, á la parte del aquilón, veinte tablas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 21, 'Y sus cuarenta basas de plata: dos basas debajo de la una tabla, y dos basas debajo de la otra tabla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 22, 'Y para el lado del tabernáculo, al occidente, harás seis tablas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 23, 'Harás además dos tablas para las esquinas del tabernáculo en los dos ángulos posteriores;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 24, 'Las cuales se unirán por abajo, y asimismo se juntarán por su alto á un gozne: así será de las otras dos que estarán á las dos esquinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 25, 'De suerte que serán ocho tablas, con sus basas de plata, diez y seis basas; dos basas debajo de la una tabla, y dos basas debajo de la otra tabla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 26, 'Harás también cinco barras de madera de Sittim, para las tablas del un lado del tabernáculo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 27, 'Y cinco barras para las tablas del otro lado del tabernáculo, y cinco barras para el otro lado del tabernáculo, que está al occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 28, 'Y la barra del medio pasará por medio de las tablas, del un cabo al otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 29, 'Y cubrirás las tablas de oro, y harás sus anillos de oro para meter por ellos las barras: también cubrirás las barras de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 30, 'Y alzarás el tabernáculo conforme á su traza que te fue mostrada en el monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 31, 'Y harás también un velo de cárdeno, y púrpura, y carmesí, y de lino torcido: será hecho de primorosa labor, con querubines:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 32, 'Y has de ponerlo sobre cuatro columnas de madera de Sittim cubiertas de oro; sus capiteles de oro, sobre basas de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 33, 'Y pondrás el velo debajo de los corchetes, y meterás allí, del velo adentro, el arca del testimonio; y aquel velo os hará separación entre el lugar santo y el santísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 34, 'Y pondrás la cubierta sobre el arca del testimonio en el lugar santísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 35, 'Y pondrás la mesa fuera del velo, y el candelero enfrente de la mesa al lado del tabernáculo al mediodía; y pondrás la mesa al lado del aquilón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 36, 'Y harás á la puerta del tabernáculo una cortina de cárdeno, y púrpura, y carmesí, y lino torcido, obra de bordador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 26, 37, 'Y harás para la cortina cinco columnas de madera de Sittim, las cuales cubrirás de oro, con sus capiteles de oro: y hacerlas has de fundición cinco basas de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 1, 'HARAS también altar de madera de Sittim de cinco codos de longitud, y de cinco codos de anchura: será cuadrado el altar, y su altura de tres codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 2, 'Y harás sus cuernos á sus cuatro esquinas; los cuernos serán de lo mismo; y lo cubrirás de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 3, 'Harás también sus calderas para echar su ceniza; y sus paletas, y sus tazones, y sus garfios, y sus braseros: harás todos sus vasos de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 4, 'Y le harás un enrejado de metal de obra de malla; y sobre el enrejado harás cuatro anillos de metal á sus cuatro esquinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 5, 'Y lo has de poner dentro del cerco del altar abajo; y llegará el enrejado hasta el medio del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 6, 'Harás también varas para el altar, varas de madera de Sittim, las cuales cubrirás de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 7, 'Y sus varas se meterán por los anillos: y estarán aquellas varas á ambos lados del altar, cuando hubiere de ser llevado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 8, 'De tablas lo harás, hueco: de la manera que te fue mostrado en el monte, así lo harás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 9, 'Asimismo harás el atrio del tabernáculo: al lado del mediodía, al austro, tendrá el atrio cortinas de lino torcido, de cien codos de longitud cada un lado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 10, 'Sus veinte columnas, y sus veinte basas serán de metal; los capiteles de las columnas y sus molduras, de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 11, 'Y de la misma manera al lado del aquilón habrá á lo largo cortinas de cien codos de longitud, y sus veinte columnas, con sus veinte basas de metal; los capiteles de sus columnas y sus molduras, de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 12, 'Y el ancho del atrio del lado occidental tendrá cortinas de cincuenta codos; sus columnas diez, con sus diez basas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 13, 'Y en el ancho del atrio por la parte de levante, al oriente, habrá cincuenta codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 14, 'Y las cortinas del un lado serán de quince codos; sus columnas tres, con sus tres basas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 15, 'Al otro lado quince codos de cortinas; sus columnas tres, con sus tres basas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 16, 'Y á la puerta del atrio habrá un pabellón de veinte codos, de cárdeno, y púrpura, y carmesí, y lino torcido, de obra de bordador: sus columnas cuatro, con sus cuatro basas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 17, 'Todas las columnas del atrio en derredor serán ceñidas de plata; sus capiteles de plata, y sus basas de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 18, 'La longitud del atrio será de cien codos, y la anchura cincuenta por un lado y cincuenta por el otro, y la altura de cinco codos: sus cortinas de lino torcido, y sus basas de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 19, 'Todos los vasos del tabernáculo en todo su servicio, y todos sus clavos, y todos los clavos del atrio, serán de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 20, 'Y tú mandarás á los hijos de Israel que te traigan aceite puro de olivas, molido, para la luminaria, para hacer arder continuamente las lámparas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 27, 21, 'En el tabernáculo del testimonio, afuera del velo que está delante del testimonio, las pondrá en orden Aarón y sus hijos, delante de Jehová desde la tarde hasta la mañana, como estatuto perpetuo de los hijos de Israel por sus generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 1, 'Y TU allega á ti á Aarón tu hermano, y á sus hijos consigo, de entre los hijos de Israel, para que sean mis sacerdotes; á Aarón, Nadab y Abiú, Eleazar é Ithamar, hijos de Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 2, 'Y harás vestidos sagrados á Aarón tu hermano, para honra y hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 3, 'Y tú hablarás á todos los sabios de corazón, á quienes yo he henchido de espíritu de sabiduría; á fin que hagan los vestidos de Aarón, para consagrarle á que me sirva de sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 4, 'Los vestidos que harán son estos: el racional, y el ephod, y el manto, y la túnica labrada, la mitra, y el cinturón. Hagan, pues, los sagrados vestidos á Aarón tu hermano, y á sus hijos, para que sean mis sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 5, 'Tomarán oro, y cárdeno, y púrpura, y carmesí, y lino torcido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 6, 'Y harán el ephod de oro y cárdeno, y púrpura, y carmesí, y lino torcido de obra de bordador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 7, 'Tendrá dos hombreras que se junten á sus dos lados, y se juntará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 8, 'Y el artificio de su cinto que está sobre él, será de su misma obra, de lo mismo; de oro, cárdeno, y púrpura, y carmesí, y lino torcido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 9, 'Y tomarás dos piedras oniquinas, y grabarás en ellas los nombres de los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 10, 'Los seis de sus nombres en la una piedra, y los otros seis nombres en la otra piedra, conforme al nacimiento de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 11, 'De obra de escultor en piedra á modo de grabaduras de sello, harás grabar aquellas dos piedras con los nombres de los hijos de Israel; harásles alrededor engastes de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 12, 'Y pondrás aquellas dos piedras sobre los hombros del ephod, para piedras de memoria á los hijos de Israel; y Aarón llevará los nombres de ellos delante de Jehová en sus dos hombros por memoria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 13, 'Harás pues, engastes de oro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 14, 'Y dos cadenillas de oro fino; las cuales harás de hechura de trenza; y fijarás las cadenas de hechura de trenza en los engastes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 15, 'Harás asimismo el racional del juicio de primorosa obra, le has de hacer conforme á la obra del ephod, de oro, y cárdeno, y púrpura, y carmesí, y lino torcido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 16, 'Será cuadrado y doble, de un palmo de largo y un palmo de ancho:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 17, 'Y lo llenarás de pedrería con cuatro órdenes de piedras: un orden de una piedra sárdica, un topacio, y un carbunclo; será el primer orden;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 18, 'El segundo orden, una esmeralda, un zafiro, y un diamante;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 19, 'El tercer orden, un rubí, un ágata, y una amatista;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 20, 'Y el cuarto orden, un berilo, un onix, y un jaspe: estarán engastadas en oro en sus encajes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 21, 'Y serán aquellas piedra según los nombres de los hijos de Israel, doce según sus nombres; como grabaduras de sello cada una con su nombre, vendrán á ser según las doce tribus.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 22, 'Harás también en el racional cadenetas de hechura de trenzas de oro fino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 23, 'Y harás en el racional dos anillos de oro, los cuales dos anillos pondrás á las dos puntas del racional.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 24, 'Y pondrás las dos trenzas de oro en los dos anillos á las dos puntas del racional:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 25, 'Y los dos cabos de las dos trenzas sobre los dos engastes, y las pondrás á los lados del ephod en la parte delantera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 26, 'Harás también dos anillos de oro, los cuales pondrás á las dos puntas del racional, en su orilla que está al lado del ephod de la parte de dentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 27, 'Harás asimismo dos anillos de oro, los cuales pondrás á los dos lados del ephod abajo en la parte delantera, delante de su juntura sobre el cinto del ephod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 28, 'Y juntarán el racional con sus anillos á los anillos del ephod con un cordón de jacinto, para que esté sobre el cinto del ephod, y no se aparte el racional del ephod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 29, 'Y llevará Aarón los nombres de los hijos de Israel en el racional del juicio sobre su corazón, cuando entrare en el santuario, para memoria delante de Jehová continuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 30, 'Y pondrás en el racional del juicio Urim y Thummim, para que estén sobre el corazón de Aarón cuando entrare delante de Jehová: y llevará siempre Aarón el juicio de los hijos de Israel sobre su corazón delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 31, 'Harás el manto del ephod todo de jacinto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 32, 'Y en medio de él por arriba habrá una abertura, la cual tendrá un borde alrededor de obra de tejedor, como el cuello de un coselete, para que no se rompa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 33, 'Y abajo en sus orillas harás granadas de jacinto, y púrpura, y carmesí, por sus bordes alrededor; y entre ellas campanillas de oro alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 34, 'Una campanilla de oro y una granada, campanilla de oro y granada, por las orillas del manto alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 35, 'Y estará sobre Aarón cuando ministrare; y oiráse su sonido cuando él entrare en el santuario delante de Jehová y cuando saliere, porque no muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 36, 'Harás además una plancha de oro fino, y grabarás en ella grabadura de sello, SANTIDAD A JEHOVA.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 37, 'Y la pondrás con un cordón de jacinto, y estará sobre la mitra; por el frente anterior de la mitra estará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 38, 'Y estará sobre la frente de Aarón: y llevará Aarón el pecado de las cosas santas, que los hijos de Israel hubieren consagrado en todas sus santas ofrendas; y sobre su frente estará continuamente para que hayan gracia delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 39, 'Y bordarás una túnica de lino, y harás una mitra de lino; harás también un cinto de obra de recamador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 40, 'Y para los hijos de Aarón harás túnicas; también les harás cintos, y les formarás chapeos (tiaras) para honra y hermosura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 41, 'Y con ellos vestirás á Aarón tu hermano, y á sus hijos con él: y los ungirás, y los consagrarás, y santificarás, para que sean mis sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 42, 'Y les harás pañetes de lino para cubrir la carne vergonzosa; serán desde los lomos hasta los muslos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 28, 43, 'Y estarán sobre Aarón y sobre sus hijos cuando entraren en el tabernáculo de testimonio, ó cuando se llegaren al altar para servir en el santuario, porque no lleven pecado, y mueran. Estatuto perpetuo para él, y para su simiente después de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 1, 'Y ESTO es lo que les harás para consagrarlos, para que sean mis sacerdotes: Toma un becerro de la vacada, y dos carneros sin tacha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 2, 'Y panes sin levadura, y tortas sin levadura amasadas con aceite, y hojaldres sin levadura untadas con aceite; las cuales cosas harás de flor de harina de trigo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 3, 'Y las pondrás en un canastillo, y en el canastillo las ofrecerás, con el becerro y los dos carneros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 4, 'Y harás llegar á Aarón y á sus hijos á la puerta del tabernáculo del testimonio, y los lavarás con agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 5, 'Y tomarás las vestiduras, y vestirás á Aarón la túnica y el manto del ephod, y el ephod, y el racional, y le ceñirás con el cinto del ephod;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 6, 'Y pondrás la mitra sobre su cabeza, y sobre la mitra pondrás la diadema santa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 7, 'Y tomarás el aceite de la unción, y derramarás sobre su cabeza, y le ungirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 8, 'Y harás llegar sus hijos, y les vestirás las túnicas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 9, 'Y les ceñirás el cinto, á Aarón y á sus hijos, y les atarás los chapeos (tiaras), y tendrán el sacerdocio por fuero perpetuo: y henchirás las manos de Aarón y de sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 10, 'Y harás llegar el becerro delante del tabernáculo del testimonio, y Aarón y sus hijos pondrán sus manos sobre la cabeza del becerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 11, 'Y matarás el becerro delante de Jehová á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 12, 'Y tomarás de la sangre del becerro, y pondrás sobre los cuernos del altar con tu dedo, y derramarás toda la demás sangre al pie del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 13, 'Tomarás también todo el sebo que cubre los intestinos, y el redaño de sobre el hígado, y los dos riñones, y el sebo que está sobre ellos, y los quemarás sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 14, 'Empero consumirás á fuego fuera del campo la carne del becerro, y su pellejo, y su estiércol: es expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 15, 'Asimismo tomarás el un carnero, y Aarón y sus hijos pondrán sus manos sobre la cabeza del carnero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 16, 'Y matarás el carnero, y tomarás su sangre, y rociarás sobre el altar alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 17, 'Y cortarás el carnero en pedazos, y lavarás sus intestinos y sus piernas, y las pondrás sobre sus trozos y sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 18, 'Y quemarás todo el carnero sobre el altar: es holocausto á Jehová, olor grato, es ofrenda quemada á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 19, 'Tomarás luego el otro carnero, y Aarón y sus hijos pondrán sus manos sobre la cabeza del carnero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 20, 'Y matarás el carnero, y tomarás de su sangre, y pondrás sobre la ternilla de la oreja derecha de Aarón, y sobre la ternilla de las orejas de sus hijos, y sobre el dedo pulgar de las manos derechas de ellos, y sobre el dedo pulgar de los pies derechos de ellos, y esparcirás la sangre sobre el altar alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 21, 'Y tomarás de la sangre que hay sobre el altar, y del aceite de la unción, y esparcirás sobre Aarón, y sobre sus vestiduras, y sobre sus hijos, y sobre las vestimentas de éstos; y él será santificado, y sus vestiduras, y sus hijos, y las vestimentas de sus hijos con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 22, 'Luego tomarás del carnero el sebo, y la cola, y el sebo que cubre los intestinos, y el redaño del hígado, y los dos riñones, y el sebo que está sobre ellos, y la espaldilla derecha; porque es carnero de consagraciones:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 23, 'También una torta de pan, y una hojaldre amasada con aceite, y una lasaña del canastillo de los ázimos presentado á Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 24, 'Y lo has de poner todo en las manos de Aarón, y en las manos de sus hijos; y lo mecerás agitándolo delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 25, 'Después lo tomarás de sus manos, y lo harás arder sobre el altar en holocausto, por olor agradable delante de Jehová. Es ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 26, 'Y tomarás el pecho del carnero de las consagraciones, que fue inmolado para la de Aarón, y lo mecerás por ofrenda agitada delante de Jehová; y será porción tuya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 27, 'Y apartarás el pecho de la ofrenda mecida, y la espaldilla de la santificación, lo que fue mecido y lo que fue santificado del carnero de las consagraciones de Aarón y de sus hijos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 28, 'Y será para Aarón y para sus hijos por estatuto perpetuo de los hijos de Israel, porque es porción elevada; y será tomada de los hijos de Israel de sus sacrificios pacíficos, porción de ellos elevada en ofrenda á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 29, 'Y las vestimentas santas, que son de Aarón, serán de sus hijos después de él, para ser ungidos con ellas, y para ser con ellas consagrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 30, 'Por siete días las vestirá el sacerdote de sus hijos, que en su lugar viniere al tabernáculo del testimonio á servir en el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 31, 'Y tomarás el carnero de las consagraciones, y cocerás su carne en el lugar del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 32, 'Y Aarón y sus hijos comerán la carne del carnero, y el pan que está en el canastillo, á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 33, 'Y comerán aquellas cosas con las cuales se hizo expiación, para henchir sus manos para ser santificados: mas el extranjero no comerá, porque es cosa santa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 34, 'Y si sobrare algo de la carne de las consagraciones y del pan hasta la mañana, quemarás al fuego lo que hubiere sobrado: no se comerá, porque es cosa santa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 35, 'Así pues harás á Aarón y á sus hijos, conforme á todas las cosas que yo te he mandado: por siete días los consagrarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 36, 'Y sacrificarás el becerro de la expiación en cada día para las expiaciones; y purificarás el altar en habiendo hecho expiación por él, y lo ungirás para santificarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 37, 'Por siete días expiarás el altar, y lo santificarás, y será un altar santísimo: cualquiera cosa que tocare al altar, será santificada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 38, 'Y esto es lo que ofrecerás sobre el altar: dos corderos de un año cada día, sin intermisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 39, 'Ofrecerás el un cordero á la mañana, y el otro cordero ofrecerás á la caída de la tarde:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 40, 'Además una décima parte de un epha de flor de harina amasada con la cuarta parte de un hin de aceite molido: y la libación será la cuarta parte de un hin de vino con cada cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 41, 'Y ofrecerás el otro cordero á la caída de la tarde, haciendo conforme á la ofrenda de la mañana, y conforme á su libación, en olor de suavidad; será ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 42, 'Esto será holocausto continuo por vuestras generaciones á la puerta del tabernáculo del testimonio delante de Jehová, en el cual me concertaré con vosotros, para hablaros allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 43, 'Y allí testificaré de mí á los hijos de Israel, y el lugar será santificado con mi gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 44, 'Y santificaré el tabernáculo del testimonio y el altar: santificaré asimismo á Aarón y á sus hijos, para que sean mis sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 45, 'Y habitaré entre los hijos de Israel, y seré su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 29, 46, 'Y conocerán que yo soy Jehová su Dios, que los saqué de la tierra de Egipto, para habitar en medio de ellos: Yo Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 1, 'HARAS asimismo un altar de sahumerio de perfume: de madera de Sittim lo harás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 2, 'Su longitud será de un codo, y su anchura de un codo: será cuadrado: y su altura de dos codos: y sus cuernos serán de lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 3, 'Y cubrirlo has de oro puro, su techado, y sus paredes en derredor, y sus cuernos: y le harás en derredor una corona de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 4, 'Le harás también dos anillos de oro debajo de su corona á sus dos esquinas en ambos lados suyos, para meter los varales con que será llevado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 5, 'Y harás los varales de madera de Sittim, y los cubrirás de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 6, 'Y lo pondrás delante del velo que está junto al arca del testimonio, delante de la cubierta que está sobre el testimonio, donde yo te testificaré de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 7, 'Y quemará sobre él Aarón sahumerio de aroma cada mañana cuando aderezare las lámparas lo quemará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 8, 'Y cuando Aarón encenderá las lámparas al anochecer, quemará el sahumerio: rito perpetuo delante de Jehová por vuestras edades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 9, 'No ofreceréis sobre él sahumerio extraño, ni holocausto, ni presente; ni tampoco derramaréis sobre él libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 10, 'Y sobre sus cuernos hará Aarón expiación una vez en el año con la sangre de la expiación para las reconciliaciones: una vez en el año hará expiación sobre él en vuestras edades: será muy santo á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 11, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 12, 'Cuando tomares el número de los hijos de Israel conforme á la cuenta de ellos, cada uno dará á Jehová el rescate de su persona, cuando los contares, y no habrá en ellos mortandad por haberlos contado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 13, 'Esto dará cualquiera que pasare por la cuenta, medio siclo conforme al siclo del santuario. El siclo es de veinte óbolos: la mitad de un siclo será la ofrenda á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 14, 'Cualquiera que pasare por la cuenta, de veinte años arriba, dará la ofrenda á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 15, 'Ni el rico aumentará, ni el pobre disminuirá de medio siclo, cuando dieren la ofrenda á Jehová para hacer expiación por vuestras personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 16, 'Y tomarás de los hijos de Israel el dinero de las expiaciones, y lo darás para la obra del tabernáculo del testimonio: y será por memoria á los hijos de Israel delante de Jehová, para expiar vuestras personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 17, 'Habló más Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 18, 'Harás también una fuente de metal, con su basa de metal, para lavar; y la has de poner entre el tabernáculo del testimonio y el altar; y pondrás en ella agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 19, 'Y de ella se lavarán Aarón y sus hijos sus manos y sus pies:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 20, 'Cuando entraren en el tabernáculo del testimonio, se han de lavar con agua, y no morirán: y cuando se llegaren al altar para ministrar, para encender á Jehová la ofrenda que se ha de consumir al fuego,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 21, 'También se lavarán las manos y los pies, y no morirán. Y lo tendrán por estatuto perpetuo él y su simiente por sus generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 22, 'Habló más Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 23, 'Y tú has de tomar de las principales drogas; de mirra excelente quinientos siclos, y de canela aromática la mitad, esto es, doscientos y cincuenta, y de cálamo aromático doscientos y cincuenta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 24, 'Y de casia quinientos, al peso del santuario, y de aceite de olivas un hin:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 25, 'Y harás de ello el aceite de la santa unción, superior ungüento, obra de perfumador, el cual será el aceite de la unción sagrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 26, 'Con él ungirás el tabernáculo del testimonio, y el arca del testimonio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 27, 'Y la mesa, y todos sus vasos, y el candelero, y todos sus vasos, y el altar del perfume,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 28, 'Y el altar del holocausto, todos sus vasos, y la fuente y su basa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 29, 'Así los consagrarás, y serán cosas santísimas: todo lo que tocare en ellos, será santificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 30, 'Ungirás también á Aarón y á sus hijos, y los consagrarás para que sean mis sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 31, 'Y hablarás á los hijos de Israel, diciendo: Este será mi aceite de la santa unción por vuestras edades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 32, 'Sobre carne de hombre no será untado, ni haréis otro semejante, conforme á su composición: santo es; por santo habéis de tenerlo vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 33, 'Cualquiera que compusiere ungüento semejante, y que pusiere de él sobre extraño, será cortado de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 34, 'Dijo aún Jehová á Moisés: Tómate aromas, estacte y uña olorosa y gálbano aromático é incienso limpio; de todo en igual peso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 35, 'Y harás de ello una confección aromática de obra de perfumador, bien mezclada, pura y santa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 36, 'Y molerás alguna de ella pulverizándola, y la pondrás delante del testimonio en el tabernáculo del testimonio, donde yo te testificaré de mí. Os será cosa santísima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 37, 'Como la confección que harás, no os haréis otra según su composición: te será cosa sagrada para Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 30, 38, 'Cualquiera que hiciere otra como ella para olerla, será cortado de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 2, 'Mira, yo he llamado por su nombre á Bezaleel, hijo de Uri, hijo de Hur, de la tribu de Judá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 3, 'Y lo he henchido de espíritu de Dios, en sabiduría, y en inteligencia, y en ciencia, y en todo artificio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 4, 'Para inventar diseños, para trabajar en oro, y en plata, y en metal,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 5, 'Y en artificio de piedras para engastar las, y en artificio de madera; para obrar en toda suerte de labor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 6, 'Y he aquí que yo he puesto con él á Aholiab, hijo de Ahisamac, de la tribu de Dan: y he puesto sabiduría en el ánimo de todo sabio de corazón, para que hagan todo lo que te he mandado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 7, 'El tabernáculo del testimonio, y el arca del testimonio, y la cubierta que está sobre ella, y todos los vasos del tabernáculo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 8, 'Y la mesa y sus vasos, y el candelero limpio y todos sus vasos, y el altar del perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 9, 'Y el altar del holocausto y todos sus vasos, y la fuente y su basa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 10, 'Y los vestidos del servicio, y las santas vestiduras para Aarón el sacerdote, y las vestiduras de sus hijos, para que ejerzan el sacerdocio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 11, 'Y el aceite de la unción, y el perfume aromático para el santuario: harán conforme á todo lo que te he mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 12, 'Habló además Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 13, 'Y tú hablarás á los hijos de Israel, diciendo: Con todo eso vosotros guardaréis mis sábados: porque es señal entre mí y vosotros por vuestras edades, para que sepáis que yo soy Jehová que os santifico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 14, 'Así que guardaréis el sábado, porque santo es á vosotros: el que lo profanare, de cierto morirá; porque cualquiera que hiciere obra alguna en él, aquella alma será cortada de en medio de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 15, 'Seis días se hará obra, mas el día séptimo es sábado de reposo consagrado á Jehová; cualquiera que hiciere obra el día del sábado, morirá ciertamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 16, 'Guardarán, pues, el sábado los hijos de Israel: celebrándolo por sus edades por pacto perpetuo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 17, 'Señal es para siempre entre mí y los hijos de Israel; porque en seis días hizo Jehová los cielos y la tierra, y en el séptimo día cesó, y reposó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 31, 18, 'Y dió á Moisés, como acabó de hablar con él en el monte de Sinaí, dos tablas del testimonio, tablas de piedra escritas con el dedo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 1, 'MAS viendo el pueblo que Moisés tardaba en descender del monte, allegóse entonces á Aarón, y dijéronle: Levántate, haznos dioses que vayan delante de nosotros; porque á este Moisés, aquel varón que nos sacó de la tierra de Egipto, no sabemos qué le haya acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 2, 'Y Aarón les dijo: Apartad los zarcillos de oro que están en las orejas de vuestras mujeres, y de vuestros hijos, y de vuestras hijas, y traédmelos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 3, 'Entonces todo el pueblo apartó los zarcillos de oro que tenían en sus orejas, y trajéronlos á Aarón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 4, 'El cual los tomó de las manos de ellos, y formólo con buril, é hizo de ello un becerro de fundición. Entonces dijeron: Israel, estos son tus dioses, que te sacaron de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 5, 'Y viendo esto Aarón, edificó un altar delante del becerro; y pregonó Aarón, y dijo: Mañana será fiesta á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 6, 'Y el día siguiente madrugaron, y ofrecieron holocaustos, y presentaron pacíficos: y sentóse el pueblo á comer y á beber, y levantáronse á regocijarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 7, 'Entonces Jehová dijo á Moisés: Anda, desciende, porque tu pueblo que sacaste de tierra de Egipto se ha corrompido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 8, 'Presto se han apartado del camino que yo les mandé, y se han hecho un becerro de fundición, y lo han adorado, y han sacrificado á él, y han dicho: Israel, estos son tus dioses, que te sacaron de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 9, 'Dijo más Jehová á Moisés: Yo he visto á este pueblo, que por cierto es pueblo de dura cerviz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 10, 'Ahora pues, déjame que se encienda mi furor en ellos, y los consuma: y á ti yo te pondré sobre gran gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 11, 'Entonces Moisés oró á la faz de Jehová su Dios, y dijo: Oh Jehová, ¿por qué se encenderá tu furor en tu pueblo, que tú sacaste de la tierra de Egipto con gran fortaleza, y con mano fuerte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 12, '¿Por qué han de hablar los Egipcios, diciendo: Para mal los sacó, para matarlos en los montes, y para raerlos de sobre la haz de la tierra? Vuélvete del furor de tu ira, y arrepiéntete del mal de tu pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 13, 'Acuérdate de Abraham, de Isaac, y de Israel tus siervos, á los cuales has jurado por ti mismo, y dícholes: Yo multiplicaré vuestra simiente como las estrellas del cielo; y daré á vuestra simiente toda esta tierra que he dicho, y la tomarán por heredad para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 14, 'Entonces Jehová se arrepintió del mal que dijo que había de hacer á su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 15, 'Y volvióse Moisés, y descendió del monte trayendo en su mano las dos tablas del testimonio, las tablas escritas por ambos lados; de una parte y de otra estaban escritas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 16, 'Y las tablas eran obra de Dios, y la escritura era escritura de Dios grabada sobre las tablas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 17, 'Y oyendo Josué el clamor del pueblo que gritaba, dijo á Moisés: Alarido de pelea hay en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 18, 'Y él respondió: No es eco de algazara de fuertes, ni eco de alaridos de flacos: algazara de cantar oigo yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 19, 'Y aconteció, que como llegó él al campo, y vió el becerro y las danzas, enardeciósele la ira á Moisés, y arrojó las tablas de sus manos, y quebrólas al pie del monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 20, 'Y tomó el becerro que habían hecho, y quemólo en el fuego, y moliólo hasta reducirlo á polvo, que esparció sobre las aguas, y diólo á beber á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 21, 'Y dijo Moisés á Aarón: ¿Qué te ha hecho este pueblo, que has traído sobre él tan gran pecado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 22, 'Y respondió Aarón: No se enoje mi señor; tú conoces el pueblo, que es inclinado á mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 23, 'Porque me dijeron: Haznos dioses que vayan delante de nosotros, que á este Moisés, el varón que nos sacó de tierra de Egipto, no sabemos qué le ha acontecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 24, 'Y yo les respondí: ¿Quién tiene oro? Apartadlo. Y diéronmelo, y echélo en el fuego, y salió este becerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 25, 'Y viendo Moisés que el pueblo estaba despojado, porque Aarón lo había despojado para vergüenza entre sus enemigos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 26, 'Púsose Moisés á la puerta del real, y dijo: ¿Quién es de Jehová? júntese conmigo. Y juntáronse con él todos los hijos de Leví.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 27, 'Y él les dijo: Así ha dicho Jehová, el Dios de Israel: Poned cada uno su espada sobre su muslo: pasad y volved de puerta á puerta por el campo, y matad cada uno á su hermano, y á su amigo, y á su pariente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 28, 'Y los hijos de Leví lo hicieron conforme al dicho de Moisés: y cayeron del pueblo en aquel día como tres mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 29, 'Entonces Moisés dijo: Hoy os habéis consagrado á Jehová, porque cada uno se ha consagrado en su hijo, y en su hermano, para que dé él hoy bendición sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 30, 'Y aconteció que el día siguiente dijo Moisés al pueblo: Vosotros habéis cometido un gran pecado: mas yo subiré ahora á Jehová; quizá le aplacaré acerca de vuestro pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 31, 'Entonces volvió Moisés á Jehová, y dijo: Ruégote, pues este pueblo ha cometido un gran pecado, porque se hicieron dioses de oro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 32, 'Que perdones ahora su pecado, y si no, ráeme ahora de tu libro que has escrito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 33, 'Y Jehová respondió á Moisés: Al que pecare contra mí, á éste raeré yo de mi libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 34, 'Ve pues ahora, lleva á este pueblo donde te he dicho: he aquí mi ángel irá delante de ti; que en el día de mi visitación yo visitaré en ellos su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 32, 35, 'Y Jehová hirió al pueblo, porque habían hecho el becerro que formó Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 1, 'Y JEHOVA dijo á Moisés: Ve, sube de aquí, tú y el pueblo que sacaste de la tierra de Egipto, á la tierra de la cual juré á Abraham, Isaac, y Jacob, diciendo: A tu simiente la daré:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 2, 'Y yo enviaré delante de ti el ángel, y echaré fuera al Cananeo y al Amorrheo, y al Hetheo, y al Pherezeo, y al Heveo y al Jebuseo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 3, '(A la tierra que fluye leche y miel); porque yo no subiré en medio de ti, porque eres pueblo de dura cerviz, no sea que te consuma en el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 4, 'Y oyendo el pueblo esta sensible palabra, vistieron luto, y ninguno se puso sus atavíos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 5, 'Pues Jehová dijo á Moisés: Di á los hijos de Israel: Vosotros sois pueblo de dura cerviz: en un momento subiré en medio de ti, y te consumiré: quítate pues ahora tus atavíos, que yo sabré lo que te tengo de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 6, 'Entonces los hijos de Israel se despojaron de sus atavíos desde el monte Horeb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 7, 'Y Moisés tomó el tabernáculo, y extendiólo fuera del campo, lejos del campo, y llamólo el Tabernáculo del Testimonio. Y fué, que cualquiera que requería á Jehová, salía al tabernáculo del testimonio, que estaba fuera del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 8, 'Y sucedía que, cuando salía Moisés al tabernáculo, todo el pueblo se levantaba, y estaba cada cual en pie á la puerta de su tienda, y miraban en pos de Moisés, hasta que él entraba en el tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 9, 'Y cuando Moisés entraba en el tabernáculo, la columna de nube descendía, y poníase á la puerta del tabernáculo, y Jehová hablaba con Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 10, 'Y viendo todo el pueblo la columna de nube, que estaba á la puerta del tabernáculo, levantábase todo el pueblo, cada uno á la puerta de su tienda y adoraba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 11, 'Y hablaba Jehová á Moisés cara á cara, como habla cualquiera á su compañero. Y volvíase al campo; mas el joven Josué, su criado, hijo de Nun, nunca se apartaba de en medio del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 12, 'Y dijo Moisés á Jehová: Mira, tú me dices á mí: Saca este pueblo: y tú no me has declarado á quién has de enviar conmigo: sin embargo, tú dices: Yo te he conocido por tu nombre, y has hallado también gracia en mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 13, 'Ahora, pues, si he hallado gracia en tus ojos, ruégote que me muestres ahora tu camino, para que te conozca, porque halle gracia en tus ojos: y mira que tu pueblo es aquesta gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 14, 'Y él dijo: Mi rostro irá contigo, y te haré descansar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 15, 'Y él respondió: Si tu rostro no ha de ir conmigo, no nos saques de aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 16, '¿Y en qué se conocerá aquí que he hallado gracia en tus ojos, yo y tu pueblo, sino en andar tú con nosotros, y que yo y tu pueblo seamos apartados de todos los pueblos que están sobre la faz de la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 17, 'Y Jehová dijo á Moisés: También haré esto que has dicho, por cuanto has hallado gracia en mis ojos, y te he conocido por tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 18, 'El entonces dijo: Ruégote que me muestres tu gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 19, 'Y respondióle: Yo haré pasar todo mi bien delante de tu rostro, y proclamaré el nombre de Jehová delante de ti; y tendré misericordia del que tendré misericordia, y seré clemente para con el que seré clemente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 20, 'Dijo más: No podrás ver mi rostro: porque no me verá hombre, y vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 21, 'Y dijo aún Jehová: He aquí lugar junto á mí, y tú estarás sobre la peña:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 22, 'Y será que, cuando pasare mi gloria, yo te pondré en una hendidura de la peña, y te cubriré con mi mano hasta que haya pasado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 33, 23, 'Después apartaré mi mano, y verás mis espaldas; mas no se verá mi rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 1, 'Y JEHOVA dijo á Moisés: Alísate dos tablas de piedra como las primeras, y escribiré sobre esas tablas las palabras que estaban en las tablas primeras que quebraste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 2, 'Apercíbete, pues, para mañana, y sube por la mañana al monte de Sinaí, y estáme allí sobre la cumbre del monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 3, 'Y no suba hombre contigo, ni parezca alguno en todo el monte; ni ovejas ni bueyes pazcan delante del monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 4, 'Y Moisés alisó dos tablas de piedra como las primeras; y levantóse por la mañana, y subió al monte de Sinaí, como le mandó Jehová, y llevó en su mano las dos tablas de piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 5, 'Y Jehová descendió en la nube, y estuvo allí con él, proclamando el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 6, 'Y pasando Jehová por delante de él, proclamó: Jehová, Jehová, fuerte, misericordioso, y piadoso; tardo para la ira, y grande en benignidad y verdad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 7, 'Que guarda la misericordia en millares, que perdona la iniquidad, la rebelión, y el pecado, y que de ningún modo justificará al malvado; que visita la iniquidad de los padres sobre los hijos y sobre los hijos de los hijos, sobre los terceros, y sobre los cuartos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 8, 'Entonces Moisés, apresurándose, bajó la cabeza hacia el suelo y encorvóse;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 9, 'Y dijo: Si ahora, Señor, he hallado gracia en tus ojos, vaya ahora el Señor en medio de nosotros; porque este es pueblo de dura cerviz; y perdona nuestra iniquidad y nuestro pecado, y poséenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 10, 'Y él dijo: He aquí, yo hago concierto delante de todo tu pueblo: haré maravillas que no han sido hechas en toda la tierra, ni en nación alguna; y verá todo el pueblo en medio del cual estás tú, la obra de Jehová; porque ha de ser cosa terrible la que yo haré contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 11, 'Guarda lo que yo te mando hoy; he aquí que yo echo de delante de tu presencia al Amorrheo, y al Cananeo, y al Hetheo, y al Pherezeo, y al Heveo, y al Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 12, 'Guárdate que no hagas alianza con los moradores de la tierra donde has de entrar, porque no sean por tropezadero en medio de ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 13, 'Mas derribaréis sus altares, y quebraréis sus estatuas, y talaréis sus bosques:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 14, 'Porque no te has de inclinar á dios ajeno; que Jehová, cuyo nombre es Celoso, Dios celoso es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 15, 'Por tanto no harás alianza con los moradores de aquella tierra; porque fornicarán en pos de sus dioses, y sacrificarán á sus dioses, y te llamarán, y comerás de sus sacrificios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 16, 'O tomando de sus hijas para tus hijos, y fornicando sus hijas en pos de sus dioses, harán también fornicar á tus hijos en pos de los dioses de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 17, 'No harás dioses de fundición para ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 18, 'La fiesta de los ázimos guardarás: siete días comerás por leudar, según te he mandado, en el tiempo del mes de Abib; porque en el mes de Abib saliste de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 19, 'Todo lo que abre matriz, mío es; y de tu ganado todo primerizo de vaca ó de oveja que fuere macho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 20, 'Empero redimirás con cordero el primerizo del asno; y si no lo redimieres, le has de cortar la cabeza. Redimirás todo primogénito de tus hijos, y no serán vistos vacíos delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 21, 'Seis días trabajarás, mas en el séptimo día cesarás: cesarás aun en la arada y en la siega.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 22, 'Y te harás la fiesta de las semanas á los principios de la siega del trigo: y la fiesta de la cosecha á la vuelta del año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 23, 'Tres veces en el año será visto todo varón tuyo delante del Señoreador Jehová, Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 24, 'Porque yo arrojaré las gentes de tu presencia, y ensancharé tu término: y ninguno codiciará tu tierra, cuando tú subieres para ser visto delante de Jehová tu Dios tres veces en el año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 25, 'No ofrecerás con leudo la sangre de mi sacrificio; ni quedará de la noche para la mañana el sacrificio de la fiesta de la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 26, 'La primicia de los primeros frutos de tu tierra meterás en la casa de Jehová tu Dios. No cocerás el cabrito en la leche de su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 27, 'Y Jehová dijo á Moisés: Escribe tú estas palabras; porque conforme á estas palabras he hecho la alianza contigo y con Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 28, 'Y él estuvo allí con Jehová cuarenta días y cuarenta noches: no comió pan, ni bebió agua; y escribió en tablas las palabras de la alianza, las diez palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 29, 'Y aconteció, que descendiendo Moisés del monte Sinaí con las dos tablas del testimonio en su mano, mientras descendía del monte, no sabía él que la tez de su rostro resplandecía, después que hubo con El hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 30, 'Y miró Aarón y todos los hijos de Israel á Moisés, y he aquí la tez de su rostro era resplandeciente; y tuvieron miedo de llegarse á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 31, 'Y llamólos Moisés; y Aarón y todos los príncipes de la congregación volvieron á él, y Moisés les habló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 32, 'Y después se llegaron todos los hijos de Israel, á los cuales mandó todas las cosas que Jehová le había dicho en el monte de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 33, 'Y cuando hubo acabado Moisés de hablar con ellos, puso un velo sobre su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 34, 'Y cuando venía Moisés delante de Jehová para hablar con él, quitábase el velo hasta que salía; y saliendo, hablaba con los hijos de Israel lo que le era mandado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 34, 35, 'Y veían los hijos de Israel el rostro de Moisés, que la tez de su rostro era resplandeciente; y volvía Moisés á poner el velo sobre su rostro, hasta que entraba á hablar con El.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 1, 'Y MOISÉS hizo juntar toda la congregación de los hijos de Israel, y díjoles: Estas son las cosas que Jehová ha mandado que hagáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 2, 'Seis días se hará obra, mas el día séptimo os será santo, sábado de reposo á Jehová: cualquiera que en él hiciere obra, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 3, 'No encenderéis fuego en todas vuestras moradas en el día del sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 4, 'Y habló Moisés á toda la congregación de los hijos de Israel, diciendo: Esto es lo que Jehová ha mandado, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 5, 'Tomad de entre vosotros ofrenda para Jehová: todo liberal de corazón la traerá á Jehová: oro, plata, metal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 6, 'Y cárdeno, y púrpura, y carmesí, y lino fino, y pelo de cabras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 7, 'Y cueros rojos de carneros, y cueros de tejones, y madera de Sittim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 8, 'Y aceite para la luminaria, y especias aromáticas para el aceite de la unción, y para el perfume aromático;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 9, 'Y piedras de onix, y demás pedrería, para el ephod, y para el racional.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 10, 'Y todo sabio de corazón de entre vosotros, vendrá y hará todas las cosas que Jehová ha mandado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 11, 'El tabernáculo, su tienda, y su cubierta, y sus anillos, y sus tablas, sus barras, sus columnas, y sus basas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 12, 'El arca, y sus varas, la cubierta, y el velo de la tienda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 13, 'La mesa, y sus varas, y todos sus vasos, y el pan de la proposición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 14, 'El candelero de la luminaria, y sus vasos, y sus candilejas, y el aceite para la luminaria;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 15, 'Y el altar del perfume, y sus varas, y el aceite de la unción, y el perfume aromático, y el pabellón de la puerta, para la entrada del tabernáculo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 16, 'El altar del holocausto, y su enrejado de metal, y sus varas, y todos sus vasos, y la fuente con su basa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 17, 'Las cortinas del atrio, sus columnas, y sus basas, y el pabellón de la puerta del atrio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 18, 'Las estacas del tabernáculo, y las estacas del atrio, y sus cuerdas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 19, 'Las vestiduras del servicio para ministrar en el santuario, las sagradas vestiduras de Aarón el sacerdote, y las vestiduras de sus hijos para servir en el sacerdocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 20, 'Y salió toda la congregación de los hijos de Israel de delante de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 21, 'Y vino todo varón á quien su corazón estimuló, y todo aquel á quien su espíritu le dió voluntad, y trajeron ofrenda á Jehová para la obra del tabernáculo del testimonio, y para toda su fábrica, y para las sagradas vestiduras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 22, 'Y vinieron así hombres como mujeres, todo voluntario de corazón, y trajeron cadenas y zarcillos, sortijas y brazaletes, y toda joya de oro; y cualquiera ofrecía ofrenda de oro á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 23, 'Todo hombre que se hallaba con jacinto, ó púrpura, ó carmesí, ó lino fino, ó pelo de cabras, ó cueros rojos de carneros, ó cueros de tejones, lo traía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 24, 'Cualquiera que ofrecía ofrenda de plata ó de metal, traía á Jehová la ofrenda: y todo el que se hallaba con madera de Sittim, traíala para toda la obra del servicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 25, 'Además todas las mujeres sabias de corazón hilaban de sus manos, y traían lo que habían hilado: cárdeno, ó púrpura, ó carmesí, ó lino fino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 26, 'Y todas las mujeres cuyo corazón las levantó en sabiduría, hilaron pelos de cabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 27, 'Y los príncipes trajeron piedras de onix, y las piedras de los engastes para el ephod y el racional;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 28, 'Y la especia aromática y aceite, para la luminaria, y para el aceite de la unción, y para el perfume aromático.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 29, 'De los hijos de Israel, así hombres como mujeres, todos los que tuvieron corazón voluntario para traer para toda la obra, que Jehová había mandado por medio de Moisés que hiciesen, trajeron ofrenda voluntaria á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 30, 'Y dijo Moisés á los hijos de Israel: Mirad, Jehová ha nombrado á Bezaleel hijo de Uri, hijo de Hur, de la tribu de Judá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 31, 'Y lo ha henchido de espíritu de Dios, en sabiduría, en inteligencia, y en ciencia, y en todo artificio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 32, 'Para proyectar inventos, para trabajar en oro, y en plata, y en metal,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 33, 'Y en obra de pedrería para engastar, y en obra de madera, para trabajar en toda invención ingeniosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 34, 'Y ha puesto en su corazón el que pueda enseñar, así él como Aholiab hijo de Ahisamac, de la tribu de Dan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 35, 35, 'Y los ha henchido de sabiduría de corazón, para que hagan toda obra de artificio, y de invención, y de recamado en jacinto, y en púrpura, y en carmesí, y en lino fino, y en telar; para que hagan toda labor, é inventen todo diseño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 1, 'HIZO, pues, Bezaleel y Aholiab, y todo hombre sabio de corazón, á quien Jehová dió sabiduría é inteligencia para que supiesen hacer toda la obra del servicio del santuario, todas las cosas que había mandado Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 2, 'Y Moisés llamó á Bezaleel y á Aholiab, y á todo varón sabio de corazón, en cuyo corazón había dado Jehová sabiduría, y á todo hombre á quien su corazón le movió á llegarse á la obra, para trabajar en ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 3, 'Y tomaron de delante de Moisés toda la ofrenda que los hijos de Israel habían traído para la obra del servicio del santuario, á fin de hacerla. Y ellos le traían aún ofrenda voluntaria cada mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 4, 'Vinieron, por tanto, todos los maestros que hacían toda la obra del santuario, cada uno de la obra que hacía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 5, 'Y hablaron á Moisés, diciendo: El pueblo trae mucho más de lo que es menester para la atención de hacer la obra que Jehová ha mandado que se haga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 6, 'Entonces Moisés mandó pregonar por el campo, diciendo: Ningún hombre ni mujer haga más obra para ofrecer para el santuario. Y así fue el pueblo impedido de ofrecer;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 7, 'Pues tenia material abundante para hacer toda la obra, y sobraba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 8, 'Y todos los sabios de corazón entre los que hacían la obra, hicieron el tabernáculo de diez cortinas, de lino torcido, y de jacinto, y de púrpura y carmesí; las cuales hicieron de obra prima, con querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 9, 'La longitud de la una cortina era de veintiocho codos, y la anchura de cuatro codos: todas las cortinas tenían una misma medida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 10, 'Y juntó las cinco cortinas la una con la otra: asimismo unió las otras cinco cortinas la una con la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 11, 'E hizo las lazadas de color de jacinto en la orilla de la una cortina, en el borde, á la juntura; y así hizo en la orilla al borde de la segunda cortina, en la juntura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 12, 'Cincuenta lazadas hizo en la una cortina, y otras cincuenta en la segunda cortina, en el borde, en la juntura; las unas lazadas enfrente de las otras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 13, 'Hizo también cincuenta corchetes de oro, con los cuales juntó las cortinas, la una con la otra; é hízose un tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 14, 'Hizo asimismo cortinas de pelo de cabras para la tienda sobre el tabernáculo, é hízolas en número de once.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 15, 'La longitud de la una cortina era de treinta codos, y la anchura de cuatro codos: las once cortinas tenían una misma medida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 16, 'Y juntó las cinco cortinas de por sí, y las seis cortinas aparte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 17, 'Hizo además cincuenta lazadas en la orilla de la postrera cortina en la juntura, y otras cincuenta lazadas en la orilla de la otra cortina en la juntura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 18, 'Hizo también cincuenta corchetes de metal para juntar la tienda, de modo que fuese una.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 19, 'E hizo una cubierta para la tienda de cueros rojos de carneros, y una cubierta encima de cueros de tejones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 20, 'Además hizo las tablas para el tabernáculo de madera de Sittim, para estar derechas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 21, 'La longitud de cada tabla de diez codos, y de codo y medio la anchura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 22, 'Cada tabla tenía dos quicios enclavijados el uno delante del otro: así hizo todas las tablas del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 23, 'Hizo, pues, las tablas para el tabernáculo: veinte tablas al lado del austro, al mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 24, 'Hizo también las cuarenta basas de plata debajo de las veinte tablas: dos basas debajo de la una tabla para sus dos quicios, y dos basas debajo de la otra tabla para sus dos quicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 25, 'Y para el otro lado del tabernáculo, á la parte del aquilón, hizo veinte tablas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 26, 'Con sus cuarenta basas de plata: dos basas debajo de la una tabla, y dos basas debajo de la otra tabla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 27, 'Y para el lado occidental del tabernáculo hizo seis tablas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 28, 'Para las esquinas del tabernáculo en los dos lados hizo dos tablas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 29, 'Las cuales se juntaban por abajo, y asimismo por arriba á un gozne: y así hizo á la una y á la otra en las dos esquinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 30, 'Eran, pues, ocho tablas, y sus basas de plata dieciséis; dos basas debajo de cada tabla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 31, 'Hizo también las barras de madera de Sittim; cinco para las tablas del un lado del tabernáculo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 32, 'Y cinco barras para las tablas del otro lado del tabernáculo, y cinco barras para las tablas del lado del tabernáculo á la parte occidental.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 33, 'E hizo que la barra del medio pasase por medio de las tablas del un cabo al otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 34, 'Y cubrió las tablas de oro, é hizo de oro los anillos de ellas por donde pasasen las barras: cubrió también de oro las barras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 35, 'Hizo asimismo el velo de cárdeno, y púrpura, y carmesí, y lino torcido, el cual hizo con querubines de delicada obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 36, 'Y para él hizo cuatro columnas de madera de Sittim; y cubriólas de oro, los capiteles de las cuales eran de oro; é hizo para ellas cuatro basas de plata de fundición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 37, 'Hizo también el velo para la puerta del tabernáculo, de jacinto, y púrpura, y carmesí, y lino torcido, obra de recamador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 36, 38, 'Y sus cinco columnas con sus capiteles: y cubrió las cabezas de ellas y sus molduras de oro: pero sus cinco basas las hizo de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 1, 'HIZO también Bezaleel el arca de madera de Sittim: su longitud era de dos codos y medio, y de codo y medio su anchura, y su altura de otro codo y medio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 2, 'Y cubrióla de oro puro por de dentro y por de fuera, é hízole una cornisa de oro en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 3, 'Hízole además de fundición cuatro anillos de oro á sus cuatro esquinas; en el un lado dos anillos y en el otro lado dos anillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 4, 'Hizo también las varas de madera de Sittim, y cubriólas de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 5, 'Y metió las varas por los anillos á los lados del arca, para llevar el arca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 6, 'Hizo asimismo la cubierta de oro puro: su longitud de dos codos y medio, y su anchura de codo y medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 7, 'Hizo también los dos querubines de oro, hízolos labrados á martillo, á los dos cabos de la cubierta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 8, 'El un querubín de esta parte al un cabo, y el otro querubín de la otra parte al otro cabo de la cubierta: hizo los querubines á sus dos cabos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 9, 'Y los querubines extendían sus alas por encima, cubriendo con sus alas la cubierta: y sus rostros el uno enfrente del otro, hacia la cubierta los rostros de los querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 10, 'Hizo también la mesa de madera de Sittim; su longitud de dos codos, y su anchura de un codo, y de codo y medio su altura;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 11, 'Y cubrióla de oro puro, é hízole una cornisa de oro en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 12, 'Hízole también una moldura alrededor, del ancho de una mano, á la cual moldura hizo la cornisa de oro en circunferencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 13, 'Hízole asimismo de fundición cuatro anillos de oro, y púsolos á las cuatro esquinas que correspondían á los cuatro pies de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 14, 'Delante de la moldura estaban los anillos, por los cuales se metiesen las varas para llevar la mesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 15, 'E hizo las varas de madera de Sittim para llevar la mesa, y cubriólas de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 16, 'También hizo los vasos que habían de estar sobre la mesa, sus platos, y sus cucharas, y sus cubiertos y sus tazones con que se había de libar, de oro fino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 17, 'Hizo asimismo el candelero de oro puro, é hízolo labrado á martillo: su pie y su caña, sus copas, sus manzanas y sus flores eran de lo mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 18, 'De sus lados salían seis brazos; tres brazos del un lado del candelero, y otros tres brazos del otro lado del candelero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 19, 'En el un brazo, tres copas figura de almendras, una manzana y una flor; y en el otro brazo tres copas figura de almendras, una manzana y una flor: y así en los seis brazos que salían del candelero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 20, 'Y en el candelero había cuatro copas figura de almendras, sus manzanas y sus flores:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 21, 'Y una manzana debajo de los dos brazos de lo mismo, y otra manzana debajo de los otros dos brazos de lo mismo, y otra manzana debajo de los otros dos brazos de lo mismo, conforme á los seis brazos que salían de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 22, 'Sus manzanas y sus brazos eran de lo mismo; todo era una pieza labrada á martillo, de oro puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 23, 'Hizo asimismo sus siete candilejas, y sus despabiladeras, y sus platillos, de oro puro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 24, 'De un talento de oro puro lo hizo, con todos sus vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 25, 'Hizo también el altar del perfume de madera de Sittim: un codo su longitud, y otro codo su anchura, era cuadrado; y su altura de dos codos; y sus cuernos de la misma pieza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 26, 'Y cubriólo de oro puro, su mesa y sus paredes alrededor, y sus cuernos: é hízole una corona de oro alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 27, 'Hízole también dos anillos de oro debajo de la corona en las dos esquinas á los dos lados, para pasar por ellos las varas con que había de ser conducido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 28, 'E hizo las varas de madera de Sittim, y cubriólas de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 37, 29, 'Hizo asimismo el aceite santo de la unción, y el fino perfume aromático, de obra de perfumador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 1, 'IGUALMENTE hizo el altar del holocausto de madera de Sittim: su longitud de cinco codos, y su anchura de otros cinco codos, cuadrado, y de tres codos de altura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 2, 'E hízole sus cuernos á sus cuatro esquinas, los cuales eran de la misma pieza, y cubriólo de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 3, 'Hizo asimismo todos los vasos del altar: calderas, y tenazas, y tazones, y garfios, y palas: todos sus vasos hizo de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 4, 'E hizo para el altar el enrejado de metal, de hechura de red, que puso en su cerco por debajo hasta el medio del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 5, 'Hizo también cuatro anillos de fundición á los cuatro cabos del enrejado de metal, para meter las varas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 6, 'E hizo las varas de madera de Sittim, y cubriólas de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 7, 'Y metió las varas por los anillos á los lados del altar, para llevarlo con ellas: hueco lo hizo, de tablas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 8, 'También hizo la fuente de metal, con su basa de metal, de los espejos de las que velaban á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 9, 'Hizo asimismo el atrio; á la parte austral del mediodía las cortinas del atrio eran de cien codos, de lino torcido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 10, 'Sus columnas veinte, con sus veinte basas de metal: los capiteles de las columnas y sus molduras, de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 11, 'Y á la parte del aquilón cortinas de cien codos: sus columnas veinte, con sus veinte basas de metal; los capiteles de las columnas y sus molduras, de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 12, 'A la parte del occidente cortinas de cincuenta codos: sus columnas diez, y sus diez basas; los capiteles de las columnas y sus molduras, de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 13, 'Y á la parte oriental, al levante, cortinas de cincuenta codos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 14, 'Al un lado cortinas de quince codos, sus tres columnas, y sus tres basas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 15, 'Al otro lado, de la una parte y de la otra de la puerta del atrio, cortinas de á quince codos, sus tres columnas, y sus tres basas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 16, 'Todas las cortinas del atrio alrededor eran de lino torcido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 17, 'Y las basas de las columnas eran de metal; los capiteles de las columnas y sus molduras, de plata; asimismo las cubiertas de las cabezas de ellas, de plata: y todas las columnas del atrio tenían molduras de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 18, 'Y el pabellón de la puerta del atrio fue de obra de recamado, de jacinto, y púrpura, y carmesí, y lino torcido: la longitud de veinte codos, y la altura en el ancho de cinco codos, conforme á las cortinas del atrio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 19, 'Y sus columnas fueron cuatro con sus cuatro basas de metal: y sus capiteles de plata; y las cubiertas de los capiteles de ellas y sus molduras, de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 20, 'Y todas las estacas del tabernáculo y del atrio alrededor fueron de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 21, 'Estas son las cuentas del tabernáculo, del tabernáculo del testimonio, lo que fué contado de orden de Moisés por mano de Ithamar, hijo de Aarón sacerdote, para el ministerio de los Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 22, 'Y Bezaleel, hijo de Uri, hijo de Hur, de la tribu de Judá, hizo todas las cosas que Jehová mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 23, 'Y con él estaba Aholiab, hijo de Ahisamac, de la tribu de Dan, artífice, y diseñador, y recamador en jacinto, y púrpura, y carmesí, y lino fino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 24, 'Todo el oro empleado en la obra, en toda la obra del santuario, el cual fué oro de ofrenda, fué veintinueve talentos, y setecientos y treinta siclos, según el siclo del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 25, 'Y la plata de los contados de la congregación fué cien talentos, y mil setecientos setenta y cinco siclos, según el siclo del santuario:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 26, 'Medio por cabeza, medio siclo, según el siclo del santuario, á todos los que pasaron por cuenta de edad de veinte a��os y arriba, que fueron seiscientos tres mil quinientos cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 27, 'Hubo además cien talentos de plata para hacer de fundición las basas del santuario y las basas del velo: en cien basas cien talentos, á talento por basa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 28, 'Y de los mil setecientos setenta y cinco siclos hizo los capiteles de las columnas, y cubrió los capiteles de ellas, y las ciñó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 29, 'Y el metal de la ofrenda fue setenta talentos, y dos mil cuatrocientos siclos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 30, 'Del cual hizo las basas de la puerta del tabernáculo del testimonio, y el altar de metal, y su enrejado de metal, y todos los vasos del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 38, 31, 'Y las basas del atrio alrededor, y las basas de la puerta del atrio, y todas las estacas del tabernáculo, y todas las estacas del atrio alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 1, 'Y DEL jacinto, y púrpura, y carmesí, hicieron las vestimentas del ministerio para ministrar en el santuario, y asimismo hicieron las vestiduras sagradas para Aarón; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 2, 'Hizo también el ephod de oro, de cárdeno y púrpura y carmesí, y lino torcido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 3, 'Y extendieron las planchas de oro, y cortaron hilos para tejerlos entre el jacinto, y entre la púrpura, y entre el carmesí, y entre el lino, con delicada obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 4, 'Hiciéronle las hombreras que se juntasen; y uníanse en sus dos lados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 5, 'Y el cinto del ephod que estaba sobre él, era de lo mismo, conforme á su obra; de oro, jacinto, y púrpura, y carmesí, y lino torcido; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 6, 'Y labraron las piedras oniquinas cercadas de engastes de oro, grabadas de grabadura de sello con los nombres de los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 7, 'Y púsolas sobre las hombreras del ephod, por piedras de memoria á los hijos de Israel; como Jehová lo había á Moisés mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 8, 'Hizo también el racional de primorosa obra, como la obra del ephod, de oro, jacinto, y púrpura, y carmesí, y lino torcido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 9, 'Era cuadrado: doblado hicieron el racional: su longitud era de un palmo, y de un palmo su anchura, doblado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 10, 'Y engastaron en él cuatro órdenes de piedras. El primer orden era un sardio, un topacio, y un carbunclo: este el primer orden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 11, 'El segundo orden, una esmeralda, un zafiro, y un diamante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 12, 'El tercer orden, un ligurio, un ágata, y un amatista.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 13, 'Y el cuarto orden, un berilo, un onix, y un jaspe: cercadas y encajadas en sus engastes de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 14, 'Las cuales piedras eran conforme á los nombres de los hijos de Israel, doce según los nombres de ellos; como grabaduras de sello, cada una con su nombre según las doce tribus.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 15, 'Hicieron también sobre el racional las cadenas pequeñas de hechura de trenza, de oro puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 16, 'Hicieron asimismo los dos engastes y los dos anillos, de oro; los cuales dos anillos de oro pusieron en los dos cabos del racional.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 17, 'Y pusieron las dos trenzas de oro en aquellos dos anillos á los cabos del racional.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 18, 'Y fijaron los dos cabos de las dos trenzas en los dos engastes, que pusieron sobre las hombreras del ephod, en la parte delantera de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 19, 'E hicieron dos anillos de oro, que pusieron en los dos cabos del racional, en su orilla, á la parte baja del ephod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 20, 'Hicieron además dos anillos de oro, los cuales pusieron en las dos hombreras del ephod, abajo en la parte delantera, delante de su juntura, sobre el cinto del ephod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 21, 'Y ataron el racional de sus anillos á los anillos del ephod con un cordón de jacinto, para que estuviese sobre el cinto del mismo ephod, y no se apartase el racional del ephod; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 22, 'Hizo también el manto del ephod de obra de tejedor, todo de jacinto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 23, 'Con su abertura en medio de él, como el cuello de un coselete, con un borde en derredor de la abertura, porque no se rompiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 24, 'E hicieron en las orillas del manto las granadas de jacinto, y púrpura, y carmesí, y lino torcido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 25, 'Hicieron también las campanillas de oro puro, las cuales campanillas pusieron entre las granadas por las orillas del manto alrededor entre las granadas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 26, 'Una campanilla y una granada, una campanilla y una granada alrededor, en las orillas del manto, para ministrar; como Jehová lo mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 27, 'Igualmente hicieron las túnicas de lino fino de obra de tejedor, para Aarón y para sus hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 28, 'Asimismo la mitra de lino fino, y los adornos de los chapeos (tiaras) de lino fino, y los pañetes de lino, de lino torcido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 29, 'También el cinto de lino torcido, y de jacinto, y púrpura, y carmesí, de obra de recamador; como Jehová lo mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 30, 'Hicieron asimismo la plancha de la diadema santa de oro puro, y escribieron en ella de grabadura de sello, el rótulo, SANTIDAD A JEHOVA.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 31, 'Y pusieron en ella un cordón de jacinto, para colocarla en alto sobre la mitra; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 32, 'Y fue acabada toda la obra del tabernáculo, del tabernáculo del testimonio: é hicieron los hijos de Israel como Jehová lo había mandado á Moisés: así lo hicieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 33, 'Y trajeron el tabernáculo á Moisés, el tabernáculo y todos sus vasos; sus corchetes, sus tablas, sus barras, y sus columnas, y sus basas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 34, 'Y la cubierta de pieles rojas de carneros, y la cubierta de pieles de tejones, y el velo del pabellón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 35, 'El arca del testimonio, y sus varas, y la cubierta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 36, 'La mesa, todos sus vasos, y el pan de la proposición;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 37, 'El candelero limpio, sus candilejas, las lámparas que debían mantenerse en orden, y todos sus vasos, y el aceite para la luminaria;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 38, 'Y el altar de oro, y el aceite de la unción, y el perfume aromático, y el pabellón para la puerta del tabernáculo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 39, 'El altar de metal, con su enrejado de metal, sus varas, y todos sus vasos; y la fuente, y su basa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 40, 'Las cortinas del atrio, y sus columnas, y sus basas, y el pabellón para la puerta del atrio, y sus cuerdas, y sus estacas, y todos los vasos del servicio del tabernáculo, del tabernáculo del testimonio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 41, 'Las vestimentas del servicio para ministrar en el santuario, las sagradas vestiduras para Aarón el sacerdote, y las vestiduras de sus hijos, para ministrar en el sacerdocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 42, 'En conformidad á todas las cosas que Jehová había mandado á Moisés, así hicieron los hijos de Israel toda la obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 39, 43, 'Y vió Moisés toda la obra, y he aquí que la habían hecho como Jehová había mandado; y bendíjolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 2, 'En el primer día del mes primero harás levantar el tabernáculo, el tabernáculo del testimonio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 3, 'Y pondrás en él el arca del testimonio, y la cubrirás con el velo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 4, 'Y meterás la mesa, y la pondrás en orden: meterás también el candelero y encenderás sus lámparas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 5, 'Y pondrás el altar de oro para el perfume delante del arca del testimonio, y pondrás el pabellón delante de la puerta del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 6, 'Después pondrás el altar del holocausto delante de la puerta del tabernáculo, del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 7, 'Luego pondrás la fuente entre el tabernáculo del testimonio y el altar; y pondrás agua en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 8, 'Finalmente pondrás el atrio en derredor, y el pabellón de la puerta del atrio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 9, 'Y tomarás el aceite de la unción y ungirás el tabernáculo, y todo lo que está en él; y le santificarás con todos sus vasos, y será santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 10, 'Ungirás también el altar del holocausto y todos sus vasos: y santificarás el altar, y será un altar santísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 11, 'Asimismo ungirás la fuente y su basa, y la santificarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 12, 'Y harás llegar á Aarón y á sus hijos á la puerta del tabernáculo del testimonio, y los lavarás con agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 13, 'Y harás vestir á Aarón las vestiduras sagradas, y lo ungirás, y lo consagrarás, para que sea mi sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 14, 'Después harás llegar sus hijos, y les vestirás las túnicas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 15, 'Y los ungirás como ungiste á su padre, y serán mis sacerdotes: y será que su unción les servirá por sacerdocio perpetuo por sus generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 16, 'Y Moisés hizo conforme á todo lo que Jehová le mandó; así lo hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 17, 'Y así en el día primero del primer mes, en el segundo año, el tabernáculo fué erigido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 18, 'Y Moisés hizo levantar el tabernáculo, y asentó sus basas, y colocó sus tablas, y puso sus barras, é hizo alzar sus columnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 19, 'Y extendió la tienda sobre el tabernáculo, y puso la sobrecubierta encima del mismo; como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 20, 'Y tomó y puso el testimonio dentro del arca, y colocó las varas en el arca, y encima la cubierta sobre el arca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 21, 'Y metió el arca en el tabernáculo, y puso el velo de la tienda, y cubrió el arca del testimonio; como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 22, 'Y puso la mesa en el tabernáculo del testimonio, al lado septentrional del pabellón, fuera del velo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 23, 'Y sobre ella puso por orden los panes delante de Jehová, como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 24, 'Y puso el candelero en el tabernáculo del testimonio, enfrente de la mesa, al lado meridional del pabellón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 25, 'Y encendió las lámparas delante de Jehová; como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 26, 'Puso también el altar de oro en el tabernáculo del testimonio, delante del velo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 27, 'Y encendió sobre él el perfume aromático; como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 28, 'Puso asimismo la cortina de la puerta del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 29, 'Y colocó el altar del holocausto á la puerta del tabernáculo, del tabernáculo del testimonio; y ofreció sobre él holocausto y presente; como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 30, 'Y puso la fuente entre el tabernáculo del testimonio y el altar; y puso en ella agua para lavar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 31, 'Y Moisés y Aarón y sus hijos lavaban en ella sus manos y sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 32, 'Cuando entraban en el tabernáculo del testimonio, y cuando se llegaban al altar, se lavaban; como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 33, 'Finalmente erigió el atrio en derredor del tabernáculo y del altar, y puso la cortina de la puerta del atrio. Y así acabó Moisés la obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 34, 'Entonces una nube cubrió el tabernáculo del testimonio, y la gloria de Jehová hinchió el tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 35, 'Y no podía Moisés entrar en el tabernáculo del testimonio, porque la nube estaba sobre él, y la gloria de Jehová lo tenía lleno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 36, 'Y cuando la nube se alzaba del tabernáculo, los hijos de Israel se movían en todas sus jornadas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 37, 'Pero si la nube no se alzaba, no se partían hasta el día en que ella se alzaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EXO', 'Éxodo', 40, 38, 'Porque la nube de Jehová estaba de día sobre el tabernáculo, y el fuego estaba de noche en él, á vista de toda la casa de Israel, en todas sus jornadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 1, 'Y LLAMO Jehová á Moisés, y habló con él desde el tabernáculo del testimonio, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 2, 'Habla á los hijos de Israel, y diles: Cuando alguno de entre vosotros ofreciere ofrenda á Jehová, de ganado vacuno ú ovejuno haréis vuestra ofrenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 3, 'Si su ofrenda fuere holocausto de vacas, macho sin tacha lo ofrecerá: de su voluntad lo ofrecerá á la puerta del tabernáculo del testimonio delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 4, 'Y pondrá su mano sobre la cabeza del holocausto; y él lo aceptará para expiarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 5, 'Entonces degollará el becerro en la presencia de Jehová; y los sacerdotes, hijos de Aarón, ofrecerán la sangre, y la rociarán alrededor sobre el altar, el cual está á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 6, 'Y desollará el holocausto, y lo dividirá en sus piezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 7, 'Y los hijos de Aarón sacerdote pondrán fuego sobre el altar, y compondrán la leña sobre el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 8, 'Luego los sacerdotes, hijos de Aarón, acomodarán las piezas, la cabeza y el redaño, sobre la leña que está sobre el fuego, que habrá encima del altar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 9, 'Y lavará con agua sus intestinos y sus piernas: y el sacerdote hará arder todo sobre el altar: holocausto es, ofrenda encendida de olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 10, 'Y si su ofrenda para holocausto fuere de ovejas, de los corderos, ó de las cabras, macho sin defecto lo ofrecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 11, 'Y ha de degollarlo al lado septentrional del altar delante de Jehová: y los sacerdotes, hijos de Aarón, rociarán su sangre sobre el altar alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 12, 'Y lo dividirá en sus piezas, con su cabeza y su redaño; y el sacerdote las acomodará sobre la leña que está sobre el fuego, que habrá encima del altar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 13, 'Y lavará sus entrañas y sus piernas con agua; y el sacerdote lo ofrecerá todo, y harálo arder sobre el altar; holocausto es, ofrenda encendida de olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 14, 'Y si el holocausto se hubiere de ofrecer á Jehová de aves, presentará su ofrenda de tórtolas, ó de palominos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 15, 'Y el sacerdote la ofrecerá sobre el altar, y ha de quitarle la cabeza, y hará que arda en el altar; y su sangre será exprimida sobre la pared del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 16, 'Y le ha de quitar el buche y las plumas, lo cual echará junto al altar, hacia el oriente, en el lugar de las cenizas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 1, 17, 'Y la henderá por sus alas, mas no la dividirá en dos: y el sacerdote la hará arder sobre el altar, sobre la leña que estará en el fuego; holocausto es, ofrenda encendida de olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 1, 'Y CUANDO alguna persona ofreciere oblación de presente á Jehová, su ofrenda será flor de harina, sobre la cual echará aceite, y pondrá sobre ella incienso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 2, 'Y la traerá á los sacerdotes, hijos de Aarón; y de ello tomará el sacerdote su puño lleno de su flor de harina y de su aceite, con todo su incienso, y lo hará arder sobre el altar: ofrenda encendida para recuerdo, de olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 3, 'Y la sobra del presente será de Aarón y de sus hijos: es cosa santísima de las ofrendas que se queman á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 4, 'Y cuando ofrecieres ofrenda de presente cocida en horno, será de tortas de flor de harina sin levadura, amasadas con aceite, y hojaldres sin levadura untadas con aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 5, 'Mas si tu presente fuere ofrenda de sartén, será de flor de harina sin levadura, amasada con aceite,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 6, 'La cual partirás en piezas, y echarás sobre ella aceite: es presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 7, 'Y si tu presente fuere ofrenda cocida en cazuela, haráse de flor de harina con aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 8, 'Y traerás á Jehová la ofrenda que se hará de estas cosas, y la presentarás al sacerdote, el cual la llegará al altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 9, 'Y tomará el sacerdote de aquel presente, en memoria del mismo, y harálo arder sobre el altar; ofrenda encendida, de suave olor á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 10, 'Y lo restante del presente será de Aarón y de sus hijos; es cosa santísima de las ofrendas que se queman á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 11, 'Ningun presente que ofreciereis á Jehová, será con levadura: porque de ninguna cosa leuda, ni de ninguna miel, se ha de quemar ofrenda á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 12, 'En la ofrenda de las primicias las ofreceréis á Jehová: mas no subirán sobre el altar en olor de suavidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 13, 'Y sazonarás toda ofrenda de tu presente con sal; y no harás que falte jamás de tu presente la sal de la alianza de tu Dios: en toda ofrenda tuya ofrecerás sal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 14, 'Y si ofrecieres á Jehová presente de primicias, tostarás al fuego las espigas verdes, y el grano desmenuzado ofrecerás por ofrenda de tus primicias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 15, 'Y pondrás sobre ella aceite, y pondrás sobre ella incienso: es presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 2, 16, 'Y el sacerdote hará arder, en memoria del don, parte de su grano desmenuzado, y de su aceite con todo su incienso; es ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 1, 'Y SI su ofrenda fuere sacrificio de paces, si hubiere de ofrecerlo de ganado vacuno, sea macho ó hembra, sin defecto lo ofrecerá delante de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 2, 'Y pondrá su mano sobre la cabeza de su ofrenda, y la degollará á la puerta del tabernáculo del testimonio; y los sacerdotes, hijos de Aarón, rociarán su sangre sobre el altar en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 3, 'Luego ofrecerá del sacrificio de las paces, por ofrenda encendida á Jehová, el sebo que cubre los intestinos, y todo el sebo que está sobre las entrañas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 4, 'Y los dos riñones, y el sebo que está sobre ellos, y sobre los ijares, y con los riñones quitará el redaño que está sobre el hígado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 5, 'Y los hijos de Aarón harán arder esto en el altar, sobre el holocausto que estará sobre la leña que habrá encima del fuego; es ofrenda de olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 6, 'Mas si de ovejas fuere su ofrenda para sacrificio de paces á Jehová, sea macho ó hembra, ofrecerála sin tacha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 7, 'Si ofreciere cordero por su ofrenda, ha de ofrecerlo delante de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 8, 'Y pondrá su mano sobre la cabeza de su ofrenda, y después la degollará delante del tabernáculo del testimonio; y los hijos de Aarón rociarán su sangre sobre el altar en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 9, 'Y del sacrificio de las paces ofrecerá por ofrenda encendida á Jehová, su sebo, y la cola entera, la cual quitará á raíz del espinazo, y el sebo que cubre los intestinos, y todo el sebo que está sobre las entrañas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 10, 'Asimismo los dos riñones, y el sebo que está sobre ellos, y el que está sobre los ijares, y con los riñones quitará el redaño de sobre el hígado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 11, 'Y el sacerdote hará arder esto sobre el altar; vianda de ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 12, 'Y si fuere cabra su ofrenda ofrecerála delante de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 13, 'Y pondrá su mano sobre la cabeza de ella, y la degollará delante del tabernáculo del testimonio; y los hijos de Aarón rociarán su sangre sobre el altar en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 14, 'Después ofrecerá de ella su ofrenda encendida á Jehová; el sebo que cubre los intestinos, y todo el sebo que está sobre las entrañas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 15, 'Y los dos riñones, y el sebo que está sobre ellos, y el que está sobre los ijares, y con los riñones quitará el redaño de sobre el hígado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 16, 'Y el sacerdote hará arder esto sobre el altar; es vianda de ofrenda que se quema en olor de suavidad á Jehová: el sebo todo es de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 3, 17, 'Estatuto perpetuo por vuestras edades; en todas vuestras moradas, ningún sebo ni ninguna sangre comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 2, 'Habla á los hijos de Israel, diciendo: Cuando alguna persona pecare por yerro en alguno de los mandamientos de Jehová sobre cosas que no se han de hacer, y obrare contra alguno de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 3, 'Si sacerdote ungido pecare según el pecado del pueblo, ofrecerá á Jehová, por su pecado que habrá cometido, un becerro sin tacha para expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 4, 'Y traerá el becerro á la puerta del tabernáculo del testimonio delante de Jehová, y pondrá su mano sobre la cabeza del becerro, y lo degollará delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 5, 'Y el sacerdote ungido tomará de la sangre del becerro, y la traerá al tabernáculo del testimonio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 6, 'Y mojará el sacerdote su dedo en la sangre, y rociará de aquella sangre siete veces delante de Jehová, hacia el velo del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 7, 'Y pondrá el sacerdote de la sangre sobre los cuernos del altar del perfume aromático, que está en el tabernáculo del testimonio delante de Jehová: y echará toda la sangre del becerro al pie del altar del holocausto, que está á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 8, 'Y tomará del becerro para la expiación todo su sebo, el sebo que cubre los intestinos, y todo el sebo que está sobre las entrañas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 9, 'Y los dos riñones, y el sebo que está sobre ellos, y el que está sobre los ijares, y con los riñones quitará el redaño de sobre el hígado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 10, 'De la manera que se quita del buey del sacrificio de las paces: y el sacerdote lo hará arder sobre el altar del holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 11, 'Y el cuero del becerro, y toda su carne, con su cabeza, y sus piernas, y sus intestinos, y su estiércol,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 12, 'En fin, todo el becerro sacará fuera del campo, á un lugar limpio, donde se echan las cenizas, y lo quemará al fuego sobre la leña: en donde se echan las cenizas será quemado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 13, 'Y si toda la congregación de Israel hubiere errado, y el negocio estuviere oculto á los ojos del pueblo, y hubieren hecho algo contra alguno de los mandamientos de Jehová en cosas que no se han de hacer, y fueren culpables;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 14, 'Luego que fuere entendido el pecado sobre que delinquieron, la congregación ofrecerá un becerro por expiación, y lo traerán delante del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 15, 'Y los ancianos de la congregación pondrán sus manos sobre la cabeza del becerro delante de Jehová; y en presencia de Jehová degollarán aquel becerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 16, 'Y el sacerdote ungido meterá de la sangre del becerro en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 17, 'Y mojará el sacerdote su dedo en la misma sangre, y rociará siete veces delante de Jehová hacia el velo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 18, 'Y de aquella sangre pondrá sobre los cuernos del altar que está delante de Jehová en el tabernáculo del testimonio, y derramará toda la sangre al pie del altar del holocausto, que está á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 19, 'Y le quitará todo el sebo, y harálo arder sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 20, 'Y hará de aquel becerro como hizo con el becerro de la expiación; lo mismo hará de él: así hará el sacerdote expiación por ellos, y obtendrán perdón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 21, 'Y sacará el becerro fuera del campamento, y lo quemará como quemó el primer becerro; expiación de la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 22, 'Y cuando pecare el príncipe, é hiciere por yerro algo contra alguno de todos los mandamientos de Jehová su Dios, sobre cosas que no se han de hacer, y pecare;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 23, 'Luego que le fuere conocido su pecado en que ha delinquido, presentará por su ofrenda un macho cabrío sin defecto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 24, 'Y pondrá su mano sobre la cabeza del macho cabrío, y lo degollará en el lugar donde se degüella el holocausto delante de Jehová; es expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 25, 'Y tomará el sacerdote con su dedo de la sangre de la expiación, y pondrá sobre los cuernos del altar del holocausto, y derramará la sangre al pie del altar del holocausto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 26, 'Y quemará todo su sebo sobre el altar, como el sebo del sacrificio de las paces: así hará el sacerdote por él la expiación de su pecado, y tendrá perdón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 27, 'Y si alguna persona del común del pueblo pecare por yerro, haciendo algo contra alguno de los mandamientos de Jehová en cosas que no se han de hacer, y delinquiere;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 28, 'Luego que le fuere conocido su pecado que cometió, traerá por su ofrenda una hembra de las cabras, una cabra sin defecto, por su pecado que habrá cometido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 29, 'Y pondrá su mano sobre la cabeza de la expiación, y la degollará en el lugar del holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 30, 'Luego tomará el sacerdote en su dedo de su sangre, y pondrá sobre los cuernos del altar del holocausto, y derramará toda su sangre al pie del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 31, 'Y le quitará todo su sebo, de la manera que fue quitado el sebo del sacrificio de las paces; y el sacerdote lo hará arder sobre el altar en olor de suavidad á Jehová: así hará el sacerdote expiación por él, y será perdonado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 32, 'Y si trajere cordero para su ofrenda por el pecado, hembra sin defecto traerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 33, 'Y pondrá su mano sobre la cabeza de la expiación, y la degollará por expiación en el lugar donde se degüella el holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 34, 'Después tomará el sacerdote con su dedo de la sangre de la expiación, y pondrá sobre los cuernos del altar del holocausto; y derramará toda la sangre al pie del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 4, 35, 'Y le quitará todo su sebo, como fué quitado el sebo del sacrificio de las paces, y harálo el sacerdote arder en el altar sobre la ofrenda encendida á Jehová: y le hará el sacerdote expiación de su pecado que habrá cometido, y será perdonado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 1, 'Y CUANDO alguna persona pecare, que hubiere oído la voz del que juró, y él fuere testigo que vió, ó supo, si no lo denunciare, él llevará su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 2, 'Asimismo la persona que hubiere tocado en cualquiera cosa inmunda, sea cuerpo muerto de bestia inmunda, ó cuerpo muerto de animal inmundo, ó cuerpo muerto de reptil inmundo, bien que no lo supiere, será inmunda y habrá delinquido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 3, 'O si tocare á hombre inmundo en cualquiera inmundicia suya de que es inmundo, y no lo echare de ver; si después llega á saberlo, será culpable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 4, 'También la persona que jurare, pronunciando con sus labios hacer mal ó bien, en cualesquiera cosas que el hombre profiere con juramento, y él no lo conociere; si después lo entiende, será culpado en una de estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 5, 'Y será que cuando pecare en alguna de estas cosas, confesará aquello en que pecó:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 6, 'Y para su expiación traerá á Jehová por su pecado que ha cometido, una hembra de los rebaños, una cordera ó una cabra como ofrenda de expiación; y el sacerdote hará expiación por él de su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 7, 'Y si no le alcanzare para un cordero, traerá en expiación por su pecado que cometió, dos tórtolas ó dos palominos á Jehová; el uno para expiación, y el otro para holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 8, 'Y ha de traerlos al sacerdote, el cual ofrecerá primero el que es para expiación, y desunirá su cabeza de su cuello, mas no la apartará del todo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 9, 'Y rociará de la sangre de la expiación sobre la pared del altar; y lo que sobrare de la sangre lo exprimirá al pie del altar; es expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 10, 'Y del otro hará holocausto conforme al rito; y hará por él el sacerdote expiación de su pecado que cometió, y será perdonado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 11, 'Mas si su posibilidad no alcanzare para dos tórtolas, ó dos palominos, el que pecó traerá por su ofrenda la décima parte de un epha de flor de harina por expiación. No pondrá sobre ella aceite, ni sobre ella pondrá incienso, porque es expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 12, 'Traerála, pues, al sacerdote, y el sacerdote tomará de ella su puño lleno, en memoria suya, y la hará arder en el altar sobre las ofrendas encendidas á Jehová: es expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 13, 'Y hará el sacerdote expiación por él de su pecado que cometió en alguna de estas cosas, y será perdonado; y el sobrante será del sacerdote, como el presente de vianda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 14, 'Habló más Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 15, 'Cuando alguna persona cometiere falta, y pecare por yerro en las cosas santificadas á Jehová, traerá su expiación á Jehová, un carnero sin tacha de los rebaños, conforme á tu estimación, en siclos de plata del siclo del santuario, en ofrenda por el pecado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 16, 'Y pagará aquello de las cosas santas en que hubiere pecado, y añadirá á ello el quinto, y lo dará al sacerdote: y el sacerdote hará expiación por él con el carnero del sacrificio por el pecado, y será perdonado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 17, 'Finalmente, si una persona pecare, ó hiciere alguna de todas aquellas cosas que por mandamiento de Jehová no se han de hacer, aun sin hacerlo á sabiendas, es culpable, y llevará su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 18, 'Traerá, pues, al sacerdote por expiación, según tú lo estimes, un carnero sin tacha de los rebaños: y el sacerdote hará expiación por él de su yerro que cometió por ignorancia, y será perdonado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 5, 19, 'Es infracción, y ciertamente delinquió contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 2, 'Cuando una persona pecare, é hiciere prevaricación contra Jehová, y negare á su prójimo lo encomendado ó dejado en su mano, ó bien robare, ó calumniare á su prójimo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 3, 'O sea que hallando lo perdido, después lo negare, y jurare en falso, en alguna de todas aquellas cosas en que suele pecar el hombre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 4, 'Entonces será que, puesto habrá pecado y ofendido, restituirá aquello que robó, ó por el daño de la calumnia, ó el depósito que se le encomendó, ó lo perdido que halló,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 5, 'O todo aquello sobre que hubiere jurado falsamente; lo restituirá, pues, por entero, y añadirá á ello la quinta parte, que ha de pagar á aquel á quien pertenece en el día de su expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 6, 'Y por su expiación traerá á Jehová un carnero sin tacha de los rebaños, conforme á tu estimación, al sacerdote para la expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 7, 'Y el sacerdote hará expiación por él delante de Jehová, y obtendrá perdón de cualquiera de todas las cosas en que suele ofender.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 8, 'Habló aún Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 9, 'Manda á Aarón y á sus hijos diciendo: Esta es la ley del holocausto: (es holocausto, porque se quema sobre el altar toda la noche hasta la mañana, y el fuego del altar arderá en él:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 10, 'El sacerdote se pondrá su vestimenta de lino, y se vestirá pañetes de lino sobre su carne; y cuando el fuego hubiere consumido el holocausto, apartará él las cenizas de sobre el altar, y pondrálas junto al altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 11, 'Después se desnudará de sus vestimentas, y se pondrá otras vestiduras, y sacará las cenizas fuera del real al lugar limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 12, 'Y el fuego encendido sobre el altar no ha de apagarse, sino que el sacerdote pondrá en él leña cada mañana, y acomodará sobre él el holocausto, y quemará sobre él los sebos de las paces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 13, 'El fuego ha de arder continuamente en el altar; no se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 14, 'Y esta es la ley del presente: Han de ofrecerlo los hijos de Aarón delante de Jehová, delante del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 15, 'Y tomará de él un puñado de la flor de harina del presente, y de su aceite, y todo el incienso que está sobre el presente, y harálo arder sobre el altar por memoria, en olor suavísimo á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 16, 'Y el sobrante de ella lo comerán Aarón y sus hijos: sin levadura se comerá en el lugar santo; en el atrio del tabernáculo del testimonio lo comerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 17, 'No se cocerá con levadura: helo dado á ellos por su porción de mis ofrendas encendidas; es cosa santísima, como la expiación por el pecado, y como la expiación por la culpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 18, 'Todos los varones de los hijos de Aarón comerán de ella. Estatuto perpetuo será para vuestras generaciones tocante á las ofrendas encendidas de Jehová: toda cosa que tocare en ellas será santificada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 19, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 20, 'Esta es la ofrenda de Aarón y de sus hijos, que ofrecerán á Jehová el día que serán ungidos: la décima parte de un epha de flor de harina, presente perpetuo, la mitad á la mañana y la mitad á la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 21, 'En sartén se aderezará con aceite; frita la traerás, y los pedazos cocidos del presente ofrecerás á Jehová en olor de suavidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 22, 'Y el sacerdote que en lugar de Aarón fuere ungido de entre sus hijos, hará la ofrenda; estatuto perpetuo de Jehová: toda ella será quemada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 23, 'Y todo presente de sacerdote será enteramente quemado; no se comerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 24, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 25, 'Habla á Aarón y á sus hijos, diciendo: Esta es la ley de la expiación: en el lugar donde será degollado el holocausto, será degollada la expiación por el pecado delante de Jehová: es cosa santísima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 26, 'El sacerdote que la ofreciere por expiación, la comerá: en el lugar santo será comida, en el atrio del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 27, 'Todo lo que en su carne tocare, será santificado; y si cayere de su sangre sobre el vestido, lavarás aquello sobre que cayere, en el lugar santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 28, 'Y la vasija de barro en que fuere cocida, será quebrada: y si fuere cocida en vasija de metal, será fregada y lavada con agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 29, 'Todo varón de entre los sacerdotes la comerá: es cosa santísima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 6, 30, 'Mas no se comerá de expiación alguna, de cuya sangre se metiere en el tabernáculo del testimonio para reconciliar en el santuario: al fuego será quemada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 1, 'ASIMISMO esta es la ley de la expiación de la culpa: es cosa muy santa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 2, 'En el lugar donde degollaren el holocausto, degollarán la víctima por la culpa; y rociará su sangre en derredor sobre el altar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 3, 'Y de ella ofrecerá todo su sebo, la cola, y el sebo que cubre los intestinos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 4, 'Y los dos riñones, y el sebo que está sobre ellos, y el que está sobre los ijares; y con los riñones quitará el redaño de sobre el hígado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 5, 'Y el sacerdote lo hará arder sobre el altar; ofrenda encendida á Jehová: es expiación de la culpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 6, 'Todo varón de entre los sacerdotes la comerá: será comida en el lugar santo: es cosa muy santa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 7, 'Como la expiación por el pecado, así es la expiación de la culpa: una misma ley tendrán: será del sacerdote que habrá hecho la reconciliación con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 8, 'Y el sacerdote que ofreciere holocausto de alguno, el cuero del holocausto que ofreciere, será para él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 9, 'Asimismo todo presente que se cociere en horno, y todo el que fuere aderezado en sartén, ó en cazuela, será del sacerdote que lo ofreciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 10, 'Y todo presente amasado con aceite, y seco, será de todos los hijos de Aarón, tanto al uno como al otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 11, 'Y esta es la ley del sacrificio de las paces, que se ofrecerá á Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 12, 'Si se ofreciere en hacimiento de gracias, ofrecerá por sacrificio de hacimiento de gracias tortas sin levadura amasadas con aceite, y hojaldres sin levadura untadas con aceite, y flor de harina frita en tortas amasadas con aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 13, 'Con tortas de pan leudo ofrecerá su ofrenda en el sacrificio de hacimiento de gracias de sus paces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 14, 'Y de toda la ofrenda presentará una parte por ofrenda elevada á Jehová, y será del sacerdote que rociare la sangre de los pacíficos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 15, 'Y la carne del sacrificio de sus pacíficos en hacimiento de gracias, se comerá en el día que fuere ofrecida: no dejarán de ella nada para otro día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 16, 'Mas si el sacrificio de su ofrenda fuere voto, ó voluntario, el día que ofreciere su sacrificio será comido; y lo que de él quedare, comerse ha el día siguiente:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 17, 'Y lo que quedare para el tercer día de la carne del sacrificio, será quemado en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 18, 'Y si se comiere de la carne del sacrificio de sus paces el tercer día, el que lo ofreciere no será acepto, ni le será imputado; abominación será, y la persona que de él comiere llevará su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 19, 'Y la carne que tocare á alguna cosa inmunda, no se comerá; al fuego será quemada; mas cualquiera limpio comerá de aquesta carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 20, 'Y la persona que comiere la carne del sacrificio de paces, el cual es de Jehová, estando inmunda, aquella persona será cortada de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 21, 'Además, la persona que tocare alguna cosa inmunda, en inmundicia de hombre, ó en animal inmundo, ó en cualquiera abominación inmunda, y comiere la carne del sacrificio de las paces, el cual es de Jehová, aquella persona será cortada de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 22, 'Habló aún Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 23, 'Habla á los hijos de Israel, diciendo: Ningún sebo de buey, ni de cordero, ni de cabra, comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 24, 'El sebo de animal mortecino, y el sebo del que fué arrebatado de fieras, se aparejará para cualquiera otro uso, mas no lo comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 25, 'Porque cualquiera que comiere sebo de animal, del cual se ofrece á Jehová ofrenda encendida, la persona que lo comiere, será cortada de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 26, 'Además, ninguna sangre comeréis en todas vuestras habitaciones, así de aves como de bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 27, 'Cualquiera persona que comiere alguna sangre, la tal persona será cortada de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 28, 'Habló más Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 29, 'Habla á los hijos de Israel, diciendo: El que ofreciere sacrificio de sus paces á Jehová, traerá su ofrenda del sacrificio de sus paces á Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 30, 'Sus manos traerán las ofrendas que se han de quemar á Jehová: traerá el sebo con el pecho: el pecho para que éste sea agitado, como sacrificio agitado delante de Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 31, 'Y el sebo lo hará arder el sacerdote en el altar, mas el pecho será de Aarón y de sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 32, 'Y daréis al sacerdote para ser elevada en ofrenda, la espaldilla derecha de los sacrificios de vuestras paces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 33, 'El que de los hijos de Aarón ofreciere la sangre de las paces, y el sebo, de él será en porción la espaldilla derecha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 34, 'Porque he tomado de los hijos de Israel, de los sacrificios de sus paces, el pecho que se agita, y la espaldilla elevada en ofrenda, y lo he dado á Aarón el sacerdote y á sus hijos, por estatuto perpetuo de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 35, 'Esta es por la unción de Aarón y la unción de sus hijos, la parte de ellos en las ofrendas encendidas á Jehová, desde el día que él los allegó para ser sacerdotes de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 36, 'Lo cual mandó Jehová que les diesen, desde el día que él los ungió de entre los hijos de Israel, por estatuto perpetuo en sus generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 37, 'Esta es la ley del holocausto, del presente, de la expiación por el pecado, y de la culpa, y de las consagraciones, y del sacrificio de las paces:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 7, 38, 'La cual intimó Jehová á Moisés, en el monte de Sinaí, el día que mandó á los hijos de Israel que ofreciesen sus ofrendas á Jehová en el desierto de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 2, 'Toma á Aarón y á sus hijos con él, y las vestimentas, y el aceite de la unción, y el becerro de la expiación, y los dos carneros, y el canastillo de los ázimos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 3, 'Y reúne toda la congregación á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 4, 'Hizo, pues, Moisés como Jehová le mandó, y juntóse la congregación á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 5, 'Y dijo Moisés á la congregación: Esto es lo que Jehová ha mandado hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 6, 'Entonces Moisés hizo llegar á Aarón y á sus hijos, y lavólos con agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 7, 'Y puso sobre él la túnica, y ciñólo con el cinto; vistióle después el manto, y puso sobre él el ephod, y ciñólo con el cinto del ephod, y ajustólo con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 8, 'Púsole luego encima el racional, y en él puso el Urim y Thummim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 9, 'Después puso la mitra sobre su cabeza; y sobre la mitra en su frente delantero puso la plancha de oro, la diadema santa; como Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 10, 'Y tomó Moisés el aceite de la unción, y ungió el tabernáculo, y todas las cosas que estaban en él, y santificólas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 11, 'Y roció de él sobre el altar siete veces, y ungió el altar y todos sus vasos, y la fuente y su basa, para santificarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 12, 'Y derramó del aceite de la unción sobre la cabeza de Aarón, y ungiólo para santificarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 13, 'Después Moisés hizo llegar los hijos de Aarón, y vistióles las túnicas, y ciñólos con cintos, y ajustóles los chapeos (tiaras), como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 14, 'Hizo luego llegar el becerro de la expiación, y Aarón y sus hijos pusieron sus manos sobre la cabeza del becerro de la expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 15, 'Y degollólo; y Moisés tomó la sangre, y puso con su dedo sobre los cuernos del altar alrededor, y purificó el altar; y echó la demás sangre al pie del altar, y santificólo para reconciliar sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 16, 'Después tomó todo el sebo que estaba sobre los intestinos, y el redaño del hígado, y los dos riñones, y el sebo de ellos, é hízolo Moisés arder sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 17, 'Mas el becerro, y su cuero, y su carne, y su estiércol, quemólo al fuego fuera del real; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 18, 'Después hizo llegar el carnero del holocausto, y Aarón y sus hijos pusieron sus manos sobre la cabeza del carnero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 19, 'Y degollólo; y roció Moisés la sangre sobre el altar en derredor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 20, 'Y cortó el carnero en trozos; y Moisés hizo arder la cabeza, y los trozos, y el sebo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 21, 'Lavó luego con agua los intestinos y piernas, y quemó Moisés todo el carnero sobre el altar: holocausto en olor de suavidad, ofrenda encendida á Jehová; como lo había Jehová mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 22, 'Después hizo llegar el otro carnero, el carnero de las consagraciones, y Aarón y sus hijos pusieron sus manos sobre la cabeza del carnero:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 23, 'Y degollólo; y tomó Moisés de su sangre, y puso sobre la ternilla de la oreja derecha de Aarón, y sobre el dedo pulgar de su mano derecha, y sobre el dedo pulgar de su pie derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 24, 'Hizo llegar luego los hijos de Aarón, y puso Moisés de la sangre sobre la ternilla de sus orejas derechas, y sobre los pulgares de sus manos derechas, y sobre los pulgares de sus pies derechos: y roció Moisés la sangre sobre el altar en derredor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 25, 'Y después tomó el sebo, y la cola, y todo el sebo que estaba sobre los intestinos, y el redaño del hígado, y los dos riñones, y el sebo de ellos, y la espaldilla derecha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 26, 'Y del canastillo de los ázimos, que estaba delante de Jehová, tomó una torta sin levadura, y una torta de pan de aceite, y una lasaña, y púsolo con el sebo y con la espaldilla derecha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 27, 'Y púsolo todo en las manos de Aarón, y en las manos de sus hijos, é hízolo mecer: ofrenda agitada delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 28, 'Después tomó aquellas cosas Moisés de las manos de ellos, é hízolas arder en el altar sobre el holocausto: las consagraciones en olor de suavidad, ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 29, 'Y tomó Moisés el pecho, y meciólo, ofrenda agitada delante de Jehová: del carnero de las consagraciones aquella fue la parte de Moisés; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 30, 'Luego tomó Moisés del aceite de la unción, y de la sangre que estaba sobre el altar, y roció sobre Aarón, y sobre sus vestiduras, sobre sus hijos, y sobre las vestiduras de sus hijos con él; y santificó á Aarón, y sus vestiduras, y á sus hijos, y las vestiduras de sus hijos con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 31, 'Y dijo Moisés á Aarón y á sus hijos: Comed la carne á la puerta del tabernáculo del testimonio; y comedla allí con el pan que está en el canastillo de las consagraciones, según yo he mandado, diciendo: Aarón y sus hijos la comerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 32, 'Y lo que sobrare de la carne y del pan, habéis de quemarlo al fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 33, 'De la puerta del tabernáculo del testimonio no saldréis en siete días, hasta el día que se cumplieren los días de vuestras consagraciones: porque por siete días seréis consagrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 34, 'De la manera que hoy se ha hecho, mandó hacer Jehová para expiaros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 35, 'A la puerta, pues, del tabernáculo del testimonio estaréis día y noche por siete días, y guardaréis la ordenanza delante de Jehová, para que no muráis; porque así me ha sido mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 8, 36, 'Y Aarón y sus hijos hicieron todas las cosas que mandó Jehová por medio de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 1, 'Y FUÉ en el día octavo, que Moisés llamó á Aarón y á sus hijos, y á los ancianos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 2, 'Y dijo á Aarón: Toma de la vacada un becerro para expiación, y un carnero para holocausto, sin defecto, y ofrécelos delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 3, 'Y á los hijos de Israel hablarás, diciendo: Tomad un macho cabrío para expiación, y un becerro y un cordero de un año, sin tacha, para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 4, 'Asimismo un buey y un carnero para sacrificio de paces, que inmoléis delante de Jehová; y un presente amasado con aceite: porque Jehová se aparecerá hoy á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 5, 'Y llevaron lo que mandó Moisés delante del tabernáculo del testimonio, y llegóse toda la congregación, y pusiéronse delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 6, 'Entonces Moisés dijo: Esto es lo que mandó Jehová; hacedlo, y la gloria de Jehová se os aparecerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 7, 'Y dijo Moisés á Aarón: Llégate al altar, y haz tu expiación, y tu holocausto, y haz la reconciliación por ti y por el pueblo: haz también la ofrenda del pueblo, y haz la reconciliación por ellos; como ha mandado Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 8, 'Entonces llegóse Aarón al altar; y degolló su becerro de la expiación que era por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 9, 'Y los hijos de Aarón le trajeron la sangre; y él mojó su dedo en la sangre, y puso sobre los cuernos del altar, y derramó la demás sangre al pie del altar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 10, 'Y el sebo y riñones y redaño del hígado, de la expiación, hízolos arder sobre el altar; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 11, 'Mas la carne y el cuero los quemó al fuego fuera del real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 12, 'Degolló asimismo el holocausto, y los hijos de Aarón le presentaron la sangre, la cual roció él alrededor sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 13, 'Presentáronle después el holocausto, á trozos, y la cabeza; é hízolos quemar sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 14, 'Luego lavó los intestinos y las piernas, y quemólos sobre el holocausto en el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 15, 'Ofreció también la ofrenda del pueblo, y tomó el macho cabrío que era para la expiación del pueblo, y degollólo, y lo ofreció por el pecado como el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 16, 'Y ofreció el holocausto, é hizo según el rito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 17, 'Ofreció asimismo el presente, é hinchió de él su mano, y lo hizo quemar sobre el altar, además del holocausto de la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 18, 'Degolló también el buey y el carnero en sacrificio de paces, que era del pueblo: y los hijos de Aarón le presentaron la sangre (la cual roció él sobre el altar alrededor),');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 19, 'Y los sebos del buey; y del carnero la cola con lo que cubre las entrañas, y los riñones, y el redaño del hígado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 20, 'Y pusieron los sebos sobre los pechos, y él quemó los sebos sobre el altar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 21, 'Empero los pechos, con la espaldilla derecha, meciólos Aarón por ofrenda agitada delante de Jehová; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 22, 'Después alzó Aarón sus manos hacia el pueblo y bendíjolos: y descendió de hacer la expiación, y el holocausto, y el sacrificio de las paces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 23, 'Y entraron Moisés y Aarón en el tabernáculo del testimonio; y salieron, y bendijeron al pueblo: y la gloria de Jehová se apareció á todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 9, 24, 'Y salió fuego de delante de Jehová, y consumió el holocausto y los sebos sobre el altar; y viéndolo todo el pueblo, alabaron, y cayeron sobre sus rostros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 1, 'Y LOS hijos de Aarón, Nadab y Abiú, tomaron cada uno su incensario, y pusieron fuego en ellos, sobre el cual pusieron perfume, y ofrecieron delante de Jehová fuego extraño, que él nunca les mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 2, 'Y salió fuego de delante de Jehová que los quemó, y murieron delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 3, 'Entonces dijo Moisés á Aarón: Esto es lo que habló Jehová, diciendo: En mis allegados me santificaré, y en presencia de todo el pueblo seré glorificado. Y Aarón calló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 4, 'Y llamó Moisés á Misael, y á Elzaphán, hijos de Uzziel, tío de Aarón, y díjoles: Llegaos y sacad á vuestros hermanos de delante del santuario fuera del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 5, 'Y ellos llegaron, y sacáronlos con sus túnicas fuera del campo, como dijo Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 6, 'Entonces Moisés dijo á Aarón, y á Eleazar y á Ithamar, sus hijos: No descubráis vuestras cabezas, ni rasguéis vuestros vestidos, porque no muráis, ni se levante la ira sobre toda la congregación: empero vuestros hermanos, toda la casa de Israel, lamentarán el incendio que Jehová ha hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 7, 'Ni saldréis de la puerta del tabernáculo del testimonio, porque moriréis; por cuanto el aceite de la unción de Jehová está sobre vosotros. Y ellos hicieron conforme al dicho de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 8, 'Y Jehová habló á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 9, 'Tú, y tus hijos contigo, no beberéis vino ni sidra, cuando hubiereis de entrar en el tabernáculo del testimonio, porque no muráis: estatuto perpetuo por vuestras generaciones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 10, 'Y para poder discernir entre lo santo y lo profano, y entre lo inmundo y lo limpio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 11, 'Y para enseñar á los hijos de Israel todos los estatutos que Jehová les ha dicho por medio de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 12, 'Y Moisés dijo á Aarón, y á Eleazar y á Ithamar, sus hijos que habían quedado: Tomad el presente que queda de las ofrendas encendidas á Jehová, y comedlo sin levadura junto al altar, porque es cosa muy santa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 13, 'Habéis, pues, de comerlo en el lugar santo: porque esto es fuero para ti, y fuero para tus hijos, de las ofrendas encendidas á Jehová, pues que así me ha sido mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 14, 'Comeréis asimismo en lugar limpio, tú y tus hijos y tus hijas contigo, el pecho de la mecida, y la espaldilla elevada, porque por fuero para ti, y fuero para tus hijos, son dados de los sacrificios de las paces de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 15, 'Con las ofrendas de los sebos que se han de encender, traerán la espaldilla que se ha de elevar, y el pecho que será mecido, para que lo mezas por ofrenda agitada delante de Jehová: y será por fuero perpetuo tuyo, y de tus hijos contigo, como Jehová lo ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 16, 'Y Moisés demandó el macho cabrío de la expiación, y hallóse que era quemado: y enojóse contra Eleazar é Ithamar, los hijos de Aarón que habían quedado, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 17, '¿Por qué no comisteis la expiación en el lugar santo? porque es muy santa, y dióla él á vosotros para llevar la iniquidad de la congregación, para que sean reconciliados delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 18, 'Veis que su sangre no fue metida dentro del santuario: habíais de comerla en el lugar santo, como yo mandé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 19, 'Y respondió Aarón á Moisés: He aquí hoy han ofrecido su expiación y su holocausto delante de Jehová: pero me han acontecido estas cosas: pues si comiera yo hoy de la expiación, ¿Hubiera sido acepto á Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 10, 20, 'Y cuando Moisés oyó esto, dióse por satisfecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 1, 'Y HABLO Jehová á Moisés y á Aarón, diciéndoles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 2, 'Hablad á los hijos de Israel, diciendo: Estos son los animales que comeréis de todos los animales que están sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 3, 'De entre los animales, todo el de pezuña, y que tiene las pezuñas hendidas, y que rumia, éste comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 4, 'Estos empero no comeréis de los que rumian y de los que tienen pezuña: el camello, porque rumia mas no tiene pezuña hendida, habéis de tenerlo por inmundo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 5, 'También el conejo, porque rumia, mas no tiene pezuña, tendréislo por inmundo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 6, 'Asimismo la liebre, porque rumia, mas no tiene pezuña, tendréisla por inmunda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 7, 'También el puerco, porque tiene pezuñas, y es de pezuñas hendidas, mas no rumia, tendréislo por inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 8, 'De la carne de ellos no comeréis, ni tocaréis su cuerpo muerto: tendréislos por inmundos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 9, 'Esto comeréis de todas las cosas que están en las aguas: todas las cosas que tienen aletas y escamas en las aguas de la mar, y en los ríos, aquellas comeréis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 10, 'Mas todas las cosas que no tienen aletas ni escamas en la mar y en los ríos, así de todo reptil de agua como de toda cosa viviente que está en las aguas, las tendréis en abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 11, 'Os serán, pues, en abominación: de su carne no comeréis, y abominaréis sus cuerpos muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 12, 'Todo lo que no tuviere aletas y escamas en las aguas, tendréislo en abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 13, 'Y de las aves, éstas tendréis en abominación; no se comerán, serán abominación: el águila, el quebrantahuesos, el esmerejón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 14, 'El milano, y el buitre según su especie;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 15, 'Todo cuervo según su especie;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 16, 'El avestruz, y la lechuza, y el laro, y el gavilán según su especie;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 17, 'Y el buho, y el somormujo, y el ibis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 18, 'Y el calamón, y el cisne, y el onocrótalo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 19, 'Y el herodión, y el caradrión, según su especie, y la abubilla, y el murciélago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 20, 'Todo reptil alado que anduviere sobre cuatro pies, tendréis en abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 21, 'Empero esto comeréis de todo reptil alado que anda sobre cuatro pies, que tuviere piernas además de sus pies para saltar con ellas sobre la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 22, 'Estos comeréis de ellos: la langosta según su especie, y el langostín según su especie, y el aregol según su especie, y el haghab según su especie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 23, 'Todo reptil alado que tenga cuatro pies, tendréis en abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 24, 'Y por estas cosas seréis inmundos: cualquiera que tocare á sus cuerpos muertos, será inmundo hasta la tarde:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 25, 'Y cualquiera que llevare de sus cuerpos muertos, lavará sus vestidos, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 26, 'Todo animal de pezuña, pero que no tiene pezuña hendida, ni rumia, tendréis por inmundo: cualquiera que los tocare será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 27, 'Y de todos los animales que andan á cuatro pies, tendréis por inmundo cualquiera que ande sobre sus garras: cualquiera que tocare sus cuerpos muertos, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 28, 'Y el que llevare sus cuerpos muertos, lavará sus vestidos, y será inmundo hasta la tarde: habéis de tenerlos por inmundos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 29, 'Y estos tendréis por inmundos de los reptiles que van arrastrando sobre la tierra: la comadreja, y el ratón, y la rana según su especie,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 30, 'Y el erizo, y el lagarto, y el caracol, y la babosa, y el topo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 31, 'Estos tendréis por inmundos de todos los reptiles: cualquiera que los tocare, cuando estuvieren muertos, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 32, 'Y todo aquello sobre que cayere alguno de ellos después de muertos, será inmundo; así vaso de madera, como vestido, ó piel, ó saco, cualquier instrumento con que se hace obra, será metido en agua, y será inmundo hasta la tarde, y así será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 33, 'Y toda vasija de barro dentro de la cual cayere alguno de ellos, todo lo que estuviere en ella será inmundo, y quebraréis la vasija:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 34, 'Toda vianda que se come, sobre la cual viniere el agua de tales vasijas, será inmunda: y toda bebida que se bebiere, será en todas esas vasijas inmunda:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 35, 'Y todo aquello sobre que cayere algo del cuerpo muerto de ellos, será inmundo: el horno ú hornillos se derribarán; son inmundos, y por inmundos los tendréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 36, 'Con todo, la fuente y la cisterna donde se recogen aguas, serán limpias: mas lo que hubiere tocado en sus cuerpos muertos será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 37, 'Y si cayere de sus cuerpos muertos sobre alguna simiente que se haya de sembrar, será limpia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 38, 'Mas si se hubiere puesto agua en la simiente, y cayere de sus cuerpos muertos sobre ella, tendréisla por inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 39, 'Y si algún animal que tuviereis para comer se muriere, el que tocare su cuerpo muerto será inmundo hasta la tarde:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 40, 'Y el que comiere de su cuerpo muerto, lavará sus vestidos, y será inmundo hasta la tarde: asimismo el que sacare su cuerpo muerto, lavará sus vestidos, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 41, 'Y todo reptil que va arrastrando sobre la tierra, es abominación; no se comerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 42, 'Todo lo que anda sobre el pecho, y todo lo que anda sobre cuatro ó más pies, de todo reptil que anda arrastrando sobre la tierra, no lo comeréis, porque es abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 43, 'No ensuciéis vuestras personas con ningún reptil que anda arrastrando, ni os contaminéis con ellos, ni seáis inmundos por ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 44, 'Pues que yo soy Jehová vuestro Dios, vosotros por tanto os santificaréis, y seréis santos, porque yo soy santo: así que no ensuciéis vuestras personas con ningún reptil que anduviere arrastrando sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 45, 'Porque yo soy Jehová, que os hago subir de la tierra de Egipto para seros por Dios: seréis pues santos, porque yo soy santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 46, 'Esta es la ley de los animales y de las aves, y de todo ser viviente que se mueve en las aguas, y de todo animal que anda arrastrando sobre la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 11, 47, 'Para hacer diferencia entre inmundo y limpio, y entre los animales que se pueden comer y los animales que no se pueden comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 2, 'Habla á los hijos de Israel, diciendo: La mujer cuando concibiere y pariere varón, será inmunda siete días; conforme á los días que está separada por su menstruo, será inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 3, 'Y al octavo día circuncidará la carne de su prepucio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 4, 'Mas ella permanecerá treinta y tres días en la sangre de su purgación: ninguna cosa santa tocará, ni vendrá al santuario, hasta que sean cumplidos los días de su purgación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 5, 'Y si pariere hembra será inmunda dos semanas, conforme á su separación, y sesenta y seis días estará purificándose de su sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 6, 'Y cuando los días de su purgación fueren cumplidos, por hijo ó por hija, traerá un cordero de un año para holocausto, y un palomino ó una tórtola para expiación, á la puerta del tabernáculo del testimonio, al sacerdote:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 7, 'Y él ofrecerá delante de Jehová, y hará expiación por ella, y será limpia del flujo de su sangre. Esta es la ley de la que pariere varón ó hembra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 12, 8, 'Y si no alcanzare su mano lo suficiente para un cordero, tomará entonces dos tórtolas ó dos palominos, uno para holocausto, y otro para expiación: y el sacerdote hará expiación por ella, y será limpia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 1, 'Y HABLO Jehová á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 2, 'Cuando el hombre tuviere en la piel de su carne hinchazón, ó postilla, ó mancha blanca, y hubiere en la piel de su carne como llaga de lepra, será traído á Aarón el sacerdote, ó á uno de los sacerdotes sus hijos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 3, 'Y el sacerdote mirará la llaga en la piel de la carne: si el pelo en la llaga se ha vuelto blanco, y pareciere la llaga más hundida que la tez de la carne, llaga de lepra es; y el sacerdote le reconocerá, y le dará por inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 4, 'Y si en la piel de su carne hubiere mancha blanca, pero no pareciere más hundida que la tez, ni su pelo se hubiere vuelto blanco, entonces el sacerdote encerrará al llagado por siete días;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 5, 'Y al séptimo día el sacerdote lo mirará; y si la llaga a su parecer se hubiere estancado, no habiéndose extendido en la piel, entonces el sacerdote le volverá á encerrar por otros siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 6, 'Y al séptimo día el sacerdote le reconocerá de nuevo; y si parece haberse oscurecido la llaga, y que no ha cundido en la piel, entonces el sacerdote lo dará por limpio: era postilla; y lavará sus vestidos, y será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 7, 'Mas si hubiere ido creciendo la postilla en la piel, después que fué mostrado al sacerdote para ser limpio, será visto otra vez del sacerdote:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 8, 'Y si reconociéndolo el sacerdote, ve que la postilla ha crecido en la piel, el sacerdote lo dará por inmundo: es lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 9, 'Cuando hubiere llaga de lepra en el hombre, será traído al sacerdote;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 10, 'Y el sacerdote mirará, y si pareciere tumor blanco en la piel, el cual haya mudado el color del pelo, y se descubre asimismo la carne viva,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 11, 'Lepra es envejecida en la piel de su carne; y le dará por inmundo el sacerdote, y no le encerrará, porque es inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 12, 'Mas si brotare la lepra cundiendo por el cutis, y ella cubriere toda la piel del llagado desde su cabeza hasta sus pies, á toda vista de ojos del sacerdote;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 13, 'Entonces el sacerdote le reconocerá; y si la lepra hubiere cubierto toda su carne, dará por limpio al llagado: hase vuelto toda ella blanca; y él es limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 14, 'Mas el día que apareciere en él la carne viva, será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 15, 'Y el sacerdote mirará la carne viva, y lo dará por inmundo. Es inmunda la carne viva: es lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 16, 'Mas cuando la carne viva se mudare y volviere blanca, entonces vendrá al sacerdote;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 17, 'Y el sacerdote mirará, y si la llaga se hubiere vuelto blanca, el sacerdote dará por limpio al que tenía la llaga, y será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 18, 'Y cuando en la carne, en su piel, hubiere apostema, y se sanare,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 19, 'Y sucediere en el lugar de la apostema tumor blanco, ó mancha blanca embermejecida, será mostrado al sacerdote:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 20, 'Y el sacerdote mirará; y si pareciere estar más baja que su piel, y su pelo se hubiere vuelto blanco, darálo el sacerdote por inmundo: es llaga de lepra que se originó en la apostema.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 21, 'Y si el sacerdote la considerare, y no pareciere en ella pelo blanco, ni estuviere más baja que la piel, sino oscura, entonces el sacerdote lo encerrará por siete días:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 22, 'Y si se fuere extendiendo por la piel, entonces el sacerdote lo dará por inmundo: es llaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 23, 'Empero si la mancha blanca se estuviere en su lugar, que no haya cundido, es la costra de la apostema; y el sacerdote lo dará por limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 24, 'Asimismo cuando la carne tuviere en su piel quemadura de fuego, y hubiere en lo sanado del fuego mancha blanquecina, bermejiza ó blanca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 25, 'El sacerdote la mirará; y si el pelo se hubiere vuelto blanco en la mancha, y pareciere estar más hundida que la piel, es lepra que salió en la quemadura; y el sacerdote declarará al sujeto inmundo, por ser llaga de lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 26, 'Mas si el sacerdote la mirare, y no pareciere en la mancha pelo blanco, ni estuviere más baja que la tez, sino que está oscura, le encerrará el sacerdote por siete días;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 27, 'Y al séptimo día el sacerdote la reconocerá: si se hubiere ido extendiendo por la piel, el sacerdote lo dará por inmundo: es llaga de lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 28, 'Empero si la mancha se estuviere en su lugar, y no se hubiere extendido en la piel, sino que está oscura, hinchazón es de la quemadura: darálo el sacerdote por limpio; que señal de la quemadura es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 29, 'Y al hombre ó mujer que le saliere llaga en la cabeza, ó en la barba,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 30, 'El sacerdote mirará la llaga; y si pareciere estar más profunda que la tez, y el pelo en ella fuera rubio y adelgazado, entonces el sacerdote lo dará por inmundo: es tiña, es lepra de la cabeza ó de la barba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 31, 'Mas cuando el sacerdote hubiere mirado la llaga de la tiña, y no pareciere estar más profunda que la tez, ni fuere en ella pelo negro, el sacerdote encerrará al llagado de la tiña por siete días:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 32, 'Y al séptimo día el sacerdote mirará la llaga: y si la tiña no pareciere haberse extendido, ni hubiere en ella pelo rubio, ni pareciere la tiña más profunda que la tez,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 33, 'Entonces lo trasquilarán, mas no trasquilarán el lugar de la tiña: y encerrará el sacerdote al que tiene la tiña por otros siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 34, 'Y al séptimo día mirará el sacerdote la tiña; y si la tiña no hubiere cundido en la piel, ni pareciere estar más profunda que la tez, el sacerdote lo dará por limpio; y lavará sus vestidos, y será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 35, 'Empero si la tiña se hubiere ido extendiendo en la piel después de su purificación,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 36, 'Entonces el sacerdote la mirará; y si la tiña hubiere cundido en la piel, no busque el sacerdote el pelo rubio, es inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 37, 'Mas si le pareciere que la tiña está detenida, y que ha salido en ella el pelo negro, la tiña está sanada; él está limpio, y por limpio lo dará el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 38, 'Asimismo el hombre ó mujer, cuando en la piel de su carne tuviere manchas, manchas blancas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 39, 'El sacerdote mirará: y si en la piel de su carne parecieren manchas blancas algo oscurecidas, es empeine que brotó en la piel, está limpia la persona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 40, 'Y el hombre, cuando se le pelare la cabeza, es calvo, mas limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 41, 'Y si á la parte de su rostro se le pelare la cabeza, es calvo por delante, pero limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 42, 'Mas cuando en la calva ó en la antecalva hubiere llaga blanca rojiza, lepra es que brota en su calva ó en su antecalva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 43, 'Entonces el sacerdote lo mirará, y si pareciere la hinchazón de la llaga blanca rojiza en su calva ó en su antecalva, como el parecer de la lepra de la tez de la carne,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 44, 'Leproso es, es inmundo; el sacerdote lo dará luego por inmundo; en su cabeza tiene su llaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 45, 'Y el leproso en quien hubiere llaga, sus vestidos serán deshechos y su cabeza descubierta, y embozado pregonará: ¡Inmundo! ¡inmundo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 46, 'Todo el tiempo que la llaga estuviere en él, será inmundo; estará impuro: habitará solo; fuera del real será su morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 47, 'Y cuando en el vestido hubiere plaga de lepra, en vestido de lana, ó en vestido de lino;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 48, 'O en estambre ó en trama, de lino ó de lana, ó en piel, ó en cualquiera obra de piel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 49, 'Y que la plaga sea verde, ó bermeja, en vestido ó en piel, ó en estambre, ó en trama, ó en cualquiera obra de piel; plaga es de lepra, y se ha de mostrar al sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 50, 'Y el sacerdote mirará la plaga, y encerrará la cosa plagada por siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 51, 'Y al séptimo día mirará la plaga: y si hubiere cundido la plaga en el vestido, ó estambre, ó en la trama, ó en piel, ó en cualquiera obra que se hace de pieles, lepra roedora es la plaga; inmunda será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 52, 'Será quemado el vestido, ó estambre ó trama, de lana ó de lino, ó cualquiera obra de pieles en que hubiere tal plaga; porque lepra roedora es; al fuego será quemada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 53, 'Y si el sacerdote mirare, y no pareciere que la plaga se haya extendido en el vestido, ó estambre, ó en la trama, ó en cualquiera obra de pieles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 54, 'Entonces el sacerdote mandará que laven donde está la plaga, y lo encerrará otra vez por siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 55, 'Y el sacerdote mirará después que la plaga fuere lavada; y si pareciere que la plaga no ha mudado su aspecto, bien que no haya cundido la plaga, inmunda es; la quemarás al fuego; corrosión es penetrante, esté lo raído en la haz ó en el revés de aquella cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 56, 'Mas si el sacerdote la viere, y pareciere que la plaga se ha oscurecido después que fué lavada, la cortará del vestido, ó de la piel, ó del estambre, ó de la trama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 57, 'Y si apareciere más en el vestido, ó estambre, ó trama, ó en cualquiera cosa de pieles, reverdeciendo en ella, quemarás al fuego aquello donde estuviere la plaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 58, 'Empero el vestido, ó estambre, ó trama, ó cualquiera cosa de piel que lavares, y que se le quitare la plaga, lavarse ha segunda vez, y entonces será limpia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 13, 59, 'Esta es la ley de la plaga de la lepra del vestido de lana ó de lino, ó del estambre, ó de la trama, ó de cualquiera cosa de piel, para que sea dada por limpia ó por inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 2, 'Esta será la ley del leproso cuando se limpiare: Será traído al sacerdote:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 3, 'Y el sacerdote saldrá fuera del real; y mirará el sacerdote, y viendo que está sana la plaga de la lepra del leproso,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 4, 'El sacerdote mandará luego que se tomen para el que se purifica dos avecillas vivas, limpias, y palo de cedro, y grana, é hisopo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 5, 'Y mandará el sacerdote matar la una avecilla en un vaso de barro sobre aguas vivas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 6, 'Después tomará la avecilla viva, y el palo de cedro, y la grana, y el hisopo, y lo mojará con la avecilla viva en la sangre de la avecilla muerta sobre las aguas vivas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 7, 'Y rociará siete veces sobre el que se purifica de la lepra, y le dará por limpio; y soltará la avecilla viva sobre la haz del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 8, 'Y el que se purifica lavará sus vestidos, y raerá todos sus pelos, y se ha de lavar con agua, y será limpio: y después entrará en el real, y morará fuera de su tienda siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 9, 'Y será, que al séptimo día raerá todos sus pelos, su cabeza, y su barba, y las cejas de sus ojos; finalmente, raerá todo su pelo, y lavará sus vestidos, y lavará su carne en aguas, y será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 10, 'Y el día octavo tomará dos corderos sin defecto, y una cordera de un año sin tacha; y tres décimas de flor de harina para presente amasada con aceite, y un log de aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 11, 'Y el sacerdote que le purifica presentará con aquellas cosas al que se ha de limpiar delante de Jehová, á la puerta del tabernáculo del testimonio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 12, 'Y tomará el sacerdote el un cordero, y ofrecerálo por la culpa, con el log de aceite, y lo mecerá como ofrenda agitada delante de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 13, 'Y degollará el cordero en el lugar donde degüellan la víctima por el pecado y el holocausto, en el lugar del santuario: porque como la víctima por el pecado, así también la víctima por la culpa es del sacerdote: es cosa muy sagrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 14, 'Y tomará el sacerdote de la sangre de la víctima por la culpa, y pondrá el sacerdote sobre la ternilla de la oreja derecha del que se purifica, y sobre el pulgar de su mano derecha, y sobre el pulgar de su pie derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 15, 'Asimismo tomará el sacerdote del log de aceite, y echará sobre la palma de su mano izquierda:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 16, 'Y mojará su dedo derecho en el aceite que tiene en su mano izquierda, y esparcirá del aceite con su dedo siete veces delante de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 17, 'Y de lo que quedare del aceite que tiene en su mano, pondrá el sacerdote sobre la ternilla de la oreja derecha del que se purifica, y sobre el pulgar de su mano derecha, y sobre el pulgar de su pie derecho, sobre la sangre de la expiación por la culpa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 18, 'Y lo que quedare del aceite que tiene en su mano, pondrá sobre la cabeza del que se purifica: y hará el sacerdote expiación por él delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 19, 'Ofrecerá luego el sacerdote el sacrificio por el pecado, y hará expiación por el que se ha de purificar de su inmundicia, y después degollará el holocausto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 20, 'Y hará subir el sacerdote el holocausto y el presente sobre el altar. Así hará el sacerdote expiación por él, y será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 21, 'Mas si fuere pobre, que no alcanzare su mano á tanto, entonces tomará un cordero para ser ofrecido como ofrenda agitada por la culpa, para reconciliarse, y una décima de flor de harina amasada con aceite para presente, y un log de aceite;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 22, 'Y dos tórtolas, ó dos palominos, lo que alcanzare su mano: y el uno será para expiación por el pecado, y el otro para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 23, 'Las cuales cosas traerá al octavo día de su purificación al sacerdote, á la puerta del tabernáculo del testimonio delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 24, 'Y el sacerdote tomará el cordero de la expiación por la culpa, y el log de aceite, y mecerálo el sacerdote como ofrenda agitada delante de Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 25, 'Luego degollará el cordero de la culpa, y tomará el sacerdote de la sangre de la culpa, y pondrá sobre la ternilla de la oreja derecha del que se purifica, y sobre el pulgar de su mano derecha, y sobre el pulgar de su pie derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 26, 'Y el sacerdote echará del aceite sobre la palma de su mano izquierda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 27, 'Y con su dedo derecho rociará el sacerdote del aceite que tiene en su mano izquierda, siete veces delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 28, 'También pondrá el sacerdote del aceite que tiene en su mano sobre la ternilla de la oreja derecha del que se purifica, y sobre el pulgar de su mano derecha, y sobre el pulgar de su pie derecho, en el lugar de la sangre de la culpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 29, 'Y lo que sobrare del aceite que el sacerdote tiene en su mano, pondrálo sobre la cabeza del que se purifica, para reconciliarlo delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 30, 'Asimismo ofrecerá la una de las tórtolas, ó de los palominos, lo que alcanzare su mano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 31, 'El uno de lo que alcanzare su mano, en expiación por el pecado, y el otro en holocausto, además del presente: y hará el sacerdote expiación por el que se ha de purificar, delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 32, 'Esta es la ley del que hubiere tenido plaga de lepra, cuya mano no alcanzare lo prescrito para purificarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 33, 'Y habló Jehová á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 34, 'Cuando hubieres entrado en la tierra de Canaán, la cual yo os doy en posesión, y pusiere yo plaga de lepra en alguna casa de la tierra de vuestra posesión,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 35, 'Vendrá aquél cuya fuere la casa, y dará aviso al sacerdote, diciendo: Como plaga ha aparecido en mi casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 36, 'Entonces mandará el sacerdote, y despejarán la casa antes que el sacerdote entre á mirar la plaga, por que no sea contaminado todo lo que estuviere en la casa: y después el sacerdote entrará á reconocer la casa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 37, 'Y mirará la plaga: y si se vieren manchas en las paredes de la casa, cavernillas verdosas ó rojas, las cuales parecieren más hundidas que la pared,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 38, 'El sacerdote saldrá de la casa á la puerta de ella, y cerrará la casa por siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 39, 'Y al séptimo día volverá el sacerdote, y mirará: y si la plaga hubiere crecido en las paredes de la casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 40, 'Entonces mandará el sacerdote, y arrancarán las piedras en que estuviere la plaga, y las echarán fuera de la ciudad, en lugar inmundo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 41, 'Y hará descostrar la casa por dentro alrededor, y derramarán el polvo que descostraren fuera de la ciudad en lugar inmundo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 42, 'Y tomarán otras piedras, y las pondrán en lugar de las piedras quitadas; y tomarán otro barro, y encostrarán la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 43, 'Y si la plaga volviere á reverdecer en aquella casa, después que hizo arrancar las piedras, y descostrar la casa, y después que fue encostrada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 44, 'Entonces el sacerdote entrará y mirará; y si pareciere haberse extendido la plaga en la casa, lepra roedora está en la casa: inmunda es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 45, 'Derribará, por tanto, la tal casa, sus piedras, y sus maderos, y toda la mezcla de la casa; y lo sacará fuera de la ciudad á lugar inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 46, 'Y cualquiera que entrare en aquella casa todos los días que la mandó cerrar, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 47, 'Y el que durmiere en aquella casa, lavará sus vestidos; también el que comiere en la casa, lavará sus vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 48, 'Mas si entrare el sacerdote y mirare, y viere que la plaga no se ha extendido en la casa después que fue encostrada, el sacerdote dará la casa por limpia, porque la plaga ha sanado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 49, 'Entonces tomará para limpiar la casa dos avecillas, y palo de cedro, y grana, é hisopo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 50, 'Y degollará la una avecilla en una vasija de barro sobre aguas vivas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 51, 'Y tomará el palo de cedro, y el hisopo, y la grana, y la avecilla viva, y mojarálo en la sangre de la avecilla muerta y en las aguas vivas, y rociará la casa siete veces:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 52, 'Y purificará la casa con la sangre de la avecilla, y con las aguas vivas, y con la avecilla viva, y el palo de cedro, y el hisopo, y la grana:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 53, 'Luego soltará la avecilla viva fuera de la ciudad sobre la haz del campo: Así hará expiación por la casa, y será limpia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 54, 'Esta es la ley acerca de toda plaga de lepra, y de tiña;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 55, 'Y de la lepra del vestido, y de la casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 56, 'Y acerca de la hinchazón, y de la postilla, y de la mancha blanca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 14, 57, 'Para enseñar cuándo es inmundo, y cuándo limpio. Aquesta es la ley tocante á la lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 1, 'Y HABLO Jehová á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 2, 'Hablad á los hijos de Israel, y decidles: Cualquier varón, cuando su simiente manare de su carne, será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 3, 'Y esta será su inmundicia en su flujo; sea que su carne destiló por causa de su flujo, ó que su carne se obstruyó á causa de su flujo, él será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 4, 'Toda cama en que se acostare el que tuviere flujo, será inmunda; y toda cosa sobre que se sentare, inmunda será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 5, 'Y cualquiera que tocare á su cama, lavará sus vestidos; lavaráse también á sí mismo con agua, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 6, 'Y el que se sentare sobre aquello en que se hubiere sentado el que tiene flujo, lavará sus vestidos, se lavará también á sí mismo con agua, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 7, 'Asimismo el que tocare la carne del que tiene flujo, lavará sus vestidos, y á sí mismo se lavará con agua, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 8, 'Y si el que tiene flujo escupiere sobre el limpio, éste lavará sus vestidos, y después de haberse lavado con agua, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 9, 'Y toda aparejo sobre que cabalgare el que tuviere flujo, será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 10, 'Y cualquiera que tocare cualquiera cosa que haya estado debajo de él, será inmundo hasta la tarde; y el que la llevare, lavará sus vestidos, y después de lavarse con agua, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 11, 'Y todo aquel á quien tocare el que tiene flujo, y no lavare con agua sus manos, lavará sus vestidos, y á sí mismo se lavará con agua, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 12, 'Y la vasija de barro en que tocare el que tiene flujo, será quebrada; y toda vasija de madera será lavada con agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 13, 'Y cuando se hubiere limpiado de su flujo el que tiene flujo, se ha de contar siete días desde su purificación, y lavará sus vestidos, y lavará su carne en aguas vivas, y será limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 14, 'Y el octavo día tomará dos tórtolas, ó dos palominos, y vendrá delante de Jehová á la puerta del tabernáculo del testimonio, y los dará al sacerdote:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 15, 'Y harálos el sacerdote, el uno ofrenda por el pecado, y el otro holocausto: y le purificará el sacerdote de su flujo delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 16, 'Y el hombre, cuando de él saliere derramamiento de semen, lavará en aguas toda su carne, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 17, 'Y toda vestimenta, ó toda piel sobre la cual hubiere el derramamiento del semen, lavaráse con agua, y será inmunda hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 18, 'Y la mujer con quien el varón tuviera ayuntamiento de semen, ambos se lavarán con agua, y serán inmundos hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 19, 'Y cuando la mujer tuviere flujo de sangre, y su flujo fuere en su carne, siete días estará apartada; y cualquiera que tocare en ella, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 20, 'Y todo aquello sobre que ella se acostare mientras su separación, será inmundo: también todo aquello sobre que se sentare, será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 21, 'Y cualquiera que tocare á su cama, lavará sus vestidos, y después de lavarse con agua, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 22, 'También cualquiera que tocare cualquier mueble sobre que ella se hubiere sentado, lavará sus vestidos; lavaráse luego á sí mismo con agua, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 23, 'Y si estuviere sobre la cama, ó sobre la silla en que ella se hubiere sentado, el que tocare en ella será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 24, 'Y si alguno durmiere con ella, y su menstruo fuere sobre él, será inmundo por siete días; y toda cama sobre que durmiere, será inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 25, 'Y la mujer, cuando siguiere el flujo de su sangre por muchos días fuera del tiempo de su costumbre, ó cuando tuviere flujo de sangre más de su costumbre; todo el tiempo del flujo de su inmundicia, será inmunda como en los días de su costumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 26, 'Toda cama en que durmiere todo el tiempo de su flujo, le será como la cama de su costumbre; y todo mueble sobre que se sentare, será inmundo, como la inmundicia de su costumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 27, 'Cualquiera que tocare en esas cosas será inmundo; y lavará sus vestidos, y á sí mismo se lavará con agua, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 28, 'Y cuando fuere libre de su flujo, se ha de contar siete días, y después será limpia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 29, 'Y el octavo día tomará consigo dos tórtolas, ó dos palominos, y los traerá al sacerdote, á la puerta del tabernáculo del testimonio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 30, 'Y el sacerdote hará el uno ofrenda por el pecado, y el otro holocausto; y la purificará el sacerdote delante de Jehová del flujo de su inmundicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 31, 'Así apartaréis los hijos de Israel de sus inmundicias, á fin de que no mueran por sus inmundicias, ensuciando mi tabernáculo que está entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 32, 'Esta es la ley del que tiene flujo, y del que sale derramamiento de semen, viniendo á ser inmundo á causa de ello;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 15, 33, 'Y de la que padece su costumbre, y acerca del que tuviere flujo, sea varón ó hembra, y del hombre que durmiere con mujer inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 1, 'Y HABLO Jehová á Moisés, después que murieron los dos hijos de Aarón, cuando se llegaron delante de Jehová, y murieron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 2, 'Y Jehová dijo á Moisés: Di á Aarón tu hermano, que no en todo tiempo entre en el santuario del velo adentro, delante de la cubierta que está sobre el arca, para que no muera: porque yo apareceré en la nube sobre la cubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 3, 'Con esto entrará Aarón en el santuario: con un becerro por expiación, y un carnero en holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 4, 'La túnica santa de lino se vestirá, y sobre su carne tendrá pañetes de lino, y ceñiráse el cinto de lino; y con la mitra de lino se cubrirá: son las santas vestiduras: con ellas, después de lavar su carne con agua, se ha de vestir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 5, 'Y de la congregación de los hijos de Israel tomará dos machos de cabrío para expiación, y un carnero para holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 6, 'Y hará allegar Aarón el becerro de la expiación, que es suyo, y hará la reconciliación por sí y por su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 7, 'Después tomará los dos machos de cabrío, y los presentará delante de Jehová á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 8, 'Y echará suertes Aarón sobre los dos machos de cabrío; la una suerte por Jehová, y la otra suerte por Azazel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 9, 'Y hará allegar Aarón el macho cabrío sobre el cual cayere la suerte por Jehová, y ofrecerálo en expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 10, 'Mas el macho cabrío, sobre el cual cayere la suerte por Azazel, lo presentará vivo delante de Jehová, para hacer la reconciliación sobre él, para enviarlo á Azazel al desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 11, 'Y hará llegar Aarón el becerro que era suyo para expiación, y hará la reconciliación por sí y por su casa, y degollará en expiación el becerro que es suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 12, 'Después tomará el incensario lleno de brasas de fuego, del altar de delante de Jehová, y sus puños llenos del perfume aromático molido, y meterálo del velo adentro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 13, 'Y pondrá el perfume sobre el fuego delante de Jehová, y la nube del perfume cubrirá la cubierta que está sobre el testimonio, y no morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 14, 'Tomará luego de la sangre del becerro, y rociará con su dedo hacia la cubierta al lado oriental: hacia la cubierta esparcirá siete veces de aquella sangre con su dedo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 15, 'Después degollará en expiación el macho cabrío, que era del pueblo, y meterá la sangre de él del velo adentro; y hará de su sangre como hizo de la sangre del becerro, y esparcirá sobre la cubierta y delante de la cubierta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 16, 'Y limpiará el santuario, de las inmundicias de los hijos de Israel, y de sus rebeliones, y de todos sus pecados: de la misma manera hará también al tabernáculo del testimonio, el cual reside entre ellos en medio de sus inmundicias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 17, 'Y ningún hombre estará en el tabernáculo del testimonio cuando él entrare á hacer la reconciliación en el santuario, hasta que él salga, y haya hecho la reconciliación por sí, y por su casa, y por toda la congregación de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 18, 'Y saldrá al altar que está delante de Jehová, y lo expiará; y tomará de la sangre del becerro, y de la sangre del macho cabrío, y pondrá sobre los cuernos del altar alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 19, 'Y esparcirá sobre él de la sangre con su dedo siete veces, y lo limpiará, y lo santificará de las inmundicias de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 20, 'Y cuando hubiere acabado de expiar el santuario, y el tabernáculo del testimonio, y el altar, hará llegar el macho cabrío vivo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 21, 'Y pondrá Aarón ambas manos suyas sobre la cabeza del macho cabrío vivo, y confesará sobre él todas las iniquidades de los hijos de Israel, y todas sus rebeliones, y todos sus pecados, poniéndolos así sobre la cabeza del macho cabrío, y lo enviará al desierto por mano de un hombre destinado para esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 22, 'Y aquel macho cabrío llevará sobre sí todas las iniquidades de ellos á tierra inhabitada: y dejará ir el macho cabrío por el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 23, 'Después vendrá Aarón al tabernáculo del testimonio, y se desnudará las vestimentas de lino, que había vestido para entrar en el santuario, y pondrálas allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 24, 'Lavará luego su carne con agua en el lugar del santuario, y después de ponerse sus vestidos saldrá, y hará su holocausto, y el holocausto del pueblo, y hará la reconciliación por sí y por el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 25, 'Y quemará el sebo de la expiación sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 26, 'Y el que hubiere llevado el macho cabrío á Azazel, lavará sus vestidos, lavará también con agua su carne, y después entrará en el real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 27, 'Y sacará fuera del real el becerro del pecado, y el macho cabrío de la culpa, la sangre de los cuales fué metida para hacer la expiación en el santuario; y quemarán en el fuego sus pellejos, y sus carnes, y su estiércol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 28, 'Y el que los quemare, lavará sus vestidos, lavará también su carne con agua, y después entrará en el real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 29, 'Y esto tendréis por estatuto perpetuo: En el mes séptimo, á los diez del mes, afligiréis vuestras almas, y ninguna obra haréis, ni el natural ni el extranjero que peregrina entre vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 30, 'Porque en este día se os reconciliará para limpiaros; y seréis limpios de todos vuestros pecados delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 31, 'Sábado de reposo es para vosotros, y afligiréis vuestras almas, por estatuto perpetuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 32, 'Y hará la reconciliación el sacerdote que fuere ungido, y cuya mano hubiere sido llena para ser sacerdote en lugar de su padre; y se vestirá las vestimentas de lino, las vestiduras sagradas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 33, 'Y expiará el santuario santo, y el tabernáculo del testimonio; expiará también el altar, y á los sacerdotes, y á todo el pueblo de la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 16, 34, 'Y esto tendréis por estatuto perpetuo, para expiar á los hijos de Israel de todos sus pecados una vez en el año. Y Moisés lo hizo como Jehová le mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 2, 'Habla á Aarón y á sus hijos, y á todos los hijos de Israel, y diles: Esto es lo que ha mandado Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 3, 'Cualquier varón de la casa de Israel que degollare buey, ó cordero, ó cabra, en el real, ó fuera del real,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 4, 'Y no lo trajere á la puerta del tabernáculo del testimonio, para ofrecer ofrenda á Jehová delante del tabernáculo de Jehová, sangre será imputada al tal varón: sangre derramó; cortado será el tal varón de entre su pueblo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 5, 'A fin de que traigan los hijos de Israel sus sacrificios, los que sacrifican sobre la haz del campo, para que los traigan á Jehová á la puerta del tabernáculo del testimonio al sacerdote, y sacrifiquen ellos sacrificios de paces á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 6, 'Y el sacerdote esparcirá la sangre sobre el altar de Jehová, á la puerta del tabernáculo del testimonio, y quemará el sebo en olor de suavidad á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 7, 'Y nunca más sacrificarán sus sacrificios á los demonios, tras de los cuales han fornicado: tendrán esto por estatuto perpetuo por sus edades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 8, 'Les dirás también: Cualquier varón de la casa de Israel, ó de los extranjeros que peregrinan entre vosotros, que ofreciere holocausto ó sacrificio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 9, 'Y no lo trajere á la puerta del tabernáculo del testimonio, para hacerlo á Jehová, el tal varón será igualmente cortado de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 10, 'Y cualquier varón de la casa de Israel, ó de los extranjeros que peregrinan entre ellos, que comiere alguna sangre, yo pondré mi rostro contra la persona que comiere sangre, y le cortaré de entre su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 11, 'Porque la vida de la carne en la sangre está: y yo os la he dado para expiar vuestras personas sobre el altar: por lo cual la misma sangre expiará la persona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 12, 'Por tanto, he dicho á los hijos de Israel: Ninguna persona de vosotros comerá sangre, ni el extranjero que peregrina entre vosotros comerá sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 13, 'Y cualquier varón de los hijos de Israel, ó de los extranjeros que peregrinan entre ellos, que cogiere caza de animal ó de ave que sea de comer, derramará su sangre y cubrirála con tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 14, 'Porque el alma de toda carne, su vida, está en su sangre: por tanto he dicho á los hijos de Israel: No comeréis la sangre de ninguna carne, porque la vida de toda carne es su sangre; cualquiera que la comiere será cortado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 15, 'Y cualquiera persona que comiere cosa mortecina ó despedazada por fiera, así de los naturales como de los extranjeros, lavará sus vestidos y á sí mismo se lavará con agua, y será inmundo hasta la tarde; y se limpiará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 17, 16, 'Y si no los lavare, ni lavare su carne, llevará su iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 2, 'Habla á los hijos de Israel, y diles: Yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 3, 'No haréis como hacen en la tierra de Egipto, en la cual morasteis; ni haréis como hacen en la tierra de Canaán, á la cual yo os conduzco; ni andaréis en sus estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 4, 'Mis derechos pondréis por obra, y mis estatutos guardaréis, andando en ellos: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 5, 'Por tanto mis estatutos y mis derechos guardaréis, los cuales haciendo el hombre, vivirá en ellos: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 6, 'Ningún varón se allegue á ninguna cercana de su carne, para descubrir su desnudez: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 7, 'La desnudez de tu padre, ó la desnudez de tu madre, no descubrirás: tu madre es, no descubrirás su desnudez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 8, 'La desnudez de la mujer de tu padre no descubrirás; es la desnudez de tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 9, 'La desnudez de tu hermana, hija de tu padre, ó hija de tu madre, nacida en casa ó nacida fuera, su desnudez no descubrirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 10, 'La desnudez de la hija de tu hijo, ó de la hija de tu hija, su desnudez no descubirás, porque es la desnudez tuya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 11, 'La desnudez de la hija de la mujer de tu padre, engendrada de tu padre, tu hermana es, su desnudez no descubrirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 12, 'La desnudez de la hermana de tu padre no descubrirás: es parienta de tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 13, 'La desnudez de la hermana de tu madre no descubrirás: porque parienta de tu madre es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 14, 'La desnudez del hermano de tu padre no descubrirás: no llegarás á su mujer: es mujer del hermano de tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 15, 'La desnudez de tu nuera no descubrirás: mujer es de tu hijo, no descubrirás su desnudez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 16, 'La desnudez de la mujer de tu hermano no descubrirás: es la desnudez de tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 17, 'La desnudez de la mujer y de su hija no descubrirás: no tomarás la hija de su hijo, ni la hija de su hija, para descubrir su desnudez: son parientas, es maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 18, 'No tomarás mujer juntamente con su hermana, para hacerla su rival, descubriendo su desnudez delante de ella en su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 19, 'Y no llegarás á la mujer en el apartamiento de su inmundicia, para descubrir su desnudez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 20, 'Además, no tendrás acto carnal con la mujer de tu prójimo, contaminándote en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 21, 'Y no des de tu simiente para hacerla pasar por el fuego á Moloch; no contamines el nombre de tu Dios: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 22, 'No te echarás con varón como con mujer: es abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 23, 'Ni con ningún animal tendrás ayuntamiento amancillándote con él; ni mujer alguna se pondrá delante de animal para ayuntarse con él: es confusión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 24, 'En ninguna de estas cosas os amancillaréis; porque en todas estas cosas se han ensuciado las gentes que yo echo de delante de vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 25, 'Y la tierra fue contaminada; y yo visité su maldad sobre ella, y la tierra vomitó sus moradores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 26, 'Guardad, pues, vosotros mis estatutos y mis derechos, y no hagáis ninguna de todas estas abominaciones: ni el natural ni el extranjero que peregrina entre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 27, '(Porque todas estas abominaciones hicieron los hombres de la tierra, que fueron antes de vosotros, y la tierra fue contaminada:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 28, 'Y la tierra no os vomitará, por haberla contaminado, como vomitó á la gente que fué antes de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 29, 'Porque cualquiera que hiciere alguna de todas estas abominaciones, las personas que las hicieren, serán cortadas de entre su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 18, 30, 'Guardad, pues, mi ordenanza, no haciendo de las prácticas abominables que tuvieron lugar antes de vosotros, y no os ensuciéis en ellas: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 2, 'Habla á toda la congregación de los hijos de Israel, y diles: Santos seréis, porque santo soy yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 3, 'Cada uno temerá á su madre y á su padre, y mis sábados guardaréis: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 4, 'No os volveréis á los ídolos, ni haréis para vosotros dioses de fundición: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 5, 'Y cuando sacrificareis sacrificio de paces á Jehová, de vuestra voluntad lo sacrificaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 6, 'Será comido el día que lo sacrificareis, y el siguiente día: y lo que quedare para el tercer día, será quemado en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 7, 'Y si se comiere el día tercero, será abominación; no será acepto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 8, 'Y el que lo comiere, llevará su delito, por cuanto profanó lo santo de Jehová; y la tal persona será cortada de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 9, 'Cuando segareis la mies de vuestra tierra, no acabarás de segar el rincón de tu haza, ni espigarás tu tierra segada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 10, 'Y no rebuscarás tu viña, ni recogerás los granos caídos de tu viña; para el pobre y para el extranjero los dejarás: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 11, 'No hurtaréis, y no engañaréis, ni mentiréis ninguno á su prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 12, 'Y no juraréis en mi nombre con mentira, ni profanarás el nombre de tu Dios: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 13, 'No oprimirás á tu prójimo, ni le robarás. No se detendrá el trabajo del jornalero en tu casa hasta la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 14, 'No maldigas al sordo, y delante del ciego no pongas tropiezo, mas tendrás temor de tu Dios: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 15, 'No harás agravio en el juicio: no tendrás respeto al pobre, ni honrarás la cara del grande: con justicia juzgarás á tu prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 16, 'No andarás chismeando en tus pueblos. No te pondrás contra la sangre de tu prójimo: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 17, 'No aborrecerás á tu hermano en tu corazón: ingenuamente reprenderás á tu prójimo, y no consentirás sobre él pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 18, 'No te vengarás, ni guardarás rencor á los hijos de tu pueblo: mas amarás á tu prójimo como á ti mismo: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 19, 'Mis estatutos guardaréis. A tu animal no harás ayuntar para misturas; tu haza no sembrarás con mistura de semillas, y no te pondrás vestidos con mezcla de diversas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 20, 'Y cuando un hombre tuviere cópula con mujer, y ella fuere sierva desposada con alguno, y no estuviere rescatada, ni le hubiere sido dada libertad, ambos serán azotados: no morirán, por cuanto ella no es libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 21, 'Y él traerá á Jehová, á la puerta del tabernáculo del testimonio, un carnero en expiación por su culpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 22, 'Y con el carnero de la expiación lo reconciliará el sacerdote delante de Jehová, por su pecado que cometió: y se le perdonará su pecado que ha cometido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 23, 'Y cuando hubiereis entrado en la tierra, y plantareis todo árbol de comer, quitaréis su prepucio, lo primero de su fruto: tres años os será incircunciso: su fruto no se comerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 24, 'Y el cuarto año todo su fruto será santidad de loores á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 25, 'Mas al quinto año comeréis el fruto de él, para que os haga crecer su fruto: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 26, 'No comeréis cosa alguna con sangre. No seréis agoreros, ni adivinaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 27, 'No cortaréis en redondo las extremidades de vuestras cabezas, ni dañarás la punta de tu barba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 28, 'Y no haréis rasguños en vuestra carne por un muerto, ni imprimiréis en vosotros señal alguna: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 29, 'No contaminarás tu hija haciéndola fornicar: porque no se prostituya la tierra, y se hincha de maldad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 30, 'Mis sábados guardaréis, y mi santuario tendréis en reverencia: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 31, 'No os volváis á los encantadores y á los adivinos: no los consultéis ensuciándoos con ellos: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 32, 'Delante de las canas te levantarás, y honrarás el rostro del anciano, y de tu Dios tendrás temor: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 33, 'Y cuando el extranjero morare contigo en vuestra tierra, no le oprimiréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 34, 'Como á un natural de vosotros tendréis al extranjero que peregrinare entre vosotros; y ámalo como á ti mismo; porque peregrinos fuisteis en la tierra de Egipto: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 35, 'No hagáis agravio en juicio, en medida de tierra, ni en peso, ni en otra medida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 36, 'Balanzas justas, pesas justas, epha justo, é hin justo tendréis: Yo Jehová vuestro Dios, que os saqué de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 19, 37, 'Guardad pues todos mis estatutos, y todos mis derechos, y ponedlos por obra: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 1, 'Y HABLO Jehová á Moisés diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 2, 'Dirás asimismo á los hijos de Israel: Cualquier varón de los hijos de Israel, ó de los extranjeros que peregrinan en Israel, que diere de su simiente á Moloch, de seguro morirá: el pueblo de la tierra lo apedreará con piedras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 3, 'Y yo pondré mi rostro contra el tal varón, y lo cortaré de entre su pueblo; por cuanto dió de su simiente á Moloch, contaminando mi santuario, y amancillando mi santo nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 4, 'Que si escondiere el pueblo de la tierra sus ojos de aquel varón que hubiere dado de su simiente á Moloch, para no matarle,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 5, 'Entonces yo pondré mi rostro contra aquel varón, y contra su familia, y le cortaré de entre su pueblo, con todos los que fornicaron en pos de él, prostituyéndose con Moloch.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 6, 'Y la persona que atendiere á encantadores ó adivinos, para prostituirse tras de ellos, yo pondré mi rostro contra la tal persona, y cortaréla de entre su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 7, 'Santificaos, pues, y sed santos, porque yo Jehová soy vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 8, 'Y guardad mis estatutos, y ponedlos por obra: Yo Jehová que os santifico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 9, 'Porque varón que maldijere á su padre ó á su madre, de cierto morirá: á su padre ó á su madre maldijo; su sangre será sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 10, 'Y el hombre que adulterare con la mujer de otro, el que cometiere adulterio con la mujer de su prójimo, indefectiblemente se hará morir al adúltero y á la adúltera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 11, 'Y cualquiera que se echare con la mujer de su padre, la desnudez de su padre descubrió; ambos han de ser muertos; su sangre será sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 12, 'Y cualquiera que durmiere con su nuera, ambos han de morir: hicieron confusión; su sangre será sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 13, 'Y cualquiera que tuviere ayuntamiento con varón como con mujer, abominación hicieron: entrambos han de ser muertos; sobre ellos será su sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 14, 'Y el que tomare mujer y á la madre de ella, comete vileza: quemarán en fuego á él y á ellas, porque no haya vileza entre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 15, 'Y cualquiera que tuviere cópula con bestia, ha de ser muerto; y mataréis á la bestia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 16, 'Y la mujer que se allegare á algún animal, para tener ayuntamiento con él, á la mujer y al animal matarás: morirán infaliblemente; será su sangre sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 17, 'Y cualquiera que tomare á su hermana, hija de su padre ó hija de su madre, y viere su desnudez, y ella viere la suya, cosa es execrable; por tanto serán muertos á ojos de los hijos de su pueblo: descubrió la desnudez de su hermana; su pecado llevará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 18, 'Y cualquiera que durmiere con mujer menstruosa, y descubriere su desnudez, su fuente descubrió, y ella descubrió la fuente de su sangre: ambos serán cortados de entre su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 19, 'La desnudez de la hermana de tu madre, ó de la hermana de tu padre, no descubrirás: por cuanto descubrió su parienta, su iniquidad llevarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 20, 'Y cualquiera que durmiere con la mujer del hermano de su padre, la desnudez del hermano de su padre descubrió; su pecado llevarán; morirán sin hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 21, 'Y el que tomare la mujer de su hermano, es suciedad; la desnudez de su hermano descubrió; sin hijos serán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 22, 'Guardad, pues, todos mis estatutos y todos mis derechos, y ponedlos por obra: y no os vomitará la tierra, en la cual yo os introduzco para que habitéis en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 23, 'Y no andéis en las prácticas de la gente que yo echaré de delante de vosotros: porque ellos hicieron todas estas cosas, y los tuve en abominación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 24, 'Empero á vosotros os he dicho: Vosotros poseeréis la tierra de ellos, y yo os la daré para que la poseáis por heredad, tierra que fluye leche y miel: Yo Jehová vuestro Dios, que os he apartado de los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 25, 'Por tanto, vosotros haréis diferencia entre animal limpio é inmundo, y entre ave inmunda y limpia: y no ensuciéis vuestras personas en los animales, ni en las aves, ni en ninguna cosa que va arrastrando por la tierra, las cuales os he apartado por inmundas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 26, 'Habéis, pues, de serme santos, porque yo Jehová soy santo, y os he apartado de los pueblos, para que seáis míos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 20, 27, 'Y el hombre ó la mujer en quienes hubiere espíritu phitónico ó de adivinación, han de ser muertos: los apedrearán con piedras; su sangre sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 1, 'Y JEHOVA dijo á Moisés: Habla á los sacerdotes hijos de Aarón, y diles que no se contaminen por un muerto en sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 2, 'Mas por su pariente cercano á sí, por su madre, ó por su padre, ó por su hijo, ó por su hermano,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 3, 'O por su hermana virgen, á él cercana, la cual no haya tenido marido, por ella se contaminará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 4, 'No se contaminará, porque es príncipe en sus pueblos, haciéndose inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 5, 'No harán calva en su cabeza, ni raerán la punta de su barba, ni en su carne harán rasguños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 6, 'Santos serán á su Dios, y no profanarán el nombre de su Dios; porque los fuegos de Jehová y el pan de su Dios ofrecen: por tanto serán santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 7, 'Mujer ramera ó infame no tomarán: ni tomarán mujer repudiada de su marido: porque es santo á su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 8, 'Lo santificarás por tanto, pues el pan de tu Dios ofrece: santo será para ti, porque santo soy yo Jehová vuestro santificador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 9, 'Y la hija del varón sacerdote, si comenzare á fornicar, á su padre amancilla: quemada será al fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 10, 'Y el sumo sacerdote entre sus hermanos, sobre cuya cabeza fué derramado el aceite de la unción, y que hinchió su mano para vestir las vestimentas, no descubrirá su cabeza, ni romperá sus vestidos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 11, 'Ni entrará donde haya alguna persona muerta, ni por su padre, ó por su madre se contaminará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 12, 'Ni saldrá del santuario, ni contaminará el santuario de su Dios; porque la corona del aceite de la unción de su Dios está sobre él: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 13, 'Y tomará él mujer con su virginidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 14, 'Viuda, ó repudiada, ó infame, ó ramera, éstas no tomará: mas tomará virgen de sus pueblos por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 15, 'Y no amancillará su simiente en sus pueblos; porque yo Jehová soy el que los santifico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 16, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 17, 'Habla á Aarón, y dile: El varón de tu simiente en sus generaciones, en el cual hubiere falta, no se allegará para ofrecer el pan de su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 18, 'Porque ningún varón en el cual hubiere falta, se allegará: varón ciego, ó cojo, ó falto, ó sobrado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 19, 'O varón en el cual hubiere quebradura de pie ó rotura de mano,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 20, 'O corcobado, ó lagañoso, ó que tuviere nube en el ojo, ó que tenga sarna, ó empeine, ó compañón relajado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 21, 'Ningún varón de la simiente de Aarón sacerdote, en el cual hubiere falta, se allegará para ofrecer las ofrendas encendidas de Jehová. Hay falta en él; no se allegará á ofrecer el pan de su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 22, 'El pan de su Dios, de lo muy santo y las cosas santificadas, comerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 23, 'Empero no entrará del velo adentro, ni se allegará al altar, por cuanto hay falta en él: y no profanará mi santuario, porque yo Jehová soy el que los santifico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 21, 24, 'Y Moisés habló esto á Aarón, y á sus hijos, y á todos los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 2, 'Di á Aarón y á sus hijos, que se abstengan de las santificaciones de los hijos de Israel, y que no profanen mi santo nombre en lo que ellos me santifican: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 3, 'Diles: Todo varón de toda vuestra simiente en vuestras generaciones que llegare á las cosas sagradas, que los hijos de Israel consagran á Jehová, teniendo inmundicia sobre sí, de delante de mí será cortada su alma: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 4, 'Cualquier varón de la simiente de Aarón que fuere leproso, ó padeciere flujo, no comerá de las cosas sagradas hasta que esté limpio: y el que tocare cualquiera cosa inmunda de mortecino, ó el varón del cual hubiere salido derramamiento de semen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 5, 'O el varón que hubiere tocado cualquier reptil, por el cual será inmundo, ú hombre por el cual venga á ser inmundo, conforme á cualquiera inmundicia suya;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 6, 'La persona que lo tocare, será inmunda hasta la tarde, y no comerá de las cosas sagradas antes que haya lavado su carne con agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 7, 'Y cuando el sol se pusiere, será limpio; y después comerá las cosas sagradas, porque su pan es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 8, 'Mortecino ni despedazado por fiera no comerá, para contaminarse en ello: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 9, 'Guarden, pues, mi ordenanza, y no lleven pecado por ello, no sea que así mueran cuando la profanaren: Yo Jehová que los santifico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 10, 'Ningún extraño comerá cosa sagrada; el huésped del sacerdote, ni el jornalero, no comerá cosa sagrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 11, 'Mas el sacerdote, cuando comprare persona de su dinero, ésta comerá de ella, y el nacido en su casa: estos comerán de su pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 12, 'Empero la hija del sacerdote, cuando se casare con varón extraño, ella no comerá de la ofrenda de las cosas sagradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 13, 'Pero si la hija del sacerdote fuere viuda, ó repudiada, y no tuviere prole, y se hubiere vuelto á la casa de su padre, como en su mocedad, comerá del pan de su padre; mas ningún extraño coma de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 14, 'Y el que por yerro comiere cosa sagrada, añadirá á ella su quinto, y darálo al sacerdote con la cosa sagrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 15, 'No profanarán, pues, las cosas santas de los hijos de Israel, las cuales apartan para Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 16, 'Y no les harán llevar la iniquidad del pecado, comiendo las cosas santas de ellos: porque yo Jehová soy el que los santifico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 17, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 18, 'Habla á Aarón y á sus hijos, y á todos los hijos de Israel, y diles: Cualquier varón de la casa de Israel, ó de los extranjeros en Israel, que ofreciere su ofrenda por todos sus votos, y por todas sus voluntarias oblaciones que ofrecieren á Jehová en holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 19, 'De vuestra voluntad ofreceréis macho sin defecto de entre las vacas, de entre los corderos, ó de entre las cabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 20, 'Ninguna cosa en que haya falta ofreceréis, porque no será acepto por vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 21, 'Asimismo, cuando alguno ofreciere sacrificio de paces á Jehová para presentar voto, ú ofreciendo voluntariamente, sea de vacas ó de ovejas, sin tacha será acepto; no ha de haber en él falta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 22, 'Ciego, ó perniquebrado, ó mutilado, ó verrugoso, ó sarnoso ó roñoso, no ofreceréis éstos á Jehová, ni de ellos pondréis ofrenda encendida sobre el altar de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 23, 'Buey ó carnero que tenga de más ó de menos, podrás ofrecer por ofrenda voluntaria; mas por voto no será acepto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 24, 'Herido ó magullado, rompido ó cortado, no ofreceréis á Jehová, ni en vuestra tierra lo haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 25, 'Y de mano de hijo de extranjero no ofreceréis el pan de vuestro Dios de todas estas cosas; porque su corrupción está en ellas: hay en ellas falta, no se os aceptarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 26, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 27, 'El buey, ó el cordero, ó la cabra, cuando naciere, siete días estará mamando de su madre: mas desde el octavo día en adelante será acepto para ofrenda de sacrificio encendido a Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 28, 'Y sea buey ó carnero, no degollaréis en un día á el y á su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 29, 'Y cuando sacrificareis sacrificio de hacimiento de gracias á Jehová, de vuestra voluntad lo sacrificaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 30, 'En el mismo día se comerá; no dejaréis de él para otro día: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 31, 'Guardad pues mis mandamientos, y ejecutadlos: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 32, 'Y no amancilléis mi santo nombre, y yo me santificaré en medio de los hijos de Israel: Yo Jehová que os santifico;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 22, 33, 'Que os saqué de la tierra de Egipto, para ser vuestro Dios: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 2, 'Habla á los hijos de Israel, y diles: Las solemnidades de Jehová, las cuales proclamaréis santas convocaciones, aquestas serán mis solemnidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 3, 'Seis días se trabajará, y el séptimo día sábado de reposo será, convocación santa: ninguna obra haréis; sábado es de Jehová en todas vuestras habitaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 4, 'Estas son las solemnidades de Jehová, las convocaciones santas, á las cuales convocaréis en sus tiempos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 5, 'En el mes primero, á los catorce del mes, entre las dos tardes, pascua es de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 6, 'Y á los quince días de este mes es la solemnidad de los ázimos á Jehová: siete días comeréis ázimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 7, 'El primer día tendréis santa convocación: ningúna obra servil haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 8, 'Y ofreceréis á Jehová siete días ofrenda encendida: el séptimo día será santa convocación; ninguna obra servil haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 9, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 10, 'Habla á los hijos de Israel, y diles: Cuando hubiereis entrado en la tierra que yo os doy, y segareis su mies, traeréis al sacerdote un omer por primicia de los primeros frutos de vuestra siega;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 11, 'El cual mecerá el omer delante de Jehová, para que seáis aceptos: el siguiente día del sábado lo mecerá el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 12, 'Y el día que ofrezcáis el omer, ofreceréis un cordero de un año, sin defecto, en holocausto á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 13, 'Y su presente será dos décimas de flor de harina amasada con aceite, ofrenda encendida á Jehová en olor suavísimo; y su libación de vino, la cuarta parte de un hin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 14, 'Y no comeréis pan, ni grano tostado, ni espiga fresca, hasta este mismo día, hasta que hayáis ofrecido la ofrenda de vuestro Dios; estatuto perpetuo es por vuestras edades en todas vuestras habitaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 15, 'Y os habéis de contar desde el siguiente día del sábado, desde el día en que ofrecisteis el omer de la ofrenda mecida; siete semanas cumplidas serán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 16, 'Hasta el siguiente día del sábado séptimo contaréis cincuenta días; entonces ofreceréis nuevo presente a Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 17, 'De vuestras habitaciones traeréis dos panes para ofrenda mecida, que serán de dos décimas de flor de harina, cocidos con levadura, por primicias á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 18, 'Y ofreceréis con el pan siete corderos de un año sin defecto, y un becerro de la vacada y dos carneros: serán holocausto á Jehová, con su presente y sus libaciones; ofrenda encendida de suave olor á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 19, 'Ofreceréis además un macho de cabrío por expiación; y dos corderos de un año en sacrificio de paces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 20, 'Y el sacerdote los mecerá en ofrenda agitada delante de Jehová, con el pan de las primicias, y los dos corderos: serán cosa sagrada de Jehová para el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 21, 'Y convocaréis en este mismo día; os será santa convocación: ninguna obra servil haréis: estatuto perpetuo en todas vuestras habitaciones por vuestras edades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 22, 'Y cuando segareis la mies de vuestra tierra, no acabarás de segar el rincón de tu haza, ni espigarás tu siega; para el pobre, y para el extranjero la dejarás: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 23, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 24, 'Habla á los hijos de Israel, y diles: En el mes séptimo, al primero del mes tendréis sábado, una conmemoración al son de trompetas, y una santa convocación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 25, 'Ninguna obra servil haréis; y ofreceréis ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 26, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 27, 'Empero á los diez de este mes séptimo será el día de las expiaciones: tendréis santa convocación, y afligiréis vuestras almas, y ofreceréis ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 28, 'Ninguna obra haréis en este mismo día; porque es día de expiaciones, para reconciliaros delante de Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 29, 'Porque toda persona que no se afligiere en este mismo día, será cortada de sus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 30, 'Y cualquiera persona que hiciere obra alguna en este mismo día, yo destruiré la tal persona de entre su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 31, 'Ninguna obra haréis: estatuto perpetuo es por vuestras edades en todas vuestras habitaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 32, 'Sábado de reposo será á vosotros, y afligiréis vuestras almas, comenzando á los nueve del mes en la tarde: de tarde á tarde holgaréis vuestro sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 33, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 34, 'Habla á los hijos de Israel, y diles: A los quince días de este mes séptimo será la solemnidad de las cabañas á Jehová por siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 35, 'El primer día habrá santa convocación: ninguna obra servil haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 36, 'Siete días ofreceréis ofrenda encendida á Jehová: el octavo día tendréis santa convocación, y ofreceréis ofrenda encendida á Jehová: es fiesta: ninguna obra servil haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 37, 'Estas son las solemnidades de Jehová, á las que convocaréis santas reuniones, para ofrecer ofrenda encendida a Jehová, holocausto y presente, sacrificio y libaciones, cada cosa en su tiempo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 38, 'Además de los sábados de Jehová y además de vuestros dones, y á más de todos vuestros votos, y además de todas vuestras ofrendas voluntarias, que daréis á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 39, 'Empero á los quince del mes séptimo, cuando hubiereis allegado el fruto de la tierra, haréis fiesta a Jehová por siete días: el primer día será sábado; sábado será también el octavo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 40, 'Y tomaréis el primer día gajos con fruto de árbol hermoso, ramos de palmas, y ramas de árboles espesos, y sauces de los arroyos; y os regocijaréis delante de Jehová vuestro Dios por siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 41, 'Y le haréis fiesta á Jehová por siete días cada un año; será estatuto perpetuo por vuestras edades; en el mes séptimo la haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 42, 'En cabañas habitaréis siete días: todo natural de Israel habitará en cabañas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 43, 'Para que sepan vuestros descendientes que en cabañas hice yo habitar á los hijos de Israel, cuando los saqué de la tierra de Egipto: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 23, 44, 'Así habló Moisés á los hijos de Israel sobre las solemnidades de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 2, 'Manda á los hijos de Israel que te traigan aceite de olivas claro, molido, para la luminaria, para hacer arder las lámparas de continuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 3, 'Fuera del velo del testimonio, en el tabernáculo del testimonio, las aderezará Aarón desde la tarde hasta la mañana delante de Jehová, de continuo: estatuto perpetuo por vuestras edades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 4, 'Sobre el candelero limpio pondrá siempre en orden las lámparas delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 5, 'Y tomarás flor de harina, y cocerás de ella doce tortas: cada torta será de dos décimas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 6, 'Y has de ponerlas en dos órdenes, seis en cada orden, sobre la mesa limpia delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 7, 'Pondrás también sobre cada orden incienso limpio, y será para el pan por perfume, ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 8, 'Cada día de sábado lo pondrá de continuo en orden delante de Jehová, de los hijos de Israel por pacto sempiterno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 9, 'Y será de Aarón y de sus hijos, los cuales lo comerán en el lugar santo; porque es cosa muy santa para él, de las ofrendas encendidas á Jehová, por fuero perpetuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 10, 'En aquella sazón el hijo de una mujer Israelita, el cual era hijo de un Egipcio, salió entre los hijos de Israel; y el hijo de la Israelita y un hombre de Israel riñeron en el real:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 11, 'Y el hijo de la mujer Israelita pronunció el Nombre, y maldijo: entonces le llevaron á Moisés. Y su madre se llamaba Selomith, hija de Dribi, de la tribu de Dan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 12, 'Y pusiéronlo en la cárcel, hasta que les fuese declarado por palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 13, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 14, 'Saca al blasfemo fuera del real, y todos los que le oyeron pongan sus manos sobre la cabeza de él, y apedréelo toda la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 15, 'Y á los hijos de Israel hablarás, diciendo: Cualquiera que maldijere á su Dios, llevará su iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 16, 'Y el que blasfemare el nombre de Jehová, ha de ser muerto; toda la congregación lo apedreará: así el extranjero como el natural, si blasfemare el Nombre, que muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 17, 'Asimismo el hombre que hiere de muerte á cualquiera persona, que sufra la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 18, 'Y el que hiere á algún animal ha de restituirlo: animal por animal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 19, 'Y el que causare lesión en su prójimo, según hizo, así le sea hecho:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 20, 'Rotura por rotura, ojo por ojo, diente por diente: según la lesión que habrá hecho á otro, tal se hará á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 21, 'El que hiere algún animal, ha de restituirlo; mas el que hiere de muerte á un hombre, que muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 22, 'Un mismo derecho tendréis: como el extranjero, así será el natural: porque yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 24, 23, 'Y habló Moisés á los hijos de Israel, y ellos sacaron al blasfemo fuera del real, y apedreáronlo con piedras. Y los hijos de Israel hicieron según que Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 1, 'Y JEHOVA habló á Moisés en el monte de Sinaí, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 2, 'Habla á los hijos de Israel, y diles: Cuando hubiereis entrado en la tierra que yo os doy, la tierra hará sábado á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 3, 'Seis años sembrarás tu tierra, y seis años podarás tu viña, y cogerás sus frutos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 4, 'Y el séptimo año la tierra tendrá sábado de holganza, sábado á Jehová: no sembrarás tu tierra, ni podarás tu viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 5, 'Lo que de suyo se naciere en tu tierra segada, no lo segarás; y las uvas de tu viñedo no vendimiarás: año de holganza será á la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 6, 'Mas el sábado de la tierra os será para comer á ti, y á tu siervo, y á tu sierva, y á tu criado, y á tu extranjero que morare contigo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 7, 'Y á tu animal, y á la bestia que hubiere en tu tierra, será todo el fruto de ella para comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 8, 'Y te has de contar siete semanas de años, siete veces siete años; de modo que los días de las siete semanas de años vendrán á serte cuarenta y nueve años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 9, 'Entonces harás pasar la trompeta de jubilación en el mes séptimo á los diez del mes; el día de la expiación haréis pasar la trompeta por toda vuestra tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 10, 'Y santificaréis el año cincuenta, y pregonaréis libertad en la tierra á todos sus moradores: este os será jubileo; y volveréis cada uno á su posesión, y cada cual volverá á su familia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 11, 'El año de los cincuenta años os será jubileo: no sembraréis, ni segaréis lo que naciere de suyo en la tierra, ni vendimiaréis sus viñedos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 12, 'Porque es jubileo: santo será á vosotros; el producto de la tierra comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 13, 'En este año de jubileo volveréis cada uno á su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 14, 'Y cuando vendiereis algo á vuestro prójimo, ó comprareis de mano de vuestro prójimo, no engañe ninguno a su hermano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 15, 'Conforme al número de los años después del jubileo comprarás de tu prójimo; conforme al número de los años de los frutos te venderá él á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 16, 'Conforme á la multitud de los años aumentarás el precio, y conforme á la disminución de los años disminuirás el precio; porque según el número de los rendimientos te ha de vender él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 17, 'Y no engañe ninguno á su prójimo; mas tendrás temor de tu Dios: porque yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 18, 'Ejecutad, pues, mis estatutos, y guardad mis derechos, y ponedlos por obra, y habitaréis en la tierra seguros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 19, 'Y la tierra dará su fruto, y comeréis hasta hartura, y habitaréis en ella con seguridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 20, 'Y si dijereis: ¿Qué comeremos el séptimo año? he aquí no hemos de sembrar, ni hemos de coger nuestros frutos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 21, 'Entonces yo os enviaré mi bendición el sexto año, y hará fruto por tres años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 22, 'Y sembraréis el año octavo, y comeréis del fruto añejo; hasta el año noveno, hasta que venga su fruto comeréis del añejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 23, 'Y la tierra no se venderá rematadamente, porque la tierra mía es; que vosotros peregrinos y extranjeros sois para conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 24, 'Por tanto, en toda la tierra de vuestra posesión, otorgaréis redención á la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 25, 'Cuando tu hermano empobreciere, y vendiere algo de su posesión, vendrá el rescatador, su cercano, y rescatará lo que su hermano hubiere vendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 26, 'Y cuando el hombre no tuviere rescatador, si alcanzare su mano, y hallare lo que basta para su rescate;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 27, 'Entonces contará los años de su venta, y pagará lo que quedare al varón á quien vendió, y volverá á su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 28, 'Mas si no alcanzare su mano lo que basta para que vuelva á él, lo que vendió estará en poder del que lo compró hasta el año del jubileo; y al jubileo saldrá, y él volverá á su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 29, 'Y el varón que vendiere casa de morada en ciudad cercada, tendrá facultad de redimirla hasta acabarse el año de su venta: un año será el término de poderse redimir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 30, 'Y si no fuere redimida dentro de un año entero, la casa que estuviere en la ciudad murada quedará para siempre por de aquel que la compró, y para sus descendientes: no saldrá en el jubileo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 31, 'Mas las casas de las aldeas que no tienen muro alrededor, serán estimadas como una haza de tierra: tendrán redención, y saldrán en el jubileo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 32, 'Pero en cuanto á las ciudades de los Levitas, siempre podrán redimir los Levitas las casas de las ciudades que poseyeren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 33, 'Y el que comprare de los Levitas, saldrá de la casa vendida, ó de la ciudad de su posesión, en el jubileo: por cuanto las casas de las ciudades de los Levitas es la posesión de ellos entre los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 34, 'Mas la tierra del ejido de sus ciudades no se venderá, porque es perpetua posesión de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 35, 'Y cuando tu hermano empobreciere, y se acogiere á ti, tú lo ampararás: como peregrino y extranjero vivirá contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 36, 'No tomarás usura de él, ni aumento; mas tendrás temor de tu Dios, y tu hermano vivirá contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 37, 'No le darás tu dinero á usura, ni tu vitualla á ganancia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 38, 'Yo Jehová vuestro Dios, que os saqué de la tierra de Egipto, para daros la tierra de Canaán, para ser vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 39, 'Y cuando tu hermano empobreciere, estando contigo, y se vendiere á ti, no le harás servir como siervo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 40, 'Como criado, como extranjero estará contigo; hasta el año del jubileo te servirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 41, 'Entonces saldrá de contigo, él y sus hijos consigo, y volverá á su familia, y á la posesión de sus padres se restituirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 42, 'Porque son mis siervos, los cuales saqué yo de la tierra de Egipto: no serán vendidos á manera de siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 43, 'No te enseñorearás de él con dureza, mas tendrás temor de tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 44, 'Así tu siervo como tu sierva que tuvieres, serán de las gentes que están en vuestro alrededor: de ellos compraréis siervos y siervas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 45, 'También compraréis de los hijos de los forasteros que viven entre vosotros, y de los que del linaje de ellos son nacidos en vuestra tierra, que están con vosotros; los cuales tendréis por posesión:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 46, 'Y los poseeréis por juro de heredad para vuestros hijos después de vosotros, como posesión hereditaria; para siempre os serviréis de ellos; empero en vuestros hermanos los hijos de Israel, no os enseñorearéis cada uno sobre su hermano con dureza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 47, 'Y si el peregrino ó extranjero que está contigo, adquiriese medios, y tu hermano que está con él empobreciere, y se vendiere al peregrino ó extranjero que está contigo, ó á la raza de la familia del extranjero;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 48, 'Después que se hubiere vendido, podrá ser rescatado: uno de sus hermanos lo rescatará;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 49, 'O su tío, ó el hijo de su tío lo rescatará, ó el cercano de su carne, de su linaje, lo rescatará; ó si sus medios alcanzaren, él mismo se redimirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 50, 'Y contará con el que lo compró, desde el año que se vendió á él hasta el año del jubileo: y ha de apreciarse el dinero de su venta conforme al número de los años, y se hará con él conforme al tiempo de un criado asalariado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 51, 'Si aún fueren muchos años, conforme á ellos volverá para su rescate del dinero por el cual se vendió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 52, 'Y si quedare poco tiempo hasta el año del jubileo, entonces contará con él, y devolverá su rescate conforme á sus años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 53, 'Como con tomado á salario anualmente hará con él: no se enseñoreará en él con aspereza delante de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 54, 'Mas si no se redimiere en esos años, en el año del jubileo saldrá, él, y sus hijos con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 25, 55, 'Porque mis siervos son los hijos de Israel; son siervos míos, á los cuales saqué de la tierra de Egipto: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 1, 'NO haréis para vosotros ídolos, ni escultura, ni os levantaréis estatua, ni pondréis en vuestra tierra piedra pintada para inclinaros á ella: porque yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 2, 'Guardad mis sábados, y tened en reverencia mi santuario: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 3, 'Si anduviereis en mis decretos, y guardareis mis mandamientos, y los pusiereis por obra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 4, 'Yo daré vuestra lluvia en su tiempo, cy la tierra rendirá sus producciones, y el árbol del campo dará su fruto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 5, 'Y la trilla os alcanzará á la vendimia, y la vendimia alcanzará á la sementera, y comeréis vuestro pan en hartura y habitaréis seguros en vuestra tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 6, 'Y yo daré paz en la tierra, y dormiréis, y no habrá quien os espante: y haré quitar las malas bestias de vuestra tierra, y no pasará por vuestro país la espada:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 7, 'Y perseguiréis á vuestros enemigos, y caerán á cuchillo delante de vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 8, 'Y cinco de vosotros perseguirán á ciento, y ciento de vosotros perseguirán á diez mil, y vuestros enemigos caerán á cuchillo delante de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 9, 'Porque yo me volveré á vosotros, y os haré crecer, y os multiplicaré, y afirmaré mi pacto con vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 10, 'Y comeréis lo añejo de mucho tiempo, y sacareis fuera lo añejo á causa de lo nuevo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 11, 'Y pondré mi morada en medio de vosotros, y mi alma no os abominará:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 12, 'Y andaré entre vosotros, y yo seré vuestro Dios, y vosotros seréis mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 13, 'Yo Jehová vuestro Dios, que os saqué de la tierra de Egipto, para que no fueseis sus siervos; y rompí las coyundas de vuestro yugo, y os he hecho andar el rostro alto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 14, 'Empero si no me oyereis, ni hiciereis todos estos mis mandamientos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 15, 'Y si abominareis mis decretos, y vuestra alma menospreciare mis derechos, no ejecutando todos mis mandamientos, é invalidando mi pacto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 16, 'Yo también haré con vosotros esto: enviaré sobre vosotros terror, extenuación y calentura, que consuman los ojos y atormenten el alma: y sembraréis en balde vuestra simiente, porque vuestros enemigos la comerán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 17, 'Y pondré mi ira sobre vosotros, y seréis heridos delante de vuestros enemigos; y los que os aborrecen se enseñorearán de vosotros, y huiréis sin que haya quien os persiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 18, 'Y si aun con estas cosas no me oyereis, yo tornaré á castigaros siete veces más por vuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 19, 'Y quebrantaré la soberbia de vuestra fortaleza, y tornaré vuestro cielo como hierro, y vuestra tierra como metal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 20, 'Y vuestra fuerza se consumirá en vano; que vuestra tierra no dará su esquilmo, y los árboles de la tierra no darán su fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 21, 'Y si anduviereis conmigo en oposición, y no me quisiereis oír, yo añadiré sobre vosotros siete veces más plagas según vuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 22, 'Enviaré también contra vosotros bestias fieras que os arrebaten los hijos, y destruyan vuestros animales, y os apoquen, y vuestros caminos sean desiertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 23, 'Y si con estas cosas no fuereis corregidos, sino que anduviereis conmigo en oposición,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 24, 'Yo también procederé con vosotros, en oposición y os heriré aún siete veces por vuestros pecados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 25, 'Y traeré sobre vosotros espada vengadora, en vindicación del pacto; y os recogeréis á vuestras ciudades; mas yo enviaré pestilencia entre vosotros, y seréis entregados en mano del enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 26, 'Cuando yo os quebrantare el arrimo del pan, cocerán diez mujeres vuestro pan en un horno, y os devolverán vuestro pan por peso; y comeréis, y no os hartaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 27, 'Y si con esto no me oyereis, mas procediereis conmigo en oposición,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 28, 'Yo procederé con vosotros en contra y con ira, y os catigaré aún siete veces por vuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 29, 'Y comeréis las carnes de vuestros hijos, y comeréis las carnes de vuestras hijas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 30, 'Y destruiré vuestros altos, y talaré vuestras imágenes, y pondré vuestros cuerpos muertos sobre los cuerpos muertos de vuestros ídolos, y mi alma os abominará:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 31, 'Y pondré vuestras ciudades en desierto, y asolaré vuestros santuarios, y no oleré la fragancia de vuestro suave perfume.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 32, 'Yo asolaré también la tierra, y se pasmarán de ella vuestros enemigos que en ella moran:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 33, 'Y á vosotros os esparciré por las gentes, y desenvainaré espada en pos de vosotros: y vuestra tierra estará asolada, y yermas vuestras ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 34, 'Entonces la tierra holgará sus sábados todos los días que estuviere asolada, y vosotros en la tierra de vuestros enemigos: la tierra descansará entonces y gozará sus sábados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 35, 'Todo el tiempo que estará asolada, holgará lo que no holgó en vuestros sábados mientras habitabais en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 36, 'Y á los que quedaren de vosotros infundiré en sus corazones tal cobardía, en la tierra de sus enemigos, que el sonido de una hoja movida los perseguirá, y huirán como de cuchillo, y caerán sin que nadie los persiga:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 37, 'Y tropezarán los unos en los otros, como si huyeran delante de cuchillo, aunque nadie los persiga; y no podréis resistir delante de vuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 38, 'Y pereceréis entre las gentes, y la tierra de vuestros enemigos os consumirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 39, 'Y los que quedaren de vosotros decaerán en las tierras de vuestros enemigos por su iniquidad; y por la iniquidad de sus padres decaerán con ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 40, 'Y confesarán su iniquidad, y la iniquidad de sus padres, por su prevaricación con que prevaricaron contra mí: y también porque anduvieron conmigo en oposición,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 41, 'Yo también habré andado con ellos en contra, y los habré metido en la tierra de sus enemigos: y entonces se humillará su corazón incircunciso, y reconocerán su pecado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 42, 'Y yo me acordaré de mi pacto con Jacob, y asimismo de mi pacto con Isaac, y también de mi pacto con Abraham me acordaré; y haré memoria de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 43, 'Que la tierra estará desamparada de ellos, y holgará sus sábados, estando yerma á causa de ellos; mas entretanto se someterán al castigo de sus iniquidades: por cuanto menospreciaron mis derechos, y tuvo el alma de ellos fastidio de mis estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 44, 'Y aun con todo esto, estando ellos en tierra de sus enemigos, yo no los desecharé, ni los abominaré para consumirlos, invalidando mi pacto con ellos: porque yo Jehová soy su Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 45, 'Antes me acordaré de ellos por el pacto antiguo, cuando los saqué de la tierra de Egipto á los ojos de las gentes, para ser su Dios: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 26, 46, 'Estos son los decretos, derechos y leyes que estableció Jehová entre sí y los hijos de Israel en el monte de Sinaí por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 2, 'Habla á los hijos de Israel, y diles: Cuando alguno hiciere especial voto á Jehová, según la estimación de las personas que se hayan de redimir, así será tu estimación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 3, 'En cuanto al varón de veinte años hasta sesenta, tu estimación será cincuenta siclos de plata, según el siclo del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 4, 'Y si fuere hembra, la estimación será treinta siclos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 5, 'Y si fuere de cinco años hasta veinte, tu estimación será respecto al varón veinte siclos, y á la hembra diez siclos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 6, 'Y si fuere de un mes hasta cinco años, tu estimación será en orden al varón, cinco siclos de plata; y por la hembra será tu estimación tres siclos de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 7, 'Mas si fuere de sesenta años arriba, por el varón tu estimación será quince siclos, y por la hembra diez siclos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 8, 'Pero si fuere más pobre que tu estimación, entonces comparecerá ante el sacerdote, y el sacerdote le pondrá tasa: conforme á la facultad del votante le impondrá tasa el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 9, 'Y si fuere animal de que se ofrece ofrenda á Jehová, todo lo que se diere de el á Jehová será santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 10, 'No será mudado ni trocado, bueno por malo, ni malo por bueno; y si se permutare un animal por otro, él y el dado por él en cambio serán sagrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 11, 'Y si fuere algún animal inmundo, de que no se ofrece ofrenda á Jehová, entonces el animal será puesto delante del sacerdote:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 12, 'Y el sacerdote lo apreciará, sea bueno ó sea malo; conforme á la estimación del sacerdote, así será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 13, 'Y si lo hubieren de redimir, añadirán su quinto sobre tu valuación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 14, 'Y cuando alguno santificare su casa consagrándola á Jehová, la apreciará el sacerdote, sea buena ó sea mala: según la apreciare el sacerdote, así quedará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 15, 'Mas si el santificante redimiere su casa, añadirá á tu valuación el quinto del dinero de ella, y será suya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 16, 'Y si alguno santificare de la tierra de su posesión á Jehová, tu estimación será conforme á su sembradura: un omer de sembradura de cebada se apreciará en cincuenta siclos de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 17, 'Y si santificare su tierra desde el año del jubileo, conforme á tu estimación quedará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 18, 'Mas si después del jubileo santificare su tierra, entonces el sacerdote hará la cuenta del dinero conforme á los años que quedaren hasta el año del jubileo, y se rebajará de tu estimación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 19, 'Y si el que santificó la tierra quisiere redimirla, añadirá á tu estimación el quinto del dinero de ella, y quedaráse para él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 20, 'Mas si él no redimiere la tierra, y la tierra se vendiere á otro, no la redimirá más;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 21, 'Sino que cuando saliere en el jubileo, la tierra será santa á Jehová, como tierra consagrada: la posesión de ella será del sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 22, 'Y si santificare alguno á Jehová la tierra que él compró, que no era de la tierra de su herencia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 23, 'Entonces el sacerdote calculará con él la suma de tu estimación hasta el año del jubileo, y aquel día dará tu señalado precio, cosa consagrada á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 24, 'En el año del jubileo, volverá la tierra á aquél de quien él la compró, cuya es la herencia de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 25, 'Y todo lo que apreciares será conforme al siclo del santuario: el siclo tiene veinte óbolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 26, 'Empero el primogénito de los animales, que por la primogenitura es de Jehová, nadie lo santificará; sea buey ú oveja, de Jehová es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 27, 'Mas si fuere de los animales inmundos, lo redimirán conforme á tu estimación, y añadirán sobre ella su quinto: y si no lo redimieren, se venderá conforme á tu estimación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 28, 'Pero ninguna cosa consagrada, que alguno hubiere santificado á Jehová de todo lo que tuviere, de hombres y animales, y de las tierras de su posesión, no se venderá, ni se redimirá: todo lo consagrado será cosa santísima á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 29, 'Cualquier anatema (cosa consagrada) de hombres que se consagrare no será redimido: indefectiblemente ha de ser muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 30, 'Y todas las décimas de la tierra, así de la simiente de la tierra como del fruto de los árboles, de Jehová son: es cosa consagrada á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 31, 'Y si alguno quisiere redimir algo de sus décimas, añadirá su quinto á ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 32, 'Y toda décima de vacas ó de ovejas, de todo lo que pasa bajo la vara, la décima será consagrada á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 33, 'No mirará si es bueno ó malo, ni lo trocará: y si lo trocare, ello y su trueque serán cosas sagradas; no se redimirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('LEV', 'Levítico', 27, 34, 'Estos son los mandamientos que ordenó Jehová á Moisés, para los hijos de Israel, en el monte de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 1, 'Y HABLO Jehová á Moisés en el desierto de Sinaí, en el tabernáculo del testimonio, en el primero del mes segundo, en el segundo año de su salida de la tierra de Egipto, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 2, 'Tomad el encabezamiento de toda la congregación de los hijos de Israel por sus familias, por las casas de sus padres, con la cuenta de los nombres, todos los varones por sus cabezas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 3, 'De veinte años arriba, todos los que pueden salir á la guerra en Israel, los contaréis tú y Aarón por sus cuadrillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 4, 'Y estará con vosotros un varón de cada tribu, cada uno cabeza de la casa de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 5, 'Y estos son los nombres de los varones que estarán con vosotros: De la tribu de Rubén, Elisur hijo de Sedeur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 6, 'De Simeón, Selumiel hijo de Zurisaddai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 7, 'De Judá, Naasón hijo de Aminadab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 8, 'De Issachâr, Nathanael hijo de Suar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 9, 'De Zabulón, Eliab hijo de Helón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 10, 'De los hijos de José: de Ephraim, Elisama hijo de Ammiud; de Manasés, Gamaliel hijo de Pedasur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 11, 'De Benjamín, Abidán hijo de Gedeón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 12, 'De Dan, Ahiezer hijo de Ammisaddai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 13, 'De Aser, Phegiel hijo de Ocrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 14, 'De Gad, Eliasaph hijo de Dehuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 15, 'De Nephtalí, Ahira hijo de Enán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 16, 'Estos eran los nombrados de la congregación, príncipes de las tribus de sus padres, capitanes de los millares de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 17, 'Tomó pues Moisés y Aarón á estos varones que fueron declarados por sus nombres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 18, 'Y juntaron toda la congregación en el primero del mes segundo, y fueron reunidos sus linajes, por las casas de sus padres, según la cuenta de los nombres, de veinte años arriba, por sus cabezas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 19, 'Como Jehová lo había mandado á Moisés; y contólos en el desierto de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 20, 'Y los hijos de Rubén, primogénito de Israel, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres por sus cabezas, todos los varones de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 21, 'Los contados de ellos, de la tribu de Rubén, fueron cuarenta y seis mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 22, 'De los hijos de Simeón, por sus generaciones, por sus familias, por las casas de sus padres, los contados de ellos conforme á la cuenta de los nombres por sus cabezas, todos los varones de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 23, 'Los contados de ellos, de la tribu de Simeón, cincuenta y nueve mil y trescientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 24, 'De los hijos de Gad, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 25, 'Los contados de ellos, de la tribu de Gad, cuarenta y cinco mil seiscientos y cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 26, 'De los hijos de Judá, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 27, 'Los contados de ellos, de la tribu de Judá, setenta y cuatro mil y seiscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 28, 'De los hijos de Issachâr, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 29, 'Los contados de ellos, de la tribu de Issachâr, cincuenta y cuatro mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 30, 'De los hijos de Zabulón, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de sus nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 31, 'Los contados de ellos, de la tribu de Zabulón, cincuenta y siete mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 32, 'De los hijos de José: de los hijos de Ephraim, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 33, 'Los contados de ellos, de la tribu de Ephraim, cuarenta mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 34, 'De los hijos de Manasés, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 35, 'Los contados de ellos, de la tribu de Manasés, treinta y dos mil y doscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 36, 'De los hijos de Benjamín, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 37, 'Los contados de ellos, de la tribu de Benjamín, treinta y cinco mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 38, 'De los hijos de Dan, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 39, 'Los contados de ellos, de la tribu de Dan, sesenta y dos mil y setecientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 40, 'De los hijos de Aser, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 41, 'Los contados de ellos, de la tribu de Aser, cuarenta y un mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 42, 'De los hijos de Nephtalí, por sus generaciones, por sus familias, por las casas de sus padres, conforme á la cuenta de los nombres, de veinte años arriba, todos los que podían salir á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 43, 'Los contados de ellos, de la tribu de Nephtalí, cincuenta y tres mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 44, 'Estos fueron los contados, los cuales contaron Moisés y Aarón, con los príncipes de Israel, que eran doce, uno por cada casa de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 45, 'Y fueron todos los contados de los hijos de Israel por las casas de sus padres, de veinte años arriba, todos los que podían salir á la guerra en Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 46, 'Fueron todos los contados seiscientos tres mil quinientos y cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 47, 'Pero los Levitas no fueron contados entre ellos según la tribu de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 48, 'Porque habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 49, 'Solamente no contarás la tribu de Leví, ni tomarás la cuenta de ellos entre los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 50, 'Mas tú pondrás á los Levitas en el tabernáculo del testimonio, y sobre todos sus vasos, y sobre todas las cosas que le pertenecen: ellos llevarán el tabernáculo y todos sus vasos, y ellos servirán en él, y asentarán sus tiendas alrededor del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 51, 'Y cuando el tabernáculo partiere, los Levitas lo desarmarán; y cuando el tabernáculo parare, los Levitas lo armarán: y el extraño que se llegare, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 52, 'Y los hijos de Israel asentarán sus tiendas cada uno en su escuadrón, y cada uno junto á su bandera, por sus cuadrillas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 53, 'Mas los Levitas asentarán las suyas alrededor del tabernáculo del testimonio, y no habrá ira sobre la congregacíon de los hijos de Israel: y los Levitas tendrán la guarda del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 1, 54, 'E hicieron los hijos de Israel conforme á todas las cosas que mandó Jehová á Moisés; así lo hicieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 1, 'Y HABLO Jehová á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 2, 'Los hijos de Israel acamparán cada uno junto á su bandera, según las enseñas de las casas de sus padres; alrededor del tabernáculo del testimonio acamparán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 3, 'Estos acamparán al levante, al oriente: la bandera del ejército de Judá, por sus escuadrones; y el jefe de los hijos de Judá, Naasón hijo de Aminadab:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 4, 'Su hueste, con los contados de ellos, setenta y cuatro mil y seiscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 5, 'Junto á él acamparán los de la tribu de Issachâr: y el jefe de los hijos de Issachâr, Nathanael hijo de Suar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 6, 'Y su hueste, con sus contados, cincuenta y cuatro mil y cuatrocientos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 7, 'Y la tribu de Zabulón: y el jefe de los hijos de Zabulón, Eliab hijo de Helón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 8, 'Y su hueste, con sus contados, cincuenta y siete mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 9, 'Todos los contados en el ejército de Judá, ciento ochenta y seis mil y cuatrocientos, por sus escuadrones, irán delante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 10, 'La bandera del ejército de Rubén al mediodía, por sus escuadrones: y el jefe de los hijos de Rubén, Elisur hijo de Sedeur;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 11, 'Y su hueste, sus contados, cuarenta y seis mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 12, 'Y acamparán junto á él los de la tribu de Simeón: y el jefe de los hijos de Simeón, Selumiel hijo de Zurisaddai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 13, 'Y su hueste, con los contados de ellos, cincuenta y nueve mil y trescientos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 14, 'Y la tribu de Gad: y el jefe de los hijos de Gad, Eliasaph hijo de Rehuel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 15, 'Y su hueste, con los contados de ellos, cuarenta y cinco mil seiscientos y cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 16, 'Todos los contados en el ejército de Rubén, ciento cincuenta y un mil cuatrocientos y cincuenta, por sus escuadrones, irán los segundos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 17, 'Luego irá el tabernáculo del testimonio, el campo de los Levitas en medio de los ejércitos: de la manera que asientan el campo, así caminarán, cada uno en su lugar, junto á sus banderas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 18, 'La bandera del ejército de Ephraim por sus escuadrones, al occidente: y el jefe de los hijos de Ephraim, Elisama hijo de Ammiud;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 19, 'Y su hueste, con los contados de ellos, cuarenta mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 20, 'Junto á él estará la tribu de Manasés; y el jefe de los hijos de Manasés, Gamaliel hijo de Pedasur;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 21, 'Y su hueste, con los contados de ellos, treinta y dos mil y doscientos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 22, 'Y la tribu de Benjamín: y el jefe de los hijos de Benjamín, Abidán hijo de Gedeón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 23, 'Y su hueste, con los contados de ellos, treinta y cinco mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 24, 'Todos los contados en el ejército de Ephraim, ciento ocho mil y ciento, por sus escuadrones, irán los terceros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 25, 'La bandera del ejército de Dan estará al aquilón, por sus escuadrones: y el jefe de los hijos de Dan, Ahiezer hijo de Amisaddai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 26, 'Y su hueste, con los contados de ellos, sesenta y dos mil y setecientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 27, 'Junto á él acamparán los de la tribu de Aser: y el jefe de los hijos de Aser, Phegiel hijo de Ocrán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 28, 'Y su hueste, con los contados de ellos, cuarenta y un mil y quinientos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 29, 'Y la tribu de Nephtalí: y el jefe de los hijos de Nephtalí, Ahira hijo de Enán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 30, 'Y su hueste, con los contados de ellos, cincuenta y tres mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 31, 'Todos los contados en el ejército de Dan, ciento cincuenta y siete mil y seiscientos: irán los postreros tras sus banderas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 32, 'Estos son los contados de los hijos de Israel, por las casas de sus padres: todos los contados por ejércitos, por sus escuadrones, seiscientos tres mil quinientos y cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 33, 'Mas los Levitas no fueron contados entre los hijos de Israel; como Jehová lo mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 2, 34, 'E hicieron los hijos de Israel conforme á todas las cosas que Jehová mandó á Moisés; así asentaron el campo por sus banderas, y así marcharon cada uno por sus familias, según las casas de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 1, 'Y ESTAS son las generaciones de Aarón y de Moisés, desde que Jehová habló á Moisés en el monte de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 2, 'Y estos son los nombres de los hijos de Aarón: Nadab el primogénito, y Abiú, Eleazar, é Ithamar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 3, 'Estos son los nombres de los hijos de Aarón, sacerdotes ungidos; cuyas manos él hinchió para administrar el sacerdocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 4, 'Mas Nadab y Abiú murieron delante de Jehová, cuando ofrecieron fuego extraño delante de Jehová, en el desierto de Sinaí: y no tuvieron hijos: y Eleazar é Ithamar ejercieron el sacerdocio delante de Aarón su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 5, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 6, 'Haz llegar á la tribu de Leví, y hazla estar delante del sacerdote Aarón, para que le ministren;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 7, 'Y desempeñen su cargo, y el cargo de toda la congregación delante del tabernáculo del testimonio, para servir en el ministerio del tabernáculo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 8, 'Y guarden todas las alhajas del tabernáculo del testimonio, y lo encargado á ellos de los hijos de Israel, y ministren en el servicio del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 9, 'Y darás los Levitas á Aarón y á sus hijos: le son enteramente dados de entre los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 10, 'Y constituirás á Aarón y á sus hijos, para que ejerzan su sacerdocio: y el extraño que se llegare, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 11, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 12, 'Y he aquí yo he tomado los Levitas de entre los hijos de Israel en lugar de todos los primogénitos que abren la matriz entre los hijos de Israel; serán pues míos los Levitas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 13, 'Porque mío es todo primogénito; desde el día que yo maté todos los primogénitos en la tierra de Egipto, yo santifiqué á mí todos los primogénitos en Israel, así de hombres como de animales: míos serán: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 14, 'Y Jehová habló á Moisés en el desierto de Sinaí, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 15, 'Cuenta los hijos de Leví por las casas de sus padres, por sus familias: contarás todos los varones de un mes arriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 16, 'Y Moisés los contó conforme á la palabra de Jehová, como le fué mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 17, 'Y los hijos de Leví fueron estos por sus nombres: Gersón, y Coath, y Merari.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 18, 'Y los nombres de los hijos de Gersón, por sus familias, estos: Libni, y Simei.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 19, 'Y los hijos de Coath, por sus familias: Amram, é Izhar, y Hebrón, y Uzziel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 20, 'Y los hijos de Merari, por sus familias: Mahali, y Musi. Estas, las familias de Leví, por las casas de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 21, 'De Gersón, la familia de Libni y la de Simei: estas son las familias de Gersón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 22, 'Los contados de ellos conforme á la cuenta de todos los varones de un mes arriba, los contados de ellos, siete mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 23, 'Las familias de Gersón asentarán sus tiendas á espaldas del tabernáculo, al occidente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 24, 'Y el jefe de la casa del padre de los Gersonitas, Eliasaph hijo de Lael.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 25, 'A cargo de los hijos de Gersón, en el tabernáculo del testimonio, estará el tabernáculo, y la tienda, y su cubierta, y el pabellón de la puerta del tabernáculo del testimonio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 26, 'Y las cortinas del atrio, y el pabellón de la puerta del atrio, que está junto al tabernáculo y junto al altar alrededor; asimismo sus cuerdas para todo su servicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 27, 'Y de Coath, la familia Amramítica, y la familia Izeharítica, y la familia Hebronítica, y la familia Ozielítica: estas son las familias Coathitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 28, 'Por la cuenta de todos los varones de un mes arriba, eran ocho mil y seiscientos, que tenían la guarda del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 29, 'Las familias de los hijos de Coath acamparán al lado del tabernáculo, al mediodía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 30, 'Y el jefe de la casa del padre de las familias de Coath, Elisaphán hijo de Uzziel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 31, 'Y á cargo de ellos estará el arca, y la mesa, y el candelero, y los altares, y los vasos del santuario con que ministran, y el velo, con todo su servicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 32, 'Y el principal de los jefes de los Levitas será Eleazar, hijo de Aarón el sacerdote, prepósito de los que tienen la guarda del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 33, 'De Merari, la familia Mahalítica y la familia Musítica: estas son las familias de Merari.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 34, 'Y los contados de ellos conforme á la cuenta de todos los varones de un mes arriba, fueron seis mil y doscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 35, 'Y el jefe de la casa del padre de las familias de Merari, Suriel hijo de Abihail: acamparán al lado del tabernáculo, al aquilón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 36, 'Y á cargo de los hijos de Merari estará la custodia de las tablas del tabernáculo, y sus barras, y sus columnas, y sus basas, y todos sus enseres, con todo su servicio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 37, 'Y las columnas en derredor del atrio, y sus basas, y sus estacas, y sus cuerdas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 38, 'Y los que acamparán delante del tabernáculo al oriente, delante del tabernáculo del testimonio al levante, serán Moisés, y Aarón y sus hijos, teniendo la guarda del santuario en lugar de los hijos de Israel: y el extraño que se acercare, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 39, 'Todos los contados de los Levitas, que Moisés y Aarón conforme á la palabra de Jehová contaron por sus familias, todos los varones de un mes arriba, fueron veinte y dos mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 40, 'Y Jehová dijo á Moisés: Cuenta todos los primogénitos varones de los hijos de Israel de un mes arriba, y toma la cuenta de los nombres de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 41, 'Y tomarás los Levitas para mí, yo Jehová, en lugar de todos los primogénitos de los hijos de Israel: y los animales de los Levitas en lugar de todos los primogénitos de los animales de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 42, 'Y contó Moisés, como Jehová le mandó, todos los primogénitos de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 43, 'Y todos los primogénitos varones, conforme á la cuenta de los nombres, de un mes arriba, los contados de ellos fueron veinte y dos mil doscientos setenta y tres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 44, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 45, 'Toma los Levitas en lugar de todos los primogénitos de los hijos de Israel, y los animales de los Levitas en lugar de sus animales; y los Levitas serán míos: Yo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 46, 'Y por los rescates de los doscientos y setenta y tres, que sobrepujan á los Levitas los primogénitos de los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 47, 'Tomarás cinco siclos por cabeza; conforme al siclo del santuario tomarás: el siclo tiene veinte óbolos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 48, 'Y darás á Aarón y á sus hijos el dinero por los rescates de los que de ellos sobran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 49, 'Tomó, pues, Moisés el dinero del rescate de los que resultaron de más de los redimidos por los Levitas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 50, 'Y recibió de los primogénitos de los hijos de Israel en dinero, mil trescientos sesenta y cinco siclos, conforme al siclo del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 3, 51, 'Y Moisés dió el dinero de los rescates á Aarón y á sus hijos, conforme al dicho de Jehová, según que Jehová había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 1, 'Y HABLO Jehová á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 2, 'Toma la cuenta de los hijos de Coath de entre los hijos de Leví, por sus familias, por las casas de sus padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 3, 'De edad de treinta años arriba hasta cincuenta años, todos los que entran en compañía, para hacer servicio en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 4, 'Este será el oficio de los hijos de Coath en el tabernáculo del testimonio, en el lugar santísimo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 5, 'Cuando se hubiere de mudar el campo, vendrán Aarón y sus hijos, y desarmarán el velo de la tienda, y cubrirán con él el arca del testimonio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 6, 'Y pondrán sobre ella la cubierta de pieles de tejones, y extenderán encima el paño todo de cárdeno, y le pondrán sus varas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 7, 'Y sobre la mesa de la proposición extenderán el paño cárdeno, y pondrán sobre ella las escudillas, y las cucharas, y las copas, y los tazones para libar: y el pan continuo estará sobre ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 8, 'Y extenderán sobre ella el paño de carmesí colorado, y lo cubrirán con la cubierta de pieles de tejones; y le pondrán sus varas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 9, 'Y tomarán un paño cárdeno, y cubrirán el candelero de la luminaria; y sus candilejas, y sus despabiladeras, y sus platillos, y todos sus vasos del aceite con que se sirve;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 10, 'Y lo pondrán con todos sus vasos en una cubierta de pieles de tejones, y lo colocarán sobre unas parihuelas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 11, 'Y sobre el altar de oro extenderán el paño cárdeno, y le cubrirán con la cubierta de pieles de tejones, y le pondrán sus varales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 12, 'Y tomarán todos los vasos del servicio, de que hacen uso en el santuario, y los pondrán en un paño cárdeno, y los cubrirán con una cubierta de pieles de tejones, y los colocarán sobre unas parihuelas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 13, 'Y quitarán la ceniza del altar, y extenderán sobre él un paño de púrpura:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 14, 'Y pondrán sobre él todos sus instrumentos de que se sirve: las paletas, los garfios, los braseros, y los tazones, todos los vasos del altar; y extenderán sobre él la cubierta de pieles de tejones, y le pondrán además las varas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 15, 'Y en acabando Aarón y sus hijos de cubrir el santuario y todos los vasos del santuario, cuando el campo se hubiere de mudar, vendrán después de ello los hijos de Coath para conducir: mas no tocarán cosa santa, que morirán. Estas serán las cargas de los hijos de Coath en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 16, 'Empero al cargo de Eleazar, hijo de Aarón el sacerdote, estará el aceite de la luminaria, y el perfume aromático, y el presente continuo, y el aceite de la unción; el cargo de todo el tabernáculo, y de todo lo que está en él, en el santuario, y en sus vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 17, 'Y habló Jehová á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 18, 'No cortaréis la tribu de las familias de Coath de entre los Levitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 19, 'Mas esto haréis con ellos, para que vivan, y no mueran cuando llegaren al lugar santísimo: Aarón y sus hijos vendrán y los pondrán á cada uno en su oficio, y en su cargo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 20, 'No entrarán para ver, cuando cubrieren las cosas santas; que morirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 21, 'Y habló Jehová á Moisés diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 22, 'Toma también la cuenta de los hijos de Gersón por las casas de sus padres, por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 23, 'De edad de treinta años arriba hasta cincuenta años los contarás; todos los que entran en compañía, para hacer servicio en el tabrenáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 24, 'Este será el oficio de las familias de Gersón, para ministrar y para llevar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 25, 'Llevarán las cortinas del tabernáculo, y el tabernáculo del testimonio, su cubierta, y la cubierta de pieles de tejones que está sobre él encima, y el pabellón de la puerta del tabernáculo del testimonio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 26, 'Y las cortinas del atrio, y el pabellón de la puerta del atrio, que está cerca del tabernáculo y cerca del altar alrededor, y sus cuerdas, y todos los instrumentos de su servicio, y todo lo que será hecho para ellos: así servirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 27, 'Según la orden de Aarón y de sus hijos será todo el ministerio de los hijos de Gersón en todos sus cargos, y en todo su servicio: y les encomendaréis en guarda todos sus cargos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 28, 'Este es el servicio de las familias de los hijos de Gersón en el tabernáculo del testimonio: y el cargo de ellos estará bajo la mano de Ithamar, hijo de Aarón el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 29, 'Contarás los hijos de Merari por sus familias, por las casas de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 30, 'Desde el de edad de treinta años arriba hasta el de cincuenta años, los contarás; todos los que entran en compañía, para hacer servicio en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 31, 'Y este será el deber de su cargo para todo su servicio en el tabernáculo del testimonio: las tablas del tabernáculo, y sus barras, y sus columnas, y sus basas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 32, 'Y las columnas del atrio alrededor, y sus basas, y sus estacas, y sus cuerdas con todos sus instrumentos, y todo su servicio; y contaréis por sus nombres todos los vasos de la guarda de su cargo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 33, 'Este será el servicio de las familias de los hijos de Merari para todo su ministerio en el tabernáculo del testimonio, bajo la mano de Ithamar, hijo de Aarón el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 34, 'Moisés, pues, y Aarón, y los jefes de la congregación, contaron los hijos de Coath por sus familias, y por las casas de sus padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 35, 'Desde el de edad de treinta años arriba hasta el de edad de cincuenta años; todos los que entran en compañía, para ministrar en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 36, 'Y fueron los contados de ellos por sus familias, dos mil setecientos y cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 37, 'Estos fueron los contados de las familias de Coath, todos los que ministran en el tabernáculo del testimonio, los cuales contaron Moisés y Aarón, como lo mandó Jehová por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 38, 'Y los contados de los hijos de Gersón, por sus familias, y por las casas de sus padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 39, 'Desde el de edad de treinta años arriba hasta el de edad de cincuenta años, todos los que entran en compañía, para ministrar en el tabernáculo del testimonio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 40, 'Los contados de ellos por sus familias, por las casas de sus padres, fueron dos mil seiscientos y treinta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 41, 'Estos son los contados de las familias de los hijos de Gersón, todos los que ministran en el tabernáculo del testimonio, los cuales contaron Moisés y Aarón por mandato de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 42, 'Y los contados de las familias de los hijos de Merari, por sus familias, por las casas de sus padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 43, 'Desde el de edad de treinta años arriba hasta el de edad de cincuenta años, todos los que entran en compañía, para ministrar en el tabernáculo del testimonio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 44, 'Los contados de ellos, por sus familias, fueron tres mil y doscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 45, 'Estos fueron los contados de las familias de los hijos de Merari, los cuales contaron Moisés y Aarón, según lo mandó Jehová por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 46, 'Todos los contados de los Levitas, que Moisés y Aarón y los jefes de Israel contaron por sus familias, y por las casas de sus padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 47, 'Desde el de edad de treinta años arriba hasta el de edad de cincuenta años, todos los que entraban para ministrar en el servicio, y tener cargo de obra en el tabernáculo del testimonio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 48, 'Los contados de ellos fueron ocho mil quinientos y ochenta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 4, 49, 'Como lo mandó Jehová por mano de Moisés fueron contados, cada uno según su oficio, y según su cargo; los cuales contó él, como le fué mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 2, 'Manda á los hijos de Israel que echen del campo á todo leproso, y á todos los que padecen flujo de semen, y á todo contaminado sobre muerto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 3, 'Así hombres como mujeres echaréis, fuera del campo los echaréis; porque no contaminen el campo de aquellos entre los cuales yo habito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 4, 'E hiciéronlo así los hijos de Israel, que los echaron fuera del campo: como Jehová dijo á Moisés, así lo hicieron los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 5, 'Además habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 6, 'Habla á los hijos de Israel: El hombre ó la mujer que cometiere alguno de todos los pecados de los hombres, haciendo prevaricación contra Jehová, y delinquiere aquella persona;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 7, 'Confesarán su pecado que cometieron, y compensarán su ofensa enteramente, y añadirán su quinto sobre ello, y lo darán á aquel contra quien pecaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 8, 'Y si aquel hombre no tuviere pariente al cual sea resarcida la ofensa, daráse la indemnización del agravio á Jehová, al sacerdote, á más del carnero de las expiaciones, con el cual hará expiación por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 9, 'Y toda ofrenda de todas las cosas santas que los hijos de Israel presentaren al sacerdote, suya será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 10, 'Y lo santificado de cualquiera será suyo: asimismo lo que cualquiera diere al sacerdote, suyo será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 11, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 12, 'Habla á los hijos de Israel, y diles: Cuando la mujer de alguno se desmandare, é hiciere traición contra él,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 13, 'Que alguno se hubiere echado con ella en carnal ayuntamiento, y su marido no lo hubiese visto por haberse ella contaminado ocultamente, ni hubiere testigo contra ella, ni ella hubiere sido cogida en el acto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 14, 'Si viniere sobre él espíritu de celo, y tuviere celos de su mujer, habiéndose ella contaminado; ó viniere sobre él espíritu de celo, y tuviere celos de su mujer, no habiéndose ella contaminado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 15, 'Entonces el marido traerá su mujer al sacerdote, y traerá su ofrenda con ella, la décima de un epha de harina de cebada; no echará sobre ella aceite, ni pondrá sobre ella incienso: porque es presente de celos, presente de recordación, que trae en memoria pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 16, 'Y el sacerdote la hará acercar, y la hará poner delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 17, 'Luego tomará el sacerdote del agua santa en un vaso de barro: tomará también el sacerdote del polvo que hubiere en el suelo del tabernáculo, y echarálo en el agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 18, 'Y hará el sacerdote estar en pie á la mujer delante de Jehová, y descubrirá la cabeza de la mujer, y pondrá sobre sus manos el presente de la recordación, que es el presente de celos: y el sacerdote tendrá en la mano las aguas amargas que acarrean maldición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 19, 'Y el sacerdote la conjurará, y le dirá: Si ninguno hubiere dormido contigo, y si no te has apartado de tu marido á inmundicia, libre seas de estas aguas amargas que traen maldición:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 20, 'Mas si te has descarriado de tu marido, y te has amancillado, y alguno hubiere tenido coito contigo, fuera de tu marido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 21, '(El sacerdote conjurará á la mujer con juramento de maldición, y dirá á la mujer): Jehová te dé en maldición y en conjuración en medio de tu pueblo, haciendo Jehová á tu muslo que caiga, y á tu vientre que se te hinche;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 22, 'Y estas aguas que dan maldición entren en tus entrañas, y hagan hinchar tu vientre, y caer tu muslo. Y la mujer dirá: Amén, amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 23, 'Y el sacerdote escribirá estas maldiciones en un libro, y las borrará con las aguas amargas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 24, 'Y dará á beber á la mujer las aguas amargas que traen maldición; y las aguas que obran maldición entrarán en ella por amargas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 25, 'Después tomará el sacerdote de la mano de la mujer el presente de los celos, y mecerálo delante de Jehová, y lo ofrecerá delante del altar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 26, 'Y tomará el sacerdote un puñado del presente, en memoria de ella, y lo quemará sobre el altar, y después dará á beber las aguas á la mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 27, 'Darále pues á beber las aguas; y será, que si fuere inmunda y hubiere hecho traición contra su marido, las aguas que obran maldición entrarán en ella en amargura, y su vientre se hinchará, y caerá su muslo; y la mujer será por maldición en medio de su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 28, 'Mas si la mujer no fuere inmunda, sino que estuviere limpia, ella será libre, y será fecunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 29, 'Esta es la ley de los celos, cuando la mujer hiciere traición á su marido, y se amancillare;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 30, 'O del marido, sobre el cual pasare espíritu de celo, y tuviere celos de su mujer: presentarála entonces delante de Jehová, y el sacerdote ejecutará en ella toda esta ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 5, 31, 'Y aquel varón será libre de iniquidad, y la mujer llevará su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 2, 'Habla á los hijos de Israel, y diles: El hombre, ó la mujer, cuando se apartare haciendo voto de Nazareo, para dedicarse á Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 3, 'Se abstendrá de vino y de sidra; vinagre de vino, ni vinagre de sidra no beberá, ni beberá algún licor de uvas, ni tampoco comerá uvas frescas ni secas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 4, 'Todo el tiempo de su nazareato, de todo lo que se hace de vid de vino, desde los granillos hasta el hollejo, no comerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 5, 'Todo el tiempo del voto de su nazareato no pasará navaja sobre su cabeza, hasta que sean cumplidos los días de su apartamiento á Jehová: santo será; dejará crecer las guedejas del cabello de su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 6, 'Todo el tiempo que se apartaré á Jehová, no entrará á persona muerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 7, 'Por su padre, ni por su madre, por su hermano, ni por su hermana, no se contaminará con ellos cuando murieren; porque consagración de su Dios tiene sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 8, 'Todo el tiempo de su nazareato, será santo á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 9, 'Y si alguno muriere muy de repente junto á el, contaminará la cabeza de su nazareato; por tanto el día de su purificacíon raerá su cabeza; al séptimo día la raerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 10, 'Y el día octavo traerá dos tórtolas ó dos palominos al sacerdote, á la puerta del tabernáculo del testimonio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 11, 'Y el sacerdote hará el uno en expiación, y el otro en holocausto: y expiarálo de lo que pecó sobre el muerto, y santificará su cabeza en aquel día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 12, 'Y consagrará á Jehová los días de su nazareato, y traerá un cordero de un año en expiación por la culpa; y los días primeros serán anulados, por cuanto fué contaminado su nazareato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 13, 'Esta es, pues, la ley del Nazareo el día que se cumpliere el tiempo de su nazareato: Vendrá á la puerta del tabernáculo del testimonio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 14, 'Y ofrecerá su ofrenda á Jehová, un cordero de un año sin tacha en holocausto, y una cordera de un año sin defecto en expiación, y un carnero sin defecto por sacrificio de paces:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 15, 'Además un canastillo de cenceñas, tortas de flor de harina amasadas con aceite, y hojaldres cenceñas untadas con aceite, y su presente, y sus libaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 16, 'Y el sacerdote lo ofrecerá delante de Jehová, y hará su expiación y su holocausto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 17, 'Y ofrecerá el carnero en sacrificio de paces á Jehová, con el canastillo de las cenceñas; ofrecerá asimismo el sacerdote su presente, y sus libaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 18, 'Entonces el Nazareo raerá á la puerta del tabernáculo del testimonio la cabeza de su nazareato, y tomará los cabellos de la cabeza de su nazareato, y los pondrá sobre el fuego que está debajo del sacrificio de las paces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 19, 'Después tomará el sacerdote la espaldilla cocida del carnero, y una torta sin levadura del canastillo, y una hojaldre sin levadura, y pondrálas sobre las manos del Nazareo, después que fuere raído su nazareato:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 20, 'Y el sacerdote mecerá aquello, ofrenda agitada delante de Jehová; lo cual será cosa santa del sacerdote, á más del pecho mecido y de la espaldilla separada: y después podrá beber vino el Nazareo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 21, 'Esta es la ley del Nazareo que hiciere voto de su ofrenda á Jehová por su nazareato, á más de lo que su mano alcanzare: según el voto que hiciere, así hará, conforme á la ley de su nazareato.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 22, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 23, 'Habla á Aarón y á sus hijos, y diles: Asi bendeciréis á los hijos de Israel, diciéndoles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 24, 'Jehová te bendiga, y te guarde:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 25, 'Haga resplandecer Jehová su rostro sobre ti, y haya de ti misericordia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 26, 'Jehová alce á ti su rostro, y ponga en ti paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 6, 27, 'Y pondrán mi nombre sobre los hijos de Israel, y yo los bendeciré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 1, 'Y ACONTECIO, que cuando Moisés hubo acabado de levantar el tabernáculo, y ungídolo, y santificádolo, con todos sus vasos; y asimismo ungido y santificado el altar, con todos sus vasos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 2, 'Entonces los príncipes de Israel, las cabezas de las casas de sus padres, los cuales eran los príncipes de las tribus, que estaban sobre los contados, ofrecieron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 3, 'Y trajeron sus ofrendas delante de Jehová, seis carros cubiertos, y doce bueyes; por cada dos príncipes un carro, y cada uno un buey; lo cual ofrecieron delante del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 4, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 5, 'Tómalo de ellos, y será para el servicio del tabernáculo del testimonio: y lo darás á los Levitas, á cada uno conforme á su ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 6, 'Entonces Moisés recibió los carros y los bueyes, y diólos á los Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 7, 'Dos carros y cuatro bueyes, dió á los hijos de Gersón, conforme á su ministerio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 8, 'Y á los hijos de Merari dió los cuatro carros y ocho bueyes, conforme á su ministerio, bajo la mano de Ithamar, hijo de Aarón el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 9, 'Y á los hijos de Coath no dió; porque llevaban sobre sí en los hombros el servicio del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 10, 'Y ofrecieron los príncipes á la dedicación del altar el día que fué ungido, ofrecieron los príncipes su ofrenda delante del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 11, 'Y Jehová dijo á Moisés: Ofrecerán su ofrenda, un príncipe un día, y otro príncipe otro día, á la dedicación del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 12, 'Y el que ofreció su ofrenda el primer día fué Naasón hijo de Aminadab, de la tribu de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 13, 'Y fué su ofrenda un plato de plata de peso de ciento y treinta siclos, y un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 14, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 15, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 16, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 17, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Naasón, hijo de Aminadab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 18, 'El segundo día ofreció Nathanael hijo de Suar, príncipe de Issachâr.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 19, 'Ofreció por su ofrenda un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 20, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 21, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 22, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 23, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Nathanael, hijo de Suar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 24, 'El tercer día, Eliab hijo de Helón, príncipe de los hijos de Zabulón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 25, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 26, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 27, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 28, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 29, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Eliab, hijo de Helón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 30, 'El cuarto día, Elisur hijo de Sedeur, príncipe de los hijos de Rubén:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 31, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario, ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 32, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 33, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 34, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 35, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Elisur, hijo de Sedeur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 36, 'El quinto día, Selumiel hijo de Zurisaddai, príncipe de los hijos de Simeón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 37, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 38, 'Una cuchara de oro de diez siclos llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 39, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 40, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 41, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Selumiel, hijo de Zurisaddai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 42, 'El sexto día, Eliasaph hijo de Dehuel, príncipe de los hijos de Gad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 43, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 44, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 45, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 46, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 47, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año, Esta fué la ofrenda de Eliasaph, hijo de Dehuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 48, 'El séptimo día, el príncipe de los hijos de Ephraim, Elisama hijo de Ammiud:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 49, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 50, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 51, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 52, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 53, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Elisama, hijo de Ammiud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 54, 'El octavo día, el príncipe de los hijos de Manasés, Gamaliel hijo de Pedasur:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 55, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 56, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 57, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 58, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 59, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Gamaliel, hijo de Pedasur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 60, 'El noveno día, el príncipe de los hijos de Benjamín, Abidán hijo de Gedeón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 61, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 62, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 63, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 64, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 65, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Abidán, hijo de Gedeón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 66, 'El décimo día, el príncipe de los hijos de Dan, Ahiezer hijo de Ammisaddai:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 67, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 68, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 69, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 70, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 71, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Ahiezer, hijo de Ammisaddai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 72, 'El undécimo día, el príncipe de los hijos de Aser, Pagiel hijo de Ocrán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 73, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 74, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 75, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 76, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 77, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Pagiel, hijo de Ocrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 78, 'El duodécimo día, el príncipe de los hijos de Nephtalí, Ahira hijo de Enán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 79, 'Y su ofrenda, un plato de plata de ciento y treinta siclos de peso, un jarro de plata de setenta siclos, al siclo del santuario; ambos llenos de flor de harina amasada con aceite para presente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 80, 'Una cuchara de oro de diez siclos, llena de perfume;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 81, 'Un becerro, un carnero, un cordero de un año para holocausto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 82, 'Un macho cabrío para expiación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 83, 'Y para sacrificio de paces, dos bueyes, cinco carneros, cinco machos de cabrío, cinco corderos de un año. Esta fué la ofrenda de Ahira, hijo de Enán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 84, 'Esta fué la dedicación del altar, el día que fué ungido, por los príncipes de Israel: doce platos de plata, doce jarros de plata, doce cucharas de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 85, 'Cada plato de ciento y treinta siclos, cada jarro de setenta: toda la plata de los vasos, dos mil y cuatrocientos siclos, al siclo del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 86, 'Las doce cucharas de oro llenas de perfume, de diez siclos cada cuchara, al siclo del santuario: todo el oro de las cucharas, ciento y veinte siclos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 87, 'Todos los bueyes para holocausto, doce becerros; doce los carneros, doce los corderos de un año, con su presente: y doce los machos de cabrío, para expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 88, 'Y todos los bueyes del sacrificio de las paces veinte y cuatro novillos, sesenta los carneros, sesenta los machos de cabrío, sesenta los corderos de un año. Esta fué la dedicación del altar, después que fué ungido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 7, 89, 'Y cuando entraba Moisés en el tabernáculo del testimonio, para hablar con El, oía la Voz que le hablaba de encima de la cubierta que estaba sobre el arca del testimonio, de entre los dos querubines: y hablaba con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 2, 'Habla á Aarón, y dile: Cuando encendieres las lámparas, las siete lámparas alumbrarán frente á frente del candelero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 3, 'Y Aarón lo hizo así; que encendió enfrente del candelero sus lámparas, como Jehová lo mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 4, 'Y esta era la hechura del candelero: de oro labrado á martillo; desde su pie hasta sus flores era labrado á martillo: conforme al modelo que Jehová mostró á Moisés, así hizo el candelero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 5, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 6, 'Toma á los Levitas de entre los hijos de Israel, y expíalos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 7, 'Y así les harás para expiarlos: rocía sobre ellos el agua de la expiación, y haz pasar la navaja sobre toda su carne, y lavarán sus vestidos, y serán expiados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 8, 'Luego tomarán un novillo, con su presente de flor de harina amasada con aceite; y tomarás otro novillo para expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 9, 'Y harás llegar los Levitas delante del tabernáculo del testimonio, y juntarás toda la congregación de los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 10, 'Y cuando habrás hecho llegar los Levitas delante de Jehová, pondrán los hijos de Israel sus manos sobre los Levitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 11, 'Y ofrecerá Aarón los Levitas delante de Jehová en ofrenda de los hijos de Israel, y servirán en el ministerio de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 12, 'Y los Levitas pondrán sus manos sobre las cabezas de los novillos: y ofrecerás el uno por expiación, y el otro en holocausto á Jehová, para expiar los Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 13, 'Y harás presentar los Levitas delante de Aarón, y delante de sus hijos, y los ofrecerás en ofrenda á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 14, 'Así apartarás los Levitas de entre los hijos de Israel; y serán míos los Levitas');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 15, 'Y después de eso vendrán los Levitas á ministrar en el tabernáculo del testimonio: los expiarás pues, y los ofrecerás en ofrenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 16, 'Porque enteramente me son á mí dados los Levitas de entre los hijos de Israel, en lugar de todo aquel que abre matriz; helos tomado para mí en lugar de los primogénitos de todos los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 17, 'Porque mío es todo primogénito en los hijos de Israel, así de hombres como de animales; desde el día que yo herí todo primogénito en la tierra de Egipto, los santifiqué para mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 18, 'Y he tomado los Levitas en lugar de todos los primogénitos en los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 19, 'Y yo he dado en don los Levitas á Aarón y á sus hijos de entre los hijos de Israel, para que sirvan el ministerio de los hijos de Israel en el tabernáculo del testimonio, y reconcilien á los hijos de Israel; porque no haya plaga en los hijos de Israel, llegando los hijos de Israel al santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 20, 'Y Moisés, y Aarón, y toda la congregación de los hijos de Israel, hicieron de los Levitas conforme á todas las cosas que mandó Jehová á Moisés acerca de los Levitas; así hicieron de ellos los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 21, 'Y los Levitas se purificaron, y lavaron sus vestidos; y Aarón los ofreció en ofrenda delante de Jehová, é hizo Aarón expiación por ellos para purificarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 22, 'Y así vinieron después los Levitas para servir en su ministerio en el tabernáculo del testimonio, delante de Aarón y delante de sus hijos: de la manera que mandó Jehová á Moisés acerca de los Levitas, así hicieron con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 23, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 24, 'Esto cuanto á los Levitas: de veinte y cinco años arriba entrarán á hacer su oficio en el servicio del tabernáculo del testimonio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 25, 'Mas desde los cincuenta años volverán del oficio de su ministerio, y nunca más servirán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 8, 26, 'Pero servirán con sus hermanos en el tabernáculo del testimonio, para hacer la guarda, bien que no servirán en el ministerio. Así harás de los Levitas cuanto á sus oficios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 1, 'Y HABLO Jehová á Moisés en el desierto de Sinaí, en el segundo año de su salida de la tierra de Egipto, en el mes primero, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 2, 'Los hijos de Israel harán la pascua á su tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 3, 'El décimocuarto día de este mes, entre las dos tardes, la haréis á su tiempo: conforme á todos sus ritos, y conforme á todas sus leyes la haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 4, 'Y habló Moisés á los hijos de Israel, para que hiciesen la pascua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 5, 'E hicieron la pascua en el mes primero, á los catorce días del mes, entre las dos tardes, en el desierto de Sinaí: conforme á todas las cosas que mandó Jehová á Moisés, así hicieron los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 6, 'Y hubo algunos que estaban inmundos á causa de muerto, y no pudieron hacer la pascua aquel día; y llegaron delante de Moisés y delante de Aarón aquel día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 7, 'Y dijéronle aquellos hombres: Nosotros somos inmundos por causa de muerto; ¿por qué seremos impedidos de ofrecer ofrenda á Jehová á su tiempo entre los hijos de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 8, 'Y Moisés les respondió: Esperad, y oiré qué mandará Jehová acerca de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 9, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 10, 'Habla á los hijos de Israel, diciendo: Cualquiera de vosotros ó de vuestras generaciones, que fuere inmundo por causa de muerto ó estuviere de viaje lejos, hará pascua á Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 11, 'En el mes segundo, á los catorce días del mes, entre las dos tardes, la harán: con cenceñas y hierbas amargas la comerán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 12, 'No dejarán de él para la mañana, ni quebrarán hueso en él: conforme á todos los ritos de la pascua la harán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 13, 'Mas el que estuviere limpio, y no estuviere de viaje, si dejare de hacer la pascua, la tal persona será cortada de sus pueblos: por cuanto no ofreció á su tiempo la ofrenda de Jehová, el tal hombre llevará su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 14, 'Y si morare con vosotros peregrino, é hiciere la pascua á Jehová, conforme al rito de la pascua y conforme á sus leyes así la hará: un mismo rito tendréis, así el peregrino como el natural de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 15, 'Y el día que el tabernáculo fué levantado, la nube cubrió el tabernáculo sobre la tienda del testimonio; y á la tarde había sobre el tabernáculo como una apariencia de fuego, hasta la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 16, 'Así era continuamente: la nube lo cubría, y de noche la apariencia de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 17, 'Y según que se alzaba la nube del tabernáculo, los hijos de Israel se partían: y en el lugar donde la nube paraba, allí alojaban los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 18, 'Al mandato de Jehová los hijos de Israel se partían: y al mandato de Jehová asentaban el campo: todos los días que la nube estaba sobre el tabernáculo, ellos estaban quedos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 19, 'Y cuando la nube se detenía sobre el tabernáculo muchos días, entonces los hijos de Israel guardaban la ordenanza de Jehová y no partían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 20, 'Y cuando sucedía que la nube estaba sobre el tabernáculo pocos días, al dicho de Jehová alojaban, y al dicho de Jehová partían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 21, 'Y cuando era que la nube se detenía desde la tarde hasta la mañana, cuando á la mañana la nube se levantaba, ellos partían: ó si había estado el día, y á la noche la nube se levantaba, entonces partían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 22, 'O si dos días, ó un mes, ó un año, mientras la nube se detenía sobre el tabernáculo quedándose sobre él, los hijos de Israel se estaban acampados y no movían: mas cuando ella se alzaba, ellos movían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 9, 23, 'Al dicho de Jehová asentaban, y al dicho de Jehová partían, guardando la ordenanza de Jehová, como lo había Jehová dicho por medio de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 2, 'Hazte dos trompetas de plata; de obra de martillo las harás, las cuales te servirán para convocar la congregación, y para hacer mover el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 3, 'Y cuando las tocaren, toda la congregación se juntará á ti á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 4, 'Mas cuando tocaren sólo la una, entonces se congregarán á ti los príncipes, las cabezas de los millares de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 5, 'Y cuando tocareis alarma, entonces moverán el campo de los que están alojados al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 6, 'Y cuando tocareis alarma la segunda vez, entonces moverán el campo de los que están alojados al mediodía: alarma tocarán á sus partidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 7, 'Empero cuando hubiereis de juntar la congregación, tocaréis, mas no con sonido de alarma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 8, 'Y los hijos de Aarón, los sacerdotes, tocarán las trompetas; y las tendréis por estatuto perpetuo por vuestras generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 9, 'Y cuando viniereis á la guerra en vuestra tierra contra el enemigo que os molestare, tocaréis alarma con las trompetas: y seréis en memoria delante de Jehová vuestro Dios, y seréis salvos de vuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 10, 'Y en el día de vuestra alegría, y en vuestras solemnidades, y en los principios de vuestros meses, tocaréis las trompetas sobre vuestros holocaustos, y sobre los sacrificios de vuestras paces, y os serán por memoria delante de vuestro Dios: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 11, 'Y fué en el año segundo, en el mes segundo, á los veinte del mes, que la nube se alzó del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 12, 'Y movieron los hijos de Israel por sus partidas del desierto de Sinaí; y paró la nube en el desierto de Parán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 13, 'Y movieron la primera vez al dicho de Jehová por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 14, 'Y la bandera del campo de los hijos de Judá comenzó á marchar primero, por sus escuadrones: y Naasón, hijo de Aminadab, era sobre su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 15, 'Y sobre el ejército de la tribu de los hijos de Issachâr, Nathanael hijo de Suar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 16, 'Y sobre el ejército de la tribu de los hijos de Zabulón, Eliab hijo de Helón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 17, 'Y después que estaba ya desarmado el tabernáculo, movieron los hijos de Gersón y los hijos de Merari, que lo llevaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 18, 'Luego comenzó á marchar la bandera del campo de Rubén por sus escuadrones: y Elisur, hijo de Sedeur, era sobre su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 19, 'Y sobre el ejército de la tribu de los hijos de Simeón, Selumiel hijo de Zurisaddai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 20, 'Y sobre el ejército de la tribu de los hijos de Gad, Eliasaph hijo de Dehuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 21, 'Luego comenzaron á marchar los Coathitas llevando el santuario; y entre tanto que ellos llegaban, los otros acondicionaron el tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 22, 'Después comenzó á marchar la bandera del campo de los hijos de Ephraim por sus escuadrones: y Elisama, hijo de Ammiud, era sobre su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 23, 'Y sobre el ejército de la tribu de los hijos de Manasés, Gamaliel hijo de Pedasur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 24, 'Y sobre el ejército de la tribu de los hijos de Benjamín, Abidán hijo de Gedeón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 25, 'Luego comenzó á marchar la bandera del campo de los hijos de Dan por sus escuadrones, recogiendo todos los campos: y Ahiezer, hijo de Ammisaddai, era sobre su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 26, 'Y sobre el ejército de la tribu de los hijos de Aser, Pagiel hijo de Ocrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 27, 'Y sobre el ejército de la tribu de los hijos de Nephtalí, Ahira hijo de Enán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 28, 'Estas son las partidas de los hijos de Israel por sus ejércitos, cuando se movían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 29, 'Entonces dijo Moisés á Hobab, hijo de Ragüel Madianita, su suegro: Nosotros nos partimos para el lugar del cual Jehová ha dicho: Yo os lo daré. Ven con nosotros, y te haremos bien: porque Jehová ha hablado bien respecto á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 30, 'Y él le respondió: Yo no iré, sino que me marcharé á mi tierra y á mi parentela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 31, 'Y él le dijo: Ruégote que no nos dejes; porque tú sabes nuestros alojamientos en el desierto, y nos serás en lugar de ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 32, 'Y será, que si vinieres con nosotros, cuando tuviéremos el bien que Jehová nos ha de hacer, nosotros te haremos bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 33, 'Así partieron del monte de Jehová, camino de tres días; y el arca de la alianza de Jehová fué delante de ellos camino de tres días, buscándoles lugar de descanso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 34, 'Y la nube de Jehová iba sobre ellos de día, desde que partieron del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 35, 'Y fué, que en moviendo el arca, Moisés decía: Levántate, Jehová, y sean disipados tus enemigos, y huyan de tu presencia los que te aborrecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 10, 36, 'Y cuando ella asentaba, decía: Vuelve, Jehová, á los millares de millares de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 1, 'Y ACONTECIO que el pueblo se quejó á oídos de Jehová: y oyólo Jehová, y enardecióse su furor, y encendióse en ellos fuego de Jehová y consumió el un cabo del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 2, 'Entonces el pueblo dió voces á Moisés, y Moisés oró á Jehová, y soterróse el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 3, 'Y llamó á aquel lugar Taberah; porque el fuego de Jehová se encendió en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 4, 'Y el vulgo que había en medio tuvo un vivo deseo, y volvieron, y aun lloraron los hijos de Israel, y dijeron: ¡Quién nos diera á comer carne!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 5, 'Nos acordamos del pescado que comíamos en Egipto de balde, de los cohombros, y de los melones, y de los puerros, y de las cebollas, y de los ajos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 6, 'Y ahora nuestra alma se seca; que nada sino maná ven nuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 7, 'Y era el maná como semilla de culantro, y su color como color de bdelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 8, 'Derrámabase el pueblo, y recogían, y molían en molinos, ó majaban en morteros, y lo cocían en caldera, ó hacían de él tortas: y su sabor era como sabor de aceite nuevo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 9, 'Y cuando descendía el rocío sobre el real de noche, el maná descendía de sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 10, 'Y oyó Moisés al pueblo, que lloraba por sus familias, cada uno á la puerta de su tienda: y el furor de Jehová se encendió en gran manera; también pareció mal á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 11, 'Y dijo Moisés á Jehová: ¿Por qué has hecho mal á tu siervo? ¿y por qué no he hallado gracia en tus ojos, que has puesto la carga de todo este pueblo sobre mi?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 12, '¿Concebí yo á todo este pueblo? ¿engendrélo yo, para que me digas: Llévalo en tu seno, como lleva la que cría al que mama, á la tierra de la cual juraste á sus padres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 13, '¿De donde tengo yo carne para dar á todo este pueblo? porque lloran á mí, diciendo: Danos carne que comamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 14, 'No puedo yo solo soportar á todo este pueblo, que me es pesado en demasía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 15, 'Y si así lo haces tú conmigo, yo te ruego que me des muerte, si he hallado gracia en tus ojos; y que yo no vea mi mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 16, 'Entonces Jehová dijo á Moisés: Júntame setenta varones de los ancianos de Israel, que tu sabes que son ancianos del pueblo y sus principales; y tráelos á la puerta del tabernáculo del testimonio, y esperen allí contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 17, 'Y yo descenderé y hablaré allí contigo; y tomaré del espíritu que está en ti, y pondré en ellos; y llevarán contigo la carga del pueblo, y no la llevarás tú solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 18, 'Empero dirás al pueblo: Santificaos para mañana, y comeréis carne: pues que habéis llorado en oídos de Jehová, diciendo: ¡Quién nos diera á comer carne! ¡cierto mejor nos iba en Egipto! Jehová, pues, os dará carne, y comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 19, 'No comeréis un día, ni dos días, ni cinco días, ni diez días, ni veinte días;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 20, 'Sino hasta un mes de tiempo, hasta que os salga por las narices, y os sea en aborrecimiento: por cuanto menospreciasteis á Jehová que está en medio de vosotros, y llorasteis delante de él, diciendo: ¿Para qué salimos acá de Egipto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 21, 'Entonces dijo Moisés: Seiscientos mil de á pie es el pueblo en medio del cual yo estoy; y tú dices: Les daré carne, y comerán el tiempo de un mes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 22, '¿Se han de degollar para ellos ovejas y bueyes que les basten? ¿ó se juntarán para ellos todos los peces de la mar para que tengan abasto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 23, 'Entonces Jehová respondió á Moisés: ¿Hase acortado la mano de Jehová? ahora verás si te sucede mi dicho, ó no.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 24, 'Y salió Moisés, y dijo al pueblo las palabras de Jehová: y juntó los setenta varones de los ancianos del pueblo, é hízolos estar alrededor del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 25, 'Entonces Jehová descendió en la nube, y hablóle; y tomó del espíritu que estaba en él, y púsolo en los setenta varones ancianos; y fué que, cuando posó sobre ellos el espíritu, profetizaron, y no cesaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 26, 'Y habían quedado en el campo dos varones, llamado el uno Eldad y el otro Medad, sobre los cuales también reposó el espíritu: estaban estos entre los escritos, mas no habían salido al tabernáculo; y profetizaron en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 27, 'Y corrió un mozo, y dió aviso á Moisés, y dijo: Eldad y Medad profetizan en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 28, 'Entonces respondió Josué hijo de Nun, ministro de Moisés, uno de sus mancebos, y dijo: Señor mío Moisés, impídelos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 29, 'Y Moisés le respondió: ¿Tienes tú celos por mí? mas ojalá que todo el pueblo de Jehová fuesen profetas, que Jehová pusiera su espíritu sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 30, 'Y recogióse Moisés al campo, él y los ancianos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 31, 'Y salió un viento de Jehová, y trajo codornices de la mar, y dejólas sobre el real, un día de camino de la una parte, y un día de camino de la otra, en derredor del campo, y casi dos codos sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 32, 'Entonces el pueblo estuvo levantado todo aquel día, y toda la noche, y todo el día siguiente, y recogiéronse codornices: el que menos, recogió diez montones; y las tendieron para sí á lo largo en derredor del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 33, 'Aun estaba la carne entre los dientes de ellos, antes que fuese mascada, cuando el furor de Jehová se encendió en el pueblo, é hirío Jehová al pueblo con una muy grande plaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 34, 'Y llamó el nombre de aquel lugar Kibroth-hattaavah, por cuanto allí sepultaron al pueblo codicioso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 11, 35, 'De Kibroth-hattaavah movió el pueblo á Haseroth, y pararon en Haseroth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 1, 'Y HABLARON María y Aarón contra Moisés á causa de la mujer Ethiope que había tomado: porque él había tomado mujer Ethiope.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 2, 'Y dijeron: ¿Solamente por Moisés ha hablado Jehová? ¿no ha hablado también por nosotros? Y oyólo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 3, 'Y aquel varón Moisés era muy manso, más que todos los hombres que había sobre la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 4, 'Y luego dijo Jehová á Moisés, y á Aarón, y á María: Salid vosotros tres al tabernáculo del testimonio. Y salieron ellos tres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 5, 'Entonces Jehová descendió en la columna de la nube, y púsose á la la puerta del tabernáculo, y llamó á Aarón y á María; y salieron ellos ambos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 6, 'Y él les dijo: Oid ahora mis palabras: si tuviereis profeta de Jehová, le apareceré en visión, en sueños hablaré con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 7, 'No así á mi siervo Moisés, que es fiel en toda mi casa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 8, 'Boca á boca hablaré con él, y á las claras, y no por figuras; y verá la apariencia de Jehová: ¿por qué pues no tuvisteis temor de hablar contra mi siervo Moisés?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 9, 'Entonces el furor de Jehová se encendió en ellos; y fuése.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 10, 'Y la nube se apartó del tabernáculo: y he aquí que María era leprosa como la nieve; y miró Aarón á María, y he aquí que estaba leprosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 11, 'Y dijo Aarón á Moisés: ¡Ah! señor mío, no pongas ahora sobre nosotros pecado; porque locamente lo hemos hecho, y hemos pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 12, 'No sea ella ahora como el que sale muerto del vientre de su madre, consumida la mitad de su carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 13, 'Entonces Moisés clamó á Jehová, diciendo: Ruégote, oh Dios, que la sanes ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 14, 'Respondió Jehová á Moisés: Pues si su padre hubiera escupido en su cara, ¿no se avergonzaría por siete días?: sea echada fuera del real por siete días, y después se reunirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 15, 'Así María fué echada del real siete días; y el pueblo no pasó adelante hasta que se le reunió María.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 12, 16, '(13-1) Y DESPUÉS movió el pueblo de Haseroth, y asentaron el campo en el desierto de Parán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 1, '(13-2) Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 2, '(13-3) Envía tú hombres que reconozcan la tierra de Canaán, la cual yo doy á los hijos de Israel: de cada tribu de sus padres enviaréis un varón, cada uno príncipe entre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 3, '(13-4) Y Moisés los envío desde el desierto de Parán, conforme á la palabra de Jehová: y todos aquellos varones eran príncipes de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 4, '(13-5) Los nombres de los cuales son estos: De la tribu de Rubén, Sammua hijo de Zaccur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 5, '(13-6) De la tribu de Simeón, Saphat hijo de Huri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 6, '(13-7) De la tribu de Judá, Caleb hijo de Jephone.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 7, '(13-8) De la tribu de Issachâr, Igal hijo de Joseph.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 8, '(13-9) De la tribu de Ephraim, Oseas hijo de Nun.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 9, '(13-10) De la tribu de Benjamín, Palti hijo de Raphu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 10, '(13-11) De la tribu de Zabulón, Gaddiel hijo de Sodi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 11, '(13-12) De la tribu de José, de la tribu de Manasés, Gaddi hijo de Susi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 12, '(13-13) De la tribu de Dan, Ammiel hijo de Gemalli.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 13, '(13-14) De la tribu de Aser, Sethur hijo de Michâel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 14, '(13-15) De la tribu de Nephtalí, Nahabí hijo de Vapsi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 15, '(13-16) De la tribu de Gad, Gehuel hijo de Machî.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 16, '(13-17) Estos son los nombres de los varones que Moisés envió á reconocer la tierra: y á Oseas hijo de Nun, le puso Moisés el nombre de Josué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 17, '(13-18) Enviólos, pues, Moisés á reconocer la tierra de Canaán, diciéndoles: Subid por aquí, por el mediodía, y subid al monte:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 18, '(13-19) Y observad la tierra qué tal es; y el pueblo que la habita, si es fuerte ó débil, si poco ó numeroso;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 19, '(13-20) Qué tal la tierra habitada, si es buena ó mala; y qué tales son las ciudades habitadas, si de tiendas ó de fortalezas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 20, '(13-21) Y cuál sea el terreno, si es pingüe ó flaco, si en él hay ó no árboles: y esforzaos, y coged del fruto del país. Y el tiempo era el tiempo de las primeras uvas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 21, '(13-22) Y ellos subieron, y reconocieron la tierra desde el desierto de Zin hasta Rehob, entrando en Emath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 22, '(13-23) Y subieron por el mediodía, y vinieron hasta Hebrón: y allí estaban Aimán, y Sesai, y Talmai, hijos de Anac. Hebrón fué edificada siete años antes de Zoán, la de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 23, '(13-24) Y llegaron hasta el arroyo de Escol, y de allí cortaron un sarmiento con un racimo de uvas, el cual trejeron dos en un palo, y de las granadas y de los higos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 24, '(13-25) Y llamóse aquel lugar Nahal-escol por el racimo que cortaron de allí los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 25, '(13-26) Y volvieron de reconocer la tierra al cabo de cuarenta días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 26, '(13-27) Y anduvieron y vinieron á Moisés y á Aarón, y á toda la congregación de los hijos de Israel, en el desierto de Parán, en Cades, y diéronles la respuesta, y á toda la congregación, y les mostraron el fruto de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 27, '(13-28) Y le contaron, y dijeron: Nosotros llegamos á la tierra á la cual nos enviaste, la que ciertamente fluye leche y miel; y este es el fruto de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 28, '(13-29) Mas el pueblo que habita aquella tierra es fuerte, y las ciudades muy grandes y fuertes; y también vimos allí los hijos de Anac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 29, '(13-30) Amalec habita la tierra del mediodía; y el Hetheo, y el Jebuseo, y el Amorrheo, habitan en el monte; y el Cananeo habita junto á la mar, y á la ribera del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 30, '(13-31) Entonces Caleb hizo callar el pueblo delante de Moisés, y dijo: Subamos luego, y poseámosla; que más podremos que ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 31, '(13-32) Mas los varones que subieron con él, dijeron: No podremos subir contra aquel pueblo; porque es más fuerte que nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 32, '(13-33) y vituperaron entre los hijos de Israel la tierra que habían reconocido, diciendo: La tierra por donde pasamos para reconocerla, es tierra que traga á sus moradores; y todo el pueblo que vimos en medio de ella, son hombres de grande estatura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 13, 33, '(13-34) También vimos allí gigantes, hijos de Anac, raza de los gigantes: y éramos nosotros, á nuestro parecer, como langostas; y así les parecíamos á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 1, 'ENTONCES toda la congregación alzaron grita, y dieron voces: y el pueblo lloró aquella noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 2, 'Y quejáronse contra Moisés y contra Aarón todos los hijos de Israel; y díjoles toda la multitud: ¡Ojalá muriéramos en la tierra de Egipto; ó en este desierto ojalá muriéramos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 3, '¿Y por qué nos trae Jehová á esta tierra para caer á cuchillo y que nuestras mujeres y nuestros chiquitos sean por presa? ¿no nos sería mejor volvernos á Egipto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 4, 'Y decían el uno al otro: Hagamos un capitán, y volvámonos á Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 5, 'Entonces Moisés y Aarón cayeron sobre sus rostros delante de toda la multitud de la congregación de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 6, 'Y Josué hijo de Nun, y Caleb hijo de Jephone, que eran de los que habían reconocido la tierra, rompieron sus vestidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 7, 'Y hablaron á toda la congregación de los hijos de Israel, diciendo: La tierra por donde pasamos para reconocerla, es tierra en gran manera buena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 8, 'Si Jehová se agradare de nosotros, él nos meterá en esta tierra, y nos la entregará; tierra que fluye leche y miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 9, 'Por tanto, no seáis rebeldes contra Jehová, ni temáis al pueblo de aquesta tierra, porque nuestro pan son: su amparo se ha apartado de ellos, y con nosotros está Jehová: no los temáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 10, 'Entonces toda la multitud habló de apedrearlos con piedras. Mas la gloria de Jehová se mostró en el tabernáculo del testimonio á todos los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 11, 'Y Jehová dijo á Moisés: ¿Hasta cuándo me ha de irritar este pueblo? ¿hasta cuándo no me ha de creer con todas las señales que he hecho en medio de ellos?.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 12, 'Yo le heriré de mortandad, y lo destruiré, y á ti te pondré sobre gente grande y más fuerte que ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 13, 'Y Moisés respondió á Jehová: Oiránlo luego los Egipcios, porque de en medio de ellos sacaste á este pueblo con tu fortaleza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 14, 'Y lo dirán á los habitadores de esta tierra; los cuales han oído que tú, oh Jehová, estabas en medio de este pueblo, que ojo á ojo aparecías tú, oh Jehová, y que tu nube estaba sobre ellos, y que de día ibas delante de ellos en columna de nube, y de noche en columna de fuego:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 15, 'Y que has hecho morir á este pueblo como á un hombre: y las gentes que hubieren oído tu fama hablarán, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 16, 'Porque no pudo Jehová meter este pueblo en la tierra de la cual les había jurado, los mató en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 17, 'Ahora, pues, yo te ruego que sea magnificada la fortaleza del Señor, como lo hablaste, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 18, 'Jehová, tardo de ira y grande en misericordia, que perdona la iniquidad y la rebelión, y absolviendo no absolverá al culpado; que visita la maldad de los padres sobre los hijos hasta los terceros y hasta los cuartos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 19, 'Perdona ahora la iniquidad de este pueblo según la grandeza de tu misericordia, y como has perdonado á este pueblo desde Egipto hasta aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 20, 'Entonces Jehová dijo: Yo lo he perdonado conforme á tu dicho:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 21, 'Mas, ciertamente vivo yo y mi gloria hinche toda la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 22, 'Que todos los que vieron mi gloria y mis señales que he hecho en Egipto y en el desierto, y me han tentado ya diez veces, y no han oído mi voz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 23, 'No verán la tierra de la cual juré á sus padres: no, ninguno de los que me han irritado la verá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 24, 'Empero mi siervo Caleb, por cuanto hubo en él otro espíritu, y cumplió de ir en pos de mi, yo le meteré en la tierra donde entró y su simiente la recibirá en heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 25, 'Ahora bien, el Amalecita y el Cananeo habitan en el valle; volveos mañana, y partíos al desierto, camino del mar Bermejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 26, 'Y Jehová habló á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 27, '¿Hasta cuándo oiré esta depravada multitud que murmura contra mí, las querellas de los hijos de Israel, que de mí se quejan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 28, 'Diles: Vivo yo, dice Jehová, que según habéis hablado á mis oídos, así haré yo con vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 29, 'En este desierto caerán vuestros cuerpos; todos vuestros contados según toda vuestra cuenta, de veinte años arriba, los cuales habéis murmurado contra mí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 30, 'Vosotros á la verdad no entraréis en la tierra, por la cual alcé mi mano de haceros habitar en ella; exceptuando á Caleb hijo de Jephone, y á Josué hijo de Nun.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 31, 'Mas vuestros chiquitos, de los cuales dijisteis que serían por presa, yo los introduciré, y ellos conocerán la tierra que vosotros despreciasteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 32, 'Y en cuanto á vosotros, vuestros cuerpos caerán en este desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 33, 'Y vuestros hijos andarán pastoreando en el desierto cuarenta años, y ellos llevarán vuestras fornicaciones, hasta que vuestros cuerpos sean consumidos en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 34, 'Conforme al número de los días, de los cuarenta días en que reconocisteis la tierra, llevaréis vuestras iniquidades cuarenta años, un año por cada día; y conoceréis mi castigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 35, 'Yo Jehová he hablado; así haré á toda esta multitud perversa que se ha juntado contra mí; en este desierto serán consumidos, y ahí morirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 36, 'Y los varones que Moisés envió á reconocer la tierra, y vueltos habían hecho murmurar contra él á toda la congregación, desacreditando aquel país,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 37, 'Aquellos varones que habían hablado mal de la tierra, murieron de plaga delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 38, 'Mas Josué hijo de Nun, y Caleb hijo de Jephone, quedaron con vida de entre aquellos hombres que habían ido á reconocer la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 39, 'Y Moisés dijo estas cosas á todos los hijos de Israel, y el pueblo se enlutó mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 40, 'Y levantáronse por la mañana, y subieron á la cumbre del monte, diciendo: Henos aquí para subir al lugar del cual ha hablado Jehová; porque hemos pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 41, 'Y dijo Moisés: ¿Por qué quebrantáis el dicho de Jehová? Esto tampoco os sucederá bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 42, 'No subáis, porque Jehová no está en medio de vosotros, no seáis heridos delante de vuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 43, 'Porque el Amalecita y el Cananeo están allí delante de vosotros, y caeréis á cuchillo: pues por cuanto os habéis retraído de seguir á Jehová, por eso no será Jehová con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 44, 'Sin embargo, se obstinaron en subir á la cima del monte: mas el arca de la alianza de Jehová, y Moisés, no se apartaron de en medio del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 14, 45, 'Y descendieron el Amalecita y el Cananeo, que habitaban en aquel monte, é hiriéronlos y derrotáronlos, persiguiéndolos hasta Horma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 2, 'Habla á los hijos de Israel, y diles: Cuando hubiereis entrado en la tierra de vuestras habitaciones, que yo os doy,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 3, 'E hiciereis ofrenda encendida á Jehová, holocausto, ó sacrificio, por especial voto, ó de vuestra voluntad, ó para hacer en vuestras solemnidades olor suave á Jehová, de vacas ó de ovejas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 4, 'Entonces el que ofreciere su ofrenda á Jehová, traerá por presente una décima de un epha de flor de harina, amasada con la cuarta parte de un hin de aceite;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 5, 'Y de vino para la libación ofrecerás la cuarta parte de un hin, además del holocausto ó del sacrificio, por cada un cordero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 6, 'Y por cada carnero harás presente de dos décimas de flor de harina, amasada con el tercio de un hin de aceite:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 7, 'Y de vino para la libación ofrecerás el tercio de un hin, en olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 8, 'Y cuando ofreciereis novillo en holocausto ó sacrificio, por especial voto, ó de paces á Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 9, 'Ofrecerás con el novillo un presente de tres décimas de flor de harina, amasada con la mitad de un hin de aceite:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 10, 'Y de vino para la libación ofrecerás la mitad de un hin, en ofrenda encendida de olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 11, 'Así se hará con cada un buey, ó carnero, ó cordero, lo mismo de ovejas que de cabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 12, 'Conforme al número así haréis con cada uno según el número de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 13, 'Todo natural hará estas cosas así, para ofrecer ofrenda encendida de olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 14, 'Y cuando habitare con vosotros extranjero, ó cualquiera que estuviere entre vosotros por vuestras edades, si hiciere ofrenda encendida de olor suave á Jehová, como vosotros hiciereis, así hará él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 15, 'Un mismo estatuto tendréis, vosotros de la congregación y el extranjero que con vosotros mora; estatuto que será perpetuo por vuestras edades: como vosotros, así será el peregrino delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 16, 'Una misma ley y un mismo derecho tendréis, vosotros y el peregrino que con vosotros mora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 17, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 18, 'Habla á los hijos de Israel, y diles: Cuando hubiereis entrado en la tierra á la cual yo os llevo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 19, 'Será que cuando comenzareis á comer el pan de la tierra, ofreceréis ofrenda á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 20, 'De lo primero que amasareis, ofreceréis una torta en ofrenda; como la ofrenda de la era, así la ofreceréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 21, 'De las primicias de vuestras masas daréis á Jehová ofrenda por vuestras generaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 22, 'Y cuando errareis, y no hiciereis todos estos mandamientos que Jehová ha dicho á Moisés,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 23, 'Todas las cosas que Jehová os ha mandado por la mano de Moisés, desde el día que Jehová lo mandó, y en adelante por vuestras edades,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 24, 'Será que, si el pecado fué hecho por yerro con ignorancia de la congregación, toda la congregación ofrecerá un novillo por holocausto, en olor suave á Jehová, con su presente y su libación, conforme á la ley; y un macho cabrío en expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 25, 'Y el sacerdote hará expiación por toda la congregación de los hijos de Israel; y les será perdonado, porque yerro es: y ellos traerán sus ofrendas, ofrenda encendida á Jehová, y sus expiaciones delante de Jehová, por sus yerros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 26, 'Y será perdonado á toda la congregación de los hijos de Israel, y al extranjero que peregrina entre ellos, por cuanto es yerro de todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 27, 'Y si una persona pecare por yerro, ofrecerá una cabra de un año por expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 28, 'Y el sacerdote hará expiación por la persona que habrá pecado por yerro, cuando pecare por yerro delante de Jehová, la reconciliará, y le será perdonado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 29, 'El natural entre los hijos de Israel, y el peregrino que habitare entre ellos, una misma ley tendréis para el que hiciere algo por yerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 30, 'Mas la persona que hiciere algo con altiva mano, así el natural como el extranjero, á Jehová injurió; y la tal persona será cortada de en medio de su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 31, 'Por cuanto tuvo en poco la palabra de Jehová, y dió por nulo su mandamiento, enteramente será cortada la tal persona: su iniquidad será sobre ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 32, 'Y estando los hijos de Israel en el desierto, hallaron un hombre que recogía leña en día de sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 33, 'Y los que le hallaron recogiendo leña trajéronle á Moisés y á Aarón, y á toda la congregación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 34, 'Y pusiéronlo en la cárcel, por que no estaba declarado qué le habían de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 35, 'Y Jehová dijo á Moisés: Irremisiblemente muera aquel hombre; apedréelo con piedras toda la congregación fuera del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 36, 'Entonces lo sacó la congregación fuera del campo, y apedreáronlo con piedras, y murió; como Jehová mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 37, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 38, 'Habla á los hijos de Israel, y diles que se hagan pezuelos (franjas) en los remates de sus vestidos, por sus generaciones; y pongan en cada pezuelo de los remates un cordón de cárdeno:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 39, 'Y serviros ha de pezuelo, para que cuando lo viereis, os acordéis de todos los mandamientos de Jehová, para ponerlos por obra; y no miréis en pos de vuestro corazón y de vuestros ojos, en pos de los cuales fornicáis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 40, 'Para que os acordéis, y hagáis todos mis mandamientos, y seáis santos á vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 15, 41, 'Yo Jehová vuestro Dios, que os saqué de la tierra de Egipto, para ser vuestro Dios: Yo Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 1, 'Y CORÉ, hijo de Ishar, hijo de Coath, hijo de Leví; y Dathán y Abiram, hijos de Eliab; y Hon, hijo de Peleth, de los hijos de Rubén, tomaron gente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 2, 'Y levantáronse contra Moisés con doscientos y cincuenta varones de los hijos de Israel, príncipes de la congregación, de los del consejo, varones de nombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 3, 'Y se juntaron contra Moisés y Aarón, y les dijeron: Básteos, porque toda la congregación, todos ellos son santos, y en medio de ellos está Jehová: ¿por qué, pues, os levantáis vosotros sobre la congregación de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 4, 'Y como lo oyó Moisés, echóse sobre su rostro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 5, 'Y habló á Coré y á todo su séquito, diciendo: Mañana mostrará Jehová quién es suyo, y al santo harálo llegar á sí; y al que él escogiere, él lo allegará á sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 6, 'Haced esto: tomad incensarios, Coré y todo su séquito:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 7, 'Y poned fuego en ellos, y poned en ellos sahumerio delante de Jehová mañana; y será que el varón á quien Jehová escogiere, aquel será el santo: básteos esto, hijos de Leví.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 8, 'Dijo más Moisés á Coré: Oid ahora, hijos de Leví:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 9, '¿Os es poco que el Dios de Israel os haya apartado de la congregación de Israel, haciéndoos allegar á sí para que ministraseis en el servicio del tabernáculo de Jehová, y estuvieseis delante de la congregación para ministrarles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 10, '¿Y que te hizo acercar á ti, y á todos tus hermanos los hijos de Leví contigo; para que procuréis también el sacerdocio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 11, 'Por tanto, tú y todo tu séquito sois los que os juntáis contra Jehová: pues Aarón, ¿qué es para que contra él murmuréis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 12, 'Y envió Moisés á llamar á Dathán y Abiram, hijos de Eliab; mas ellos respondieron: No iremos allá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 13, '¿Es poco que nos hayas hecho venir de una tierra que destila leche y miel, para hacernos morir en el desierto, sino que también te enseñorees de nosotros imperiosamente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 14, 'Ni tampoco nos has metido tú en tierra que fluya leche y miel, ni nos has dado heredades de tierras y viñas: ¿has de arrancar los ojos de estos hombres? No subiremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 15, 'Entonces Moisés se enojó en gran manera, y dijo á Jehová: No mires á su presente: ni aun un asno he tomado de ellos, ni á ninguno de ellos he hecho mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 16, 'Después dijo Moisés á Coré: Tú y todo tu séquito, poneos mañana delante de Jehová; tú, y ellos, y Aarón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 17, 'Y tomad cada uno su incensario, y poned sahumerio en ellos, y allegad delante de Jehová cada uno su incensario: doscientos y cincuenta incensarios: tú también, y Aarón, cada uno con su incensario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 18, 'Y tomaron cada uno su incensario, y pusieron en ellos fuego, y echaron en ellos sahumerio, y pusiéronse á la puerta del tabernáculo del testimonio con Moisés y Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 19, 'Ya Coré había hecho juntar contra ellos toda la congregación á la puerta del tabernáculo del testimonio: entonces la gloria de Jehová apareció á toda la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 20, 'Y Jehová habló á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 21, 'Apartaos de entre esta congregación, y consumirlos he en un momento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 22, 'Y ellos se echaron sobre sus rostros, y dijeron: Dios, Dios de los espíritus de toda carne, ¿no es un hombre el que pecó? ¿y airarte has tu contra toda la congregación?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 23, 'Entonces Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 24, 'Habla á la congregación, diciendo: Apartaos de en derredor de la tienda de Coré, Dathán, y Abiram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 25, 'Y Moisés se levantó, y fué á Dathán y Abiram; y los ancianos de Israel fueron en pos de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 26, 'Y él habló á la congregación, diciendo: Apartaos ahora de las tiendas de estos impíos hombres, y no toquéis ninguna cosa suya, por que no perezcáis en todos sus pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 27, 'Y apartáronse de las tiendas de Coré, de Dathán, y de Abiram en derredor: y Dathán y Abiram salieron y pusiéronse á las puertas de sus tiendas, con sus mujeres, y sus hijos, y sus chiquitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 28, 'Y dijo Moisés: En esto conoceréis que Jehová me ha enviado para que hiciese todas estas cosas: que no de mi corazón las hice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 29, 'Si como mueren todos los hombres murieren éstos, ó si fueren ellos visitados á la manera de todos los hombres, Jehová no me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 30, 'Mas si Jehová hiciere una nueva cosa, y la tierra abriere su boca, y los tragare con todas sus cosas, y descendieren vivos al abismo, entonces conoceréis que estos hombres irritaron á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 31, 'Y aconteció, que en acabando él de hablar todas estas palabras, rompióse la tierra que estaba debajo de ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 32, 'Y abrió la tierra su boca, y tragólos á ellos, y á sus casas, y á todos los hombres de Coré, y á toda su hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 33, 'Y ellos, con todo lo que tenían, descendieron vivos al abismo, y cubriólos la tierra, y perecieron de en medio de la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 34, 'Y todo Israel, los que estaban en derredor de ellos, huyeron al grito de ellos; porque decían: No nos trague también la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 35, 'Y salió fuego de Jehová, y consumió los doscientos y cincuenta hombres que ofrecían el sahumerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 36, 'Entonces Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 37, 'Di á Eleazar, hijo de Aarón sacerdote, que tome los incensarios de en medio del incendio, y derrame más allá el fuego; porque son santificados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 38, 'Los incensarios de estos pecadores contra sus almas: y harán de ellos planchas extendidas para cubrir el altar: por cuanto ofrecieron con ellos delante de Jehová, son santificados; y serán por señal á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 39, 'Y el sacerdote Eleazar tomó los incensarios de metal con que los quemados habían ofrecido; y extendiéronlos para cubrir el altar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 40, 'En recuerdo á los hijos de Israel que ningún extraño que no sea de la simiente de Aarón, llegue á ofrecer sahumerio delante de Jehová, porque no sea como Coré, y como su séquito; según se lo dijo Jehová por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 41, 'El día siguiente toda la congregación de los hijos de Israel murmuró contra Moisés y Aarón, diciendo: Vosotros habéis muerto al pueblo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 42, 'Y aconteció que, como se juntó la congregación contra Moisés y Aarón, miraron hacia el tabernáculo del testimonio, y he aquí la nube lo había cubierto, y apareció la gloria de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 43, 'Y vinieron Moisés y Aarón delante del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 44, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 45, 'Apartaos de en medio de esta congregación, y consumirélos en un momento. Y ellos se echaron sobre sus rostros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 46, 'Y dijo Moisés A Aarón: Toma el incensario, y pon en él fuego del altar, y sobre él pon perfume, y ve presto á la congregación, y haz expiación por ellos; porque el furor ha salido de delante de la faz de Jehová: la mortandad ha comenzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 47, 'Entonces tomó Aarón el incensario, como Moisés dijo, y corrió en medio de la congregación: y he aquí que la mortandad había comenzado en el pueblo: y él puso perfume, é hizo expiación por el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 48, 'Y púsose entre los muertos y los vivos, y cesó la mortandad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 49, 'Y los que murieron en aquella mortandad fueron catorce mil y setecientos, sin los muertos por el negocio de Coré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 16, 50, 'Después se volvió Aarón á Moisés á la puerta del tabernáculo del testimonio, cuando la mortandad había cesado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 2, 'Habla á los hijos de Israel, y toma de ellos una vara por cada casa de los padres, de todos los príncipes de ellos, doce varas conforme á las casas de sus padres; y escribirás el nombre de cada uno sobre su vara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 3, 'Y escribirás el nombre de Aarón sobre la vara de Leví; porque cada cabeza de familia de sus padres tendrá una vara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 4, 'Y las pondrás en el tabernáculo del testimonio delante del testimonio, donde yo me declararé á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 5, 'Y será, que el varón que yo escogiere, su vara florecerá: y haré cesar de sobre mí las quejas de los hijos de Israel, con que murmuran contra vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 6, 'Y Moisés habló á los hijos de Israel, y todos los príncipes de ellos le dieron varas; cada príncipe por las casas de sus padres una vara, en todas doce varas; y la vara de Aarón estaba entre las varas de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 7, 'Y Moisés puso las varas delante de Jehová en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 8, 'Y aconteció que el día siguiente vino Moisés al tabernáculo del testimonio; y he aquí que la vara de Aarón de la casa de Leví había brotado, y echado flores, y arrojado renuevos, y producido almendras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 9, 'Entonces sacó Moisés todas las varas de delante de Jehová á todos los hijos de Israel; y ellos lo vieron, y tomaron cada uno su vara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 10, 'Y Jehová dijo á Moisés: Vuelve la vara de Aarón delante del testimonio, para que se guarde por señal á los hijos rebeldes; y harás cesar sus quejas de sobre mí, porque no mueran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 11, 'E hízolo Moisés: como le mandó Jehová, así hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 12, 'Entonces los hijos de Israel hablaron á Moisés, diciendo: He aquí nosotros somos muertos, perdidos somos, todos nosotros somos perdidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 17, 13, 'Cualquiera que se llegare, el que se acercare al tabernáculo de Jehová morirá: ¿acabaremos de perecer todos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 1, 'Y JEHOVA dijo á Aarón: Tú y tus hijos, y la casa de tu padre contigo, llevaréis el pecado del santuario: y tú y tus hijos contigo llevaréis el pecado de vuestro sacerdocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 2, 'Y á tus hermanos también, la tribu de Leví, la tribu de tu padre, hazlos llegar á ti, y júntense contigo, y servirte han; y tú y tus hijos contigo serviréis delante del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 3, 'Y guardarán lo que tú ordenares, y el cargo de todo el tabernáculo: mas no llegarán á los vasos santos ni al altar, porque no mueran ellos y vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 4, 'Se juntarán, pues, contigo, y tendrán el cargo del tabernáculo del testimonio en todo el servicio del tabernáculo; ningún extraño se ha de llegar á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 5, 'Y tendréis la guarda del santuario, y la guarda del altar, para que no sea más la ira sobre los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 6, 'Porque he aquí yo he tomado á vuestros hermanos los Levitas de entre los hijos de Israel, dados á vosotros en don de Jehová, para que sirvan en el ministerio del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 7, 'Mas tú y tus hijos contigo guardaréis vuestro sacerdocio en todo negocio del altar, y del velo adentro, y ministraréis. Yo os he dado en don el servicio de vuestro sacerdocio; y el extraño que se llegare, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 8, 'Dijo más Jehová á Aarón: He aquí yo te he dado también la guarda de mis ofrendas: todas las cosas consagradas de los hijos de Israel te he dado por razón de la unción, y á tus hijos, por estatuto perpetuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 9, 'Esto será tuyo de la ofrenda de las cosas santas reservadas del fuego: toda ofrenda de ellos, todo presente suyo, y toda expiación por el pecado de ellos, que me han de presentar, será cosa muy santa para ti y para tus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 10, 'En el santuario la comerás; todo varón comerá de ella: cosa santa será para ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 11, 'Esto también será tuyo: la ofrenda elevada de sus dones, y todas las ofrendas agitadas de los hijos de Israel, he dado á ti, y á tus hijos, y á tus hijas contigo, por estatuto perpetuo: todo limpio en tu casa comerá de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 12, 'De aceite, y de mosto, y de trigo, todo lo más escogido, las primicias de ello, que presentarán á Jehová, á ti las he dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 13, 'Las primicias de todas las cosas de la tierra de ellos, las cuales traerán á Jehová, serán tuyas: todo limpio en tu casa comerá de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 14, 'Todo lo consagrado por voto en Israel será tuyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 15, 'Todo lo que abriere matriz en toda carne que ofrecerán á Jehová, así de hombres como de animales, será tuyo: mas has de hacer redimir el primogénito del hombre: también harás redimir el primogénito de animal inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 16, 'Y de un mes harás efectuar el rescate de ellos, conforme á tu estimación, por precio de cinco siclos, al siclo del santuario, que es de veinte óbolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 17, 'Mas el primogénito de vaca, y el primogénito de oveja, y el primogénito de cabra, no redimirás; santificados son: la sangre de ellos rociarás sobre el altar, y quemarás la grosura de ellos, ofrenda encendida en olor suave á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 18, 'Y la carne de ellos será tuya: como el pecho de la mecedura y como la espaldilla derecha, será tuya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 19, 'Todas las ofrendas elevadas de las cosas santas, que los hijos de Israel ofrecieren á Jehová, helas dado para ti, y para tus hijos y para tus hijas contigo, por estatuto perpetuo: pacto de sal perpetuo es delante de Jehová para ti y para tu simiente contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 20, 'Y Jehová dijo á Aarón: De la tierra de ellos no tendrás heredad, ni entre ellos tendrás parte: Yo soy tu parte y tu heredad en medio de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 21, 'Y he aquí yo he dado á los hijos de Leví todos los diezmos en Israel por heredad, por su ministerio, por cuanto ellos sirven en el ministerio del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 22, 'Y no llegarán más los hijos de Israel al tabernáculo del testimonio, porque no lleven pecado, por el cual mueran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 23, 'Mas los Levitas harán el servicio del tabernáculo del testimonio, y ellos llevarán su iniquidad: estatuto perpetuo por vuestras edades; y no poseerán heredad entre los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 24, 'Porque á los Levitas he dado por heredad los diezmos de los hijos de Israel, que ofrecerán á Jehová en ofrenda: por lo cual les he dicho: Entre los hijos de Israel no poseerán heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 25, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 26, 'Así hablarás á los Levitas, y les dirás: Cuando tomareis de los hijos de Israel los diezmos que os he dado de ellos por vuestra heredad, vosotros presentaréis de ellos en ofrenda mecida á Jehová el diezmo de los diezmos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 27, 'Y se os contará vuestra ofrenda como grano de la era, y como acopio del lagar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 28, 'Así ofreceréis también vosotros ofrenda á Jehová de todos vuestros diezmos que hubiereis recibido de los hijos de Israel; y daréis de ellos la ofrenda de Jehová á Aarón el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 29, 'De todos vuestros dones ofreceréis toda ofrenda á Jehová; de todo lo mejor de ellos ofreceréis la porción que ha de ser consagrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 30, 'Y les dirás: Cuando ofreciereis lo mejor de ellos, será contado á los Levitas por fruto de la era, y commo fruto del lagar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 31, 'Y lo comeréis en cualquier lugar, vosotros y vuestra familia: pues es vuestra remuneración por vuestro ministerio en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 18, 32, 'Y cuando vosotros hubiereis ofrecido de ello lo mejor suyo, no llevaréis por ello pecado: y no habéis de contaminar las cosas santas de los hijos de Israel, y no moriréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 1, 'Y Jehová habló á Moisés y á Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 2, 'Esta es la ordenanza de la ley que Jehová ha prescrito, diciendo: Di á los hijos de Israel que te traigan una vaca bermeja, perfecta, en la cual no haya falta, sobre la cual no se haya puesto yugo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 3, 'Y la daréis á Eleazar el sacerdote, y él la sacará fuera del campo, y harála degollar en su presencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 4, 'Y tomará Eleazar el sacerdote de su sangre con su dedo, y rociará hacia la delantera del tabernáculo del testimonio con la sangre de ella siete veces;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 5, 'Y hará quemar la vaca ante sus ojos: su cuero y su carne y su sangre, con su estiercol, hará quemar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 6, 'Luego tomará el sacerdote palo de cedro, é hisopo, y escarlata, y lo echará en medio del fuego en que arde la vaca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 7, 'El sacerdote lavará luego sus vestidos, lavará también su carne con agua, y después entrará en el real; y será inmundo el sacerdote hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 8, 'Asimismo el que la quemó, lavará sus vestidos en agua, también lavará en agua su carne, y será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 9, 'Y un hombre limpio recogerá las cenizas de la vaca, y las pondrá fuera del campo en lugar limpio, y las guardará la congregación de los hijos de Israel para el agua de separación: es una expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 10, 'Y el que recogió las cenizas de la vaca, lavará sus vestidos, y será inmundo hasta la tarde: y será á los hijos de Israel, y al extranjero que peregrina entre ellos, por estatuto perpetuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 11, 'El que tocare muerto de cualquiera persona humana, siete días será inmundo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 12, 'Este se purificará al tercer día con aquesta agua, y al séptimo día será limpio; y si al tercer día no se purificare, no será limpio al séptimo día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 13, 'Cualquiera que tocare en muerto, en persona de hombre que estuviere muerto, y no se purificare, el tabernáculo de Jehová contaminó; y aquella persona será cortada de Israel: por cuanto el agua de la separación no fué rociada sobre él, inmundo será; y su inmundicia será sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 14, 'Esta es la ley para cuando alguno muriere en la tienda: cualquiera que entrare en la tienda y todo lo que estuviere en ella, será inmundo siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 15, 'Y todo vaso abierto, sobre el cual no hubiere tapadera bien ajustada, sera inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 16, 'Y cualquiera que tocare en muerto á cuchillo sobre la haz del campo, ó en muerto, ó en hueso humano, ó en sepulcro, siete días será inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 17, 'Y para el inmundo tomarán de la ceniza de la quemada vaca de la expiación, y echarán sobre ella agua viva en un vaso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 18, 'Y un hombre limpio tomará hisopo. y mojarálo en el agua, y rociará sobre la tienda, y sobre todos los muebles, y sobre las personas que allí estuvieren, y sobre aquel que hubiere tocado el hueso, ó el matado, ó el muerto, ó el sepulcro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 19, 'Y el limpio rociará sobre el inmundo al tercero y al séptimo día: y cuando lo habrá purificado al día séptimo, él lavará luego sus vestidos, y á sí mismo se lavará con agua, y será limpio á la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 20, 'Y el que fuere inmundo, y no se purificare, la tal persona será cortada de entre la congregación, por cuanto contaminó el tabernáculo de Jehová: no fué rociada sobre él el agua de separación, es inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 21, 'Y les será por estatuto perpetuo: también el que rociare el agua de la separación lavará sus vestidos; y el que tocare el agua de la separación, será inmundo hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 19, 22, 'Y todo lo que el inmundo tocare, será inmundo: y la persona que lo tocare, será inmunda hasta la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 1, 'Y LLEGARON los hijos de Israel, toda la congregación, al desierto de Zin, en el mes primero, y asentó el pueblo en Cades; y allí murió María, y fué allí sepultada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 2, 'Y como no hubiese agua para la congregación, juntáronse contra Moisés y Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 3, 'Y regañó el pueblo con Moisés, y hablaron diciendo: ¡Ojalá que nosotros hubiéramos muerto cuando perecieron nuestros hermanos delante de Jehová!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 4, 'Y ¿por qué hiciste venir la congregación de Jehová á este desierto, para que muramos aquí nosotros y nuestras bestias?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 5, '¿Y por qué nos has hecho subir de Egipto, para traernos á este mal lugar? No es lugar de sementera, de higueras, de viñas, ni granadas: ni aun de agua para beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 6, 'Y fuéronse Moisés y Aarón de delante de la congregación á la puerta del tabernáculo del testimonio, y echáronse sobre sus rostros; y la gloria de Jehová apareció sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 7, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 8, 'Toma la vara y reune la congregación, tú y Aarón tu hermano, y hablad á la peña en ojos de ellos; y ella dará su agua, y les sacarás aguas de la peña, y darás de beber á la congregación, y á sus bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 9, 'Entonces Moisés tomó la vara de delante de Jehová, como él le mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 10, 'Y juntaron Moisés y Aarón la congregación delante de la peña, y díjoles: Oid ahora, rebeldes: ¿os hemos de hacer salir aguas de esta peña?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 11, 'Entonces alzó Moisés su mano, é hirió la peña con su vara dos veces: y salieron muchas aguas, y bebió la congregación, y sus bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 12, 'Y Jehová dijo á Moisés y á Aarón: Por cuanto no creísteis en mí, para santificarme en ojos de los hijos de Israel, por tanto, no meteréis esta congregación en la tierra que les he dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 13, 'Estas son las aguas de la rencilla, por las cuales contendieron los hijos de Israel con Jehová, y él se santificó en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 14, 'Y envió Moisés embajadores al rey de Edom desde Cades: Así dice Israel tu hermano: Tú has sabido todo el trabajo que nos ha venido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 15, 'Cómo nuestros padres descendieron á Egipto, y estuvimos en Egipto largo tiempo, y los Egipcios nos maltrataron, y á nuestros padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 16, 'Y clamamos á Jehová, el cual oyó nuestra voz, y envió ángel, y sacónos de Egipto; y he aquí estamos en Cades, ciudad al extremo de tus confines:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 17, 'Rogámoste que pasemos por tu tierra; no pasaremos por labranza, ni por viña, ni beberemos agua de pozos: por el camino real iremos, sin apartarnos á la diestra ni á la siniestra, hasta que hayamos pasado tu término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 18, 'Y Edom le respondió: No pasarás por mi país, de otra manera saldré contra ti armado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 19, 'Y los hijos de Israel dijeron: Por el camino seguido iremos; y si bebiéremos tus aguas yo y mis ganados, daré el precio de ellas: ciertamente sin hacer otra cosa, pasaré de seguida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 20, 'Y él respondió: No pasarás. Y salió Edom contra él con mucho pueblo, y mano fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 21, 'No quiso, pues, Edom dejar pasar á Israel por su término, y apartóse Israel de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 22, 'Y partidos de Cades los hijos de Israel, toda aquella congregación, vinieron al monte de Hor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 23, 'Y Jehová habló á Moisés y Aarón en el monte de Hor, en los confines de la tierra de Edom, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 24, 'Aarón será reunido á sus pueblos; pues no entrará en la tierra que yo di á los hijos de Israel, por cuanto fuisteis rebeldes á mi mandamiento en las aguas de la rencilla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 25, 'Toma á Aarón y á Eleazar su hijo, y hazlos subir al monte de Hor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 26, 'Y haz desnudar á Aarón sus vestidos, y viste de ellos á Eleazar su hijo; porque Aarón será reunido á sus pueblos, y allí morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 27, 'Y Moisés hizo como Jehová le mandó: y subieron al monte de Hor á ojos de toda la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 28, 'Y Moisés hizo desnudar á Aarón de sus vestidos y vistiólos á Eleazar su hijo: y Aarón murió allí en la cumbre del monte: y Moisés y Eleazar descendieron del monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 20, 29, 'Y viendo toda la congregación que Aarón era muerto, hiciéronle duelo por treinta días todas las familias de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 1, 'Y OYENDO el Cananeo, el rey de Arad, el cual habitaba al mediodía, que venía Israel por el camino de los centinelas, peleó con Israel, y tomó de él presa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 2, 'Entonces Israel hizo voto á Jehová, y dijo: Si en efecto entregares á este pueblo en mi mano, yo destruiré sus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 3, 'Y Jehová escuchó la voz de Israel, y entregó al Cananeo, y destruyólos á ellos y á sus ciudades; y llamó el nombre de aquel lugar Horma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 4, 'Y partieron del monte de Hor, camino del mar Bermejo, para rodear la tierra de Edom; y abatióse el ánimo del pueblo por el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 5, 'Y habló el pueblo contra Dios y Moisés: ¿Por qué nos hiciste subir de Egipto para que muramos en este desierto? que ni hay pan, ni agua, y nuestra alma tiene fastidio de este pan tan liviano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 6, 'Y Jehová envió entre el pueblo serpientes ardientes, que mordían al pueblo: y murió mucho pueblo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 7, 'Entonces el pueblo vino á Moisés, y dijeron: Pecado hemos por haber hablado contra Jehová, y contra ti: ruega á Jehová que quite de nosotros estas serpientes. Y Moisés oró por el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 8, 'Y Jehová dijo á Moisés: Hazte una serpiente ardiente, y ponla sobre la bandera: y será que cualquiera que fuere mordido y mirare á ella, vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 9, 'Y Moisés hizo una serpiente de metal, y púsola sobre la bandera, y fué, que cuando alguna serpiente mordía á alguno, miraba á la serpiente de metal, y vivía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 10, 'Y partieron los hijos de Israel, y asentaron campo en Oboth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 11, 'Y partidos de Oboth, asentaron en Ije-abarim, en el desierto que está delante de Moab, al nacimiento del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 12, 'Partidos de allí, asentaron en la arroyada de Zared.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 13, 'De allí movieron, y asentaron de la otra parte de Arnón, que está en el desierto, y que sale del término del Amorrheo; porque Arnón es término de Moab, entre Moab y el Amorrheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 14, 'Por tanto se dice en el libro de las batallas de Jehová: Lo que hizo en el mar Bermejo, Y en los arroyos de Arnón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 15, 'Y á la corriente de los arroyos Que va á parar en Ar, Y descansa en el término de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 16, 'Y de allí vinieron á Beer: este es el pozo del cual Jehová dijo á Moisés: Junta al pueblo, y les daré agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 17, 'Entonces cantó Israel esta canción: Sube, oh pozo; á él cantad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 18, 'Pozo, el cual cavaron los señores; Caváronlo los príncipes del pueblo, Y el legislador, con sus bordones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 19, 'Y de Mathana á Nahaliel: y de Nahaliel á Bamoth:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 20, 'Y de Bamoth al valle que está en los campos de Moab, y á la cumbre de Pisga, que mira á Jesimón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 21, 'Y envió Israel embajadores á Sehón, rey de los Amorrheos, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 22, 'Pasaré por tu tierra: no nos apartaremos por los labrados, ni por las viñas; no beberemos las aguas de los pozos: por el camino real iremos, hasta que pasemos tu término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 23, 'Mas Sehón no dejó pasar á Israel por su término: antes juntó Sehón todo su pueblo, y salió contra Israel en el desierto: y vino á Jahaz, y peleó contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 24, 'E hirióle Israel á filo de espada, y tomó su tierra desde Arnón hasta Jaboc, hasta los hijos de Ammón: porque el término de los hijos de Ammón era fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 25, 'Y tomó Israel todas estas ciudades: y habitó Israel en todas las ciudades del Amorrheo, en Hesbón y en todas sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 26, 'Porque Hesbón era la ciudad de Sehón, rey de los Amorrheos; el cual había tenido guerra antes con el rey de Moab, y tomado de su poder toda su tierra hasta Arnón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 27, 'Por tanto, dicen los proverbistas: Venid á Hesbón, Edifíquese y repárese la ciudad de Sehón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 28, 'Que fuego salió de Hesbón, Y llama de la ciudad de Sehón, Y consumió á Ar de Moab, A los señores de los altos de Arnón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 29, '¡¡Ay de ti, Moab¡ Perecido has, pueblo de Chêmos: Puso sus hijos en huída, Y sus hijas en cautividad, Por Sehón rey de los Amorrheos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 30, 'Mas devastamos el reino de ellos; pereció Hesbón hasta Dibón, Y destruimos hasta Nopha y Medeba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 31, 'Así habitó Israel en la tierra del Amorrheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 32, 'Y envió Moisés á reconocer á Jazer; y tomaron sus aldeas, y echaron al Amorrheo que estaba allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 33, 'Y volvieron, y subieron camino de Basán, y salió contra ellos Og rey de Basán, él y todo su pueblo, para pelear en Edrei.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 34, 'Entonces Jehová dijo á Moisés: No le tengas miedo, que en tu mano lo he dado, á el y á todo su pueblo, y á su tierra; y harás de él como hiciste de Sehón, rey de los Amorrheos, que habitaba en Hesbón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 21, 35, 'E hirieron á él, y á sus hijos, y á toda su gente, sin que le quedara uno, y poseyeron su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 1, 'Y MOVIERON los hijos de Israel, y asentaron en los campos de Moab, de esta parte del Jordán de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 2, 'Y vió Balac, hijo de Zippor, todo lo que Israel había hecho al Amorrheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 3, 'Y Moab temió mucho á causa del pueblo que era mucho; y angustióse Moab á causa de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 4, 'Y dijo Moab á los ancianos de Madián: Ahora lamerá esta gente todos nuestros contornos, como lame el buey la grama del campo. Y Balac, hijo de Zippor, era entonces rey de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 5, 'Por tanto envió mensajeros á Balaam hijo de Beor, á Pethor, que está junto al río en la tierra de los hijos de su pueblo, para que lo llamasen, diciendo: Un pueblo ha salido de Egipto, y he aquí cubre la haz de la tierra, y habita delante de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 6, 'Ven pues ahora, te ruego, maldíceme este pueblo, porque es más fuerte que yo: quizá podré yo herirlo, y echarlo de la tierra: que yo sé que el que tú bendijeres, será bendito, y el que tú maldijeres, será maldito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 7, 'Y fueron los ancianos de Moab, y los ancianos de Madián, con las dádivas de adivinación en su mano, y llegaron á Balaam, y le dijeron las palabras de Balac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 8, 'Y él les dijo: Reposad aquí esta noche, y yo os referiré las palabras, como Jehová me hablare. Así los príncipes de Moab se quedaron con Balaam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 9, 'Y vino Dios á Balaam, y díjole: ¿Qué varones son estos que están contigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 10, 'Y Balaam respondió á Dios: Balac hijo de Zippor, rey de Moab, ha enviado á mí diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 11, 'He aquí este pueblo que ha salido de Egipto, cubre la haz de la tierra: ven pues ahora, y maldícemelo; quizá podré pelear con él, y echarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 12, 'Entonces dijo Dios á Balaam: No vayas con ellos, ni maldigas al pueblo; porque es bendito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 13, 'Así Balaam se levantó por la mañana, y dijo á los príncipes de Balac: Volveos á vuestra tierra, porque Jehová no me quiere dejar ir con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 14, 'Y los príncipes de Moab se levantaron, y vinieron á Balac, y dijeron: Balaam no quiso venir con nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 15, 'Y tornó Balac á enviar otra vez más príncipes, y más honorables que los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 16, 'Los cuales vinieron á Balaam, y dijéronle: Así dice Balac, hijo de Zippor: Ruégote que no dejes de venir á mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 17, 'Porque sin duda te honraré mucho, y haré todo lo que me dijeres: ven pues ahora, maldíceme á este pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 18, 'Y Balaam respondió, y dijo á los siervos de Balac: Aunque Balac me diese su casa llena de plata y oro, no puedo traspasar la palabra de Jehová mi Dios, para hacer cosa chica ni grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 19, 'Ruégoos por tanto ahora, que reposeis aquí esta noche, para que yo sepa que me vuelve á decir Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 20, 'Y vino Dios á Balaam de noche, y díjole: Si vinieren á llamarte hombres, levántate y ve con ellos: empero harás lo que yo te dijere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 21, 'Así Balaam se levantó por la mañana, y cinchó su asna, y fué con los príncipes de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 22, 'Y el furor de Dios se encendió porque él iba; y el ángel de Jehová se puso en el camino por adversario suyo. Iba, pues, él montado sobre su asna, y con él dos mozos suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 23, 'Y el asna vió al ángel de Jehová, que estaba en el camino con su espada desnuda en su mano; y apartóse el asna del camino, é iba por el campo. Entonces hirió Balaam al asna para hacerla volver al camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 24, 'Mas el ángel de Jehová se puso en una senda de viñas que tenía pared de una parte y pared de otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 25, 'Y viendo el asna al ángel de Jehová, pegóse á la pared, y apretó contra la pared el pie de Balaam: y él volvió á herirla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 26, 'Y el ángel de Jehová pasó más allá, y púsose en una angostura, donde no había camino para apartarse ni á diestra ni á siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 27, 'Y viendo el asna al ángel de Jehová, echóse debajo de Balaam: y enojóse Balaam, é hirió al asna con el palo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 28, 'Entonces Jehová abrió la boca al asna, la cual dijo á Balaam: ¿Qué te he hecho, que me has herido estas tres veces?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 29, 'Y Balaam respondió al asna: Porque te has burlado de mí: ¡ojalá tuviera espada en mi mano, que ahora te mataría!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 30, 'Y el asna dijo á Balaam: ¿No soy yo tu asna? sobre mí has cabalgado desde que tú me tienes hasta este día; ¿he acostumbrado á hacerlo así contigo? Y él respondió: No.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 31, 'Entonces Jehová abrió los ojos á Balaam, y vió al ángel de Jehová que estaba en el camino, y tenía su espada desnuda en su mano. Y Balaam hizo reverencia, é inclinóse sobre su rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 32, 'Y el ángel de Jehová le dijo: ¿Por qué has herido tu asna estas tres veces? he aquí yo he salido para contrarrestarte, porque tu camino es perverso delante de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 33, 'El asna me ha visto, y hase apartado luego de delante de mí estas tres veces: y si de mí no se hubiera apartado, yo también ahora te mataría á ti, y á ella dejaría viva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 34, 'Entonces Balaam dijo al ángel de Jehová: He pecado, que no sabía que tú te ponías delante de mí en el camino: mas ahora, si te parece mal, yo me volveré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 35, 'Y el ángel de Jehová dijo á Balaam: Ve con esos hombres: empero la palabra que yo te dijere, esa hablarás. Así Balaam fué con los príncipes de Balac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 36, 'Y oyendo Balac que Balaam venía, salió á recibirlo á la ciudad de Moab, que está junto al término de Arnón, que es el cabo de los confines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 37, 'Y Balac dijo á Balaam: ¿No envié yo á ti á llamarte? ¿por qué no has venido á mí? ¿no puedo yo honrarte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 38, 'Y Balaam respondió á Balac: He aquí yo he venido á ti: mas ¿podré ahora hablar alguna cosa? La palabra que Dios pusiere en mi boca, esa hablaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 39, 'Y fué Balaam con Balac, y vinieron á la ciudad de Husoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 40, 'Y Balac hizo matar bueyes y ovejas, y envió á Balaam, y á los príncipes que estaban con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 22, 41, 'Y el día siguiente Balac tomó á Balaam, é hízolo subir á los altos de Baal, y desde allí vió la extremidad del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 1, 'Y BALAAM dijo á Balac: Edifícame aquí siete altares, y prepárame aquí siete becerros y siete carneros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 2, 'Y Balac hizo como le dijo Balaam: y ofrecieron Balac y Balaam un becerro y un carnero en cada altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 3, 'Y Balaam dijo á Balac: Ponte junto á tu holocausto, y yo iré: quizá Jehová me vendrá al encuentro, y cualquiera cosa que me mostrare, te la noticiaré. Y así se fué solo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 4, 'Y vino Dios al encuentro de Balaam, y éste le dijo: Siete altares he ordenado, y en cada altar he ofrecido un becerro y un carnero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 5, 'Y Jehová puso palabra en la boca de Balaam, y díjole: Vuelve á Balac, y has de hablar así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 6, 'Y volvió á él, y he aquí estaba él junto á su holocausto, él y todos los príncipes de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 7, 'Y él tomó su parábola, y dijo: De Aram me trajo Balac, Rey de Moab, de los montes del oriente: Ven, maldíceme á Jacob; Y ven, execra á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 8, '¿Por qué maldeciré yo al que Dios no maldijo? ¿Y por qué he de execrar al que Jehová no ha execrado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 9, 'Porque de la cumbre de las peñas lo veré, Y desde los collados lo miraré: He aquí un pueblo que habitará confiado, Y no será contado entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 10, '¿Quién contará el polvo de Jacob, O el número de la cuarta parte de Israel? Muera mi persona de la muerte de los rectos, Y mi postrimería sea como la suya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 11, 'Entonces Balac dijo á Balaam: ¿Qué me has hecho? hete tomado para que maldigas á mis enemigos, y he aquí has proferido bendiciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 12, 'Y él respondió, y dijo: ¿No observaré yo lo que Jehová pusiere en mi boca para decirlo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 13, 'Y dijo Balac: Ruégote que vengas conmigo á otro lugar desde el cual lo veas; su extremidad solamente verás, que no lo verás todo; y desde allí me lo maldecirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 14, 'Y llevólo al campo de Sophim, á la cumbre de Pisga, y edificó siete altares, y ofreció un becerro y un carnero en cada altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 15, 'Entonces él dijo á Balac: Ponte aquí junto á tu holocausto, y yo iré á encontrar á Dios allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 16, 'Y Jehová salió al encuentro de Balaam, y puso palabra en su boca, y díjole: Vuelve á Balac, y así has de decir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 17, 'Y vino á él, y he aquí que él estaba junto á su holocausto, y con él los príncipes de Moab: y díjole Balac: ¿Qué ha dicho Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 18, 'Entonces él tomó su parábola, y dijo: Balac, levántate y oye; Escucha mis palabras, hijo de Zippor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 19, 'Dios no es hombre, para que mienta; Ni hijo de hombre para que se arrepienta: El dijo, ¿y no hará?; Habló, ¿y no lo ejecutará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 20, 'He aquí, yo he tomado bendición: Y él bendijo, y no podré revocarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 21, 'No ha notado iniquidad en Jacob, Ni ha visto perversidad en Israel: Jehová su Dios es con él, Y júbilo de rey en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 22, 'Dios los ha sacado de Egipto; Tiene fuerzas como de unicornio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 23, 'Porque en Jacob no hay agüero, Ni adivinación en Israel: Como ahora, será dicho de Jacob y de Israel: ¡Lo que ha hecho Dios!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 24, 'He aquí el pueblo, que como león se levantará, Y como león se erguirá: No se echará hasta que coma la presa, Y beba la sangre de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 25, 'Entonces Balac dijo á Balaam: Ya que no lo maldices, ni tampoco lo bendigas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 26, 'Y Balaam respondió, y dijo á Balac: ¿No te he dicho que todo lo que Jehová me dijere, aquello tengo de hacer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 27, 'Y dijo Balac á Balaam: Ruégote que vengas, te llevaré á otro lugar; por ventura parecerá bien á Dios que desde allí me lo maldigas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 28, 'Y Balac llevó á Balaam á la cumbre de Peor, que mira hacia Jesimón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 29, 'Entonces Balaam dijo á Balac: Edifícame aquí siete altares, y prepárame aquí siete becerros y siete carneros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 23, 30, 'Y Balac hizo como Balaam le dijo; y ofreció un becerro y un carnero en cada altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 1, 'Y COMO vió Balaam que parecía bien á Jehová que el bendijese á Israel, no fué, como la primera y segunda vez, á encuentro de agüeros, sino que puso su rostro hacia el desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 2, 'Y alzando sus ojos, vió á Israel alojado por sus tribus; y el espíritu de Dios vino sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 3, 'Entonces tomó su parábola, y dijo: Dijo Balaam hijo de Beor, Y dijo el varón de ojos abiertos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 4, 'Dijo el que oyó los dichos de Dios, El que vió la visión del Omnipotente; Caído, mas abiertos los ojos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 5, '¡Cuán hermosas son tus tiendas, oh Jacob, Tus habitaciones, oh Israel!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 6, 'Como arroyos están extendidas, Como huertos junto al río, Como lináloes plantados por Jehová, Como cedros junto á las aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 7, 'De sus manos destilarán aguas, Y su simiente será en muchas aguas: Y ensalzarse ha su rey más que Agag, Y su reino será ensalzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 8, 'Dios lo sacó de Egipto; Tiene fuerzas como de unicornio: Comerá á las gentes sus enemigas, Y desmenuzará sus huesos, Y asaeteará con sus saetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 9, 'Se encorvará para echarse como león, Y como leona; ¿quién lo despertará? Benditos los que te bendijeren, Y malditos los que te maldijeren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 10, 'Entonces se encendió la ira de Balac contra Balaam, y batiendo sus palmas le dijo: Para maldecir á mis enemigos te he llamado, y he aquí los has resueltamente bendecido ya tres veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 11, 'Húyete, por tanto, ahora á tu lugar: yo dije que te honraría, mas he aquí que Jehová te ha privado de honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 12, 'Y Balaam le respondió: ¿No lo declaré yo también á tus mensajeros que me enviaste, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 13, 'Si Balac me diése su casa llena de plata y oro, yo no podré traspasar el dicho de Jehová para hacer cosa buena ni mala de mi arbitrio; mas lo que Jehová hablare, eso diré yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 14, 'He aquí yo me voy ahora á mi pueblo: por tanto, ven, te indicaré lo que este pueblo ha de hacer á tu pueblo en los postrimeros días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 15, 'Y tomó su parábola, y dijo: Dijo Balaam hijo de Beor, Dijo el varón de ojos abiertos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 16, 'Dijo el que oyó los dichos de Jehová, Y el que sabe la ciencia del Altísimo, El que vió la visión del Omnipotente; Caído, mas abiertos los ojos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 17, 'Verélo, mas no ahora: Lo miraré, mas no de cerca: Saldrá ESTRELLA de Jacob, Y levantaráse cetro de Israel, Y herirá los cantones de Moab, Y destruirá á todos los hijos de Seth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 18, 'Y será tomada Edom, Será también tomada Seir por sus enemigos, E Israel se portará varonilmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 19, 'Y el de Jacob se enseñoreará, Y destruirá de la ciudad lo que quedare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 20, 'Y viendo á Amalec, tomó su parábola, y dijo: Amalec, cabeza de gentes; Mas su postrimería perecerá para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 21, 'Y viendo al Cineo, tomó su parábola, y dijo: Fuerte es tu habitación, Pon en la peña tu nido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 22, 'Que el Cineo será echado, Cuando Assur te llevará cautivo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 23, 'Todavía tomó su parábola, y dijo: ¡Ay! ¿quién vivirá cuando hiciere Dios estas cosas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 24, 'Y vendrán navíos de la costa de Cittim, Y afligirán á Assur, afligirán también á Eber: Mas él también perecerá para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 24, 25, 'Entonces se levantó Balaam, y se fué, y volvióse á su lugar: y también Balac se fué por su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 1, 'Y REPOSO Israel en Sittim, y el pueblo empezó á fornicar con las hijas de Moab:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 2, 'Las cuales llamaron al pueblo á los sacrificios de sus dioses: y el pueblo comió, é inclinóse á sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 3, 'Y allegóse el pueblo á Baal-peor; y el furor de Jehová se encendió contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 4, 'Y Jehová dijo á Moisés: Toma todos los príncipes del pueblo, y ahórcalos á Jehová delante del sol; y la ira del furor de Jehová se apartará de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 5, 'Entonces Moisés dijo á los jueces de Israel: Matad cada uno á aquellos de los suyos que se han allegado á Baal-peor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 6, 'Y he aquí un varón de los hijos de Israel vino y trajo una Madianita á sus hermanos, á ojos de Moisés y de toda la congregación de los hijos de Israel, llorando ellos á la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 7, 'Y viólo Phinees, hijo de Eleazar, hijo de Aarón el sacerdote, y levantóse de en medio de la congregación, y tomó una lanza en su mano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 8, 'Y fué tras el varón de Israel á la tienda, y alanceólos á ambos, al varón de Israel, y á la mujer por su vientre. Y cesó la mortandad de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 9, 'Y murieron de aquella mortandad veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 10, 'Entonces Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 11, 'Phinees, hijo de Eleazar, hijo de Aarón el sacerdote, ha hecho tornar mi furor de los hijos de Israel, llevado de celo entre ellos: por lo cual yo no he consumido en mi celo á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 12, 'Por tanto di les: He aquí yo establezco mi pacto de paz con él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 13, 'Y tendrá él, y su simiente después de él, el pacto del sacerdocio perpetuo; por cuanto tuvo celo por su Dios, é hizo expiación por los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 14, 'Y el nombre del varón muerto, que fué muerto con la Madianita, era Zimri hijo de Salu, jefe de una familia de la tribu de Simeón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 15, 'Y el nombre de la mujer Madianita muerta, era Cozbi, hija de Zur, príncipe de pueblos, padre de familia en Madián.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 16, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 17, 'Hostilizaréis á los Madianitas, y los heriréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 25, 18, 'Por cuanto ellos os afligieron á vosotros con sus ardides, con que os han engañado en el negocio de Peor, y en el negocio de Cozbi, hija del príncipe de Madián, su hermana, la cual fué muerta el día de la mortandad por causa de Peor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 1, 'Y ACONTECIO después de la mortandad, que Jehová habló á Moisés, y á Eleazar hijo del sacerdote Aarón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 2, 'Tomad la suma de toda la congregación de los hijos de Israel, de veinte años arriba, por las casas de sus padres, todos los que puedan salir á la guerra en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 3, 'Y Moisés y Eleazar el sacerdote hablaron con ellos en los campos de Moab, junto al Jordán de Jericó, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 4, 'Contaréis el pueblo de veinte años arriba, como mandó Jehová á Moisés y á los hijos de Israel, que habían salido de tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 5, 'Rubén primogénito de Israel: los hijos de Rubén: Hanoc, del cual era la familia de los Hanochîtas; de Phallú, la familia de los Phalluitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 6, 'De Hesrón, la familia de los Hesronitas; de Carmi, la familia de los Carmitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 7, 'Estas son las familias de los Rubenitas: y sus contados fueron cuarenta y tres mil setecientos y treinta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 8, 'Y los hijos de Phallú: Eliab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 9, 'Y los hijos de Eliab: Nemuel, y Dathán, y Abiram. Estos Dathán y Abiram fueron los del consejo de la congregación, que hicieron el motín contra Moisés y Aarón con la compañía de Coré, cuando se amotinaron contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 10, 'Que la tierra abrió su boca y tragó á ellos y á Coré, cuando aquella compañía murió, cuando consumió el fuego doscientos y cincuenta varones, los cuales fueron por señal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 11, 'Mas los hijos de Coré no murieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 12, 'Los hijos de Simeón por sus familias: de Nemuel, la familia de los Nemuelitas; de Jamín, la familia de los Jaminitas; de Jachîn, la familia de los Jachînitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 13, 'De Zera, la familia de los Zeraitas; de Saul, la familia de los Saulitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 14, 'Estas son las familias de los Simeonitas, veinte y dos mil y doscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 15, 'Los hijos de Gad por sus familias: de Zephón, la familia de los Zephonitas; de Aggi, la familia de los Aggitas; de Suni, la familia de los Sunitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 16, 'De Ozni, la familia de los Oznitas; de Eri, la familia de los Eritas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 17, 'De Aroz, la familia de los Aroditas; de Areli, la familia de los Arelitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 18, 'Estas son las familias de Gad, por sus contados, cuarenta mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 19, 'Los hijos de Judá: Er y Onán; y Er y Onán murieron en la tierra de Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 20, 'Y fueron los hijos de Judá por sus familias: de Sela, la familia de los Selaitas; de Phares, la familia de los Pharesitas; de Zera, la familia de los Zeraitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 21, 'Y fueron los hijos de Phares: de Hesrón, la familia de los Hesronitas; de Hamul, la familia de los Hamulitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 22, 'Estas son las familias de Judá, por sus contados, setenta y seis mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 23, 'Los hijos de Issachâr por sus familias: de Thola, la familia de los Tholaitas; de Puá la familia de los Puanitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 24, 'De Jasub, la familia de los Jasubitas; de Simron, la familia de los Simronitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 25, 'Estas son las familias de Issachâr, por sus contados, sesenta y cuatro mil y trescientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 26, 'Los hijos de Zabulón por sus familias: de Sered, la familia de los Sereditas; de Elón, la familia de los Elonitas; de Jalel, la familia de los Jalelitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 27, 'Estas son las familias de los Zabulonitas, por sus contados, sesenta mil y quinientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 28, 'Los hijos de José por sus familias: Manasés y Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 29, 'Los hijos de Manasés: de Machîr, la familia de los Machîritas; y Machîr engendró á Galaad; de Galaad, la familia de los Galaaditas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 30, 'Estos son los hijos de Galaad: de Jezer, la familia de los Jezeritas; de Helec, la familia de los Helecitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 31, 'De Asriel, la familia de los Asrielitas: de Sechêm, la familia de los Sechêmitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 32, 'De Semida, la familia de los Semidaitas; de Hepher, la familia de los Hepheritas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 33, 'Y Salphaad, hijo de Hepher, no tuvo hijos sino hijas: y los nombres de las hijas de Salphaad fueron Maala, y Noa, y Hogla, y Milca, y Tirsa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 34, 'Estas son las familias de Manasés; y sus contados, cincuenta y dos mil y setecientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 35, 'Estos son los hijos de Ephraim por sus familias: de Suthala, la familia de los Suthalaitas; de Bechêr, la familia de los Bechêritas; de Tahan, la familia de los Tahanitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 36, 'Y estos son los hijos de Suthala: de Herán, la familia de los Heranitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 37, 'Estas son las familias de los hijos de Ephraim, por sus contados, treinta y dos mil y quinientos. Estos son los hijos de José por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 38, 'Los hijos de Benjamín por sus familias: de Bela, la familia de los Belaitas; de Asbel, la familia de los Asbelitas; de Achîram, la familia de los Achîramitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 39, 'De Supham, la familia de los Suphamitas; de Hupham, la familia de los Huphamitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 40, 'Y los hijos de Bela fueron Ard y Naamán: de Ard, la familia de los Arditas; de Naamán, la familia de los Naamanitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 41, 'Estos son los hijos de Benjamín por sus familias; y sus contados, cuarenta y cinco mil y seiscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 42, 'Estos son los hijos de Dan por sus familias: de Suham, la familia de los Suhamitas. Estas son las familias de Dan por sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 43, 'Todas las familias de los Suhamitas, por sus contados, sesenta y cuatro mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 44, 'Los hijos de Aser por sus familias: de Imna, la familia de los Imnaitas; de Issui, la familia de los Issuitas; de Beria, la familia de los Beriaitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 45, 'Los hijos de Beria: de Heber, la familia de los Heberitas; de Malchîel, la familia de los Malchîelitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 46, 'Y el nombre de la hija de Aser fué Sera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 47, 'Estas son las familias de los hijos de Aser, por sus contados, cincuenta y tres mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 48, 'Los hijos de Nephtalí por sus familias: de Jahzeel, la familia de los Jahzeelitas; de Guni, la familia de los Gunitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 49, 'De Jeser, la familia de los Jeseritas; de Sillem, la familia de los Sillemitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 50, 'Estas son las familias de Nephtalí por sus familias; y sus contados, cuarenta y cinco mil y cuatrocientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 51, 'Estos son los contados de los hijos de Israel, seiscientos y un mil setecientos y treinta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 52, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 53, 'A estos se repartirá la tierra en heredad, por la cuenta de los nombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 54, 'A los más darás mayor heredad, y á los menos menor; y á cada uno se le dará su heredad conforme á sus contados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 55, 'Empero la tierra será repartida por suerte; y por los nombres de las tribus de sus padres heredarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 56, 'Conforme á la suerte será repartida su heredad entre el grande y el pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 57, 'Y los contados de los Levitas por sus familias son estos: de Gersón, la familia de los Gersonitas; de Coath, la familia de los Coathitas; de Merari, la familia de los Meraritas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 58, 'Estas son las familias de los Levitas: la familia de los Libnitas, la familia de los Hebronitas, la familia de los Mahalitas, la familia de los Musitas, la familia de los Coritas. Y Coath engendró á Amram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 59, 'Y la mujer de Amram se llamó Jochâbed, hija de Leví, la cual nació á Leví en Egipto: ésta parió de Amram á Aarón y á Moisés, y á María su hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 60, 'Y á Aarón nacieron Nadab y Abiú, Eleazar é Ithamar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 61, 'Mas Nadab y Abiú murieron, cuando ofrecieron fuego extraño delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 62, 'Y los contados de los Levitas fueron veinte y tres mil, todos varones de un mes arriba: porque no fueron contados entre los hijos de Israel, por cuanto no les había de ser dada heredad entre los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 63, 'Estos son los contados por Moisés y Eleazar el sacerdote, los cuales contaron los hijos de Israel en los campos de Moab, junto al Jordán de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 64, 'Y entre estos ninguno hubo de los contados por Moisés y Aarón el sacerdote, los cuales contaron á los hijos de Israel en el desierto de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 26, 65, 'Porque Jehová les dijo: Han de morir en el desierto: y no quedó varón de ellos, sino Caleb hijo de Jephone, y Josué hijo de Nun.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 1, 'Y LAS hijas de Salphaad, hijo de Hepher, hijo de Galaad, hijo de Machîr, hijo de Manasés, de las familias de Manasés, hijo de José, los nombres de las cuales eran Maala, y Noa, y Hogla, y Milca, y Tirsa, llegaron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 2, 'Y presentáronse delante de Moisés, y delante del sacerdote Eleazar, y delante de los príncipes, y de toda la congregación, á la puerta del tabernáculo del testimonio, y dijeron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 3, 'Nuestro padre murió en el desierto, el cual no estuvo en la junta que se reunió contra Jehová en la compañía de Coré: sino que en su pecado murió, y no tuvo hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 4, '¿Por qué será quitado el nombre de nuestro padre de entre su familia, por no haber tenido hijo? Danos heredad entre los hermanos de nuestro padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 5, 'Y Moisés llevó su causa delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 6, 'Y Jehová respondió á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 7, 'Bien dicen las hijas de Salphaad: has de darles posesión de heredad entre los hermanos de su padre; y traspasarás la heredad de su padre á ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 8, 'Y á los hijos de Israel hablarás, diciendo: Cuando alguno muriere sin hijos, traspasaréis su herencia á su hija:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 9, 'Y si no tuviere hija, daréis su herencia á sus hermanos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 10, 'Y si no tuviere hermanos, daréis su herencia á los hermanos de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 11, 'Y si su padre no tuviere hermanos, daréis su herencia á su pariente más cercano de su linaje, el cual la poseerá: y será á los hijos de Israel por estatuto de derecho, como Jehová mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 12, 'Y Jehová dijo á Moisés: Sube á este monte Abarim, y verás la tierra que he dado á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 13, 'Y después que la habrás visto, tú también serás reunido á tus pueblos, como fué reunido tu hermano Aarón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 14, 'Pues fuisteis rebeldes á mi dicho en el desierto de Zin, en la rencilla de la congregación, para santificarme en las aguas á ojos de ellos. Estas son las aguas de la rencilla de Cades en el desierto de Zin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 15, 'Entonces respondió Moisés á Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 16, 'Ponga Jehová, Dios de los espíritus de toda carne, varón sobre la congregación,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 17, 'Que salga delante de ellos, y que entre delante de ellos, que los saque y los introduzca; porque la congregación de Jehová no sea como ovejas sin pastor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 18, 'Y Jehová dijo á Moisés: Toma á Josué hijo de Nun, varón en el cual hay espíritu, y pondrás tu mano sobre él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 19, 'Y ponerlo has delante de Eleazar el sacerdote, y delante de toda la congregación; y le darás órdenes en presencia de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 20, 'Y pondrás de tu dignidad sobre él, para que toda la congregación de los hijos de Israel le obedezcan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 21, 'Y él estará delante de Eleazar el sacerdote, y á él preguntará por el juicio del Urim delante de Jehová: por el dicho de él saldrán, y por el dicho de él entrarán, él, y todos los hijos de Israel con él, y toda la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 22, 'Y Moisés hizo como Jehová le había mandado; que tomó á Josué, y le puso delante de Eleazar el sacerdote, y de toda la congregación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 27, 23, 'Y puso sobre él sus manos, y dióle órdenes, como Jehová había mandado por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 1, 'Y HABLO Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 2, 'Manda á los hijos de Israel, y diles: Mi ofrenda, mi pan con mis ofrendas encendidas en olor á mí agradable, guardaréis, ofreciéndomelo á su tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 3, 'Y les dirás: Esta es la ofrenda encendida que ofreceréis á Jehová: dos corderos sin tacha de un año, cada un día, será el holocausto continuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 4, 'El un cordero ofrecerás por la mañana, y el otro cordero ofrecerás entre las dos tardes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 5, 'Y la décima de un epha de flor de harina, amasada con una cuarta de un hin de aceite molido, en presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 6, 'Es holocausto continuo, que fué hecho en el monte de Sinaí en olor de suavidad, ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 7, 'Y su libación, la cuarta de un hin con cada cordero: derramarás libación de superior vino á Jehová en el santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 8, 'Y ofrecerás el segundo cordero entre las dos tardes: conforme á la ofrenda de la mañana, y conforme á su libación ofrecerás, ofrenda encendida en olor de suavidad á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 9, 'Mas el día del sábado dos corderos de un año sin defecto, y dos décimas de flor de harina amasada con aceite, por presente, con su libación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 10, 'Es el holocausto del sábado en cada sábado, además del holocausto continuo y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 11, 'Y en los principios de vuestros meses ofreceréis en holocausto á Jehová dos becerros de la vacada, y un carnero, y siete corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 12, 'Y tres décimas de flor de harina amasada con aceite, por presente con cada becerro; y dos décimas de flor de harina amasada con aceite, por presente con cada carnero;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 13, 'Y una décima de flor de harina amasada con aceite, en ofrenda por presente con cada cordero: holocausto de olor suave, ofrenda encendida á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 14, 'Y sus libaciones de vino, medio hin con cada becerro, y el tercio de un hin con cada carnero, y la cuarta de un hin con cada cordero. Este es el holocausto de cada mes por todos los meses del año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 15, 'Y un macho cabrío en expiación se ofrecerá á Jehová, además del holocausto continuo con su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 16, 'Mas en el mes primero, á los catorce del mes será la pascua de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 17, 'Y á los quince días de aqueste mes, la solemnidad: por siete días se comerán ázimos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 18, 'El primer día, santa convocación; ninguna obra servil haréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 19, 'Y ofreceréis por ofrenda encendida en holocausto á Jehová dos becerros de la vacada, y un carnero, y siete corderos de un año: sin defecto los tomaréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 20, 'Y su presente de harina amasada con aceite: tres décimas con cada becerro, y dos décimas con cada carnero ofreceréis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 21, 'Con cada uno de los siete corderos ofreceréis una décima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 22, 'Y un macho cabrío por expiación, para reconciliaros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 23, 'Esto ofreceréis además del holocausto de la mañana, que es el holocausto continuo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 24, 'Conforme á esto ofreceréis cada uno de los siete días, vianda y ofrenda encendida en olor de suavidad á Jehová; ofrecerse ha, además del holocausto continuo, con su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 25, 'Y el séptimo día tendréis santa convocación: ninguna obra servil haréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 26, 'Además el día de las primicias, cuando ofreciereis presente nuevo á Jehová en vuestras semanas, tendréis santa convocación: ninguna obra servil haréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 27, 'Y ofreceréis en holocausto, en olor de suavidad á Jehová, dos becerros de la vacada, un carnero, siete corderos de un año:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 28, 'Y el presente de ellos, flor de harina amasada con aceite, tres décimas con cada becerro, dos décimas con cada carnero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 29, 'Con cada uno de los siete corderos una décima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 30, 'Un macho cabrío, para hacer expiación por vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 28, 31, 'Los ofreceréis, además del holocausto continuo con sus presentes, y sus libaciones: sin defecto los tomaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 1, 'Y EL séptimo mes, al primero del mes tendréis santa convocación: ninguna obra servil haréis; os será día de sonar las trompetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 2, 'Y ofreceréis holocausto por olor de suavidad á Jehová, un becerro de la vacada, un carnero, siete corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 3, 'Y el presente de ellos, de flor de harina amasada con aceite, tres décimas con cada becerro, dos décimas con cada carnero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 4, 'Y con cada uno de los siete corderos, una décima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 5, 'Y un macho cabrío por expiación, para reconciliaros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 6, 'Además del holocausto del mes, y su presente, y el holocausto continuo y su presente, y sus libaciones, conforme á su ley, por ofrenda encendida á Jehová en olor de suavidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 7, 'Y en el diez de este mes séptimo tendréis santa convocación, y afligiréis vuestras almas: ninguna obra haréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 8, 'Y ofreceréis en holocausto á Jehová por olor de suavidad, un becerro de la vacada, un carnero, siete corderos de un año; sin defecto los tomaréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 9, 'Y sus presentes, flor de harina amasada con aceite, tres décimas con cada becerro, dos décimas con cada carnero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 10, 'Y con cada uno de los siete corderos, una décima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 11, 'Un macho cabrío por expiación: además de la ofrenda de las expiaciones por el pecado, y del holocausto continuo, y de sus presentes, y de sus libaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 12, 'También á los quince días del mes séptimo tendréis santa convocación; ninguna obra servil haréis, y celebraréis solemnidad á Jehová por siete días;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 13, 'Y ofreceréis en holocausto, en ofrenda encendida á Jehová en olor de suavidad, trece becerros de la vacada, dos carneros, catorce corderos de un año: han de ser sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 14, 'Y los presentes de ellos, de flor de harina amasada con aceite, tres décimas con cada uno de los trece becerros, dos décimas con cada uno de los dos carneros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 15, 'Y con cada uno de los catorce corderos, una décima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 16, 'Y un macho cabrío por expiación: además del holocausto continuo, su presente y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 17, 'Y el segundo día, doce becerros de la vacada, dos carneros, catorce corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 18, 'Y sus presentes y sus libaciones con los becerros, con los carneros, y con los corderos, según el número de ellos, conforme á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 19, 'Y un macho cabrío por expiación: además del holocausto continuo, y su presente y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 20, 'Y el día tercero, once becerros, dos carneros, catorce corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 21, 'Y sus presentes y sus libaciones con los becerros, con los carneros, y con los corderos, según el número de ellos, conforme á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 22, 'Y un macho cabrío por expiación: además del holocausto continuo, y su presente y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 23, 'Y el cuarto día, diez becerros, dos carneros, catorce corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 24, 'Sus presentes y sus libaciones con los becerros, con los carneros, y con los corderos, según el número de ellos, conforme á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 25, 'Y un macho cabrío por expiación: además del holocausto continuo, su presente y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 26, 'Y el quinto día, nueve becerros, dos carneros, catorce corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 27, 'Y sus presentes y sus libaciones con los becerros, con los carneros, y con los corderos, según el número de ellos, conforme á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 28, 'Y un macho cabrío por expiación: además del holocausto continuo, su presente y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 29, 'Y el sexto día, ocho becerros, dos carneros, catorce corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 30, 'Y sus presentes y sus libaciones con los becerros, con los carneros, y con los corderos, según el número de ellos, conforme á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 31, 'Y un macho cabrío por expiación: además del holocausto continuo, su presente y sus libaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 32, 'Y el séptimo día, siete becerros, dos carneros, catorce corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 33, 'Y sus presentes y sus libaciones con los becerros, con los carneros, y con los corderos, según el número de ellos, conforme á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 34, 'Y un macho cabrío por expiación: además del holocausto continuo, con su presente y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 35, 'El octavo día tendréis solemnidad: ninguna obra servil haréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 36, 'Y ofreceréis en holocausto, en ofrenda encendida de olor suave á Jehová, un novillo, un carnero, siete corderos de un año sin defecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 37, 'Sus presentes y sus libaciones con el novillo, con el carnero, y con los corderos, según el número de ellos, conforme á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 38, 'Y un macho cabrío por expiación: además del holocausto continuo, con su presente y su libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 39, 'Estas cosas ofreceréis á Jehová en vuestras solemnidades, además de vuestros votos, y de vuestras ofrendas libres, para vuestros holocaustos, y para vuestros presentes, y para vuestras libaciones y para vuestras paces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 29, 40, '(30-1) Y MOISÉS dijo á los hijos de Israel, conforme á todo lo que Jehová le había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 1, '(30-2) Y habló Moisés á los príncipes de las tribus de los hijos de Israel, diciendo: Esto es lo que Jehová ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 2, '(30-3) Cuando alguno hiciere voto á Jehová, ó hiciere juramento ligando su alma con obligación, no violará su palabra: hará conforme á todo lo que salió de su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 3, '(30-4) Mas la mujer, cuando hiciere voto á Jehová, y se ligare con obligación en casa de su padre, en su mocedad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 4, '(30-5) Si su padre oyere su voto, y la obligación con que ligó su alma, y su padre callare á ello, todos los votos de ella serán firmes, y toda obligación con que hubiere ligado su alma, firme será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 5, '(30-6) Mas si su padre le vedare el día que oyere todos sus votos y sus obligaciones, con que ella hubiere ligado su alma, no serán firmes; y Jehová la perdonará, por cuanto su padre le vedó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 6, '(30-7) Empero si fuére casada, é hiciere votos, o pronunciare de sus labios cosa con que obligue su alma;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 7, '(30-8) Si su marido lo oyere, y cuando lo oyere callare á ello, los votos de ella serán firmes, y la obligación con que ligó su alma, firme será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 8, '(30-9) Pero si cuando su marido lo oyó, le vedó, entonces el voto que ella hizo, y lo que pronunció de sus labios con que ligó su alma, será nulo; y Jehová lo perdonará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 9, '(30-10) Mas todo voto de viuda, ó repudiada, con que ligare su alma, será firme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 10, '(30-11) Y si hubiere hecho voto en casa de su marido, y hubiere ligado su alma con obligación de juramento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 11, '(30-12) Si su marido oyó, y calló á ello, y no le vedó; entonces todos sus votos serán firmes, y toda obligación con que hubiere ligado su alma, firme será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 12, '(30-13) Mas si su marido los anuló el día que los oyó; todo lo que salió de sus labios cuanto á sus votos, y cuanto á la obligación de su alma, será nulo; su marido los anuló, y Jehová la perdonará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 13, '(30-14) Todo voto, ó todo juramento obligándose á afligir el alma, su marido lo confirmará, ó su marido lo anulará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 14, '(30-15) Empero si su marido callare á ello de día en día, entonces confirmó todos sus votos, y todas las obligaciones que están sobre ella: confirmólas, por cuanto calló á ello el día que lo oyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 15, '(30-16) Mas si las anulare después de haberlas oido, entonces él llevará el pecado de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 30, 16, '(30-17) Estas son las ordenanzas que Jehová mandó á Moisés entre el varón y su mujer, entre el padre y su hija, durante su mocedad en casa de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 2, 'Haz la venganza de los hijos de Israel sobre los Madianitas; después serás recogido á tus pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 3, 'Entonces Moisés habló al pueblo, diciendo: Armaos algunos de vosotros para la guerra, é irán contra Madián, y harán la venganza de Jehová en Madián.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 4, 'Mil de cada tribu de todas las tribus de los hijos de Israel, enviaréis á la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 5, 'Así fueron dados de los millares de Israel, mil por cada tribu, doce mil á punto de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 6, 'Y Moisés los envió á la guerra: mil por cada tribu envió: y Phinees, hijo de Eleazar sacerdote, fué á la guerra con los santos instrumentos, con las trompetas en su mano para tocar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 7, 'Y pelearon contra Madián, como Jehová lo mandó á Moisés, y mataron á todo varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 8, 'Mataron también, entre los muertos de ellos, á los reyes de Madián: Evi, y Recem, y Zur, y Hur, y Reba, cinco reyes de Madián; á Balaam también, hijo de Beor, mataron á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 9, 'Y llevaron cautivas los hijos de Israel las mujeres de los Madianitas, y sus chiquitos y todas sus bestias, y todos sus ganados; y arrebataron toda su hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 10, 'Y abrasaron con fuego todas sus ciudades, aldeas y castillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 11, 'Y tomaron todo el despojo, y toda la presa, así de hombres como de bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 12, 'Y trajeron á Moisés, y á Eleazar el sacerdote, y á la congregación de los hijos de Israel, los cautivos y la presa y los despojos, al campo en los llanos de Moab, que están junto al Jordán de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 13, 'Y salieron Moisés y Eleazar el sacerdote, y todos los príncipes de la congregación, á recibirlos fuera del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 14, 'Y enojóse Moisés contra los capitanes del ejército, contra los tribunos y centuriones que volvían de la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 15, 'Y díjoles Moisés: ¿Todas las mujeres habéis reservado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 16, 'He aquí ellas fueron á los hijos de Israel, por consejo de Balaam, para causar prevaricación contra Jehová en el negocio de Peor; por lo que hubo mortandad en la congregación de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 17, 'Matad pues ahora todos los varones entre los niños: matad también toda mujer que haya conocido varón carnalmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 18, 'Y todas las niñas entre las mujeres, que no hayan conocido ayuntamiento de varón, os reservaréis vivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 19, 'Y vosotros quedaos fuera del campo siete días: y todos los que hubieren matado persona, y cualquiera que hubiere tocado muerto, os purificaréis al tercero y al séptimo día, vosotros y vuestros cautivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 20, 'Asimismo purificaréis todo vestido, y toda prenda de pieles, y toda obra de pelos de cabra, y todo vaso de madera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 21, 'Y Eleazar el sacerdote dijo á los hombres de guerra que venían de la guerra: Esta es la ordenanza de la ley que Jehová ha mandado á Moisés:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 22, 'Ciertamente el oro, y la plata, metal, hierro, estaño, y plomo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 23, 'Todo lo que resiste el fuego, por fuego lo haréis pasar, y será limpio, bien que en las aguas de purificación habrá de purificarse: mas haréis pasar por agua todo lo que no aguanta el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 24, 'Además lavaréis vuestros vestidos el séptimo día, y así seréis limpios; y después entraréis en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 25, 'Y Jehová habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 26, 'Toma la cuenta de la presa que se ha hecho, así de las personas como de las bestias, tú y el sacerdote Eleazar, y las cabezas de los padres de la congregación:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 27, 'Y partirás por mitad la presa entre los que pelearon, los que salieron á la guerra, y toda la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 28, 'Y apartarás para Jehová el tributo de los hombres de guerra, que salieron á la guerra: de quinientos uno, así de las personas como de los bueyes, de los asnos, y de las ovejas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 29, 'De la mitad de ellos lo tomarás; y darás á Eleazar el sacerdote la ofrenda de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 30, 'Y de la mitad perteneciente á los hijos de Israel tomarás uno de cincuenta, de las personas, de los bueyes, de los asnos, y de las ovejas, de todo animal; y los darás á los Levitas, que tienen la guarda del tabernáculo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 31, 'E hicieron Moisés y Eleazar el sacerdote como Jehová mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 32, 'Y fué la presa, el resto de la presa que tomaron los hombres de guerra, seiscientas y setenta y cinco mil ovejas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 33, 'Y setenta y dos mil bueyes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 34, 'Y setenta y un mil asnos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 35, 'Y en cuanto á personas, de mujeres que no habían conocido ayuntamiento de varón, en todas trenita y dos mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 36, 'Y la mitad, la parte de los que habían salido á la guerra, fué el número de trescientas treinta y siete mil y quinientas ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 37, 'Y el tributo para Jehová de la ovejas, fué seiscientas setenta y cinco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 38, 'Y de los bueyes, treinta y seis mil: y de ellos el tributo para Jehová, setenta y dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 39, 'Y de los asnos, treinta mil y quinientos: y de ellos el tributo para Jehová, setenta y uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 40, 'Y de las personas, diez y seis mil: y de ellas el tributo para Jehová, trteinta y dos personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 41, 'Y dió Moisés el tributo, por elevada ofrenda á Jehová, á Eleazar el sacerdote, como Jehová lo mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 42, 'Y de la mitad para los hijos de Israel, que apartó Moisés de los hombres que habían ido á la guerra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 43, '(La mitad para la congregación fué: de las ovejas, trescientas treinta y siete mil y quinientas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 44, 'Y de los bueyes, treinta y seis mil;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 45, 'Y de los asnos, treinta mil y quinientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 46, 'Y de las personas, diez y seis mil:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 47, 'De la mitad, pues, para los hijos de Israel tomó Moisés uno de cada cincuenta, así de las personas como de los animales, y diólos á los Levitas, que tenían la guarda del tabernáculo de Jehová; como Jehová lo había mandado á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 48, 'Y llegaron á Moisés los jefes de los millares de aquel ejército, los tribunos y centuriones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 49, 'Y dijeron á Moisés: Tus siervos han tomado razón de los hombres de guerra que están en nuestro poder, y ninguno ha faltado de nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 50, 'Por lo cual hemos ofrecido á Jehová ofrenda, cada uno de lo que ha hallado, vasos de oro, brazaletes, manillas, anillos, zarcillos, y cadenas, para hacer expiación por nuestras almas delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 51, 'Y Moisés y el sacerdote Eleazar recibieron el oro de ellos, alhajas, todas elaboradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 52, 'Y todo el oro de la ofrenda que ofrecieron á Jehová de los tribunos y centuriones, fué diez y seis mil setecientos y cincuenta siclos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 53, 'Los hombres del ejército habían pillado cada uno para sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 31, 54, 'Recibieron, pues, Moisés y el sacerdote Eleazar, el oro de los tribunos y centuriones, y trajéronlo al tabernáculo del testimonio, por memoria de los hijos de Israel delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 1, 'Y LOS hijos de Rubén y los hijos de Gad tenían una muy grande muchedumbre de ganado; los cuales viendo la tierra de Jazer y de Galaad, parecióles el país lugar de ganado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 2, 'Y vinieron los hijos de Gad y los hijos de Rubén, y hablaron á Moisés, y á Eleazar el sacerdote, y á los príncipes de la congregación, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 3, 'Ataroth, y Dibón, y Jazer, y Nimra, y Hesbón, y Eleale, y Sabán, y Nebo, y Beón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 4, 'La tierra que Jehová hirió delante de la congregación de Israel, es tierra de ganado, y tus siervos tienen ganado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 5, 'Por tanto, dijeron, si hallamos gracia en tus ojos, dése esta tierra á tus siervos en heredad, y no nos hagas pasar el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 6, 'Y respondió Moisés á los hijos de Gad y á los hijos de Rubén: ¿Vendrán vuestros hermanos á la guerra, y vosotros os quedaréis aquí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 7, '¿Y por qué prevenís el ánimo de los hijos de Israel, para que no pasen á la tierra que les ha dado Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 8, 'Así hicieron vuestros padres, cuando los envié desde Cades-barnea para que viesen la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 9, 'Que subieron hasta la arroyada de Escol, y después que vieron la tierra, preocuparon el ánimo de los hijos de Israel, para que no viniesen á la tierra que Jehová les había dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 10, 'Y el furor de Jehová se encendió entonces, y juró diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 11, 'Que no verán los varones que subieron de Egipto de veinte años arriba, la tierra por la cual juré á Abraham, Isaac, y Jacob, por cuanto no fueron perfectos en pos de mí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 12, 'Excepto Caleb, hijo de Jephone Cenezeo, y Josué hijo de Nun, que fueron perfectos en pos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 13, 'Y el furor de Jehová se encendió en Israel, é hízolos andar errantes cuarenta años por el desierto, hasta que fué acabada toda aquella generación, que había hecho mal delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 14, 'Y he aquí vosotros habéis sucedido en lugar de vuestros padres, prole de hombres pecadores, para añadir aún á la ira de Jehová contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 15, 'Si os volviereis de en pos de él, él volverá otra vez á dejaros en el desierto, y destruiréis á todo este pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 16, 'Entonces ellos se allegaron á él y dijeron: Edificaremos aquí majadas para nuestro ganado, y ciudades para nuestros niños;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 17, 'Y nosotros nos armaremos, é iremos con diligencia delante de los hijos de Israel, hasta que los metamos en su lugar: y nuestros niños quedarán en ciudades fuertes á causa de los moradores del país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 18, 'No volveremos á nuestras casas hasta que los hijos de Israel posean cada uno su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 19, 'Porque no tomaremos heredad con ellos al otro lado del Jordán ni adelante, por cuanto tendremos ya nuestra heredad de estotra parte del Jordán al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 20, 'Entonces les respondió Moisés: Si lo hiciereis así, si os apercibiereis para ir delante de Jehová á la guerra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 21, 'Y pasareis todos vosotros armados el Jordán delante de Jehová, hasta que haya echado á sus enemigos de delante de sí,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 22, 'Y sea el país sojuzgado delante de Jehová; luego volveréis, y seréis libres de culpa para con Jehová, y para con Israel; y esta tierra será vuestra en heredad delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 23, 'Mas si así no lo hiciereis, he aquí habréis pecado á Jehová; y sabed que os alcanzará vuestro pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 24, 'Edificaos ciudades para vuestros niños, y majadas para vuestras ovejas, y haced lo que ha salido de vuestra boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 25, 'Y hablaron los hijos de Gad y los hijos de Rubén á Moisés, diciendo: Tus siervos harán como mi señor ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 26, 'Nuestros niños, nuestras mujeres, nuestros ganados, y todas nuestras bestias, estarán ahí en las ciudades de Galaad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 27, 'Y tus siervos, armados todos de guerra, pasarán delante de Jehová á la guerra, de la manera que mi señor dice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 28, 'Entonces los encomendó Moisés á Eleazar el sacerdote, y á Josué hijo de Nun, y á los príncipes de los padres de las tribus de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 29, 'Y díjoles Moisés: Si los hijos de Gad y los hijos de Rubén, pasaren con vosotros el Jordán, armados todos de guerra delante de Jehová, luego que el país fuere sojuzgado delante de vosotros, les daréis la tierra de Galaad en posesión:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 30, 'Mas si no pasaren armados con vosotros, entonces tendrán posesión entre vosotros en la tierra de Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 31, 'Y los hijos de Gad y los hijos de Rubén respondieron, diciendo: Haremos lo que Jehová ha dicho á tus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 32, 'Nosotros pasaremos armados delante de Jehová á la tierra de Canaán, y la posesión de nuestra heredad será de esta parte del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 33, 'Así les dió Moisés á los hijos de Gad y á los hijos de Rubén, y á la media tribu de Manasés hijo de José, el reino de Sehón rey Amorrheo, y el reino de Og rey de Basán, la tierra con sus ciudades y términos, las ciudades del país alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 34, 'Y los hijos de Gad edificaron á Dibón, y á Ataroth, y á Aroer,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 35, 'Y á Atroth-sophan, y á Jazer, y á Jogbaa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 36, 'Y á Beth-nimra, y á Betharán: ciudades fuertes, y también majadas para ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 37, 'Y los hijos de Rubén edificaron á Hesbón, y á Eleale, y á Kiriathaim,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 38, 'Y á Nebo, y á Baal-meón, (mudados los nombres), y á Sibma: y pusieron nombres á las ciudades que edificaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 39, 'Y los hijos de Machîr hijo de Manasés fueron á Galaad, y tomáronla, y echaron al Amorrheo que estaba en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 40, 'Y Moisés dió Galaad á Machîr hijo de Manasés, el cual habitó en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 41, 'También Jair hijo de Manasés fué y tomó sus aldeas, y púsoles por nombre Havoth-jair.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 32, 42, 'Asimismo Noba fué y tomó á Kenath y sus aldeas, y llamóle Noba, conforme á su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 1, 'Estas son las estancias de los hijos de Israel, los cuales salieron de la tierra de Egipto por sus escuadrones, bajo la conducta de Moisés y Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 2, 'Y Moisés escribió sus salidas conforme á sus jornadas por mandato de Jehová. Estas, pues, son sus estancias con arreglo á sus partidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 3, 'De Rameses partieron en el mes primero, á los quince diás del mes primero: el segundo día de la pascua salieron los hijos de Israel con mano alta, á ojos de todos los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 4, 'Estaban enterrando los Egipcios los que Jehová había muerto de ellos, á todo primogénito; habiendo Jehová hecho también juicios en sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 5, 'Partieron, pues, los hijos de Israel de Rameses, y asentaron campo en Succoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 6, 'Y partiendo de Succoth, asentaron en Etham, que está al cabo del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 7, 'Y partiendo de Etham, volvieron sobre Pi-hahiroth, que está delante de Baalsephon, y asentaron delante de Migdol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 8, 'Y partiendo de Pi-hahiroth, pasaron por medio de la mar al desierto, y anduvieron camino de tres días por el desierto de Etham, y asentaron en Mara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 9, 'Y partiendo de Mara, vinieron á Elim, donde había doce fuentes de aguas, y setenta palmeras; y asentaron allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 10, 'Y partidos de Elim, asentaron junto al mar Bermejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 11, 'Y partidos del mar Bermejo, asentaron en el desierto de Sin.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 12, 'Y partidos del desierto de Sin, asentaron en Dophca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 13, 'Y partidos de Dophca, asentaron en Alús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 14, 'Y partidos de Alús, asentaron en Rephidim, donde el pueblo no tuvo aguas para beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 15, 'Y partidos de Rephidim, asentaron en el desierto de Sinaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 16, 'Y partidos del desierto de Sinaí, asentaron en fmfm Kibroth-hataava.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 17, 'Y partidos de Kibroth-hataava, asentaron en Haseroth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 18, 'Y partidos de Haseroth, asentaron en Ritma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 19, 'Y partidos de Ritma, asentaron en Rimmón-peres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 20, 'Y partidos de Rimmón-peres, asentaron en Libna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 21, 'Y partidos de Libna, asentaron en Rissa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 22, 'Y partidos de Rissa, asentaron en Ceelatha,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 23, 'Y partidos de Ceelatha, asentaron en el monte de Sepher.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 24, 'Y partidos del monte de Sepher, asentaron en Harada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 25, 'Y partidos de Harada, asentaron en Maceloth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 26, 'Y partidos de Maceloth, asentaron en Tahath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 27, 'Y partidos de Tahath, asentaron en Tara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 28, 'Y partidos de Tara, asentaron en Mithca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 29, 'Y partidos de Mithca, asentaron en Hasmona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 30, 'Y partidos de Hasmona, asentaron en Moseroth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 31, 'Y partidos de Moseroth, asentaron en Bene-jaacán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 32, 'Y partidos de Bene-jaacán, asentaron en el monte de Gidgad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 33, 'Y partidos del monte de Gidgad, asentaron en Jotbatha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 34, 'Y partidos de Jotbatha, asentaron en Abrona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 35, 'Y partidos de Abrona, asentaron en Esion-geber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 36, 'Y partidos de Esion-geber, asentaron en el desierto de Zin, que es Cades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 37, 'Y partidos de Cades, asentaron en el monte de Hor, en la extremidad del país de Edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 38, 'Y subió Aarón el sacerdote al monte de Hor, conforme al dicho de Jehová, y allí murió á los cuarenta años de la salida de los hijos de Israel de la tierra de Egipto, en el mes quinto, en el primero del mes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 39, 'Y era Aarón de edad de ciento y veinte y tres años, cuando murió en el monte de Hor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 40, 'Y el Cananeo, rey de Arad, que habitaba al mediodía en la tierra de Canaán, oyó como habían venido los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 41, 'Y partidos del monte de Hor, asentaron en Salmona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 42, 'Y partidos de Salmona, asentaron en Phunón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 43, 'Y partidos de Phunón, asentaron en Oboth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 44, 'Y partidos de Oboth, asentaron en Ije-abarim; en el término de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 45, 'Y partidos de Ije-abarim, asentaron en Dibón-gad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 46, 'Y partidos de Dibón-gad, asentaron en Almon-diblathaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 47, 'Y partidos de Almon-diblathaim, asentaron en los montes de Abarim, delante de Nebo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 48, 'Y partidos de los montes de Abarim, asentaron en los campos de Moab, junto al Jordán de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 49, 'Finalmente asentaron junto al Jordán, desde Beth-jesimoth hasta Abel-sitim, en los campos de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 50, 'Y habló Jehová á Moisés en los campos de Moab junto al Jordán de Jericó, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 51, 'Habla á los hijos de Israel, y diles: Cuando hubiereis pasado el Jordán á la tierra de Canaán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 52, 'Echaréis á todos los moradores del país de delante de vosotros, y destruiréis todas sus pinturas, y todas sus imágenes de fundición, y arruinaréis todos sus altos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 53, 'Y echaréis los moradores de la tierra, y habitaréis en ella; porque yo os la he dado para que la poseáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 54, 'Y heredaréis la tierra por suertes por vuestras familias: á los muchos daréis mucho por su heredad, y á los pocos daréis menos por heredad suya: donde le saliere la suerte, allí la tendrá cada uno: por las tribus de vuestros padres heredaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 55, 'Y si no echareis los moradores del país de delante de vosotros, sucederá que los que dejareis de ellos serán por aguijones en vuestros ojos, y por espinas en vuestros costados, y afligiros han sobre la tierra en que vosotros habitareis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 33, 56, 'Será además, que haré á vosotros como yo pensé hacerles á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 1, 'Y JEHOVA habló á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 2, 'Manda á los hijos de Israel, y diles: Cuando hubiereis entrado en la tierra de Canaán, es á saber, la tierra que os ha de caer en heredad, la tierra de Canaán según sus términos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 3, 'Tendréis el lado del mediodía desde el desierto de Zin hasta los términos de Edom; y os será el término del mediodía al extremo del mar salado hacia el oriente:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 4, 'Y este término os irá rodeando desde el mediodía hasta la subida de Acrabbim, y pasará hasta Zin; y sus salidas serán del mediodía á Cades-barnea; y saldrá á Hasar-addar, y pasará hasta Asmón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 5, 'Y rodeará este término, desde Asmón hasta el torrente de Egipto, y sus remates serán al occidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 6, 'Y el término occidental os será la gran mar: este término os será el término occidental.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 7, 'Y el término del norte será este: desde la gran mar os señalaréis el monte de Hor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 8, 'Del monte de Hor señalaréis á la entrada de Hamath, y serán las salidas de aquel término á Sedad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 9, 'Y saldrá este término á Ziphón, y serán sus remates en Hasar-enán: este os será el término del norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 10, 'Y por término al oriente os señalaréis desde Hasar-enán hasta Sepham;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 11, 'Y bajará este término desde Sepham á Ribla, al oriente de Ain: y descenderá el término, y llegará á la costa de la mar de Cinnereth al oriente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 12, 'Después descenderá este término al Jordán, y serán sus salidas al mar Salado: esta será vuestra tierra: por sus términos alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 13, 'Y mandó Moisés á los hijos de Israel, diciendo: Esta es la tierra que heredaréis por suerte, la cual mandó Jehová que diese á las nueve tribus, y á la media tribu:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 14, 'Porque la tribu de los hijos de Rubén según las casas de sus padres, y la tribu de los hijos de Gad según las casas de sus padres, y la media tribu de Manasés, han tomado su herencia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 15, 'Dos tribus y media tomaron su heredad de esta parte del Jordán de Jericó al oriente, al nacimiento del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 16, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 17, 'Estos son los nombres de los varones que os aposesionarán la tierra: Eleazar el sacerdote, y Josué hijo de Nun.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 18, 'Tomaréis también de cada tribu un príncipe, para dar la posesión de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 19, 'Y estos son los nombres de los varones: De la tribu de Judá, Caleb hijo de Jephone.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 20, 'Y de la tribu de los hijos de Simeón, Samuel hijo de Ammiud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 21, 'De la tribu de Benjamín; Elidad hijo de Chislón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 22, 'Y de la tribu de los hijos de Dan, el príncipe Bucci hijo de Jogli.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 23, 'De los hijos de José: de la tribu de los hijos de Manasés, el príncipe Haniel hijo de Ephod.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 24, 'Y de la tribu de los hijos de Ephraim, el príncipe Chêmuel hijo de Siphtán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 25, 'Y de la tribu de los hijos de Zabulón, el príncipe Elisaphán hijo de Pharnach.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 26, 'Y de la tribu de los hijos de Issachâr, el príncipe Paltiel hijo de Azan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 27, 'Y de la tribu de los hijos de Aser, el príncipe Ahiud hijo de Selomi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 28, 'Y de la tribu de los hijos de Nephtalí, el príncipe Pedael hijo de Ammiud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 34, 29, 'Estos son á los que mandó Jehová que hiciesen la partición de la herencia á los hijos de Israel en la tierra de Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 1, 'Y HABLO Jehová á Moisés en los campos de Moab, junto al Jordán de Jericó, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 2, 'Manda á los hijos de Israel, que den á los Levitas de la posesión de su heredad ciudades en que habiten: También daréis á los Levitas ejidos de esas ciudades alrededor de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 3, 'Y tendrán ellos las ciudades para habitar, y los ejidos de ellas serán para sus animales, y para sus ganados, y para todas sus bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 4, 'Y los ejidos de las ciudades que daréis á los Levitas, serán mil codos alrededor, desde el muro de la ciudad para afuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 5, 'Luego mediréis fuera de la ciudad á la parte del oriente dos mil codos, y á la parte del mediodía dos mil codos, y á la parte del occidente dos mil codos, y á la parte del norte dos mil codos, y la ciudad en medio: esto tendrán por los ejidos de las ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 6, 'Y de las ciudades que daréis á los Levitas, seis ciudades serán de acogimiento, las cuales daréis para que el homicida se acoja allá: y además de éstas daréis cuarenta y dos ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 7, 'Todas las ciudades que daréis á los Levitas serán cuarenta y ocho ciudades; ellas con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 8, 'Y las ciudades que diereis de la heredad de los hijos de Israel, del que mucho tomaréis mucho, y del que poco tomaréis poco: cada uno dará de sus ciudades á los Levitas según la posesión que heredará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 9, 'Y habló Jehová á Moisés, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 10, 'Habla á los hijos de Israel, y diles: Cuando hubiereis pasado el Jordán á la tierra de Canaán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 11, 'Os señalaréis ciudades, ciudades de acogimiento tendréis, donde huya el homicida que hiriere á alguno de muerte por yerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 12, 'Y os serán aquellas ciudades por acogimiento del pariente, y no morirá el homicida hasta que esté á juicio delante de la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 13, 'De las ciudades, pues, que daréis, tendréis seis ciudades de acogimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 14, 'Tres ciudades daréis de esta parte del Jordán, y tres ciudades daréis en la tierra de Canaán; las cuales serán ciudades de acogimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 15, 'Estas seis ciudades serán para acogimiento á los hijos de Israel, y al peregrino, y al que morare entre ellos, para que huya allá cualquiera que hiriere de muerte á otro por yerro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 16, 'Y si con instrumento de hierro lo hiriere y muriere, homicida es; el homicida morirá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 17, 'Y si con piedra de mano, de que pueda morir, lo hiriere, y muriere, homicida es; el homicida morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 18, 'Y si con instrumento de palo de mano, de que pueda morir, lo hiriere, y muriere, homicida es; el homicida morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 19, 'El pariente del muerto, él matará al homicida: cuando lo encontrare, él le matará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 20, 'Y si por odio lo empujó, ó echó sobre él alguna cosa por asechanzas, y muere;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 21, 'O por enemistad lo hirió con su mano, y murió: el heridor morirá; es homicida; el pariente del muerto matará al homicida, cuando lo encontrare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 22, 'Mas si casualmente lo empujó sin enemistades, ó echó sobre él cualquier instrumento sin asechanzas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 23, 'O bien, sin verlo, hizo caer sobre él alguna piedra, de que pudo morir, y muriere, y él no era su enemigo, ni procuraba su mal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 24, 'Entonces la congregación juzgará entre el heridor y el pariente del muerto conforme á estas leyes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 25, 'Y la congregación librará al homicida de mano del pariente del muerto, y la congregación lo hará volver á su ciudad de acogimiento, á la cual se había acogido; y morará en ella hasta que muera el gran sacerdote, el cual fué ungido con el aceite santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 26, 'Y si el homicida saliere fuera del término de su ciudad de refugio, á la cual se acogió,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 27, 'Y el pariente del muerto le hayare fuera del término de la ciudad de su acogida, y el pariente del muerto al homicida matare, no se le culpará por ello:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 28, 'Pues en su ciudad de refugio deberá aquél habitar hasta que muera el gran sacerdote: y después que muriere el gran sacerdote, el homicida volverá á la tierra de su posesión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 29, 'Y estas cosas os serán por ordenanza de derecho por vuestras edades, en todas vuestras habitaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 30, 'Cualquiera que hiriere á alguno, por dicho de testigos, morirá el homicida: mas un solo testigo no hará fé contra alguna persona para que muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 31, 'Y no tomaréis precio por la vida del homicida; porque está condenado á muerte: mas indefectiblemente morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 32, 'Ni tampoco tomaréis precio del que huyó á su ciudad de refugio, para que vuelva á vivir en su tierra, hasta que muera el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 33, 'Y no contaminaréis la tierra donde estuviereis: porque esta sangre amancillará la tierra: y la tierra no será expiada de la sangre que fué derramada en ella, sino por la sangre del que la derramó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 35, 34, 'No contaminéis, pues, la tierra donde habitáis, en medio de la cual yo habito; porque yo Jehová habito en medio de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 1, 'Y LLEGARON los príncipes de los padres de la familia de Galaad, hijo de Machîr, hijo de Manasés, de las familias de los hijos de José; y hablaron delante de Moisés, y de los príncipes, cabezas de padres de los hijos de Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 2, 'Y dijeron: Jehová mandó á mi señor que por suerte diese la tierra á los hijos de Israel en posesión: también ha mandado Jehová á mi señor, que dé la posesión de Salphaad nuestro hermano á sus hijas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 3, 'Las cuales, si se casaren con algunos de los hijos de las otras tribus de los hijos de Israel, la herencia de ellas será así desfalcada de la herencia de nuestros padres, y será añadida á la herencia de la tribu á que serán unidas: y será quitada de la suerte de nuestra heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 4, 'Y cuando viniere el jubileo de los hijos de Israel, la heredad de ellas será añadida á la heredad de la tribu de sus maridos; y así la heredad de ellas será quitada de la heredad de la tribu de nuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 5, 'Entonces Moisés mandó á los hijos de Israel por dicho de Jehová, diciendo: La tribu de los hijos de José habla rectamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 6, 'Esto es lo que ha mandado Jehová acerca de las hijas de Salphaad, diciendo: Cásense como á ellas les pluguiere, empero en la familia de la tribu de su padre se casarán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 7, 'Para que la heredad de los hijos de Israel no sea traspasada de tribu en tribu; porque cada uno de los hijos de Israel se allegará á la heredad de la tribu de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 8, 'Y cualquiera hija que poseyere heredad de las tribus de los hijos de Israel, con alguno de la familia de la tribu de su padre se casará, para que los hijos de Israel posean cada uno la heredad de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 9, 'Y no ande la heredad rodando de una tribu á otra: mas cada una de las tribus de los hijos de Israel se llegue á su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 10, 'Como Jehová mandó á Moisés, así hicieron las hijas de Salphaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 11, 'Y así Maala, y Tirsa, y Hogla, y Milchâ, y Noa, hijas de Salphaad, se casaron con hijos de sus tíos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 12, 'De la familia de los hijos de Manasés, hijo de José, fueron mujeres; y la heredad de ellas quedó en la tribu de la familia de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NUM', 'Números', 36, 13, 'Estos son los mandamientos y los estatutos que mandó Jehová por mano de Moisés á los hijos de Israel en los campos de Moab, junto al Jordán de Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 1, 'ESTAS son las palabras que habló Moisés á todo Israel de esta parte del Jordán en el desierto, en el llano delante del mar Bermejo, entre Parán, y Thopel, y Labán, y Haseroth, y Dizahab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 2, 'Once jornadas hay desde Horeb, camino del monte de Seir, hasta Cades-barnea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 3, 'Y fué, que á los cuarenta años, en el mes undécimo, al primero del mes, Moisés habló á los hijos de Israel conforme á todas las cosas que Jehová le había mandado acerca de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 4, 'Después que hirió á Sehón rey de los Amorrheos, que habitaba en Hesbón, y á Og rey de Basán, que habitaba en Astarot en Edrei:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 5, 'De esta parte del Jordán, en tierra de Moab, resolvió Moisés declarar esta ley, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 6, 'Jehová nuestro Dios nos habló en Horeb, diciendo: Harto habéis estado en este monte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 7, 'Volveos, partíos é id al monte del Amorrheo, y á todas sus comarcas, en el llano, en el monte, y en los valles, y al mediodía, y á la costa de la mar, á la tierra del Cananeo, y el Líbano, hasta el gran río, el río Eufrates.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 8, 'Mirad, yo he dado la tierra en vuestra presencia; entrad y poseed la tierra que Jehová juró á vuestros padres Abraham, Isaac, y Jacob, que les daría á ellos y á su simiente después de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 9, 'Y yo os hablé entonces, diciendo: Yo no puedo llevaros solo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 10, 'Jehová vuestro Dios os ha multiplicado, y he aquí sois hoy vosotros como las estrellas del cielo en multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 11, '¡Jehová Dios de vuestros padres añada sobre vosotros como sois mil veces, y os bendiga, como os ha prometido!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 12, '¿Cómo llevaré yo solo vuestras molestias, vuestras cargas, y vuestros pleitos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 13, 'Dad me de entre vosotros, de vuestras tribus, varones sabios y entendidos y expertos, para que yo los ponga por vuestros jefes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 14, 'Y me respondisteis, y dijisteis: Bueno es hacer lo que has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 15, 'Y tomé los principales de vuestras tribus, varones sabios y expertos, y púselos por jefes sobre vosotros, jefes de millares, y jefes de cientos, y jefes de cincuenta, y cabos de diez, y gobernadores á vuestras tribus.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 16, 'Y entonces mandé á vuestros jueces, diciendo: Oid entre vuestros hermanos, y juzgad justamente entre el hombre y su hermano, y el que le es extranjero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 17, 'No tengáis respeto de personas en el juicio: así al pequeño como al grande oiréis: no tendréis temor de ninguno, porque el juicio es de Dios: y la causa que os fuere difícil, la traeréis á mí, y yo la oiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 18, 'Os mandé, pues, en aquel tiempo todo lo que habíais de hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 19, 'Y partidos de Horeb, anduvimos todo aquel grande y terrible desierto que habéis visto, por el camino del monte del Amorrheo, como Jehová nuestro Dios nos lo mandó; y llegamos hasta Cades-barnea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 20, 'Entonces os dije: Llegado habéis al monte del Amorrheo, el cual Jehová nuestro Dios nos da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 21, 'Mira, Jehová tu Dios ha dado delante de ti la tierra: sube y posée la, como Jehová el Dios de tus padres te ha dicho; no temas ni desmayes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 22, 'Y llegasteis á mí todos vosotros, y dijisteis: Enviemos varones delante de nosotros, que nos reconozcan la tierra y nos traigan de vuelta razón del camino por donde hemos de subir, y de las ciudades adonde hemos de llegar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 23, 'Y el dicho me pareció bien: y tomé doce varones de vosotros, un varón por tribu:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 24, 'Y se encaminaron, y subieron al monte, y llegaron hasta la arroyada de Escol, y reconocieron la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 25, 'Y tomaron en sus manos del fruto del país, y nos lo trajeron, y diéronnos cuenta, y dijeron: Es buena la tierra que Jehová nuestro Dios nos da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 26, 'Empero no quisisteis subir, antes fuisteis rebeldes al dicho de Jehová vuestro Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 27, 'Y murmurasteis en vuestras tiendas, diciendo: Porque Jehová nos aborrecía, nos ha sacado de tierra de Egipto, para entregarnos en mano del Amorrheo para destruirnos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 28, '¿A dónde subimos? Nuestros hermanos han hecho desfallecer nuestro corazón, diciendo: Este pueblo es mayor y más alto que nosotros, las ciudades grandes y muradas hasta el cielo; y también vimos allí hijos de gigantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 29, 'Entonces os dije: No temáis, ni tengáis miedo de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 30, 'Jehová vuestro Dios, el cual va delante de vosotros, él peleará por vosotros, conforme á todas las cosas que hizo por vosotros en Egipto delante de vuestros ojos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 31, 'Y en el desierto has visto que Jehová tu Dios te ha traído, como trae el hombre á su hijo, por todo el camino que habéis andado, hasta que habéis venido á este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 32, 'Y aun con esto no creisteis en Jehová vuestro Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 33, 'El cual iba delante de vosotros por el camino, para reconoceros el lugar donde habíais de asentar el campo, con fuego de noche para mostraros el camino por donde aduvieseis, y con nube de día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 34, 'Y oyó Jehová la voz de vuestras palabras, y enojóse, y juró diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 35, 'No verá hombre alguno de estos de esta mala generación, la buena tierra que juré había de dar á vuestros padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 36, 'Excepto Caleb hijo de Jephone: él la verá, y á él le daré la tierra que pisó, y á sus hijos; porque cumplió en pos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 37, 'Y también contra mí se airó Jehová por vosotros, diciendo: Tampoco tú entrarás allá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 38, 'Josué hijo de Nun, que está delante de ti, él entrará allá: anímale; porque él la hará heredar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 39, 'Y vuestros chiquitos, de los cuales dijisteis serán por presa, y vuestros hijos que no saben hoy bueno ni malo, ellos entrarán allá, y á ellos la daré, y ellos la heredarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 40, 'Y vosotros volveos, y partíos al desierto camino del mar Bermejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 41, 'Entonces respondisteis y me dijisteis: Pecado hemos contra Jehová; nosotros subiremos y pelearemos, conforme á todo lo que Jehová nuestro Dios nos ha mandado. Y os armasteis cada uno de sus armas de guerra, y os apercibisteis para subir al monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 42, 'Y Jehová me dijo: Diles: No subáis, ni peleéis, pues no estoy entre vosotros; porque no seáis heridos delante de vuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 43, 'Y os hablé, y no disteis oído; antes fuisteis rebeldes al dicho de Jehová, y persistiendo con altivez, subisteis al monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 44, 'Y salió el Amorrheo, que habitaba en aquel monte, á vuestro encuentro, y os persiguieron, como hacen las avispas, y os derrotaron en Seir, persiguiéndoos hasta Horma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 45, 'Y volvisteis, y llorasteis delante de Jehová; pero Jehová no escuchó vuestra voz, ni os prestó oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 1, 46, 'Y estuvisteis en Cades por muchos días, como en los días que habéis estado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 1, 'Y VOLVIMOS, y partímonos al desierto camino del mar Bermejo, como Jehová me había dicho; y rodeamos el monte de Seir por muchos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 2, 'Y Jehová me habló, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 3, 'Harto habéis rodeado este monte; volveos al aquilón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 4, 'Y manda al pueblo, diciendo: Pasando vosotros por el término de vuestros hermanos los hijos de Esaú, que habitan en Seir, ellos tendrán miedo de vosotros; mas vosotros guardaos mucho:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 5, 'No os metáis con ellos; que no os daré de su tierra ni aun la holladura de la planta de un pie; porque yo he dado por heredad á Esaú el monte de Seir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 6, 'Compraréis de ellos por dinero las viandas, y comeréis; y también compraréis de ellos el agua, y beberéis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 7, 'Pues Jehová tu Dios te ha bendecido en toda obra de tus manos: él sabe que andas por este gran desierto: estos cuarenta años Jehová tu Dios fué contigo; y ninguna cosa te ha faltado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 8, 'Y pasamos de nuestros hermanos los hijos de Esaú, que habitaban en Seir, por el camino de la llanura de Elath y de Esiongeber. Y volvimos, y pasamos camino del desierto de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 9, 'Y Jehová me dijo: No molestes á Moab, ni te empeñes con ellos en guerra, que no te daré posesión de su tierra; porque yo he dado á Ar por heredad á los hijos de Lot.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 10, '(Los Emimeos habitaron en ella antes, pueblo grande, y numeroso, y alto como fhnumeroso, y alto como fh gigantes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 11, 'Por gigantes eran ellos también contados, como los Anaceos; y los Moabitas los llaman Emimeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 12, 'Y en Seir habitaron antes los Horeos, á los cuales echaron los hijos de Esaú; y los destruyeron de delante de sí, y moraron en lugar de ellos; como hizo Israel en la tierra de su posesión que les dió Jehová.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 13, 'Levantaos ahora, y pasad el arroyo de Zered. Y pasamos el arroyo de Zered.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 14, 'Y los días que anduvimos de Cades-barnea hasta que pasamos el arroyo de Zered, fueron treinta y ocho años; hasta que se acabó toda la generación de los hombres de guerra de en medio del campo, como Jehová les había jurado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 15, 'Y también la mano de Jehová fué sobre ellos para destruirlos de en medio del campo, hasta acabarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 16, 'Y aconteció que cuando se hubieron acabado de morir todos los hombres de guerra de entre el pueblo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 17, 'Jehová me habló, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 18, 'Tú pasarás hoy el término de Moab, á Ar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 19, 'Y te acercarás delante de los hijos de Ammón: no los molestes, ni te metas con ellos; porque no te tengo de dar posesión de la tierra de los hijos de Ammón; que á los hijos de Lot la he dado por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 20, '(Por tierra de gigantes fué también ella tenida: habitaron en ella gigantes en otro tiempo, á los cuales los Ammonitas llamaban Zomzommeos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 21, 'Pueblo grande, y numeroso, y alto, como los Anaceos; á los cuales Jehová destruyó de delante de los Ammonitas, quienes les sucedieron, y habitaron en su lugar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 22, 'Como hizo con los hijos de Esaú, que habitaban en Seir, de delante de los cuales destruyó á los Horeos; y ellos les sucedieron, y habitaron en su lugar hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 23, 'Y á los Heveos que habitaban en Haserin hasta Gaza, los Caftoreos que salieron de Caftor los destruyeron, y habitaron en su lugar.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 24, 'Levantaos, partid, y pasad el arroyo de Arnón: he aquí he dado en tu mano á Sehón rey de Hesbón, Amorrheo, y á su tierra: comienza á tomar posesión, y empéñate con él en guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 25, 'Hoy comenzaré á poner tu miedo y tu espanto sobre los pueblos debajo de todo el cielo, los cuales oirán tu fama, y temblarán, y angustiarse han delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 26, 'Y envié mensajeros desde el desierto de Cademoth á Sehón rey de Hesbón, con palabras de paz, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 27, 'Pasaré por tu tierra por el camino: por el camino iré, sin apartarme á diestra ni á siniestra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 28, 'La comida me venderás por dinero y comeré: el agua también me darás por dinero, y beberé: solamente pasaré á pie;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 29, 'Como lo hicieron conmigo los hijos de Esaú que habitaban en Seir, y los Moabitas que habitaban en Ar; hasta que pase el Jordán á la tierra que nos da Jehová nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 30, 'Mas Sehón rey de Hesbón no quiso que pasásemos por el territorio suyo; porque Jehová tu Dios había endurecido su espíritu, y obstinado su corazón para entregarlo en tu mano, como hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 31, 'Y díjome Jehová: He aquí yo he comenzado á dar delante de ti á Sehón y á su tierra; comienza á tomar posesión, para que heredes su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 32, 'Y saliónos Sehón al encuentro, él y todo su pueblo, para pelear en Jaas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 33, 'Mas Jehová nuestro Dios lo entregó delante de nosotros; y herimos á él y á sus hijos, y á todo su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 34, 'Y tomamos entonces todas sus ciudades, y destruimos todas las ciudades, hombres, y mujeres, y niños; no dejamos ninguno:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 35, 'Solamente tomamos para nosotros las bestias, y los despojos de las ciudades que habíamos tomado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 36, 'Desde Aroer, que está junto á la ribera del arroyo de Arnón, y la ciudad que está en el arroyo, hasta Galaad, no hubo ciudad que escapase de nosotros: todas las entregó Jehová nuestro Dios en nuestro poder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 2, 37, 'Solamente á la tierra de los hijos de Ammón no llegaste, ni á todo lo que está á la orilla del arroyo de Jaboc ni á las ciudades del monte, ni á lugar alguno que Jehová nuestro Dios había prohibido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 1, 'Y VOLVIMOS, y subimos camino de Basán, y saliónos al encuentro Og rey de Basán para pelear, él y todo su pueblo, en Edrei.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 2, 'Y díjome Jehová: No tengas temor de él, porque en tu mano he entregado á él y á todo su pueblo, y su tierra: y harás con él como hiciste con Sehón rey Amorrheo, que habitaba en Hesbón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 3, 'Y Jehová nuestro Dios entregó también en nuestra mano á Og rey de Basán, y á todo su pueblo, al cual herimos hasta no quedar de él ninguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 4, 'Y tomamos entonces todas sus ciudades; no quedó ciudad que no les tomásemos: sesenta ciudades, toda la tierra de Argob, del reino de Og en Basán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 5, 'Todas éstas eran ciudades fortalecidas con alto muro, con puertas y barras; sin otras muy muchas ciudades sin muro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 6, 'Y destruímoslas, como hicimos á Sehón rey de Hesbón, destruyendo en toda ciudad hombres, mujeres, y niños.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 7, 'Y tomamos para nosotros todas las bestias, y los despojos de las ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 8, 'También tomamos en aquel tiempo de mano de dos reyes Amorrheos que estaban de esta parte del Jordán, la tierra desde el arroyo de Arnón hasta el monte de Hermón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 9, '(Los Sidonios llaman á Hermón Sirión; y los Amorrheos, Senir:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 10, 'Todas las ciudades de la llanura, y todo Galaad, y todo Basán hasta Salchâ y Edrei, ciudades del reino de Og en Basán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 11, 'Porque sólo Og rey de Basán había quedado de los gigantes que quedaron. He aquí su cama, una cama de hierro, ¿no está en Rabbath de los hijos de Ammón?; la longitud de ella de nueve codos, y su anchura de cuatro codos, al codo de un hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 12, 'Y esta tierra que heredamos entonces desde Aroer, que está al arroyo de Arnón, y la mitad del monte de Galaad con sus ciudades, dí á los Rubenitas y á los Gaditas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 13, 'Y el resto de Galaad, y todo Basán, del reino de Og, dí lo á la media tribu de Manasés; toda la tierra de Argob, todo Basán, que se llamaba la tierra de los gigantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 14, 'Jair hijo de Manasés tomó toda la tierra de Argob hasta el término de Gessuri y Machâti; y llamóla de su nombre Basán-havoth-jair, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 15, 'Y á Machîr dí á Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 16, 'Y á los Rubenitas y Gaditas dí de Galaad hasta el arroyo de Arnón, el medio del arroyo por término; hasta el arroyo de Jaboc, término de los hijos de Ammón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 17, 'Asimismo la campiña, y el Jordán, y el término, desde Cinereth hasta la mar del llano, el mar Salado, las vertientes abajo del Pisga al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 18, 'Y os mandé entonces, diciendo: Jehová vuestro Dios os ha dado esta tierra para que la poseáis: pasaréis armados delante de vuestros hermanos los hijos de Israel todos los valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 19, 'Solamente vuestras mujeres, vuestros niños, y vuestros ganados, (yo sé que tenéis mucho ganado,) quedarán en vuestras ciudades que os he dado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 20, 'Hasta que Jehová dé reposo á vuestros hermanos, así como á vosotros, y hereden también ellos la tierra que Jehová vuestro Dios les da á la otra parte del Jordán: entonces os volveréis cada uno a su heredad que yo os he dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 21, 'Mandé también á Josué entonces, diciendo: Tus ojos vieron todo lo que Jehová vuestro Dios ha hecho á aquellos dos reyes: así hará Jehová á todos los reinos á los cuales pasarás tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 22, 'No los temáis; que Jehová vuestro Dios, él es el que pelea por vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 23, 'Y oré á Jehová en aquel tiempo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 24, 'Señor Jehová, tú has comenzado á mostrar á tu siervo tu grandeza, y tu mano fuerte: porque ¿qué dios hay en el cielo ni en la tierra que haga según tus obras, y según tus valentías?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 25, 'Pase yo, ruégote, y vea aquella tierra buena, que está á la parte allá del Jordán, aquel buen monte, y el Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 26, 'Mas Jehová se había enojado contra mí por causa de vosotros, por lo cual no me oyó: y díjome Jehová: Bástate, no me hables más de este negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 27, 'Sube á la cumbre del Pisga, y alza tus ojos al occidente, y al aquilón, y al mediodía, y al oriente, y ve por tus ojos: porque no pasarás este Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 28, 'Y manda a Josué, y anímalo, y confórtalo; porque él ha de pasar delante de este pueblo, y él les hará heredar la tierra que verás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 3, 29, 'Y paramos en el valle delante de Beth-peor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 1, 'AHORA pues, oh Israel, oye los estatutos y derechos que yo os enseño, para que los ejecutéis, y viváis, y entréis, y poseáis la tierra que Jehová el Dios de vuestros padres te da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 2, 'No añadiréis á la palabra que yo os mando, ni disminuiréis de ella, para que guardéis los mandamientos de Jehová vuestro Dios que yo os ordeno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 3, 'Vuestros ojos vieron lo que hizo Jehová con motivo de Baal-peor; que á todo hombre que fué en pos de Baal-peor destruyó Jehová tu Dios de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 4, 'Mas vosotros que os allegasteis á Jehová vuestro Dios, todos estáis vivos hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 5, 'Mirad, yo os he enseñado estatutos y derechos, como Jehová mi Dios me mandó, para que hagáis así en medio de la tierra en la cual entráis para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 6, 'Guardadlos, pues, y ponedlos por obra: porque esta es vuestra sabiduría y vuestra inteligencia en ojos de los pueblos, los cuales oirán todos estos estatutos, y dirán: Ciertamente pueblo sabio y entendido, gente grande es ésta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 7, 'Porque ¿qué gente grande hay que tenga los dioses cercanos á sí, como lo está Jehová nuestro Dios en todo cuanto le pedimos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 8, 'Y ¿qué gente grande hay que tenga estatutos y derechos justos, como es toda esta ley que yo pongo hoy delante de vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 9, 'Por tanto, guárdate, y guarda tu alma con diligencia, que no te olvides de las cosas que tus ojos han visto, ni se aparten de tu corazón todos los días de tu vida: y enseñarlas has á tus hijos, y á los hijos de tus hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 10, 'El día que estuviste delante de Jehová tu Dios en Horeb, cuando Jehová me dijo: Júntame el pueblo, para que yo les haga oir mis palabras, las cuales aprenderán, para temerme todos los días que vivieren sobre la tierra: y las enseñarán á sus hijos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 11, 'Y os llegasteis, y os pusisteis al pie del monte; y el monte ardía en fuego hasta en medio de los cielos con tinieblas, nube, y oscuridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 12, 'Y habló Jehová con vosotros de en medio del fuego: oisteis la voz de sus palabras, mas á excepción de oir la voz, ninguna figura visteis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 13, 'Y él os anunció su pacto, el cual os mandó poner por obra, las diez palabras; y escribiólas en dos tablas de piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 14, 'A mí también me mandó Jehová entonces enseñaros los estatutos y derechos, para que los pusieseis por obra en la tierra á la cual pasáis para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 15, 'Guardad pues mucho vuestras almas: pues ninguna figura visteis el día que Jehová habló con vosotros de en medio del fuego:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 16, 'Porque no os corrompáis, y hagáis para vosotros escultura, imagen de figura alguna, efigie de varón ó hembra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 17, 'Figura de algún animal que sea en la tierra, figura de ave alguna alada que vuele por el aire,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 18, 'Figura de ningún animal que vaya arrastrando por la tierra, figura de pez alguno que haya en el agua debajo de la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 19, 'Y porque alzando tus ojos al cielo, y viendo el sol y la luna y las estrellas, y todo el ejército del cielo, no seas incitado, y te inclines á ellos, y les sirvas; que Jehová tu Dios los ha concedido á todos los pueblos debajo de todos los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 20, 'Empero á vosotros Jehová os tomó, y os ha sacado del horno de hierro, de Egipto, para que le seáis por pueblo de heredad como en este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 21, 'Y Jehová se enojó contra mí sobre vuestros negocios, y juró que yo no pasaría el Jordán, ni entraría en la buena tierra, que Jehová tu Dios te da por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 22, 'Así que yo voy á morir en esta tierra; y no paso el Jordán: mas vosotros pasaréis, y poseeréis aquella buena tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 23, 'Guardaos no os olvidéis del pacto de Jehová vuestro Dios, que él estableció con vosotros, y os hagáis escultura ó imagen de cualquier cosa, que Jehová tu Dios te ha vedado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 24, 'Porque Jehová tu Dios es fuego que consume, Dios celoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 25, 'Cuando hubiereis engendrado hijos y nietos, y hubiereis envejecido en la tierra, y os corrompiereis, é hiciereis escultura ó imagen de cualquier cosa, é hiciereis mal en ojos de Jehová vuestro Dios, para enojarlo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 26, 'Yo pongo hoy por testigos al cielo y á la tierra, que presto pereceréis totalmente de la tierra hacia la cual pasáis el Jordán para poseerla: no estaréis en ella largos días sin que seáis destruídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 27, 'Y Jehová os esparcirá entre los pueblos, y quedaréis pocos en número entre las gentes á las cuales os llevará Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 28, 'Y serviréis allí á dioses hechos de manos de hombres, á madera y á piedra, que no ven, ni oyen, ni comen, ni huelen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 29, 'Mas si desde allí buscares á Jehová tu Dios, lo hallarás, si lo buscares de todo tu corazón y de toda tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 30, 'Cuando estuviereis en angustia, y te alcanzaren todas estas cosas, si en los postreros días te volvieres á Jehová tu Dios, y oyeres su voz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 31, 'Porque Dios misericordioso es Jehová tu Dios; no te dejará, ni te destruirá, ni se olvidará del pacto de tus padres que les juró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 32, 'Porque pregunta ahora de los tiempos pasados, que han sido antes de ti, desde el día que crió Dios al hombre sobre la tierra, y desde el un cabo del cielo al otro, si se ha hecho cosa semejante á esta gran cosa, ó se haya oído otra como ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 33, '¿Ha oído pueblo la voz de Dios, que hablase de en medio del fuego, como tú la has oído, y vivido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 34, '¿O ha Dios probado á venir á tomar para sí gente de en medio de otra gente, con pruebas, con señales, con milagros, y con guerra, y mano fuerte, y brazo extendido, y grandes espantos, según todas las cosas que hizo con vosotros Jehová vuestro Dios en Egipto ante tus ojos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 35, 'A ti te fué mostrado, para que supieses que Jehová él es Dios; no hay más fuera de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 36, 'De los cielos te hizo oir su voz, para enseñarte: y sobre la tierra te mostró su gran fuego: y has oído sus palabras de en medio del fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 37, 'Y por cuanto él amó á tus padres, escogió su simiente después de ellos, y sacóte delante de sí de Egipto con su gran poder;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 38, 'Para echar de delante de ti gentes grandes y más fuertes que tú, y para introducirte, y darte su tierra por heredad, como hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 39, 'Aprende pues hoy, y reduce á tu corazón que Jehová él es el Dios arriba en el cielo, y abajo sobre la tierra; no hay otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 40, 'Y guarda sus estatutos y sus mandamientos, que yo te mando hoy, para que te vaya bien á ti y á tus hijos después de ti, y prolongues tus días sobre la tierra que Jehová tu Dios te da para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 41, 'Entonces apartó Moisés tres ciudades de esta parte del Jordán al nacimiento del sol,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 42, 'Para que huyese allí el homicida que matase á su prójimo por yerro, sin haber tenido enemistad con él desde ayer ni antes de ayer; y que huyendo á una de estas ciudades salvara la vida:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 43, 'A Beser en el desierto, en tierra de la llanura, de los Rubenitas; y á Ramoth en Galaad, de los Gaditas; y á Golán en Basán, de los de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 44, 'Esta, pues, es la ley que Moisés propuso delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 45, 'Estos son los testimonios, y los estatutos, y los derechos, que Moisés notificó á los hijos de Israel, cuando hubieron salido de Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 46, 'De esta parte del Jordán, en el valle delante de Beth-peor, en la tierra de Sehón rey de los Amorrheos, que habitaba en Hesbón, al cual hirió Moisés con los hijos de Israel, cuando hubieron salido de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 47, 'Y poseyeron su tierra, y la tierra de Og rey de Basán; dos reyes de los Amorrheos que estaban de esta parte del Jordán, al nacimiento del sol:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 48, 'Desde Aroer, que está junto á la ribera del arroyo de Arnón, hasta el monte de Sión, que es Hermón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 4, 49, 'Y toda la llanura de esta parte del Jordán, al oriente, hasta la mar del llano, las vertientes de las aguas abajo del Pisga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 1, 'Y LLAMO Moisés á todo Israel, y díjoles: Oye, Israel, los estatutos y derechos que yo pronuncio hoy en vuestros oídos: y aprendedlos, y guardadlos, para ponerlos por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 2, 'Jehová nuestro Dios hizo pacto con nosotros en Horeb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 3, 'No con nuestros padres hizo Jehová este pacto, sino con nosotros todos los que estamos aquí hoy vivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 4, 'Cara á cara habló Jehová con vosotros en el monte de en medio del fuego,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 5, '(Yo estaba entonces entre Jehová y vosotros, para denunciaros la palabra de Jehová; porque vosotros tuvisteis temor del fuego, y no subisteis al monte;) diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 6, 'Yo soy Jehová tu Dios, que te saqué de tierra de Egipto, de casa de siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 7, 'No tendrás dioses extraños delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 8, 'No harás para ti escultura, ni imagen alguna de cosa que está arriba en los cielos, ó abajo en la tierra, ó en las aguas debajo de la tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 9, 'No te inclinarás á ellas ni les servirás: porque yo soy Jehová tu Dios, fuerte, celoso, que visito la iniquidad de los padres sobre los hijos, y sobre los terceros, y sobre los cuartos, á los que me aborrecen,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 10, 'Y que hago misericordia á millares á los que me aman, y guardan mis mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 11, 'No tomarás en vano el nombre de Jehová tu Dios; porque Jehová no dará por inocente al que tomare en vano su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 12, 'Guardarás el día del reposo para santificarlo, como Jehová tu Dios te ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 13, 'Seis días trabajarás y harás toda tu obra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 14, 'Mas el séptimo es reposo á Jehová tu Dios: ninguna obra harás tú, ni tu hijo, ni tu hija, ni tu siervo, ni tu sierva, ni tu buey, ni tu asno, ni ningún animal tuyo, ni tu peregrino que está dentro de tus puertas: porque descanse tu siervo y tu sierva como tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 15, 'Y acuérdate que fuiste siervo en tierra de Egipto, y que Jehová tu Dios te sacó de allá con mano fuerte y brazo extendido: por lo cual Jehová tu Dios te ha mandado que guardes el día del reposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 16, 'Honra á tu padre y á tu madre, como Jehová tu Dios te ha mandado, para que sean prolongados tus días, y para que te vaya bien sobre la tierra que Jehová tu Dios te da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 17, 'No matarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 18, 'No adulterarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 19, 'No hurtarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 20, 'No dirás falso testimonio contra tu prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 21, 'No codiciarás la mujer de tu prójimo, ni desearás la casa de tu prójimo, ni su tierra, ni su siervo, ni su sierva, ni su buey, ni su asno, ni ninguna cosa que sea de tu prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 22, 'Estas palabras habló Jehová á toda vuestra congregación en el monte, de en medio del fuego, de la nube y de la oscuridad, á gran voz: y no añadió más. Y escribiólas en dos tablas de piedra, las cuales me dió á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 23, 'Y aconteció, que como vosotros oisteis la voz de en medio de las tinieblas, y visteis al monte que ardía en fuego, llegasteis á mí todos los príncipes de vuestras tribus, y vuestros ancianos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 24, 'Y dijisteis: He aquí, Jehová nuestro Dios nos ha mostrado su gloria y su grandeza, y hemos oído su voz de en medio del fuego: hoy hemos visto que Jehová habla al hombre, y éste vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 25, 'Ahora pues, ¿por qué moriremos? que este gran fuego nos consumirá: si tornáremos á oir la voz de Jehová nuestro Dios, moriremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 26, 'Porque, ¿qué es toda carne, para que oiga la voz del Dios viviente que habla de en medio del fuego, como nosotros la oímos, y viva?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 27, 'Llega tú, y oye todas las cosas que dijere Jehová nuestro Dios; y tú nos dirás todo lo que Jehová nuestro Dios te dijere, y nosotros oiremos y haremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 28, 'Y oyó Jehová la voz de vuestras palabras, cuando me hablabais; y díjome Jehová: He oído la voz de las palabras de este pueblo, que ellos te han hablado: bien está todo lo que han dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 29, '¡Quién diera que tuviesen tal corazón, que me temiesen, y guardasen todos los días todos mis mandamientos, para que á ellos y á sus hijos les fuese bien para siempre!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 30, 'Ve, diles: Volveos á vuestras tiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 31, 'Y tú estáte aquí conmigo, y te diré todos los mandamientos, y estatutos, y derechos que les has de enseñar, a fin que los pongan ahora por obra en la tierra que yo les doy para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 32, 'Mirad, pues, que hagáis como Jehová vuestro Dios os ha mandado: no os apartéis á diestra ni á siniestra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 5, 33, 'Andad en todo camino que Jehová vuestro Dios os ha mandado, para que viváis, y os vaya bien, y tengáis largos días en la tierra que habéis de poseer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 1, 'ESTOS pues son los mandamientos, estatutos, y derechos que Jehová vuestro Dios mandó que os enseñase, para que los pongáis por obra en la tierra á la cual pasáis vosotros para poseerla:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 2, 'Para que temas á Jehová tu Dios, guardando todos sus estatutos y sus mandamientos que yo te mando, tú, y tu hijo, y el hijo de tu hijo, todos los días de tu vida, y que tus días sean prolongados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 3, 'Oye pues, oh Israel, y cuida de ponerlos por obra, para que te vaya bien, y seáis multiplicados, como te ha dicho Jehová el Dios de tus padres, en la tierra que destila leche y miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 4, 'Oye, Israel: Jehová nuestro Dios, Jehová uno es:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 5, 'Y Amarás á Jehová tu Dios de todo tu corazón, y de toda tu alma, y con todo tu poder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 6, 'Y estas palabras que yo te mando hoy, estarán sobre tu corazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 7, 'Y las repetirás á tus hijos, y hablarás de ellas estando en tu casa, y andando por el camino, y al acostarte, y cuando te levantes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 8, 'Y has de atarlas por señal en tu mano, y estarán por frontales entre tus ojos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 9, 'Y las escribirás en los postes de tu casa, y en tus portadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 10, 'Y será, cuando Jehová tu Dios te hubiere introducido en la tierra que juró á tus padres Abraham, Isaac, y Jacob, que te daría; en ciudades grandes y buenas que tú no edificaste,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 11, 'Y casas llenas de todo bien, que tú no henchiste, y cisternas cavadas, que tú no cavaste, viñas y olivares que no plantaste: luego que comieres y te hartares,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 12, 'Guárdate que no te olvides de Jehová, que te sacó de tierra de Egipto, de casa de siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 13, 'A Jehová tu Dios temerás, y á él servirás, y por su nombre jurarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 14, 'No andaréis en pos de dioses ajenos, de los dioses de los pueblos que están en vuestros contornos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 15, 'Porque el Dios celoso, Jehová tu Dios, en medio de ti está; porque no se inflame el furor de Jehová tu Dios contra ti, y te destruya de sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 16, 'No tentaréis á Jehová vuestro Dios, como lo tentasteis en Massa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 17, 'Guardad cuidadosamente los mandamientos de Jehová vuestro Dios, y sus testimonios, y sus estatutos, que te ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 18, 'Y harás lo recto y bueno en ojos de Jehová, para que te vaya bien, y entres y poseas la buena tierra que Jehová juró á tus padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 19, 'Para que él eche á todos sus enemigos de delante de ti, como Jehová ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 20, 'Cuando mañana te preguntare tu hijo, diciendo: ¿Qué significan los testimonios, y estatutos, y derechos, que Jehová nuestro Dios os mandó?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 21, 'Entonces dirás á tu hijo: Nosotros éramos siervos de Faraón en Egipto, y Jehová nos sacó de Egipto con mano fuerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 22, 'Y dió Jehová señales y milagros grandes y nocivos en Egipto, sobre Faraón y sobre toda su casa, delante de nuestros ojos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 23, 'Y sacónos de allá, para traernos y darnos la tierra que juró á nuestros padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 24, 'Y mandónos Jehová que ejecutásemos todos estos estatutos, y que temamos á Jehová nuestro Dios, porque nos vaya bien todos los días, y para que nos dé vida, como hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 6, 25, 'Y tendremos justicia cuando cuidáremos de poner por obra todos estos mandamientos delante de Jehová nuestro Dios, como él nos ha mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 1, 'CUANDO Jehová tu Dios te hubiere introducido en la tierra en la cual tú has de entrar para poseerla, y hubiere echado de delante de ti muchas gentes, al Hetheo, al Gergeseo, y al Amorrheo, y al Cananeo, y al Pherezeo, y al Heveo, y al Jebuseo, siete naciones mayores y más fuertes que tú;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 2, 'Y Jehová tu Dios las hubiere entregado delante de ti, y las hirieres, del todo las destruirás: no harás con ellos alianza, ni las tomarás á merced.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 3, 'Y no emparentarás con ellos: no darás tu hija á su hijo, ni tomarás á su hija para tu hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 4, 'Porque desviará á tu hijo de en pos de mí, y servirán á dioses ajenos; y el furor de Jehová se encenderá sobre vosotros, y te destruirá presto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 5, 'Mas así habéis de hacer con ellos: sus altares destruiréis, y quebraréis sus estatuas, y cortaréis sus bosques, y quemaréis sus esculturas en el fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 6, 'Porque tú eres pueblo santo á Jehová tu Dios: Jehová tu Dios te ha escogido para serle un pueblo especial, más que todos los pueblos que están sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 7, 'No por ser vosotros más que todos los pueblos os ha querido Jehová, y os ha escogido; porque vosotros erais los más pocos de todos los pueblos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 8, 'Sino porque Jehová os amó, y quiso guardar el juramento que juró á vuestros padres, os ha sacado Jehová con mano fuerte, y os ha rescatado de casa de siervos, de la mano de Faraón, rey de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 9, 'Conoce, pues, que Jehová tu Dios es Dios, Dios fiel, que guarda el pacto y la misericordia á los que le aman y guardan sus mandamientos, hasta las mil generaciones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 10, 'Y que da el pago en su cara al que le aborrece, destruyéndolo: ni lo dilatará al que le odia, en su cara le dará el pago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 11, 'Guarda por tanto los mandamientos, y estatutos, y derechos que yo te mando hoy que cumplas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 12, 'Y será que, por haber oído estos derechos, y guardado y puéstolos por obra, Jehová tu Dios guardará contigo el pacto y la misericordia que juró á tus padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 13, 'Y te amará, y te bendecirá, y te multiplicará, y bendecirá el fruto de tu vientre, y el fruto de tu tierra, y tu grano, y tu mosto, y tu aceite, la cría de tus vacas, y los rebaños de tus ovejas, en la tierra que juró á tus padres que te daría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 14, 'Bendito serás más que todos los pueblos: no habrá en ti varón ni hembra estéril, ni en tus bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 15, 'Y quitará Jehová de ti toda enfermedad; y todas las malas plagas de Egipto, que tú sabes, no las pondrá sobre ti, antes las pondrá sobre todos los que te aborrecieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 16, 'Y consumirás á todos los pueblos que te da Jehová tu Dios: no los perdonará tu ojo; ni servirás á sus dioses, que te será tropiezo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 17, 'Cuando dijeres en tu corazón: Estas gentes son muchas más que yo, ¿cómo las podré desarraigar?;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 18, 'No tengas temor de ellos: acuérdate bien de lo que hizo Jehová tu Dios con Faraón y con todo Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 19, 'De las grandes pruebas que vieron tus ojos, y de las señales y milagros, y de la mano fuerte y brazo extendido con que Jehová tu Dios te sacó: así hará Jehová tu Dios con todos los pueblos de cuya presencia tú temieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 20, 'Y también enviará Jehová tu Dios sobre ellos avispas, hasta que perezcan los que quedaren, y los que se hubieren escondido de delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 21, 'No desmayes delante de ellos, que Jehová tu Dios está en medio de ti, Dios grande y terrible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 22, 'Y Jehová tu Dios echará á estas gentes de delante de ti poco á poco: no las podrás acabar luego, porque las bestias del campo no se aumenten contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 23, 'Mas Jehová tu Dios las entregará delante de ti, y él las quebrantará con grande destrozo, hasta que sean destruídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 24, 'Y él entregará sus reyes en tu mano, y tú destruirás el nombre de ellos de debajo del cielo: nadie te hará frente hasta que los destruyas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 25, 'Las esculturas de sus dioses quemarás en el fuego: no codiciarás plata ni oro de sobre ellas para tomarlo para ti, porque no tropieces en ello, pues es abominación á Jehová tu Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 7, 26, 'Y no meterás abominación en tu casa, porque no seas anatema como ello; del todo lo aborrecerás y lo abominarás; porque es anatema.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 1, 'CUIDARÉIS de poner por obra todo mandamiento que yo os ordeno hoy, porque viváis, y seáis multiplicados, y entréis, y poseáis la tierra, de la cual juró Jehová á vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 2, 'Y acordarte has de todo el camino por donde te ha traído Jehová tu Dios estos cuarenta años en el desierto, para afligirte, por probarte, para saber lo que estaba en tu corazón, si habías de guardar ó no sus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 3, 'Y te afligió, é hízote tener hambre, y te sustentó con maná, comida que no conocías tú, ni tus padres la habían conocido; para hacerte saber que el hombre no vivirá de solo pan, mas de todo lo que sale de la boca de Jehová vivirá el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 4, 'Tu vestido nunca se envejeció sobre ti, ni el pie se te ha hinchado por estos cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 5, 'Reconoce asimismo en tu corazón, que como castiga el hombre á su hijo, así Jehová tu Dios te castiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 6, 'Guardarás, pues, los mandamientos de Jehová tu Dios, andando en sus caminos, y temiéndolo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 7, 'Porque Jehová tu Dios te introduce en la buena tierra, tierra de arroyos, de aguas, de fuentes, de abismos que brotan por vegas y montes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 8, 'Tierra de trigo y cebada, y de vides, é higueras, y granados; tierra de olivas, de aceite, y de miel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 9, 'Tierra en la cual no comerás el pan con escasez, no te faltará nada en ella; tierra que sus piedras son hierro, y de sus montes cortarás metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 10, 'Y comerás y te hartarás, y bendecirás á Jehová tu Dios por la buena tierra que te habrá dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 11, 'Guárdate, que no te olvides de Jehová tu Dios, para no observar sus mandamientos, y sus derechos, y sus estatutos, que yo te ordeno hoy:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 12, 'Que quizá no comas y te hartes, y edifiques buenas casas en que mores,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 13, 'Y tus vacas y tus ovejas se aumenten, y la plata y el oro se te multiplique, y todo lo que tuvieres se te aumente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 14, 'Y se eleve luego tu corazón, y te olvides de Jehová tu Dios, que te sacó de tierra de Egipto, de casa de siervos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 15, 'Que te hizo caminar por un desierto grande y espantoso, de serpientes ardientes, y de escorpiones, y de sed, donde ningún agua había, y él te sacó agua de la roca del pedernal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 16, 'Que te sustentó con maná en el desierto, comida que tus padres no habían conocido, afligiéndote y probándote, para á la postre hacerte bien;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 17, 'Y digas en tu corazón: Mi poder y la fortaleza de mi mano me han traído esta riqueza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 18, 'Antes acuérdate de Jehová tu Dios: porque él te da el poder para hacer las riquezas, á fin de confirmar su pacto que juró á tus padres, como en este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 19, 'Mas será, si llegares á olvidarte de Jehová tu Dios, y anduvieres en pos de dioses ajenos, y les sirvieres, y á ellos te encorvares, protésto lo hoy contra vosotros, que de cierto pereceréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 8, 20, 'Como las gentes que Jehová destruirá delante de vosotros, así pereceréis; por cuanto no habréis atendido á la voz de Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 1, 'OYE, Israel: tú estás hoy para pasar el Jordán, para entrar á poseer gentes más numerosas y más fuertes que tú, ciudades grandes y encastilladas hasta el cielo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 2, 'Un pueblo grande y alto, hijos de gigantes, de los cuales tienes tú conocimiento, y has oído decir: ¿Quién se sostendrá delante de los hijos del gigante?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 3, 'Sabe, pues, hoy que Jehová tu Dios es el que pasa delante de ti, fuego consumidor, que los destruirá y humillará delante de ti: y tú los echarás, y los destruirás luego, como Jehová te ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 4, 'No discurras en tu corazón cuando Jehová tu Dios los habrá echado de delante de ti, diciendo: Por mi justicia me ha metido Jehová á poseer esta tierra; pues por la impiedad de estas gentes Jehová las echa de delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 5, 'No por tu justicia, ni por la rectitud de tu corazón entras a poseer la tierra de ellos; mas por la impiedad de estas gentes Jehová tu Dios las echa de delante de ti, y por confirmar la palabra que Jehová juró á tus padres Abraham, Isaac, y Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 6, 'Por tanto, sabe que no por tu justicia Jehová tu Dios te da esta buena tierra para poseerla; que pueblo duro de cerviz eres tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 7, 'Acuérdate, no te olvides que has provocado á ira á Jehová tu Dios en el desierto: desde el día que saliste de la tierra de Egipto, hasta que entrasteis en este lugar, habéis sido rebeldes á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 8, 'Y en Horeb provocasteis á ira á Jehová, y enojóse Jehová contra vosotros para destruiros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 9, 'Cuando yo subí al monte para recibir las tablas de piedra, las tablas del pacto que Jehová hizo con vosotros, estuve entonces en el monte cuarenta días y cuarenta noches, sin comer pan ni beber agua:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 10, 'Y dióme Jehová las dos tablas de piedra escritas con el dedo de Dios; y en ellas estaba escrito conforme á todas las palabras que os habló Jehová en el monte de en medio del fuego, el día de la asamblea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 11, 'Y fué al cabo de los cuarenta días y cuarenta noches, que Jehová me dió dos las tablas de piedra, las tablas del pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 12, 'Y díjome Jehová: Levántate, desciende presto de aquí; que tu pueblo que sacaste de Egipto se ha corrompido: pronto se han apartado del camino que yo les mandé: hanse hecho una efigie de fundición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 13, 'Y hablóme Jehová, diciendo: He visto ese pueblo, y he aquí, que él es pueblo duro de cerviz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 14, 'Déjame que los destruya, y raiga su nombre de debajo del cielo; que yo te pondré sobre gente fuerte y mucha más que ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 15, 'Y volví y descendí del monte, el cual ardía en fuego, con las tablas del pacto en mis dos manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 16, 'Y miré, y he aquí habíais pecado contra Jehová vuestro Dios: os habíais hecho un becerro de fundición, apartándoos presto del camino que Jehová os había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 17, 'Entonces tomé las dos tablas, y arrojélas de mis dos manos, y quebrélas delante de vuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 18, 'Y postréme delante de Jehová, como antes, cuarenta días y cuarenta noches: no comí pan ni bebí agua, á causa de todo vuestro pecado que habíais cometido haciendo mal en ojos de Jehová para enojarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 19, 'Porque temí á causa del furor y de la ira con que Jehová estaba enojado contra vosotros para destruiros. Pero Jehová me oyó aún esta vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 20, 'Contra Aarón también se enojó Jehová en gran manera para destruirlo: y también oré por Aarón entonces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 21, 'Y tomé vuestro pecado, el becerro que habíais hecho, y quemélo en el fuego, y lo desmenucé moliéndole muy bien, hasta que fué reducido á polvo: y eché el polvo de él en el arroyo que descendía del monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 22, 'También en Tabera, y en Massa, y en Kibroth-hataavah, enojasteis á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 23, 'Y cuando Jehová os envió desde Cades-barnea, diciendo: Subid y poseed la tierra que yo os he dado; también fuisteis rebeldes al dicho de Jehová vuestro Dios, y no lo creisteis, ni obedecisteis á su voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 24, 'Rebeldes habéis sido á Jehová desde el día que yo os conozco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 25, 'Postréme, pues, delante de Jehová cuarenta días y cuarenta noches que estuve postrado; porque Jehová dijo que os había de destruir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 26, 'Y oré á Jehová, diciendo: Oh Señor Jehová, no destruyas tu pueblo y tu heredad que has redimido con tu grandeza, al cual sacaste de Egipto con mano fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 27, 'Acuérdate de tus siervos Abraham, Isaac, y Jacob; no mires á la dureza de este pueblo, ni á su impiedad, ni á su pecado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 28, 'Porque no digan los de la tierra de donde nos sacaste: Por cuanto no pudo Jehová introducirlos en la tierra que les había dicho, ó porque los aborrecía, los sacó para matarlos en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 9, 29, 'Y ellos son tu pueblo y tu heredad, que sacaste con tu gran fortaleza y con tu brazo extendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 1, 'EN aquel tiempo Jehová me dijo: Lábrate dos tablas de piedra como las primeras, y sube á mí al monte, y hazte un arca de madera:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 2, 'Y escribiré en aquellas tablas palabras que estaban en las tablas primeras que quebraste; y las pondrás en el arca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 3, 'E hice un arca de madera de Sittim, y labré dos tablas de piedra como las primeras, y subí al monte con las dos tablas en mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 4, 'Y escribió en las tablas conforme á la primera escritura, las diez palabras que Jehová os había hablado en el monte de en medio del fuego, el día de la asamblea; y diómelas Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 5, 'Y volví y descendí del monte, y puse las tablas en el arca que había hecho; y allí están, como Jehová me mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 6, '(Después partieron los hijos de Israel de Beerot-bene-jacaam á Moserá: allí murió Aarón, y allí fué sepultado; y en lugar suyo tuvo el sacerdocio su hijo Eleazar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 7, 'De allí partieron á Gudgod, y de Gudgod á Jotbath, tierra de arroyos de aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 8, 'En aquel tiempo apartó Jehová la tribu de Leví, para que llevase el arca del pacto de Jehová, para que estuviese delante de Jehová para servirle, y para bendecir en su nombre, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 9, 'Por lo cual Leví no tuvo parte ni heredad con sus hermanos: Jehová es su heredad, como Jehová tu Dios le dijo.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 10, 'Y yo estuve en el monte como los primeros días, cuarenta días y cuarenta noches; y Jehová me oyó también esta vez, y no quiso Jehová destruirte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 11, 'Y díjome Jehová: Levántate, anda, para que partas delante del pueblo, para que entren y posean la tierra que juré á sus padres les había de dar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 12, 'Ahora pues, Israel, ¿qué pide Jehová tu Dios de ti, sino que temas á Jehová tu Dios, que andes en todos sus caminos, y que lo ames, y sirvas á Jehová tu Dios con todo tu corazón, y con toda tu alma;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 13, 'Que guardes los mandamientos de Jehová y sus estatutos, que yo te prescribo hoy, para que hayas bien?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 14, 'He aquí, de Jehová tu Dios son los cielos, y los cielos de los cielos: la tierra, y todas las cosas que hay en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 15, 'Solamente de tus padres se agradó Jehová para amarlos, y escogió su simiente después de ellos, á vosotros, de entre todos los pueblos, como en este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 16, 'Circuncidad pues el prepucio de vuestro corazón, y no endurezcáis más vuestra cerviz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 17, 'Porque Jehová vuestro Dios es Dios de dioses, y Señor de señores, Dios grande, poderoso, y terrible, que no acepta persona, ni toma cohecho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 18, 'Que hace justicia al huérfano y á la viuda; que ama también al extranjero dándole pan y vestido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 19, 'Amaréis pues al extranjero: porque extranjeros fuisteis vosotros en tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 20, 'A Jehová tu Dios temerás, á él servirás, á él te allegarás, y por su nombre jurarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 21, 'El es tu alabanza, y él es tu Dios, que ha hecho contigo estas grandes y terribles cosas que tus ojos han visto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 10, 22, 'Con setenta almas descendieron tus padres á Egipto; y ahora Jehová te ha hecho como las estrellas del cielo en multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 1, 'AMARAS pues á Jehová tu Dios, y guardarás su ordenanza, y sus estatutos y sus derechos y sus mandamientos, todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 2, 'Y comprended hoy: porque no hablo con vuestros hijos que no han sabido ni visto el castigo de Jehová vuestro Dios, su grandeza, su mano fuerte, y su brazo extendido,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 3, 'Y sus señales, y sus obras que hizo en medio de Egipto á Faraón, rey de Egipto, y á toda su tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 4, 'Y lo que hizo al ejército de Egipto, á sus caballos, y á sus carros; cómo hizo ondear las aguas del mar Bermejo sobre ellos, cuando venían tras vosotros, y Jehová los destruyó hasta hoy;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 5, 'Y lo que ha hecho con vosotros en el desierto, hasta que habéis llegado á este lugar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 6, 'Y lo que hizo con Dathán y Abiram, hijos de Eliab hijo de Rubén; cómo abrió la tierra su boca, y tragóse á ellos y á sus casas, y sus tiendas, y toda la hacienda que tenían en pie en medio de todo Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 7, 'Mas vuestros ojos han visto todos los grandes hechos que Jehová ha ejecutado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 8, 'Guardad, pues, todos los mandamientos que yo os prescribo hoy, para que seáis esforzados, y entréis y poseáis la tierra, á la cual pasáis para poseerla;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 9, 'Y para que os sean prolongados los días sobre la tierra, que juró Jehová á vuestros padres había de dar á ellos y á su simiente, tierra que fluye leche y miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 10, 'Que la tierra á la cual entras para poseerla, no es como la tierra de Egipto de donde habéis salido, donde sembrabas tu simiente, y regabas con tu pie, como huerto de hortaliza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 11, 'La tierra á la cual pasáis para poseerla, es tierra de montes y de vegas; de la lluvia del cielo ha de beber las aguas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 12, 'Tierra de la cual Jehová tu Dios cuida: siempre están sobre ella los ojos de Jehová tu Dios, desde el principio del año hasta el fin de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 13, 'Y será que, si obedeciereis cuidadosamente mis mandamientos que yo os prescribo hoy, amando á Jehová vuestro Dios, y sirviéndolo con todo vuestro corazón, y con toda vuestra alma,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 14, 'Yo daré la lluvia de vuestra tierra en su tiempo, la temprana y la tardía; y cogerás tu grano, y tu vino, y tu aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 15, 'Daré también hierba en tu campo para tus bestias; y comerás, y te hartarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 16, 'Guardaos, pues, que vuestro corazón no se infatúe, y os apartéis, y sirváis á dioses ajenos, y os inclinéis á ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 17, 'Y así se encienda el furor de Jehová sobre vosotros, y cierre los cielos, y no haya lluvia, ni la tierra dé su fruto, y perezcáis presto de la buena tierra que os da Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 18, 'Por tanto, pondréis estas mis palabras en vuestro corazón y en vuestra alma, y las ataréis por señal en vuestra mano, y serán por frontales entre vuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 19, 'Y las enseñaréis á vuestros hijos, hablando de ellas, ora sentado en tu casa, ó andando por el camino, cuando te acuestes, y cuando te levantes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 20, 'Y las escribirás en los postes de tu casa, y en tus portadas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 21, 'Para que sean aumentados vuestros días, y los días de vuestros hijos, sobre la tierra que juró Jehová á vuestros padres que les había de dar, como los días de los cielos sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 22, 'Porque si guardareis cuidadosamente todos estos mandamientos que yo os prescribo, para que los cumpláis; como améis á Jehová vuestro Dios andando en todos sus caminos, y á él os allegareis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 23, 'Jehová también echará todas estas gentes de delante de vosotros y poseeréis gentes grandes y más fuertes que vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 24, 'Todo lugar que pisare la planta de vuestro pie, será vuestro: desde el desierto y el Líbano, desde el río, el río Eufrates, hasta la mar postrera será vuestro término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 25, 'Nadie se sostendrá delante de vosotros: miedo y temor de vosotros pondrá Jehová vuestro Dios sobre la haz de toda la tierra que hollareis, como él os ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 26, 'He aquí yo pongo hoy delante de vosotros la bendición y la maldición:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 27, 'La bendición, si oyereis los mandamientos de Jehová vuestro Dios, que yo os prescribo hoy;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 28, 'Y la maldición, si no oyereis los mandamientos de Jehová vuestro Dios, y os apartareis del camino que yo os ordeno hoy, para ir en pos de dioses ajenos que no habéis conocido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 29, 'Y será que, cuando Jehová tu Dios te introdujere en la tierra á la cual vas para poseerla, pondrás la bendición sobre el monte Gerizim, y la maldición sobre el monte Ebal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 30, 'Los cuales están de la otra parte del Jordán, tras el camino del occidente en la tierra del Cananeo, que habita en la campiña delante de Gilgal, junto á los llanos de Moreh.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 31, 'Porque vosotros pasáis el Jordán, para ir a poseer la tierra que os da Jehová vuestro Dios; y la poseeréis, y habitaréis en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 11, 32, 'Cuidaréis, pues, de poner por obra todos los estatutos y derechos que yo presento hoy delante de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 1, 'ESTOS son los estatutos y derechos que cuidaréis de poner por obra, en la tierra que Jehová el Dios de tus padres te ha dado para que la poseas, todos los días que vosotros viviereis sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 2, 'Destruiréis enteramente todos los lugares donde las gentes que vosotros heredareis sirvieron á sus dioses, sobre los montes altos, y sobre los collados, y debajo de todo árbol espeso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 3, 'Y derribaréis sus altares, y quebraréis sus imágenes, y sus bosques consumiréis con fuego: y destruiréis las esculturas de sus dioses, y extirparéis el nombre de ellas de aquel lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 4, 'No haréis así á Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 5, 'Mas el lugar que Jehová vuestro Dios escogiere de todas vuestras tribus, para poner allí su nombre para su habitación, ése buscaréis, y allá iréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 6, 'Y allí llevaréis vuestros holocaustos, y vuestros sacrificios, y vuestros diezmos, y la ofrenda elevada de vuestras manos, y vuestros votos, y vuestras ofrendas voluntarias, y los primerizos de vuestras vacas y de vuestras ovejas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 7, 'Y comeréis allí delante de Jehová vuestro Dios, y os alegraréis, vosotros y vuestras familias, en toda obra de vuestras manos en que Jehová tu Dios te hubiere bendecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 8, 'No haréis como todo lo que nosotros hacemos aquí ahora, cada uno lo que le parece,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 9, 'Porque aun hasta ahora no habéis entrado al reposo y á la heredad que os da Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 10, 'Mas pasaréis el Jordán, y habitaréis en la tierra que Jehová vuestro Dios os hace heredar, y él os dará reposo de todos vuestros enemigos alrededor, y habitaréis seguros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 11, 'Y al lugar que Jehová vuestro Dios escogiere para hacer habitar en él su nombre, allí llevaréis todas las cosas que yo os mando: vuestros holocaustos, y vuestros sacrificios, vuestros diezmos, y las ofrendas elevadas de vuestras manos, y todo lo escogido de vuestros votos que hubiereis prometido á Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 12, 'Y os alegraréis delante de Jehová vuestro Dios, vosotros, y vuestros hijos, y vuestras hijas, y vuestros siervos, y vuestras siervas, y el Levita que estuviere en vuestras poblaciones: por cuanto no tiene parte ni heredad con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 13, 'Guárdate, que no ofrezcas tus holocaustos en cualquier lugar que vieres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 14, 'Mas en el lugar que Jehová escogiere, en una de tus tribus, allí ofrecerás tus holocaustos, y allí harás todo lo que yo te mando.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 15, 'Con todo, podrás matar y comer carne en todas tus poblaciones conforme al deseo de tu alma, según la bendición de Jehová tu Dios que él te habrá dado: el inmundo y el limpio la comerá, como la de corzo ó de ciervo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 16, 'Salvo que sangre no comeréis; sobre la tierra la derramaréis como agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 17, 'Ni podrás comer en tus poblaciones el diezmo de tu grano, ó de tu vino, ó de tu aceite, ni los primerizos de tus vacas, ni de tus ovejas, ni tus votos que prometieres, ni tus ofrendas voluntarias, ni las elevadas ofrendas de tus manos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 18, 'Mas delante de Jehová tu Dios las comerás, en el lugar que Jehová tu Dios hubiere escogido, tú, y tu hijo, y tu hija, y tu siervo, y tu sierva, y el Levita que está en tus poblaciones: y alegrarte has delante de Jehová tu Dios en toda obra de tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 19, 'Ten cuidado de no desamparar al Levita en todos tus días sobre tu tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 20, 'Cuando Jehová tu Dios ensanchare tu término, como él te ha dicho, y tú dijeres: Comeré carne, porque deseó tu alma comerla, conforme á todo el deseo de tu alma comerás carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 21, 'Cuando estuviere lejos de ti el lugar que Jehová tu Dios habrá escogido, para poner allí su nombre, matarás de tus vacas y de tus ovejas, que Jehová te hubiere dado, como te he mandado yo, y comerás en tus puertas según todo lo que deseare tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 22, 'Lo mismo que se come el corzo y el ciervo, así las comerás: el inmundo y el limpio comerán también de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 23, 'Solamente que te esfuerces á no comer sangre: porque la sangre es el alma; y no has de comer el alma juntamente con su carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 24, 'No la comerás: en tierra la derramarás como agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 25, 'No comerás de ella; para que te vaya bien á ti, y á tus hijos después de ti, cuando hicieres lo recto en ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 26, 'Empero las cosas que tuvieres tú consagradas, y tus votos, las tomarás, y vendrás al lugar que Jehová hubiere escogido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 27, 'Y ofrecerás tus holocaustos, la carne y la sangre, sobre el altar de Jehová tu Dios: y la sangre de tus sacrificios será derramada sobre el altar de Jehová tu Dios, y comerás la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 28, 'Guarda y escucha todas estas palabras que yo te mando, porque te vaya bien á ti y á tus hijos después de ti para siempre, cuando hicieres lo bueno y lo recto en los ojos de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 29, 'Cuando hubiere devastado delante de ti Jehová tu Dios las naciones á donde tú vas para poseerlas, y las heredares, y habitares en su tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 30, 'Guárdate que no tropieces en pos de ellas, después que fueren destruídas delante de ti: no preguntes acerca de sus dioses, diciendo: De la manera que servían aquellas gentes á sus dioses, así haré yo también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 31, 'No harás así á Jehová tu Dios; porque todo lo que Jehová aborrece, hicieron ellos á sus dioses; pues aun á sus hijos é hijas quemaban en el fuego á sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 12, 32, 'Cuidaréis de hacer todo lo que yo os mando: no añadirás á ello, ni quitarás de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 1, 'CUANDO se levantare en medio de ti profeta, ó soñador de sueños, y te diere señal ó prodigio,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 2, 'Y acaeciere la señal ó prodigio que él te dijo, diciendo: Vamos en pos de dioses ajenos, que no conociste, y sirvámosles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 3, 'No darás oído á las palabras de tal profeta, ni al tal soñador de sueños: porque Jehová vuestro Dios os prueba, para saber si amáis á Jehová vuestro Dios con todo vuestro corazón, y con toda vuestra alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 4, 'En pos de Jehová vuestro Dios andaréis, y á él temeréis, y guardaréis sus mandamientos, y escucharéis su voz, y á él serviréis, y á él os allegaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 5, 'Y el tal profeta ó soñador de sueños, ha de ser muerto; por cuanto trató de rebelión contra Jehová vuestro Dios, que te sacó de tierra de Egipto, y te rescató de casa de siervos, y de echarte del camino por el que Jehová tu Dios te mandó que anduvieses: y así quitarás el mal de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 6, 'Cuando te incitare tu hermano, hijo de tu madre, ó tu hijo, ó tu hija, ó la mujer de tu seno, ó tu amigo que sea como tu alma, diciendo en secreto: Vamos y sirvamos á dioses ajenos, que ni tú ni tus padres conocisteis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 7, 'De los dioses de los pueblos que están en vuestros alrededores cercanos á ti, ó lejos de ti, desde el un cabo de la tierra hasta el otro cabo de ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 8, 'No consentirás con él, ni le darás oído; ni tu ojo le perdonará, ni tendrás compasión, ni lo encubrirás:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 9, 'Antes has de matarlo; tu mano será primero sobre él para matarle, y después la mano de todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 10, 'Y has de apedrearlo con piedras, y morirá; por cuanto procuró apartarte de Jehová tu Dios, que te sacó de tierra de Egipto, de casa de siervos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 11, 'Para que todo Israel oiga, y tema, y no tornen á hacer cosa semejante á esta mala cosa en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 12, 'Cuando oyeres de alguna de tus ciudades que Jehová tu Dios te da para que mores en ellas, que se dice:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 13, 'Hombres, hijos de impiedad, han salido de en medio de ti, que han instigado á los moradores de su ciudad, diciendo: Vamos y sirvamos á dioses ajenos, que vosotros no conocisteis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 14, 'Tú inquirirás, y buscarás, y preguntarás con diligencia; y si pareciere verdad, cosa cierta, que tal abominación se hizo en medio de ti,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 15, 'Irremisiblemente herirás á filo de espada los moradores de aquella ciudad, destruyéndola con todo lo que en ella hubiere, y también sus bestias á filo de espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 16, 'Y juntarás todo el despojo de ella en medio de su plaza, y consumirás con fuego la ciudad y todo su despojo, todo ello, á Jehová tu Dios: y será un montón para siempre: nunca más se edificará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 17, 'Y no se pegará algo á tu mano del anatema; porque Jehová se aparte del furor de su ira, y te dé mercedes, y tenga misericordia de ti, y te multiplique, como lo juró á tus padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 13, 18, 'Cuando obedecieres á la voz de Jehová tu Dios, guardando todos sus mandamientos que yo te prescribo hoy, para hacer lo recto en ojos de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 1, 'HIJOS sois de Jehová vuestro Dios: no os sajaréis, ni pondréis calva sobre vuestros ojos por muerto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 2, 'Porque eres pueblo santo á Jehová tu Dios, y Jehová te ha escogido para que le seas un pueblo singular de entre todos los pueblos que están sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 3, 'Nada abominable comerás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 4, 'Estos son los animales que comeréis: el buey, la oveja, y la cabra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 5, 'El ciervo, el corzo, y el búfalo, y el cabrío salvaje, y el unicornio, y buey salvaje, y cabra montés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 6, 'Y todo animal de pezuñas, que tiene hendidura de dos uñas, y que rumiare entre los animales, ese comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 7, 'Empero estos no comeréis de los que rumian, ó tienen uña hendida: camello, y liebre, y conejo, porque rumian, mas no tienen uña hendida, os serán inmundos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 8, 'Ni puerco: porque tiene uña hendida, mas no rumia, os será inmundo. De la carne de éstos no comeréis, ni tocaréis sus cuerpos muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 9, 'Esto comeréis de todo lo que está en el agua: todo lo que tiene aleta y escama comeréis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 10, 'Mas todo lo que no tuviere aleta y escama, no comeréis: inmundo os será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 11, 'Toda ave limpia comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 12, 'Y estas son de las que no comeréis: el águila, y el azor, y el esmerejón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 13, 'Y el ixio, y el buitre, y el milano según su especie,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 14, 'Y todo cuervo según su especie,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 15, 'Y el búho, y la lechuza, y el cuclillo, y el halcón según su especie,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 16, 'Y el herodión, y el cisne, y el ibis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 17, 'Y el somormujo, y el calamón, y el corvejón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 18, 'Y la cigüeña, y la garza según su especie, y la abubilla, y el murciélago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 19, 'Y todo reptil alado os será inmundo: no se comerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 20, 'Toda ave limpia comeréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 21, 'Ninguna cosa mortecina comeréis: al extranjero que está en tus poblaciones la darás, y él la comerá: ó véndela al extranjero; porque tú eres pueblo santo á Jehová tu Dios. No cocerás el cabrito en la leche de su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 22, 'Indispensablemente diezmarás todo el producto de tu simiente, que rindiere el campo cada un año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 23, 'Y comerás delante de Jehová tu Dios en el lugar que él escogiere para hacer habitar allí su nombre, el diezmo de tu grano, de tu vino, y de tu aceite, y los primerizos de tus manadas, y de tus ganados, para que aprendas á temer á Jehová tu Dios todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 24, 'Y si el camino fuere tan largo que tú no puedas llevarlo por él, por estar lejos de ti el lugar que Jehová tu Dios hubiere escogido para poner en él su nombre, cuando Jehová tu Dios te bendijere,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 25, 'Entonces venderlo has, y atarás el dinero en tu mano, y vendrás al lugar que Jehová tu Dios escogiere;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 26, 'Y darás el dinero por todo lo que deseare tu alma, por vacas, ó por ovejas, ó por vino, ó por sidra, ó por cualquier cosa que tu alma te demandare: y comerás allí delante de Jehová tu Dios, y te alegrarás tú y tu familia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 27, 'Y no desampararás al Levita que habitare en tus poblaciones; porque no tiene parte ni heredad contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 28, 'Al cabo de cada tres años sacarás todo el diezmo de tus productos de aquel año, y lo guardarás en tus ciudades:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 14, 29, 'Y vendrá el Levita, que no tiene parte ni heredad contigo, y el extranjero, y el huérfano, y la viuda, que hubiere en tus poblaciones, y comerán y serán saciados; para que Jehová tu Dios te bendiga en toda obra de tus manos que hicieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 1, 'AL cabo de siete años harás remisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 2, 'Y esta es la manera de la remisión: perdonará á su deudor todo aquél que hizo empréstito de su mano, con que obligó á su prójimo: no lo demandará más á su prójimo, ó á su hermano; porque la remisión de Jehová es pregonada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 3, 'Del extranjero demandarás el reintegro: mas lo que tu hermano tuviere tuyo, lo perdonará tu mano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 4, 'Para que así no haya en ti mendigo; porque Jehová te bendecirá con abundancia en la tierra que Jehová tu Dios te da por heredad para que la poseas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 5, 'Si empero escuchares fielmente la voz de Jehová tu Dios, para guardar y cumplir todos estos mandamientos que yo te intimo hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 6, 'Ya que Jehová tu Dios te habrá bendecido, como te ha dicho, prestarás entonces á muchas gentes, mas tú no tomarás prestado; y enseñorearte has de muchas gentes, pero de ti no se enseñorearán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 7, 'Cuando hubiere en ti menesteroso de alguno de tus hermanos en alguna de tus ciudades, en tu tierra que Jehová tu Dios te da, no endurecerás tu corazón, ni cerrarás tu mano á tu hermano pobre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 8, 'Mas abrirás á él tu mano liberalmente, y en efecto le prestarás lo que basta, lo que hubiere menester.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 9, 'Guárdate que no haya en tu corazón perverso pensamiento, diciendo: Cerca está el año séptimo, el de la remisión; y tu ojo sea maligno sobre tu hermano menesteroso para no darle: que él podrá clamar contra ti á Jehová, y se te imputará á pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 10, 'Sin falta le darás, y no sea tu corazón maligno cuando le dieres: que por ello te bendecirá Jehová tu Dios en todos tus hechos, y en todo lo que pusieres mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 11, 'Porque no faltarán menesterosos de en medio de la tierra; por eso yo te mando, diciendo: Abrirás tu mano á tu hermano, á tu pobre, y á tu menesteroso en tu tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 12, 'Cuando se vendiere á ti tu hermano Hebreo ó Hebrea, y te hubiere servido seis años, al séptimo año le despedirás libre de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 13, 'Y cuando lo despidieres libre de ti, no lo enviarás vacío:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 14, 'Le abastecerás liberalmente de tus ovejas, de tu era, y de tu lagar; le darás de aquello en que Jehová te hubiere bendecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 15, 'Y te acordarás que fuiste siervo en la tierra de Egipto, y que Jehová tu Dios te rescató: por tanto yo te mando esto hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 16, 'Y será que, si él te dijere: No saldré de contigo; porque te ama á ti y á tu casa, que le va bien contigo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 17, 'Entonces tomarás una lesna, y horadarás su oreja junto á la puerta, y será tu siervo para siempre: así también harás á tu criada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 18, 'No te parezca duro cuando le enviares libre de ti; que doblado del salario de mozo jornalero te sirvió seis años: y Jehová tu Dios te bendecirá en todo cuanto hicieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 19, 'Santificarás á Jehová tu Dios todo primerizo macho que nacerá de tus vacas y de tus ovejas: no te sirvas del primerizo de tus vacas, ni trasquiles el primerizo de tus ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 20, 'Delante de Jehová tu Dios los comerás cada un año, tú y tu familia, en el lugar que Jehová escogiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 21, 'Y si hubiere en él tacha, ciego ó cojo, ó cualquiera mala falta, no lo sacrificarás á Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 22, 'En tus poblaciones lo comerás: el inmundo lo mismo que el limpio comerán de él, como de un corzo ó de un ciervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 15, 23, 'Solamente que no comas su sangre: sobre la tierra la derramarás como agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 1, 'GUARDARAS el mes de Abib, y harás pascua á Jehová tu Dios: porque en el mes de Abib te sacó Jehová tu Dios de Egipto de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 2, 'Y sacrificarás la pascua á Jehová tu Dios, de las ovejas y de las vacas, en el lugar que Jehová escogiere para hacer habitar allí su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 3, 'No comerás con ella leudo; siete días comerás con ella pan por leudar, pan de aflicción, porque apriesa saliste de tierra de Egipto: para que te acuerdes del día en que saliste de la tierra de Egipto todos los días de tu vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 4, 'Y no se dejará ver levadura contigo en todo tu término por siete días; y de la carne que matares á la tarde del primer día, no quedará hasta la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 5, 'No podrás sacrificar la pascua en ninguna de tus ciudades, que Jehová tu Dios te da;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 6, 'Sino en el lugar que Jehová tu Dios escogiere para hacer habitar allí su nombre, sacrificarás la pascua por la tarde á puesta del sol, al tiempo que saliste de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 7, 'Y la asarás y comerás en el lugar que Jehová tu Dios hubiere escogido; y por la mañana te volverás y restituirás á tu morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 8, 'Seis días comerás ázimos, y el séptimo día será solemnidad á Jehová tu Dios: no harás obra en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 9, 'Siete semanas te contarás: desde que comenzare la hoz en las mieses comenzarás á contarte las siete semanas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 10, 'Y harás la solemnidad de las semanas á Jehová tu Dios: de la suficiencia voluntaria de tu mano será lo que dieres, según Jehová tu Dios te hubiere bendecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 11, 'Y te alegrarás delante de Jehová tu Dios, tú, y tu hijo, y tu hija, y tu siervo, y tu sierva, y el Levita que estuviere en tus ciudades, y el extranjero, y el huérfano, y la viuda, que estuvieren en medio de ti, en el lugar que Jehová tu Dios hubiere escogido para hacer habitar allí su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 12, 'Y acuérdate que fuiste siervo en Egipto; por tanto guardarás y cumplirás estos estatutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 13, 'La solemnidad de las cabañas harás por siete días, cuando hubieres hecho la cosecha de tu era y de tu lagar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 14, 'Y te alegrarás en tus solemnidades, tú, y tu hijo, y tu hija, y tu siervo, y tu sierva, y el Levita, y el extranjero, y el huérfano, y la viuda, que están en tus poblaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 15, 'Siete días celebrarás solemnidad á Jehová tu Dios en el lugar que Jehová escogiere; porque te habrá bendecido Jehová tu Dios en todos tus frutos, y en toda obra de tus manos, y estarás ciertamente alegre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 16, 'Tres veces cada un año parecerá todo varón tuyo delante de Jehová tu Dios en el lugar que él escogiere: en la solemnidad de los ázimos, y en la solemnidad de las semanas, y en la solemnidad de las cabañas. Y no parecerá vacío delante de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 17, 'Cada uno con el don de su mano, conforme á la bendición de Jehová tu Dios, que te hubiere dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 18, 'Jueces y alcaldes te pondrás en todas tus ciudades que Jehová tu Dios te dará en tus tribus, los cuales juzgarán al pueblo con justo juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 19, 'No tuerzas el derecho; no hagas acepción de personas, ni tomes soborno; porque el soborno ciega los ojos de los sabios, y pervierte las palabras de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 20, 'La justicia, la justicia seguirás, porque vivas y heredes la tierra que Jehová tu Dios te da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 21, 'No te plantarás bosque de ningún árbol cerca del altar de Jehová tu Dios, que tú te habrás hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 16, 22, 'Ni te levantarás estatua; lo cual aborrece Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 1, 'NO sacrificarás á Jehová tu Dios buey, ó cordero, en el cual haya falta ó alguna cosa mala: porque es abominación á Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 2, 'Cuando se hallare entre ti, en alguna de tus ciudades que Jehová tu Dios te da, hombre, ó mujer, que haya hecho mal en ojos de Jehová tu Dios traspasando su pacto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 3, 'Que hubiere ido y servido á dioses ajenos, y se hubiere inclinado á ellos, ora al sol, ó á la luna, ó á todo el ejército del cielo, lo cual yo no he mandado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 4, 'Y te fuere dado aviso, y, después que oyeres y hubieres indagado bien, la cosa parece de verdad cierta, que tal abominación ha sido hecha en Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 5, 'Entonces sacarás al hombre ó mujer que hubiere hecho esta mala cosa, á tus puertas, hombre ó mujer, y los apedrearás con piedras, y así morirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 6, 'Por dicho de dos testigos, ó de tres testigos, morirá el que hubiere de morir; no morirá por el dicho de un solo testigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 7, 'La mano de los testigos será primero sobre él para matarlo, y después la mano de todo el pueblo: así quitarás el mal de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 8, 'Cuando alguna cosa te fuere oculta en juicio entre sangre y sangre, entre causa y causa, y entre llaga y llaga, en negocios de litigio en tus ciudades; entonces te levantarás y recurrirás al lugar que Jehová tu Dios escogiere;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 9, 'Y vendrás á los sacerdotes Levitas, y al juez que fuere en aquellos días, y preguntarás; y te enseñarán la sentencia del juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 10, 'Y harás según la sentencia que te indicaren los del lugar que Jehová escogiere, y cuidarás de hacer según todo lo que te manifestaren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 11, 'Según la ley que ellos te enseñaren, y según el juicio que te dijeren, harás: no te apartarás ni á diestra ni á siniestra de la sentencia que te mostraren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 12, 'Y el hombre que procediere con soberbia, no obedeciendo al sacerdote que está para ministrar allí delante de Jehová tu Dios, ó al juez, el tal varón morirá: y quitarás el mal de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 13, 'Y todo el pueblo oirá, y temerá, y no se ensoberbecerán más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 14, 'Cuando hubieres entrado en la tierra que Jehová tu Dios te da, y la poseyeres, y habitares en ella, y dijeres: Pondré rey sobre mí, como todas las gentes que están en mis alrededores;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 15, 'Sin duda pondrás por rey sobre ti al que Jehová tu Dios escogiere: de entre tus hermanos pondrás rey sobre ti: no podrás poner sobre ti hombre extranjero, que no sea tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 16, 'Empero que no se aumente caballos, ni haga volver el pueblo á Egipto para acrecentar caballos: porque Jehová os ha dicho: No procuraréis volver más por este camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 17, 'Ni aumentará para sí mujeres, porque su corazón no se desvíe: ni plata ni oro acrecentará para sí en gran copia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 18, 'Y será, cuando se asentare sobre el solio de su reino, que ha de escribir para sí en un libro un traslado de esta ley, del original de delante de los sacerdotes Levitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 19, 'Y lo tendrá consigo, y leerá en él todos los días de su vida, para que aprenda á temer á Jehová su Dios, para guardar todas las palabras de aquesta ley y estos estatutos, para ponerlos por obra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 17, 20, 'Para que no se eleve su corazón sobre sus hermanos, ni se aparte del mandamiento á diestra ni á siniestra: á fin que prolongue sus días en su reino, él y sus hijos, en medio de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 1, 'LOS sacerdotes Levitas, toda la tribu de Leví, no tendrán parte ni heredad con Israel; de las ofrendas encendidas á Jehová, y de la heredad de él comerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 2, 'No tendrán, pues, heredad entre sus hermanos: Jehová es su heredad, como él les ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 3, 'Y este será el derecho de los sacerdotes de parte del pueblo, de los que ofrecieren en sacrificio buey ó cordero: darán al sacerdote la espalda, y las quijadas, y el cuajar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 4, 'Las primicias de tu grano, de tu vino, y de tu aceite, y las primicias de la lana de tus ovejas le darás:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 5, 'Porque le ha escogido Jehová tu Dios de todas tus tribus, para que esté para ministrar al nombre de Jehová, él y sus hijos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 6, 'Y cuando el Levita saliere de alguna de tus ciudades de todo Israel, donde hubiere peregrinado, y viniere con todo deseo de su alma al lugar que Jehová escogiere,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 7, 'Ministrará al nombre de Jehová su Dios, como todos sus hermanos los Levitas que estuvieren allí delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 8, 'Porción como la porción de los otros comerán, además de sus patrimonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 9, 'Cuando hubieres entrado en la tierra que Jehová tu Dios te da, no aprenderás á hacer según las abominaciones de aquellas gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 10, 'No sea hallado en ti quien haga pasar su hijo ó su hija por el fuego, ni practicante de adivinaciones, ni agorero, ni sortílego, ni hechicero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 11, 'Ni fraguador de encantamentos, ni quien pregunte á pitón, ni mágico, ni quien pregunte á los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 12, 'Porque es abominación á Jehová cualquiera que hace estas cosas, y por estas abominaciones Jehová tu Dios las echó de delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 13, 'Perfecto serás con Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 14, 'Porque estas gentes que has de heredar, á agoreros y hechiceros oían: mas tú, no así te ha dado Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 15, 'Profeta de en medio de ti, de tus hermanos, como yo, te levantará Jehová tu Dios: á él oiréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 16, 'Conforme á todo lo que pediste á Jehová tu Dios en Horeb el día de la asamblea, diciendo: No vuelva yo á oir la voz de Jehová mi Dios, ni vea yo más este gran fuego, porque no muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 17, 'Y Jehová me dijo: Bien han dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 18, 'Profeta les suscitaré de en medio de sus hermanos, como tú; y pondré mis palabras en su boca, y él les hablará todo lo que yo le mandare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 19, 'Mas será, que cualquiera que no oyere mis palabras que él hablare en mi nombre, yo le residenciaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 20, 'Empero el profeta que presumiere hablar palabra en mi nombre, que yo no le haya mandado hablar, ó que hablare en nombre de dioses ajenos, el tal profeta morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 21, 'Y si dijeres en tu corazón: ¿Cómo conoceremos la palabra que Jehová no hubiere hablado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 18, 22, 'Cuando el profeta hablare en nombre de Jehová, y no fuere la tal cosa, ni viniere, es palabra que Jehová no ha hablado: con soberbia la habló aquel profeta: no tengas temor de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 1, 'CUANDO Jehová tu Dios talare las gentes, cuya tierra Jehová tu Dios te da á ti, y tú las heredares, y habitares en sus ciudades, y en sus casas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 2, 'Te apartarás tres ciudades en medio de tu tierra que Jehová tu Dios te da para que la poseas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 3, 'Arreglarte has el camino, y dividirás en tres partes el término de tu tierra, que Jehová tu Dios te dará en heredad, y será para que todo homicida se huya allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 4, 'Y este es el caso del homicida que ha de huir allí, y vivirá: el que hiriere á su prójimo por yerro, que no le tenía enemistad desde ayer ni antes de ayer:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 5, 'Como el que fué con su prójimo al monte á cortar leña, y poniendo fuerza con su mano en el hacha para cortar algún leño, saltó el hierro del cabo, y encontró á su prójimo, y murió; aquél huirá á una de aquestas ciudades, y vivirá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 6, 'No sea que el pariente del muerto vaya tras el homicida, cuando se enardeciere su corazón, y le alcance por ser largo el camino, y le hiera de muerte, no debiendo ser condenado á muerte; por cuanto no tenía enemistad desde ayer ni antes de ayer con el muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 7, 'Por tanto yo te mando, diciendo: Tres ciudades te apartarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 8, 'Y si Jehová tu Dios ensanchare tu término, como lo juró á tus padres, y te diere toda la tierra que dijo á tus padres que había de dar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 9, 'Cuando guardases todos estos mandamientos, que yo te prescribo hoy, para ponerlos por obra, que ames á Jehová tu Dios y andes en sus caminos todos los días, entonces añadirás tres ciudades á más de estas tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 10, 'Porque no sea derramada sangre inocente en medio de tu tierra, que Jehová tu Dios te da por heredad, y sea sobre ti sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 11, 'Mas cuando hubiere alguno que aborreciere á su prójimo, y lo acechare, y se levantare sobre él, y lo hiriere de muerte, y muriere, y huyere á alguna de estas ciudades;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 12, 'Entonces los ancianos de su ciudad enviarán y lo sacarán de allí, y entregarlo han en mano del pariente del muerto, y morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 13, 'No le perdonará tu ojo: y quitarás de Israel la sangre inocente, y te irá bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 14, 'No reducirás el término de tu prójimo, el cual señalaron los antiguos en tu heredad, la que poseyeres en la tierra que Jehová tu Dios te da para que la poseas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 15, 'No valdrá un testigo contra ninguno en cualquier delito, ó en cualquier pecado, en cualquier pecado que se cometiere. En el dicho de dos testigos, ó en el dicho de tres testigos consistirá el negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 16, 'Cuando se levantare testigo falso contra alguno, para testificar contra él rebelión,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 17, 'Entonces los dos hombres litigantes se presentarán delante de Jehová, delante de los sacerdotes y jueces que fueren en aquellos días:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 18, 'Y los jueces inquirirán bien, y si pareciere ser aquél testigo falso, que testificó falsamente contra su hermano,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 19, 'Haréis á él como él pensó hacer á su hermano: y quitarás el mal de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 20, 'Y los que quedaren oirán, y temerán, y no volverán más á hacer una mala cosa como ésta, en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 19, 21, 'Y no perdonará tu ojo: vida por vida, ojo por ojo, diente por diente, mano por mano, pie por pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 1, 'CUANDO salieres á la guerra contra tus enemigos, y vieres caballos y carros, un pueblo más grande que tú, no tengas temor de ellos, que Jehová tu Dios es contigo, el cual te sacó de tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 2, 'Y será que, cuando os acercareis para combatir, llegaráse el sacerdote, y hablará al pueblo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 3, 'Y les dirá: Oye, Israel, vosotros os juntáis hoy en batalla contra vuestros enemigos: no se ablande vuestro corazón, no temáis, no os azoréis, ni tampoco os desalentéis delante de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 4, 'Que Jehová vuestro Dios anda con vosotros, para pelear por vosotros contra vuestros enemigos, para salvaros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 5, 'Y los oficiales hablarán al pueblo, diciendo: ¿Quién ha edificado casa nueva, y no la ha estrenado? Vaya, y vuélvase á su casa, porque quizá no muera en la batalla, y otro alguno la estrene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 6, '¿Y quién ha plantado viña, y no ha hecho común uso de ella? Vaya, y vuélvase á su casa, porque quizá no muera en la batalla, y otro alguno la goce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 7, '¿Y quién se ha desposado con mujer, y no la ha tomado? Vaya, y vuélvase á su casa, porque quizá no muera en la batalla, y algún otro la tome.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 8, 'Y tornarán los oficiales á hablar al pueblo, y dirán: ¿Quién es hombre medroso y tierno de corazón? Vaya, y vuélvase á su casa, y no apoque el corazón de sus hermanos, como su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 9, 'Y será que, cuando los oficiales acabaren de hablar al pueblo, entonces los capitanes de los ejércitos mandarán delante del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 10, 'Cuando te acercares á una ciudad para combatirla, le intimarás la paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 11, 'Y será que, si te respondiere, Paz, y te abriere, todo el pueblo que en ella fuere hallado te serán tributarios, y te servirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 12, 'Mas si no hiciere paz contigo, y emprendiere contigo guerra, y la cercares,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 13, 'Luego que Jehová tu Dios la entregare en tu mano, herirás á todo varón suyo á filo de espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 14, 'Solamente las mujeres y los niños, y los animales, y todo lo que hubiere en la ciudad, todos sus despojos, tomarás para ti: y comerás del despojo de tus enemigos, los cuales Jehová tu Dios te entregó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 15, 'Así harás á todas la ciudades que estuvieren muy lejos de ti, que no fueren de las ciudades de estas gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 16, 'Empero de las ciudades de estos pueblos que Jehová tu Dios te da por heredad, ninguna persona dejarás con vida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 17, 'Antes del todo los destruirás: al Hetheo, y al Amorrheo, y al Cananeo, y al Pherezeo, y al Heveo, y al Jebuseo; como Jehová tu Dios te ha mandado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 18, 'Porque no os enseñen á hacer según todas sus abominaciones, que ellos hacen á sus dioses, y pequéis contra Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 19, 'Cuando pusieres cerco á alguna ciudad, peleando contra ella muchos días para tomarla, no destruyas su arboleda metiendo en ella hacha, porque de ella comerás; y no la talarás, que no es hombre el árbol del campo para venir contra ti en el cerco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 20, 20, 'Mas el árbol que supieres que no es árbol para comer, lo destruirás y lo talarás, y construye baluarte contra la ciudad que pelea contigo, hasta sojuzgarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 1, 'CUANDO fuere hallado en la tierra que Jehová tu Dios te da para que la poseas, muerto echado en el campo, y no se supiere quién lo hirió,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 2, 'Entonces tus ancianos y tus jueces saldrán y medirán hasta las ciudades que están alrededor del muerto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 3, 'Y será, que los ancianos de aquella ciudad, de la ciudad más cercana al muerto, tomarán de la vacada una becerra que no haya servido, que no haya traído yugo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 4, 'Y los ancianos de aquella ciudad traerán la becerra á un valle áspero, que nunca haya sido arado ni sembrado, y cortarán el pescuezo á la becerra allí en el valle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 5, 'Entonces vendrán los sacerdotes hijos de Leví, porque á ellos escogió Jehová tu Dios para que le sirvan, y para bendecir en nombre de Jehová; y por el dicho de ellos se determinará todo pleito y toda llaga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 6, 'Y todos los ancianos de aquella ciudad más cercana al muerto lavarán sus manos sobre la becerra degollada en el valle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 7, 'Y protestarán, y dirán: Nuestras manos no han derramado esta sangre, ni nuestros ojos lo vieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 8, 'Expía á tu pueblo Israel, al cual redimiste, oh Jehová; y no imputes la sangre inocente derramada en medio de tu pueblo Israel. Y la sangre les será perdonada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 9, 'Y tú quitarás la culpa de sangre inocente de en medio de ti, cuando hicieres lo que es recto en los ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 10, 'Cuando salieres á la guerra contra tus enemigos, y Jehová tu Dios los entregare en tu mano, y tomares de ellos cautivos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 11, 'Y vieres entre los cautivos alguna mujer hermosa, y la codiciares, y la tomares para ti por mujer,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 12, 'La meterás en tu casa; y ella raerá su cabeza, y cortará sus uñas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 13, 'Y se quitará el vestido de su cautiverio, y quedaráse en tu casa: y llorará á su padre y á su madre el tiempo de un mes: y después entrarás á ella, y tu serás su marido, y ella tu mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 14, 'Y será, si no te agradare, que la has de dejar en su libertad; y no la venderás por dinero, ni mercadearás con ella, por cuanto la afligiste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 15, 'Cuando un hombre tuviere dos mujeres, la una amada y la otra aborrecida, y la amada y la aborrecida le parieren hijos, y el hijo primogénito fuere de la aborrecida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 16, 'Será que, el día que hiciere heredar á sus hijos lo que tuviere, no podrá dar el derecho de primogenitura á los hijos de la amada en preferencia al hijo de la aborrecida, que es el primogénito;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 17, 'Mas al hijo de la aborrecida reconocerá por primogénito, para darle dos tantos de todo lo que se hallare que tiene: porque aquél es el principio de su fuerza, el derecho de la primogenitura es suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 18, 'Cuando alguno tuviere hijo contumaz y rebelde, que no obedeciere á la voz de su padre ni á la voz de su madre, y habiéndolo castigado, no les obedeciere;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 19, 'Entonces tomarlo han su padre y su madre, y lo sacarán á los ancianos de su ciudad, y á la puerta del lugar suyo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 20, 'Y dirán á los ancianos de la ciudad: Este nuestro hijo es contumaz y rebelde, no obedece á nuestra voz; es glotón y borracho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 21, 'Entonces todos los hombres de su ciudad lo apedrearán con piedras, y morirá: así quitarás el mal de en medio de ti; y todo Israel oirá, y temerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 22, 'Cuando en alguno hubiere pecado de sentencia de muerte, por el que haya de morir, y le habrás colgado de un madero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 21, 23, 'No estará su cuerpo por la noche en el madero, mas sin falta lo enterrarás el mismo día, porque maldición de Dios es el colgado: y no contaminarás tu tierra, que Jehová tu Dios te da por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 1, 'NO verás el buey de tu hermano, ó su cordero, perdidos, y te retirarás de ellos: precisamente los volverás á tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 2, 'Y si tu hermano no fuere tu vecino, ó no le conocieres, los recogerás en tu casa, y estarán contigo hasta que tu hermano los busque, y se los devolverás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 3, 'Y así harás de su asno, así harás también de su vestido, y lo mismo harás con toda cosa perdida de tu hermano que se le perdiere, y tú la hallares: no podrás retraerte de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 4, 'No verás el asno de tu hermano, ó su buey, caídos en el camino, y te esconderás de ellos: con él has de procurar levantarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 5, 'No vestirá la mujer hábito de hombre, ni el hombre vestirá ropa de mujer; porque abominación es á Jehová tu Dios cualquiera que esto hace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 6, 'Cuando topares en el camino algún nido de ave en cualquier árbol, ó sobre la tierra, con pollos ó huevos, y estuviere la madre echada sobre los pollos ó sobre los huevos, no tomes la madre con los hijos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 7, 'Dejarás ir á la madre, y tomarás los pollos para ti; para que te vaya bien, y prolongues tus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 8, 'Cuando edificares casa nueva, harás pretil á tu terrado, porque no pongas sangre en tu casa, si de él cayere alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 9, 'No sembrarás tu viña de varias semillas, porque no se deprave la plenitud de la semilla que sembraste, y el fruto de la viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 10, 'No ararás con buey y con asno juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 11, 'No te vestirás de mistura, de lana y lino juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 12, 'Hacerte has flecos en los cuatro cabos de tu manto con que te cubrieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 13, 'Cuando alguno tomare mujer, y después de haber entrado á ella la aborreciere,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 14, 'Y le pusiere algunas faltas, y esparciere sobre ella mala fama, y dijere: Esta tomé por mujer, y llegué á ella, y no la hallé virgen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 15, 'Entonces el padre de la moza y su madre tomarán, y sacarán las señales de la virginidad de la doncella á los ancianos de la ciudad, en la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 16, 'Y dirá el padre de la moza á los ancianos: Yo dí mi hija á este hombre por mujer, y él la aborrece;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 17, 'Y, he aquí, él le pone tachas de algunas cosas, diciendo: No he hallado tu hija virgen; empero, he aquí las señales de la virginidad de mi hija. Y extenderán la sábana delante de los ancianos de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 18, 'Entonces los ancianos de la ciudad tomarán al hombre y lo castigarán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 19, 'Y le han de penar en cien piezas de plata, las cuales darán al padre de la moza, por cuanto esparció mala fama sobre virgen de Israel: y la ha de tener por mujer, y no podrá despedirla en todos sus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 20, 'Mas si este negocio fué verdad, que no se hubiere hallado virginidad en la moza,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 21, 'Entonces la sacarán á la puerta de la casa de su padre, y la apedrearán con piedras los hombres de su ciudad, y morirá; por cuanto hizo vileza en Israel fornicando en casa de su padre: así quitarás el mal de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 22, 'Cuando se sorprendiere alguno echado con mujer casada con marido, entrambos morirán, el hombre que se acostó con la mujer, y la mujer: así quitarás el mal de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 23, 'Cuando fuere moza virgen desposada con alguno, y alguno la hallare en la ciudad, y se echare con ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 24, 'Entonces los sacaréis á ambos á la puerta de aquella ciudad, y los apedrearéis con piedras, y morirán; la moza porque no dió voces en la ciudad, y el hombre porque humilló á la mujer de su prójimo: así quitarás el mal de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 25, 'Mas si el hombre halló una moza desposada en la campo, y él la agarrare, y se echare con ella, morirá sólo el hombre que con ella se habrá echado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 26, 'Y á la moza no harás nada; no tiene la moza culpa de muerte: porque como cuando alguno se levanta contra su prójimo, y le quita la vida, así es esto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 27, 'Porque él la halló en el campo: dió voces la moza desposada, y no hubo quien la valiese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 28, 'Cuando alguno hallare moza virgen, que no fuere desposada, y la tomare, y se echare con ella, y fueren hallados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 29, 'Entonces el hombre que se echó con ella dará al padre de la moza cincuenta piezas de plata, y ella será su mujer, por cuanto la humilló: no la podrá despedir en todos sus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 22, 30, 'No tomará alguno la mujer de su padre, ni descubrirá el regazo de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 1, 'NO entrará en la congregación de Jehová el que fuere quebrado, ni el castrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 2, 'No entrará bastardo en la congregación de Jehová: ni aun en la décima generación entrará en la congregación de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 3, 'No entrará Ammonita ni Moabita en la congregación de Jehová; ni aun en la décima generación entrará en la congregación de Jehová para siempre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 4, 'Por cuanto no os salieron á recibir con pan y agua al camino, cuando salisteis de Egipto; y porque alquiló contra ti á Balaam hijo de Beor de Pethor de Mesopotamia de Siria, para que te maldijese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 5, 'Mas no quiso Jehová tu Dios oir á Balaam; y Jehová tu Dios te volvió la maldición en bendición, porque Jehová tu Dios te amaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 6, 'No procurarás la paz de ellos ni su bien en todos los días para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 7, 'No abominarás al Idumeo, que tu hermano es: no abominarás al egipcio, que extranjero fuiste en su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 8, 'Los hijos que nacieren de ellos, á la tercera generación entrarán en la congregación de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 9, 'Cuando salieres á campaña contra tus enemigos, guárdate de toda cosa mala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 10, 'Cuando hubiere en ti alguno que no fuere limpio por accidente de noche, saldráse del campo, y no entrará en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 11, 'Y será que al declinar de la tarde se lavará con agua, y cuando fuere puesto el sol, entrará en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 12, 'Y tendrás un lugar fuera del real, y saldrás allá fuera;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 13, 'Tendrás también una estaca entre tus armas; y será que, cuando estuvieres allí fuera, cavarás con ella, y luego al volverte cubrirás tu excremento:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 14, 'Porque Jehová tu Dios anda por medio de tu campo, para librarte y entregar tus enemigos delante de ti; por tanto será tu real santo: porque él no vea en ti cosa inmunda, y se vuelva de en pos de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 15, 'No entregarás á su señor el siervo que se huyere á ti de su amo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 16, 'More contigo, en medio de ti, en el lugar que escogiere en alguna de tus ciudades, donde bien le estuviere: no le harás fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 17, 'No habrá ramera de las hijas de Israel, ni habrá sodomítico de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 18, 'No traerás precio de ramera, ni precio de perro á la casa de Jehová tu Dios por ningún voto; porque abominación es á Jehová tu Dios así lo uno como lo otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 19, 'No tomarás de tu hermano logro de dinero, ni logro de comida, ni logro de cosa alguna que se suele tomar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 20, 'Del extraño tomarás logro, mas de tu hermano no lo tomarás, porque te bendiga Jehová tu Dios en toda obra de tus manos sobre la tierra á la cual entras para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 21, 'Cuando prometieres voto á Jehová tu Dios, no tardarás en pagarlo; porque ciertamente lo demandará Jehová tu Dios de ti, y habría en ti pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 22, 'Mas cuando te abstuvieres de prometer, no habrá en ti pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 23, 'Guardarás lo que tus labios pronunciaren; y harás, como prometiste á Jehová tu Dios, lo que de tu voluntad hablaste por tu boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 24, 'Cuando entrares en la viña de tu prójimo, comerás uvas hasta saciar tu deseo: mas no pondrás en tu vaso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 23, 25, 'Cuando entrares en la mies de tu prójimo, podrás cortar espigas con tu mano; mas no aplicarás hoz á la mies de tu prójimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 1, 'CUANDO alguno tomare mujer y se casare con ella, si no le agradare por haber hallado en ella alguna cosa torpe, le escribirá carta de repudio, y se la entregará en su mano, y despedirála de su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 2, 'Y salida de su casa, podrá ir y casarse con otro hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 3, 'Y si la aborreciere aqueste último, y le escribiere carta de repudio, y se la entregare en su mano, y la despidiere de su casa; ó si muriere el postrer hombre que la tomó para sí por mujer,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 4, 'No podrá su primer marido, que la despidió, volverla á tomar para que sea su mujer, después que fué amancillada; porque es abominación delante de Jehová, y no has de pervertir la tierra que Jehová tu Dios te da por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 5, 'Cuando tomare alguno mujer nueva, no saldrá á la guerra, ni en ninguna cosa se le ocupará; libre estará en su casa por un año, para alegrar á su mujer que tomó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 6, 'No tomarás en prenda la muela de molino, ni la de abajo ni la de arriba: porque sería prendar la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 7, 'Cuando fuere hallado alguno que haya hurtado persona de sus hermanos los hijos de Israel, y hubiere mercadeado con ella, ó la hubiere vendido, el tal ladrón morirá, y quitarás el mal de en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 8, 'Guárdate de llaga de lepra, observando diligentemente, y haciendo según todo lo que os enseñaren los sacerdotes Levitas: cuidaréis de hacer como les he mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 9, 'Acuérdate de lo que hizo Jehová tu Dios á María en el camino, después que salisteis de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 10, 'Cuando dieres á tu prójimo alguna cosa emprestada, no entrarás en su casa para tomarle prenda:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 11, 'Fuera estarás, y el hombre á quien prestaste, te sacará afuera la prenda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 12, 'Y si fuere hombre pobre, no duermas con su prenda:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 13, 'Precisamente le devolverás la prenda cuando el sol se ponga, para que duerma en su ropa, y te bendiga: y te será justicia delante de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 14, 'No hagas agravio al jornalero pobre y menesteroso, así de tus hermanos como de tus extranjeros que están en tu tierra en tus ciudades:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 15, 'En su día le darás su jornal, y no se pondrá el sol sin dárselo: pues es pobre, y con él sustenta su vida: porque no clame contra ti á Jehová, y sea en ti pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 16, 'Los padres no morirán por los hijos, ni los hijos por los padres; cada uno morirá por su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 17, 'No torcerás el derecho del peregrino y del huérfano; ni tomarás por prenda la ropa de la viuda:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 18, 'Mas acuérdate que fuiste siervo en Egipto, y de allí te rescató Jehová tu Dios: por tanto, yo te mando que hagas esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 19, 'Cuando segares tu mies en tu campo, y olvidares alguna gavilla en el campo, no volverás a tomarla: para el extranjero, para el huérfano, y para la viuda será; porque te bendiga Jehová tu Dios en toda obra de tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 20, 'Cuando sacudieres tus olivas, no recorrerás las ramas tras ti: para el extranjero, para el huérfano, y para la viuda será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 21, 'Cuando vendimiares tu viña, no rebuscarás tras ti: para el extranjero, para el huérfano, y para la viuda será.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 24, 22, 'Y acuérdate que fuiste siervo en tierra de Egipto: por tanto, yo te mando que hagas esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 1, 'CUANDO hubiere pleito entre algunos, y vinieren á juicio, y los juzgaren, y absolvieren al justo y condenaren al inicuo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 2, 'Será que, si el delincuente mereciere ser azotado, entonces el juez lo hará echar en tierra, y harále azotar delante de sí, según su delito, por cuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 3, 'Harále dar cuarenta azotes, no más: no sea que, si lo hiriere con muchos azotes a más de éstos, se envilezca tu hermano delante de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 4, 'No pondrás bozal al buey cuando trillare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 5, 'Cuando hermanos estuvieren juntos, y muriere alguno de ellos, y no tuviere hijo, la mujer del muerto no se casará fuera con hombre extraño: su cuñado entrará á ella, y la tomará por su mujer, y hará con ella parentesco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 6, 'Y será que el primogénito que pariere ella, se levantará en nombre de su hermano el muerto, porque el nombre de éste no sea raído de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 7, 'Y si el hombre no quisiere tomar á su cuñada, irá entonces la cuñada suya á la puerta á los ancianos, y dirá: Mi cuñado no quiere suscitar nombre en Israel á su hermano; no quiere emparentar conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 8, 'Entonces los ancianos de aquella ciudad lo harán venir, y hablarán con él: y si él se levantare, y dijere, No quiero tomarla,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 9, 'Llegaráse entonces su cuñada á él delante de los ancianos, y le descalzará el zapato de su pie, y escupirále en el rostro, y hablará y dirá: Así será hecho al varón que no edificare la casa de su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 10, 'Y su nombre será llamado en Israel: La casa del descalzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 11, 'Cuando algunos riñeren juntos el uno con el otro, y llegare la mujer del uno para librar á su marido de mano del que le hiere, y metiere su mano y le trabare de sus vergüenzas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 12, 'La cortarás entonces la mano, no la perdonará tu ojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 13, 'No tendrás en tu bolsa pesa grande y pesa chica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 14, 'No tendrás en tu casa epha grande y epha pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 15, 'Pesas cumplidas y justas tendrás; epha cabal y justo tendrás: para que tus días sean prolongados sobre la tierra que Jehová tu Dios te da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 16, 'Porque abominación es á Jehová tu Dios cualquiera que hace esto, cualquiera que hace agravio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 17, 'Acuérdate de lo que te hizo Amalec en el camino, cuando salisteis de Egipto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 18, 'Que te salió al camino, y te desbarató la retaguardia de todos los flacos que iban detrás de ti, cuando tú estabas cansado y trabajado; y no temió á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 25, 19, 'Será pues, cuando Jehová tu Dios te hubiere dado reposo de tus enemigos alrededor, en la tierra que Jehová tu Dios te da por heredar para que la poseas, que raerás la memoria de Amalec de debajo del cielo: no te olvides.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 1, 'Y SERA que, cuando hubieres entrado en la tierra que Jehová tu Dios te da por heredad, y la poseyeres, y habitares en ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 2, 'Entonces tomarás de las primicias de todos los frutos de la tierra, que sacares de tu tierra que Jehová tu Dios te da, y lo pondrás en un canastillo, é irás al lugar que Jehová tu Dios escogiere para hacer habitar allí su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 3, 'Y llegarás al sacerdote que fuere en aquellos días, y le dirás: Reconozco hoy á Jehová tu Dios que he entrado en la tierra que juró Jehová á nuestros padres que nos había de dar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 4, 'Y el sacerdote tomará el canastillo de tu mano, y pondrálo delante del altar de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 5, 'Entonces hablarás y dirás delante de Jehová tu Dios: Un Siro á punto de perecer fué mi padre, el cual descendió á Egipto y peregrinó allá con pocos hombres, y allí creció en gente grande, fuerte y numerosa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 6, 'Y los Egipcios nos maltrataron, y nos afligieron, y pusieron sobre nosotros dura servidumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 7, 'Y clamamos á Jehová Dios de nuestros padres; y oyó Jehová nuestra voz, y vió nuestra aflicción, y nuestro trabajo, y nuestra opresión:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 8, 'Y sacónos Jehová de Egipto con mano fuerte, y con brazo extendido, y con grande espanto, y con señales y con milagros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 9, 'Y trájonos á este lugar, y diónos esta tierra, tierra que fluye leche y miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 10, 'Y ahora, he aquí, he traído las primicias del fruto de la tierra que me diste, oh Jehová. Y lo dejarás delante de Jehová tu Dios, é inclinarte has delante de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 11, 'Y te alegrarás con todo el bien que Jehová tu Dios te hubiere dado á ti y á tu casa, tú y el Levita, y el extranjero que está en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 12, 'Cuando hubieres acabado de diezmar todo el diezmo de tus frutos en el año tercero, el año del diezmo, darás también al Levita, al extranjero, al huérfano y á la viuda; y comerán en tus villas, y se saciarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 13, 'Y dirás delante de Jehová tu Dios: Yo he sacado lo consagrado de mi casa, y también lo he dado al Levita, y al extranjero, y al huérfano, y á la viuda, conforme á todos tus mandamientos que me ordenaste: no he traspasado tus mandamientos, ni me he olvidado de ellos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 14, 'No he comido de ello en mi luto, ni he sacado de ello en inmundicia, ni de ello he dado para mortuorio: he obedecido á la voz de Jehová mi Dios, he hecho conforme á todo lo que me has mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 15, 'Mira desde la morada de tu santidad, desde el cielo, y bendice á tu pueblo Israel, y á la tierra que nos has dado, como juraste á nuestros padres, tierra que fluye leche y miel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 16, 'Jehová tu Dios te manda hoy que cumplas estos estatutos y derechos; cuida, pues, de ponerlos por obra con todo tu corazón, y con toda tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 17, 'A Jehová has ensalzado hoy para que te sea por Dios, y para andar en sus caminos, y para guardar sus estatutos y sus mandamientos y sus derechos, y para oir su voz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 18, 'Y Jehová te ha ensalzado hoy para que le seas su peculiar pueblo, como él te lo he dicho, y para que guardes todos sus mandamientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 26, 19, 'Y para ponerte alto sobre todas las gentes que hizo, para loor, y fama, y gloria; y para que seas pueblo santo á Jehová tu Dios, como él ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 1, 'Y MANDO Moisés, con los ancianos de Israel, al pueblo, diciendo: Guardaréis todos los mandamientos que yo prescribo hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 2, 'Y será que, el día que pasareis el Jordán á la tierra que Jehová tu Dios te da, te has de levantar piedras grandes, las cuales revocarás con cal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 3, 'Y escribirás en ellas todas las palabras de esta ley, cuando hubieres pasado para entrar en la tierra que Jehová tu Dios te da, tierra que fluye leche y miel, como Jehová el Dios de tus padres te ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 4, 'Será pues, cuando hubieres pasado el Jordán, que levantaréis estas piedras que yo os mando hoy, en el monte de Ebal, y las revocarás con cal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 5, 'Y edificarás allí altar á Jehová tu Dios, altar de piedras: no alzarás sobre ellas hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 6, 'De piedras enteras edificarás el altar de Jehová tu Dios; y ofrecerás sobre él holocausto á Jehová tu Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 7, 'Y sacrificarás pacíficos, y comerás allí; y alegrarte has delante de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 8, 'Y escribirás en las piedras todas las palabras de esta ley muy claramente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 9, 'Y Moisés, con los sacerdotes Levitas, habló á todo Israel, diciendo: Atiende y escucha, Israel: hoy eres hecho pueblo de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 10, 'Oirás pues la voz de Jehová tu Dios, y cumplirás sus mandamientos y sus estatutos, que yo te ordeno hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 11, 'Y mandó Moisés al pueblo en aquel día, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 12, 'Estos estarán sobre el monte de Gerizim para bendecir al pueblo, cuando hubiereis pasado el Jordán: Simeón, y Leví, y Judá, é Issachâr, y José y Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 13, 'Y estos estarán para pronunciar la maldición en el de Ebal: Rubén, Gad, y Aser, y Zabulón, Dan, y Nephtalí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 14, 'Y hablarán los Levitas, y dirán á todo varón de Israel en alta voz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 15, 'Maldito el hombre que hiciere escultura ó imagen de fundición, abominación á Jehová, obra de mano de artífice, y la pusiere en oculto. Y todo el pueblo responderá y dirá: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 16, 'Maldito el que deshonrare á su padre ó á su madre. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 17, 'Maldito el que redujere el término de su prójimo. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 18, 'Maldito el que hiciere errar al ciego en el camino. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 19, 'Maldito el que torciere el derecho del extranjero, del huérfano, y de la viuda. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 20, 'Maldito el que se echare con la mujer de su padre; por cuanto descubrió el regazo de su padre. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 21, 'Maldito el que tuviere parte con cualquiera bestia. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 22, 'Maldito el que se echare con su hermana, hija de su padre, ó hija de su madre. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 23, 'Maldito el que se echare con su suegra. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 24, 'Maldito el que hiriere á su prójimo ocultamente. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 25, 'Maldito el que recibiere don para herir de muerte al inocente. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 27, 26, 'Maldito el que no confirmare las palabras de esta ley para cumplirlas. Y dirá todo el pueblo: Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 1, 'Y SERA que, si oyeres diligente la voz de Jehová tu Dios, para guardar, para poner por obra todos sus mandamientos que yo te prescribo hoy, también Jehová tu Dios te pondrá alto sobre todas las gentes de la tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 2, 'Y vendrán sobre ti todas estas bendiciones, y te alcanzarán, cuando oyeres la voz de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 3, 'Bendito serás tú en la ciudad, y bendito tú en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 4, 'Bendito el fruto de tu vientre, y el fruto de tu bestia, la cría de tus vacas, y los rebaños de tus ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 5, 'Bendito tu canastillo y tus sobras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 6, 'Bendito serás en tu entrar, y bendito en tu salir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 7, 'Pondrá Jehová á tus enemigos que se levantaren contra ti, de rota batida delante de ti: por un camino saldrán á ti, por siete caminos huirán delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 8, 'Enviará Jehová contigo la bendición en tus graneros, y en todo aquello en que pusieres tu mano; y te bendecirá en la tierra que Jehová tu Dios te da.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 9, 'Confirmarte ha Jehová por pueblo suyo santo, como te ha jurado, cuando guardares los mandamientos de Jehová tu Dios, y anduvieres en sus caminos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 10, 'Y verán todos los pueblos de la tierra que el nombre de Jehová es llamado sobre ti, y te temerán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 11, 'Y te hará Jehová sobreabundar en bienes, en el fruto de tu vientre, y en el fruto de tu bestia, y en el fruto de tu tierra, en el país que juró Jehová á tus padres que te había de dar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 12, 'Abrirte ha Jehová su buen depósito, el cielo, para dar lluvia á tu tierra en su tiempo, y para bendecir toda obra de tus manos. Y prestarás á muchas gentes, y tú no tomarás emprestado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 13, 'Y te pondrá Jehová por cabeza, y no por cola: y estarás encima solamente, y no estarás debajo; cuando obedecieres á los mandamientos de Jehová tu Dios, que yo te ordeno hoy, para que los guardes y cumplas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 14, 'Y no te apartes de todas las palabras que yo os mando hoy, ni á diestra ni á siniestra, para ir tras dioses ajenos para servirles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 15, 'Y será, si no oyeres la voz de Jehová tu Dios, para cuidar de poner por obra todos sus mandamientos y sus estatutos, que yo te intimo hoy, que vendrán sobre ti todas estas maldiciones, y te alcanzarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 16, 'Maldito serás tu en la ciudad, y maldito en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 17, 'Maldito tu canastillo, y tus sobras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 18, 'Maldito el fruto de tu vientre, y el fruto de tu tierra, y la cría de tus vacas, y los rebaños de tus ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 19, 'Maldito serás en tu entrar, y maldito en tu salir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 20, 'Y Jehová enviará contra ti la maldición, quebranto y asombro en todo cuanto pusieres mano é hicieres, hasta que seas destruído, y perezcas presto á causa de la maldad de tus obras, por las cuales me habrás dejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 21, 'Jehová hará que se te pegue mortandad, hasta que te consuma de la tierra á la cual entras para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 22, 'Jehová te herirá de tisis, y de fiebre, y de ardor, y de calor, y de cuchillo, y de calamidad repentina, y con añublo; y perseguirte han hasta que perezcas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 23, 'Y tus cielos que están sobre tu cabeza, serán de metal; y la tierra que está debajo de ti, de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 24, 'Dará Jehová por lluvia á tu tierra polvo y ceniza: de los cielos descenderán sobre ti hasta que perezcas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 25, 'Jehová te entregará herido delante de tus enemigos: por un camino saldrás á ellos, y por siete caminos huirás delante de ellos: y serás sacudido á todos los reinos de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 26, 'Y será tu cuerpo muerto por comida á toda ave del cielo, y bestia de la tierra, y no habrá quien las espante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 27, 'Jehová te herirá de la plaga de Egipto, y con almorranas, y con sarna, y con comezón, de que no puedas ser curado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 28, 'Jehová te herirá con locura, y con ceguedad, y con pasmo de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 29, 'Y palparás al mediodía, como palpa el ciego en la oscuridad, y no serás prosperado en tus caminos: y nunca serás sino oprimido y robado todos los días, y no habrá quien te salve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 30, 'Te desposarás con mujer, y otro varón dormirá con ella; edificarás casa, y no habitarás en ella; plantarás viña, y no la vendimiarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 31, 'Tu buey será matado delante de tus ojos, y tú no comerás de él; tu asno será arrebatado de delante de ti, y no se te volverá; tus ovejas serán dadas á tus enemigos, y no tendrás quien te las rescate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 32, 'Tus hijos y tus hijas serán entregados á otro pueblo, y tus ojos lo verán, y desfallecerán por ellos todo el día: y no habrá fuerza en tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 33, 'El fruto de tu tierra y todo tu trabajo comerá pueblo que no conociste; y nunca serás sino oprimido y quebrantado todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 34, 'Y enloquecerás á causa de lo que verás con tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 35, 'Herirte ha Jehová con maligna pústula en las rodillas y en las piernas, sin que puedas ser curado: aun desde la planta de tu pie hasta tu mollera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 36, 'Jehová llevará á ti, y á tu rey que hubieres puesto sobre ti, á gente que no conociste tú ni tus padres; y allá servirás á dioses ajenos, al palo y á la piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 37, 'Y serás por pasmo, por ejemplo y por fábula, á todos los pueblos á los cuales te llevará Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 38, 'Sacarás mucha simiente al campo, y cogerás poco: porque la langosta lo consumirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 39, 'Plantarás viñas y labrarás, mas no beberás vino, ni cogerás uvas; porque el gusano las comerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 40, 'Tendrás olivas en todo tu término, mas no te ungirás con el aceite; porque tu aceituna se caerá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 41, 'Hijos é hijas engendrarás, y no serán para ti; porque irán en cautiverio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 42, 'Toda tu arboleda y el fruto de tu tierra consumirá la langosta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 43, 'El extranjero que estará en medio de ti subirá sobre ti muy alto, y tú serás puesto muy bajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 44, 'El te prestará á ti, y tú no prestarás á él: él será por cabeza, y tú serás por cola.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 45, 'Y vendrán sobre ti todas estas maldiciones, y te perseguirán, y te alcanzarán hasta que perezcas; por cuanto no habrás atendido á la voz de Jehová tu Dios, para guardar sus mandamientos y sus estatutos, que él te mandó:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 46, 'Y serán en ti por señal y por maravilla, y en tu simiente para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 47, 'Por cuanto no serviste á Jehová tu Dios con alegría y con gozo de corazón, por la abundancia de todas las cosas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 48, 'Servirás por tanto á tus enemigos que enviare Jehová contra ti, con hambre y con sed y con desnudez, y con falta de todas las cosas; y él pondrá yugo de hierro sobre tu cuello, hasta destruirte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 49, 'Jehová traerá sobre ti gente de lejos, del cabo de la tierra, que vuele como águila, gente cuya lengua no entiendas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 50, 'Gente fiera de rostro, que no tendrá respeto al anciano, ni perdonará al niño:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 51, 'Y comerá el fruto de tu bestia y el fruto de tu tierra, hasta que perezcas: y no te dejará grano, ni mosto, ni aceite, ni la cría de tus vacas, ni los rebaños de tus ovejas, hasta destruirte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 52, 'Y te pondrá cerco en todas tus ciudades, hasta que caigan tus muros altos y encastillados en que tú confías, en toda tu tierra: te cercará, pues, en todas tus ciudades y en toda tu tierra, que Jehová tu Dios te habrá dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 53, 'Y comerás el fruto de tu vientre, la carne de tus hijos y de tus hijas que Jehová tu Dios te dió, en el cerco y en al apuro con que te angustiará tu enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 54, 'El hombre tierno en ti, y el muy delicado, su ojo será maligno para con su hermano, y para con la mujer de su seno, y para con el resto de sus hijos que le quedaren;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 55, 'Para no dar á alguno de ellos de la carne de sus hijos, que él comerá, porque nada le habrá quedado, en el cerco y en el apuro con que tu enemigo te oprimirá en todas tus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 56, 'La tierna y la delicada entre vosotros, que nunca la planta de su pie probó á sentar sobre la tierra, de ternura y delicadeza, su ojo será maligno para con el marido de su seno, y para con su hijo, y para con su hija,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 57, 'Y para con su chiquita que sale de entre sus pies, y para con sus hijos que pariere; pues los comerá escondidamente, á falta de todo, en el cerco y en el apuro con que tu enemigo te oprimirá en tus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 58, 'Si no cuidares de poner por obra todas las palabras de aquesta ley que están escritas en este libro, temiendo este nombre glorioso y terrible, JEHOVA TU DIOS,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 59, 'Jehová aumentará maravillosamente tus plagas y las plagas de tu simiente, plagas grandes y estables, y enfermedades malignas y duraderas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 60, 'Y hará volver sobre ti todos los males de Egipto, delante de los cuales temiste, y se te pegarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 61, 'Asismismo toda enfermedad y toda plaga que no está escrita en el libro de esta ley, Jehová la enviará sobre ti, hasta que tú seas destruído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 62, 'Y quedaréis en poca gente, en lugar de haber sido como las estrellas del cielo en multitud; por cuanto no obedeciste á la voz de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 63, 'Y será que como Jehová se gozó sobre vosotros para haceros bien, y para multiplicaros, así se gozará Jehová sobre vosotros para arruinaros, y para destruiros; y seréis arrancados de sobre la tierra, á la cual entráis para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 64, 'Y Jehová te esparcirá por todos los pueblos, desde el un cabo de la tierra hasta el otro cabo de ella; y allí servirás á dioses ajenos que no conociste tú ni tus padres, al leño y á la piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 65, 'Y ni aun entre las mismas gentes descansarás, ni la planta de tu pie tendrá reposo; que allí te dará Jehová corazón temeroso, y caimiento de ojos, y tristeza de alma:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 66, 'Y tendrás tu vida como colgada delante de ti, y estarás temeroso de noche y de día, y no confiarás de tu vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 67, 'Por la mañana dirás: ¡Quién diera fuese la tarde! y á la tarde dirás: ¡Quién diera fuese la mañana! por el miedo de tu corazón con que estarás amedrentado, y por lo que verán tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 28, 68, 'Y Jehová te hará tornar á Egipto en navíos por el camino del cual te ha dicho: Nunca más volveréis: y allí seréis vendidos á vuestros enemigos por esclavos y por esclavas, y no habrá quien os compre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 1, 'ESTAS son las palabras del pacto que Jehová mandó á Moisés concertara con los hijos de Israel en la tierra de Moab, además del pacto que concertó con ellos en Horeb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 2, 'Moisés pues llamó á todo Israel, y díjoles: Vosotros habéis visto todo lo que Jehová ha hecho delante de vuestros ojos en la tierra de Egipto á Faraón y á todos sus siervos, y á toda su tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 3, 'Las pruebas grandes que vieron tus ojos, las señales, y las grandes maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 4, 'Y Jehová no os dió corazón para entender, ni ojos para ver, ni oídos para oir, hasta el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 5, 'Y yo os he traído cuarenta años por el desierto: vuestros vestidos no se han envejecido sobre vosotros, ni tu zapato se ha envejecido sobre tu pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 6, 'No habéis comido pan, ni bebisteis vino ni sidra: para que supieseis que yo soy Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 7, 'Y llegasteis á este lugar, y salió Sehón rey de Hesbón, y Og rey de Basán, delante de nosotros para pelear, y herímoslos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 8, 'Y tomamos su tierra, y dímosla por heredad á Rubén y á Gad, y á la media tribu de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 9, 'Guardaréis, pues, las palabras de este pacto, y las pondréis por obra, para que prosperéis en todo lo que hiciereis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 10, 'Vosotros todos estáis hoy delante de Jehová vuestro Dios; vuestros príncipes de vuestras tribus, vuestros ancianos, y vuestros oficiales, todos los varones de Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 11, 'Vuestros niños, vuestras mujeres, y tus extranjeros que habitan en medio de tu campo, desde el que corta tu leña hasta el que saca tus aguas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 12, 'Para que entres en el pacto de Jehová tu Dios, y en su juramento, que Jehová tu Dios acuerda hoy contigo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 13, 'Para confirmarte hoy por su pueblo, y que él te sea á ti por Dios, de la manera que él te ha dicho, y como él juró á tus padres Abraham, Isaac, y Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 14, 'Y no con vosotros solos acuerdo yo este pacto y este juramento,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 15, 'Sino con los que están aquí presentes hoy con nosotros delante de Jehová nuestro Dios, y con los que no están aquí hoy con nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 16, 'Porque vosotros sabéis cómo habitamos en la tierra de Egipto, y cómo hemos pasado por medio de las gentes que habéis pasado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 17, 'Y habéis visto sus abominaciones y sus ídolos, madera y piedra, plata y oro, que tienen consigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 18, 'Quizá habrá entre vosotros varón, ó mujer, ó familia, ó tribu, cuyo corazón se vuelva hoy de con Jehová nuestro Dios, por andar á servir á los dioses de aquellas gentes; quizá habrá en vosotros raíz que eche veneno y ajenjo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 19, 'Y sea que, cuando el tal oyere las palabras de esta maldición, él se bendiga en su corazón, diciendo: Tendré paz, aunque ande según el pensamiento de mi corazón, para añadir la embriaguez á la sed:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 20, 'Jehová no querrá perdonarle; antes humeará luego el furor de Jehová y su celo sobre el tal hombre, y asentaráse sobre él toda maldición escrita en este libro, y Jehová raerá su nombre de debajo del cielo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 21, 'Y apartarálo Jehová de todas las tribus de Israel para mal, conforme á todas las maldiciones del pacto escrito en este libro de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 22, 'Y dirá la generación venidera, vuestros hijos que vendrán después de vosotros, y el extranjero que vendrá de lejanas tierras, cuando vieren las plagas de aquesta tierra, y sus enfermedades de que Jehová la hizo enfermar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 23, '(Azufre y sal, abrasada toda su tierra: no será sembrada, ni producirá, ni crecerá en ella hierba ninguna, como en la subversión de Sodoma y de Gomorra, de Adma y de Seboim, que Jehová subvirtió en su furor y en su ira:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 24, 'Dirán, pues, todas las gentes: ¿Por qué hizo Jehová esto á esta tierra? ¿qué ira es ésta de tan gran furor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 25, 'Y responderán. Por cuanto dejaron el pacto de Jehová el Dios de sus padres, que él concertó con ellos cuando los sacó de la tierra de Egipto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 26, 'Y fueron y sirvieron á dioses ajenos, é inclináronse á ellos, dioses que no conocían, y que ninguna cosa les habían dado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 27, 'Encendióse por tanto, el furor de Jehová contra esta tierrra, para traer sobre ella todas las maldiciones escritas en esta libro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 28, 'Y Jehová los desarraigó de su tierra con enojo, y con saña, y con furor grande, y los echó á otra tierra, como hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 29, 29, 'Las cosas secretas pertenecen á Jehová nuestro Dios: mas las reveladas son para nosotros y para nuestros hijos por siempre, para que cumplamos todas las palabras de esta ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 1, 'Y SERA que, cuando te sobrevinieren todas estas cosas, la bendición y la maldición que he puesto delante de ti, y volvieres á tu corazón en medio de todas las gentes á las cuales Jehová tu Dios te hubiere echado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 2, 'Y te convirtieres á Jehová tu Dios, y obedecieres á su voz conforme á todo lo que yo te mando hoy, tú y tus hijos, con todo tu corazón y con toda tu alma,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 3, 'Jehová también volverá tus cautivos, y tendrá misericordia de ti, y tornará á recogerte de todos los pueblos á los cuales te hubiere esparcido Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 4, 'Si hubieres sido arrojado hasta el cabo de los cielos, de allí te recogerá Jehová tu Dios, y de allá te tomará:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 5, 'Y volverte ha Jehová tu Dios á la tierra que heredaron tus padres, y la poseerás; y te hará bien, y te multiplicará más que á tus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 6, 'Y circuncidará Jehová tu Dios tu corazón, y el corazón de tu simiente, para que ames á Jehová tu Dios con todo tu corazón y con toda tu alma, á fin de que tú vivas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 7, 'Y pondrá Jehová tu Dios todas estas maldiciones sobre tus enemigos, y sobre tus aborrecedores que te persiguieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 8, 'Y tú volverás, y oirás la voz de Jehová, y pondrás por obra todos sus mandamientos, que yo te intimo hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 9, 'Y hacerte ha Jehová tu Dios abundar en toda obra de tus manos, en el fruto de tu vientre, en el fruto de tu bestia, y en el fruto de tu tierra, para bien: porque Jehová volverá á gozarse sobre ti para bien, de la manera que se gozó sobre tus padres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 10, 'Cuando oyeres la voz de Jehová tu Dios, para guardar sus mandamientos y sus estatutos escritos en este libro de la ley; cuando te convirtieres á Jehová tu Dios con todo tu corazón y con toda tu alma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 11, 'Porque este mandamiento que yo te intimo hoy, no te es encubierto, ni está lejos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 12, 'No está en el cielo, para que digas: ¿Quién subirá por nosotros al cielo, y nos lo traerá y nos lo representará, para que lo cumplamos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 13, 'Ni está de la otra parte de la mar, para que digas: ¿Quién pasará por nosotros la mar, para que nos lo traiga y nos lo represente, á fin de que lo cumplamos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 14, 'Porque muy cerca de ti está la palabra, en tu boca y en tu corazón, para que la cumplas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 15, 'Mira, yo he puesto delante de ti hoy la vida y el bien, la muerte y el mal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 16, 'Porque yo te mando hoy que ames á Jehová tu Dios, que andes en sus caminos, y guardes sus mandamientos y sus estatutos y sus derechos, para que vivas y seas multiplicado, y Jehová tu Dios te bendiga en la tierra á la cual entras para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 17, 'Mas si tu corazón se apartare, y no oyeres, y fueres incitado, y te inclinares á dioses ajenos, y los sirvieres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 18, 'Protéstoos hoy que de cierto pereceréis: no tendréis largos días sobre la tierra, para ir á la cual pasas el Jordán para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 19, 'A los cielos y la tierra llamo por testigos hoy contra vosotros, que os he puesto delante la vida y la muerte, la bendición y la maldición: escoge pues la vida, porque vivas tú y tu simiente:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 30, 20, 'Que ames á Jehová tu Dios, que oigas su voz, y te allegues á él; porque él es tu vida, y la longitud de tus días; á fin de que habites sobre la tierra que juró Jehová á tus padres Abraham, Isaac, y Jacob, que les había de dar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 1, 'Y FUÉ Moisés, y habló estas palabras á todo Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 2, 'Y díjoles: De edad de ciento y veinte años soy hoy día; no puedo más salir ni entrar: á más de esto Jehová me ha dicho: No pasarás este Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 3, 'Jehová tu Dios, él pasa delante de ti; él destruirá estas gentes de delante de ti, y las heredarás: Josué será el que pasará delante de ti, como Jehová ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 4, 'Y hará Jehová con ellos como hizo con Sehón y con Og, reyes de los Amorrheos, y con su tierra, que los destruyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 5, 'Y los entregará Jehová delante de vosotros, y haréis con ellos conforme á todo lo que os he mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 6, 'Esforzaos y cobrad ánimo; no temáis, ni tengáis miedo de ellos: que Jehová tu Dios es el que va contigo: no te dejará ni te desamparará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 7, 'Y llamó Moisés á Josué, y díjole á vista de todo Israel: Esfuérzate y anímate; porque tú entrarás con este pueblo á la tierra que juró Jehová á sus padres que les había de dar, y tú se la harás heredar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 8, 'Y Jehová es el que va delante de ti; él será contigo, no te dejará, ni te desamparará; no temas, ni te intimides.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 9, 'Y escribió Moisés esta ley, y dióla á los sacerdotes, hijos de Leví, que llevaban el arca del pacto de Jehová, y á todos los ancianos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 10, 'Y mandóles Moisés, diciendo: Al cabo del séptimo año, en el año de la remisión, en la fiesta de las Cabañas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 11, 'Cuando viniere todo Israel á presentarse delante de Jehová tu Dios en el lugar que él escogiere, leerás esta ley delante de todo Israel á oídos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 12, 'Harás congregar el pueblo, varones y mujeres y niños, y tus extranjeros que estuvieren en tus ciudades, para que oigan y aprendan, y teman á Jehová vuestro Dios, y cuiden de poner por obra todas las palabras de esta ley:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 13, 'Y los hijos de ellos que no supieron oigan, y aprendan á temer á Jehová vuestro Dios todos los días que viviereis sobre la tierra, para ir á la cual pasáis el Jordán para poseerla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 14, 'Y Jehová dijo á Moisés: He aquí se han acercado tus días para que mueras: llama á Josué, y esperad en el tabernáculo del testimonio, y le mandaré. Fueron pues Moisés y Josué, y esperaron en el tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 15, 'Y aparecióse Jehová en el tabernáculo, en la columna de nube; y la columna de nube se puso sobre la puerta del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 16, 'Y Jehová dijo á Moisés: He aquí tú vas á dormir con tus padres, y este pueblo se levantará y fornicará tras los dioses ajenos de la tierra adonde va, en estando en medio de ella; y me dejará, é invalidará mi pacto que he concertado con él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 17, 'Y mi furor se encenderá contra él en aquel día; y los abandonaré, y esconderé de ellos mi rostro, y serán consumidos; y le hallarán muchos males y angustias, y dirá en aquel día: ¿No me han hallado estos males porque no está mi Dios en medio de mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 18, 'Empero yo esconderé ciertamente mi rostro en aquel día, por todo el mal que ellos habrán hecho, por haberse vuelto á dioses ajenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 19, 'Ahora, pues, escribíos este cántico, y enséñalo á los hijos de Israel: ponlo en boca de ellos, para que este cántico me sea por testigo contra los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 20, 'Porque yo le introduciré en la tierra que juré á sus padres, la cual fluye leche y miel; y comerá, y se hartará, y se engordará: y volveránse á dioses ajenos, y les servirán, y me enojarán, é invalidarán mi pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 21, 'Y será que cuando le vinieren muchos males y angustias, entonces responderá en su cara este cántico como testigo, pues no caerá en olvido de la boca de su linaje: porque yo conozco su ingenio, y lo que hace hoy antes que le introduzca en la tierra que juré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 22, 'Y Moisés escribió este cántico aquel día, y enseñólo á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 23, 'Y dió orden á Josué hijo de Nun, y dijo: Esfuérzate y anímate, que tú meterás los hijos de Israel en la tierra que les juré, y yo seré contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 24, 'Y como acabó Moisés de escribir las palabras de esta ley en un libro hasta concluirse,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 25, 'Mandó Moisés á los Levitas que llevaban el arca del pacto de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 26, 'Tomad este libro de la ley, y ponedlo al lado del arca del pacto de Jehová vuestro Dios, y esté allí por testigo contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 27, 'Porque yo conozco tu rebelión, y tu cerviz dura: he aquí que aun viviendo yo hoy con vosotros, sois rebeldes á Jehová; y ¿cuánto más después que yo fuere muerto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 28, 'Congregad á mí todos los ancianos de vuestras tribus, y á vuestros oficiales, y hablaré en sus oídos estas palabras, y llamaré por testigos contra ellos los cielos y la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 29, 'Porque yo sé que después de mi muerte, ciertamente os corromperéis y os aparteréis del camino que os he mandado; y que os ha de venir mal en los postreros días, por haber hecho mal en ojos de Jehová, enojándole con la obra de vuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 31, 30, 'Entonces habló Moisés en oídos de toda la congregación de Israel las palabras de este cántico hasta acabarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 1, 'ESCUCHAD, cielos, y hablaré; Y oiga la tierra los dichos de mi boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 2, 'Goteará como la lluvia mi doctrina; Destilará como el rocío mi razonamiento; Como la llovizna sobre la grama, Y como las gotas sobre la hierba:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 3, 'Porque el nombre de Jehová invocaré: Engrandeced á nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 4, 'El es la Roca, cuya obra es perfecta, Porque todos sus caminos son rectitud: Dios de verdad, y ninguna iniquidad en él: Es justo y recto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 5, 'La corrupción no es suya: á sus hijos la mancha de ellos, Generación torcida y perversa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 6, '¿Así pagáis á Jehová, Pueblo loco é ignorante? ¿No es él tu padre que te poseyó? El te hizo y te ha organizado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 7, 'Acuérdate de los tiempos antiguos; Considerad los años de generación y generación: Pregunta á tu padre, que él te declarará; A tus viejos, y ellos te dirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 8, 'Cuando el Altísimo hizo heredar á las gentes, Cuando hizo dividir los hijos de los hombres, Estableció los términos de los pueblos Según el número de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 9, 'Porque la parte de Jehová es su pueblo; Jacob la cuerda de su heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 10, 'Hallólo en tierra de desierto, Y en desierto horrible y yermo; Trájolo alrededor, instruyólo, Guardólo como la niña de su ojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 11, 'Como el águila despierta su nidada, Revolotea sobre sus pollos, Extiende sus alas, los toma, Los lleva sobre sus plumas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 12, 'Jehová solo le guió, Que no hubo con él dios ajeno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 13, 'Hízolo subir sobre las alturas de la tierra, Y comió los frutos del campo, E hizo que chupase miel de la peña, Y aceite del duro pedernal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 14, 'Manteca de vacas y leche de ovejas, Con grosura de corderos, Y carneros de Basán; también machos de cabrío, Con grosura de riñones de trigo: Y sangre de uva bebiste, vino puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 15, 'Y engrosó Jeshurun, y tiró coces: Engordástete, engrosástete, cubrístete: Y dejó al Dios que le hizo, Y menospreció la Roca de su salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 16, 'Despertáronle á celos con los dioses ajenos; Ensañáronle con abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 17, 'Sacrificaron á los diablos, no á Dios; A dioses que no habían conocido, A nuevos dioses venidos de cerca, Que no habían temido vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 18, 'De la Roca que te crió te olvidaste: Te has olvidado del Dios tu criador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 19, 'Y vió lo Jehová, y encendióse en ira, por el menosprecio de sus hijos y de sus hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 20, 'Y dijo: Esconderé de ellos mi rostro, Veré cuál será su postrimería: Que son generación de perversidades, Hijos sin fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 21, 'Ellos me movieron á celos con lo que no es Dios; Hiciéronme ensañar con sus vanidades: Yo también los moveré á celos con un pueblo que no es pueblo, Con gente insensata los haré ensañar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 22, 'Porque fuego se encenderá en mi furor, Y arderá hasta el profundo; Y devorará la tierra y sus frutos, Y abrasará los fundamentos de los montes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 23, 'Yo allegaré males sobre ellos; Emplearé en ellos mis saetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 24, 'Consumidos serán de hambre, y comidos de fiebre ardiente Y de amarga pestilencia; Diente de bestias enviaré también sobre ellos, Con veneno de serpiente de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 25, 'De fuera desolará la espada, Y dentro de las cámaras el espanto: Así al mancebo como á la doncella, Al que mama como el hombre cano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 26, 'Dije: Echaríalos yo del mundo, Haría cesar de entre los hombres la memoria de ellos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 27, 'Si no temiese la ira del enemigo, No sea que se envanezcan sus adversarios, No sea que digan: Nuestra mano alta Ha hecho todo esto, no Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 28, 'Porque son gente de perdidos consejos, Y no hay en ellos entendimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 29, '¡Ojalá fueran sabios, que comprendieran esto, Y entendieran su postrimería!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 30, '¿Cómo podría perseguir uno á mil, Y dos harían huir á diez mil, Si su Roca no los hubiese vendido, Y Jehová no los hubiera entregado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 31, 'Que la roca de ellos no es como nuestra Roca: Y nuestros enemigos sean de ello jueces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 32, 'Porque de la vid de Sodoma es la vid de ellos, Y de los sarmientos de Gomorra: Las uvas de ellos son uvas ponzoñosas, Racimos muy amargos tienen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 33, 'Veneno de dragones es su vino, Y ponzoña cruel de áspides.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 34, '¿No tengo yo esto guardado, Sellado en mis tesoros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 35, 'Mía es la venganza y el pago, Al tiempo que su pie vacilará; Porque el día de su aflicción está cercano, Y lo que les está preparado se apresura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 36, 'Porque Jehová juzgará á su pueblo, Y por amor de sus siervos se arrepentirá, Cuando viere que la fuerza pereció, Y que no hay guardado, mas desamparado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 37, 'Y dirá: ¿Dónde están sus dioses, La roca en que se guarecían;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 38, 'Que comían el sebo de sus sacrificios, Bebían el vino de sus libaciones? Levántense, que os ayuden Y os defiendan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 39, 'Ved ahora que yo, yo soy, Y no hay dioses conmigo: Yo hago morir, y yo hago vivir: Yo hiero, y yo curo: Y no hay quien pueda librar de mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 40, 'Cuando yo alzaré á los cielos mi mano, Y diré: Vivo yo para siempre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 41, 'Si afilare mi reluciente espada, Y mi mano arrebatare el juicio, Yo volveré la venganza á mis enemigos, Y daré el pago á los que me aborrecen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 42, 'Embriagaré de sangre mis saetas, Y mi espada devorará carne: En la sangre de los muertos y de los cautivos, De las cabezas, con venganzas de enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 43, 'Alabad, gentes, á su pueblo, Porque él vengará la sangre de sus siervos, Y volverá la venganza á sus enemigos, Y expiará su tierra, á su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 44, 'Y vino Moisés, y recitó todas las palabras de este cántico á oídos del pueblo, él, y Josué hijo de Nun.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 45, 'Y acabó Moisés de recitar todas estas palabras á todo Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 46, 'Y díjoles: Poned vuestro corazón á todas las palabras que yo os protesto hoy, para que las mandéis á vuestros hijos, y cuiden de poner por obra todas las palabras de esta ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 47, 'Porque no os es cosa vana, mas es vuestra vida: y por ellas haréis prolongar los días sobre la tierra, para poseer la cual pasáis el Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 48, 'Y habló Jehová á Moisés aquel mismo día, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 49, 'Sube á este monte de Abarim, al monte Nebo, que está en la tierra de Moab, que está en derecho de Jericó, y mira la tierra de Canaán, que yo doy por heredad á los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 50, 'Y muere en el monte al cual subes, y sé reunido á tus pueblos; al modo que murió Aarón tu hermano en el monte de Hor, y fué reunido á sus pueblos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 51, 'Por cuanto prevaricasteis contra mí en medio de los hijos de Israel en las aguas de la rencilla de Cades, en el desierto de Zin; porque no me santificasteis en medio de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 32, 52, 'Verás por tanto delante de ti la tierra; mas no entrarás allá, á la tierra que doy á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 1, 'Y ESTA es la bendición con la cual bendijo Moisés varón de Dios á los hijos de Israel, antes que muriese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 2, 'Y dijo: Jehová vino de Sinaí, Y de Seir les esclareció; Resplandeció del monte de Parán, Y vino con diez mil santos: A su diestra la ley de fuego para ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 3, 'Aun amó los pueblos; Todos sus santos en tu mano: Ellos también se llegaron á tus pies: Recibieron de tus dichos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 4, 'Ley nos mandó Moisés, Heredad á la congregación de Jacob.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 5, 'Y fué rey en Jeshurun, Cuando se congregaron las cabezas del pueblo Con las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 6, 'Viva Rubén, y no muera; Y sean sus varones en número.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 7, 'Y esta bendición para Judá. Dijo así: Oye, oh Jehová, la voz de Judá, Y llévalo á su pueblo; Sus manos le basten, Y tú seas ayuda contra sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 8, 'Y a Leví dijo: Tu Thummim y tu Urim, con tu buen varón Al cual tentaste en Massa, Y le hiciste reñir en las aguas de la rencilla;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 9, 'El que dijo á su padre y á su madre: Nunca los vi: Ni conoció á sus hermanos, Ni conoció á sus hijos: Por lo cual ellos guardarán tus palabras, Y observarán tu pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 10, 'Ellos enseñarán tus juicios á Jacob, Y tu ley á Israel; Pondrán el perfume delante de ti, Y el holocausto sobre tu altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 11, 'Bendice, oh Jehová, lo que hicieren, Y recibe con agrado la obra de sus manos: Hiere los lomos de sus enemigos, Y de los que le aborrecieren; para que nunca se levanten.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 12, 'Y á Benjamín dijo: El amado de Jehová habitará confiado cerca de él: Cubrirálo siempre, Y entre sus hombros morará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 13, 'Y á José dijo: Bendita de Jehová su tierra, Por los regalos de los cielos, por el rocío, Y por el abismo que abajo yace,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 14, 'Y por los regalados frutos del sol, Y por los regalos de las influencias de las lunas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 15, 'Y por la cumbre de los montes antiguos, Y por los regalos de los collados eternos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 16, 'Y por los regalos de la tierra y su plenitud; Y la gracia del que habitó en la zarza Venga sobre la cabeza de José, Y sobre la mollera del apartado de sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 17, 'El es aventajado como el primogénito de su toro, Y sus cuernos, cuernos de unicornio: Con ellos acorneará los pueblos juntos hasta los fines de la tierra: Y estos son los diez millares de Ephraim, Y estos los millares de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 18, 'Y á Zabulón dijo: Alégrate, Zabulón, cuando salieres: Y tu Issachâr, en tus tiendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 19, 'Llamarán los pueblos al monte: Allí sacrificarán sacrificios de justicia: Por lo cual chuparán la abundancia de los mares, Y los tesoros escondidos de la arena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 20, 'Y a Gad dijo: Bendito el que hizo ensanchar á Gad: Como león habitará, Y arrebatará brazo y testa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 21, 'Y él se ha provisto de la parte primera, Porque allí una porción del legislador fuéle reservada, Y vino en la delantera del pueblo; La justicia de Jehová ejecutará, Y sus juicios con Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 22, 'Y á Dan dijo: Dan, cachorro de león: Saltará desde Basán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 23, 'Y á Nephtalí dijo: Nephtalí, saciado de benevolencia, Y lleno de la bendición de Jehová, Posee el occidente y el mediodía,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 24, 'Y á Aser dijo: Bendito Aser en hijos: Agradable será á sus hermanos, Y mojará en aceite su pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 25, 'Hierro y metal tu calzado, Y como tus días tu fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 26, 'No hay como el Dios de Jeshurun, Montado sobre los cielos para tu ayuda, Y sobre las nubes con su grandeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 27, 'El eterno Dios es tu refugio Y acá abajo los brazos eternos; El echará de delante de ti al enemigo, Y dirá: Destruye.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 28, 'E Israel, fuente de Jacob, habitará confiado solo En tierra de grano y de vino: También sus cielos destilarán rocío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 33, 29, 'Bienaventurado tú, oh Israel, ¿Quién como tú, Pueblo salvo por Jehová, Escudo de tu socorro, Y espada de tu excelencia? Así que tus enemigos serán humillados, Y tú hollarás sobre sus alturas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 1, 'Y SUBIO Moisés de los campos de Moab al monte de Nebo, á la cumbre de Pisga, que está enfrente de Jericó: y mostróle Jehová toda la tierra de Galaad hasta Dan,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 2, 'Y á todo Nephtalí, y la tierra de Ephraim y de Manasés, toda la tierra de Judá hasta la mar postrera;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 3, 'Y la parte meridional, y la campiña, la vega de Jericó, ciudad de las palmas, hasta Soar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 4, 'Y díjole Jehová: Esta es la tierra de que juré á Abraham, á Isaac, y á Jacob, diciendo: A tu simiente la daré. Hétela hecho ver con tus ojos, mas no pasarás allá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 5, 'Y murió allí Moisés siervo de Jehová, en la tierra de Moab, conforme al dicho de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 6, 'Y enterrólo en el valle, en tierra de Moab, enfrente de Bethpeor; y ninguno sabe su sepulcro hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 7, 'Y era Moisés de edad de ciento y veinte años cuando murió: sus ojos nunca se oscurecieron, ni perdió su vigor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 8, 'Y lloraron los hijos de Israel á Moisés en los campos de Moab treinta días: Y así se cumplieron los días del lloro del luto de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 9, 'Y Josué hijo de Nun fué lleno de espíritu de sabiduría, porque Moisés había puesto sus manos sobre él: y los hijos de Israel le obedecieron, é hicieron como Jehová mandó á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 10, 'Y nunca más se levantó profeta en Israel como Moisés, á quien haya conocido Jehová cara á cara;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 11, 'En todas las señales y prodigios que le envió Jehová á hacer en tierra de Egipto á Faraón, y á todos sus siervos, y á toda su tierra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('DEU', 'Deuteronomio', 34, 12, 'Y en toda aquella mano esforzada, y en todo el espanto grande que causó Moisés á ojos de todo Israel.');
